// p1_1112 — NUDGE "rekod sesi LIVE sebelum balik" (Zaid: "dia kena key in setiap kali before balik").
// Syarat: APK + Ariff + selepas 5 petang + hari ni belum ada rekod live + belum dijawab hari ni.
// Muncul waktu login petang & tiap kali app dibuka semula dari latar (sampai dia jawab).
window.__liveNudgeCheck = async function(){
 try {
  const u = window.currentUser || {};
  if(!window.__isPOSApp || !window.__isLiveHost(u)) return; // p1_1164 — Ariff + Tarmizi Kael
  if(typeof db === 'undefined' || !db) return;
  const now = new Date();
  if(now.getHours() < 17) return;
  const today = now.getFullYear()+'-'+String(now.getMonth()+1).padStart(2,'0')+'-'+String(now.getDate()).padStart(2,'0');
  try { if(localStorage.getItem('posLiveNudge_' + today)) return; } catch(e){}
  if(document.getElementById('liveNudgeOverlay')) return;
  const { data } = await db.from('live_sessions').select('id').eq('host_name', u.name).eq('session_date', today).limit(1); // p1_1164 — semak rekod host ini, bukan hardcode Ariff
  if(data && data.length){ try { localStorage.setItem('posLiveNudge_' + today, 'done'); } catch(e){} return; }
  const ov = document.createElement('div');
  ov.id = 'liveNudgeOverlay';
  ov.style.cssText = 'position:fixed;inset:0;background:rgba(15,23,42,.6);z-index:9995;display:flex;align-items:center;justify-content:center;padding:20px;backdrop-filter:blur(2px);';
  ov.innerHTML = '<div style="background:#fff;border-radius:16px;max-width:360px;width:100%;padding:22px;box-shadow:0 24px 60px rgba(0,0,0,.4);font-family:var(--font-main,Poppins),sans-serif;text-align:center;">'
   + '<i data-lucide="radio" style="width:34px;height:34px;color:var(--primary);"></i>'
   + '<div style="font-size:16px;font-weight:800;color:#101010;margin:10px 0 6px;">Rekod sesi LIVE sebelum balik</div>'
   + '<p style="font-size:12.5px;color:#6B7280;line-height:1.6;margin:0 0 16px;">' + (u.name ? hesc(String(u.name).split(' ')[0]) : 'Hai') + ', kalau hari ni ada buat LIVE TikTok, masukkan masa mula &amp; tamat SEKARANG — komisen 5% margin dikira dari rekod ni. Tak rekod = tak dikira.</p>'
   + '<button onclick="document.getElementById(\'liveNudgeOverlay\').remove(); window.__posAppGo(\'live\');" style="width:100%;background:var(--primary);color:#fff;border:none;padding:13px;border-radius:11px;font-size:14px;font-weight:800;cursor:pointer;">Rekod Sekarang</button>'
   + '<button onclick="try{localStorage.setItem(\'posLiveNudge_' + today + '\',\'tiada\')}catch(e){}; document.getElementById(\'liveNudgeOverlay\').remove();" style="width:100%;margin-top:8px;background:#fff;border:1.5px solid var(--border-color,#E5E7EB);color:#374151;padding:11px;border-radius:11px;font-size:12.5px;font-weight:700;cursor:pointer;">Tiada LIVE hari ni</button>'
   + '<button onclick="document.getElementById(\'liveNudgeOverlay\').remove();" style="width:100%;margin-top:6px;background:none;border:none;color:#9CA3AF;padding:6px;font-size:11.5px;font-weight:600;cursor:pointer;">Ingatkan lagi nanti</button>'
   + '</div>';
  document.body.appendChild(ov);
  if(window.lucide && lucide.createIcons) try { lucide.createIcons(); } catch(e){}
 } catch(e){}
};
document.addEventListener('visibilitychange', function(){ if(document.visibilityState === 'visible') { try { window.__liveNudgeCheck(); } catch(e){} } });

// p1_786 (C1) — attach the staff Supabase session token so gated mutating functions
// (shopee-disconnect, marketplace-settings write) can verify the caller is a logged-in staff.
// Returns the base headers unchanged (no Authorization) if there is no active session.
window.__authHeaders = async function(base) {
 const h = Object.assign({}, base || {});
 try {
  if(db && db.auth && typeof db.auth.getSession === 'function') {
   const { data } = await db.auth.getSession();
   const tok = data && data.session && data.session.access_token;
   if(tok) h['Authorization'] = 'Bearer ' + tok;
  }
 } catch(e){}
 return h;
};

// p1_787 (C1) — SYNC variant for fire-and-forget calls (can't await). Reads the token straight from
// the supabase-js session in localStorage (key sb-<ref>-auth-token). Slightly staler than getSession()
// but fine for a gate check; if the token is briefly stale the cron backstop re-syncs.
window.__authHeaderSync = function(base) {
 const h = Object.assign({}, base || {});
 try {
  const raw = localStorage.getItem('sb-asehjdnfzoypbwfeazra-auth-token');
  if(raw) {
   const s = JSON.parse(raw);
   const tok = (s && (s.access_token || (s.currentSession && s.currentSession.access_token))) || null;
   if(tok) h['Authorization'] = 'Bearer ' + tok;
  }
 } catch(e){}
 return h;
};

// Cara B — hantar (auto-create) satu produk ke TikTok Seller Centre sebagai DRAF.
// Guna auth staff (Authorization JWT via __authHeaderSync). Server: tiktok-create-product.
window.__tiktokPushProduct = async function(sku, opts){
 opts = opts || {};
 if(!sku) return { ok:false, error:'no sku' };
 try {
  const res = await fetch('/api/tiktok-create-product', {
   method:'POST',
   headers: window.__authHeaderSync({ 'Content-Type':'application/json' }),
   body: JSON.stringify({ sku: sku, force: !!opts.force })
  });
  const j = await res.json().catch(()=>({ ok:false, error:'respons tak sah' }));
  if(opts.toast !== false && typeof showToast === 'function'){
   if(j.ok && j.product_id) showToast('TikTok: draf produk dicipta ('+sku+')', 'success');
   else if(j.already) showToast('TikTok: '+sku+' sudah ada di TikTok', 'info');
   else showToast('TikTok gagal ('+sku+'): '+(j.tiktok_msg||j.error||(j.errors&&j.errors[0])||'tak diketahui'), 'warn');
  }
  return j;
 } catch(e){
  if(opts.toast !== false && typeof showToast === 'function') showToast('TikTok ralat: '+e.message, 'warn');
  return { ok:false, error:String(e) };
 }
};

// Butang manual dari senarai produk — hantar + kemas kini badge tempatan + render semula.
window.__tiktokPushFromList = async function(sku){
 if(!sku) return;
 if(typeof showToast === 'function') showToast('Menghantar '+sku+' ke TikTok…', 'info');
 const j = await window.__tiktokPushProduct(sku, { toast:true });
 if(j && j.ok && j.product_id && typeof masterProducts !== 'undefined'){
  (masterProducts||[]).forEach(p=>{
   if(p.sku===sku || p.parent_sku===sku){ p.metadata = Object.assign({}, p.metadata||{}, { tiktok_product_id: j.product_id }); }
  });
  if(typeof renderProductDatabase === 'function') renderProductDatabase();
 }
};

// p1_75: Auto-login on refresh — Supabase persists session in localStorage by default.
// On boot, fetch active session; if user matches authUsers, loginAs silent
// (skip welcome modal flash). Staff stays logged in across refresh.
window.__restoreSession = async function() {
 try {
 if(!db || !db.auth || typeof db.auth.getSession !== 'function') return false;
 const { data, error } = await db.auth.getSession();
 if(error || !data || !data.session || !data.session.user) return false;
 const email = (data.session.user.email || '').toLowerCase();
 const user = (typeof authUsers !== 'undefined' ? authUsers : []).find(u => (u.email || '').toLowerCase() === email);
 if(!user) {
 // Stale Supabase session for an unknown email — sign out to avoid loops.
 try { await db.auth.signOut({ scope: 'local' }); } catch(e){}
 return false;
 }
 // p1_1030 — MOBILE app (peranti kongsi): JANGAN silent-restore → wajib PIN setiap launch.
 // Sesi Supabase kekal sah (PIN login guna semula = laju); cuma tak auto-buka tanpa PIN.
 // Boot (baris ~34) akan panggil handleLogin() bila restored=false + posapp. Web/desktop kekal stay-login.
 // p1_1089 — KECUALI peranti peribadi: kalau device ni ditanda milik staf yang SAMA dengan
 // sesi yang tersimpan, benarkan silent-restore (tak tanya PIN). Staf lain / tiada flag = PIN.
 if(window.__isPOSApp) {
 const pd = (typeof window.__getPersonalDevice === 'function') ? window.__getPersonalDevice() : null;
 if(!pd || pd.staff_id !== user.staff_id) return false;
 }
 // Hide any lingering login overlay, then boot user session silently.
 const overlay = document.getElementById('pinLoginOverlay');
 if(overlay) overlay.style.display = 'none';
 loginAs(user, { silent: true });
 return true;
 } catch(e) {
 console.warn('Session restore failed:', e);
 return false;
 }
};


// Money helper: avoid float-drift accumulation. Use after every += / arithmetic
// that contributes to a money total. Display layers can still toFixed(2).
window.round2 = function(n) { return Math.round((parseFloat(n) || 0) * 100) / 100; };
// p1_863 — format duit seragam (en-MY, pemisah ribuan + 2 titik perpuluhan) untuk SEMUA paparan tunai
window.__money = function(n) { return Number(n || 0).toLocaleString('en-MY', { minimumFractionDigits: 2, maximumFractionDigits: 2 }); };
const round2 = window.round2;

// p1_452 — SATU sumber kebenaran utk "jualan dikira dalam analytics".
// Buang order test + void/cancel/refund. Diguna SEMUA halaman analytics/reports
// supaya angka konsisten & tepat (definisi sama macam home dashboard p1_449).
window.__isRealSale = function(s) {
 if (!s || s.is_test) return false;
 const st = (s.status || '').toLowerCase();
 if (st.includes('void') || st.includes('cancel') || st.includes('refund')) return false;
 return true;
};

// p1_1085 — TELEMETRY klien (siasat aduan Ariff "cashier lag / Selesai tak load" yang tak dapat
// direproduce). Hantar event ringan (checkout timing + JS error) ke client-telemetry fn →
// table client_telemetry. Fire-and-forget: TAK BOLEH ganggu cashier walau apa pun (silent fail).
window.__telAppV = (function(){ try { const s = document.querySelector('script[src*="app.js?v="]'); const m = s && /v=(\d+)/.exec(s.src); return m ? m[1] : ''; } catch(e){ return ''; } })();

// p1_1093 — PENGAWAL VERSI. Punca: APK/WebView tak pernah reload sendiri — device staf boleh
// jalan JS basi BERHARI-HARI selepas deploy (kes sebenar: fix OOS p1_1092 dah live tapi device
// Zaid masih tunjuk Stok Habis sebab kod lama kekal dlm memori; kes Ariff pun disyaki sama).
// Check versi HTML server bila app resume (throttle 5 min) + tiap 30 min + sekali lepas boot.
// Versi baru: reload AUTO bila selamat (troli kosong), kalau tengah jual → toast, cuba lagi nanti.
(function(){
 if (!window.__telAppV) return; // versi tak dikesan (dev/file://) — skip
 let lastCheck = 0;
 async function check(){
  const now = Date.now();
  if (now - lastCheck < 5*60*1000) return;
  lastCheck = now;
  try {
   const res = await fetch('/?vercheck=' + now, { cache: 'no-store' });
   if (!res.ok) return;
   const m = /app\.js\?v=(\d+)/.exec(await res.text());
   if (!m) return;
   const server = parseInt(m[1],10), local = parseInt(window.__telAppV,10);
   if (!(server > local)) return;
   const busy = (typeof cart !== 'undefined' && Array.isArray(cart) && cart.length > 0);
   const key = 'posVerReload_' + server;
   if (!busy && !sessionStorage.getItem(key)) {
    try { sessionStorage.setItem(key,'1'); } catch(e){}
    location.reload();
    return;
   }
   if (busy && window.showToast) showToast('Versi baru POS sedia (v'+server+'). Habiskan jualan ni — app kemaskini sendiri lepas troli kosong.','warn');
  } catch(e){}
 }
 document.addEventListener('visibilitychange', function(){ if(document.visibilityState==='visible') check(); });
 setInterval(check, 30*60*1000);
 setTimeout(check, 20000);
})();

// p1_1099 — PULL-TO-REFRESH (APK sahaja): tarik skrin ke bawah di PALING ATAS → segar.
// Urutan: (1) check versi server — ada baru & troli kosong → reload penuh (dapat kod baru);
// (2) kalau tak, SOFT refresh: tarik semula produk + stok (paged p1_1092) + render semula
// skrin semasa — TANPA reload page (elak kena PIN semula p1_1030). Indikator pill atas.
(function(){
 if (!window.__isPOSApp) return;
 let startY = 0, armed = false, pulling = false, lastDy = 0;
 const THRESH = 90;
 function pill(txt){
  let el = document.getElementById('ptrPill');
  if(!el){
   el = document.createElement('div'); el.id = 'ptrPill';
   el.style.cssText = 'position:fixed;top:calc(env(safe-area-inset-top,0px) + 10px);left:50%;transform:translateX(-50%);z-index:99999;background:#101010;color:#FAF6EF;font:700 12px var(--font-main,Poppins),sans-serif;padding:8px 16px;border-radius:50px;box-shadow:0 4px 14px rgba(0,0,0,.25);pointer-events:none;white-space:nowrap;';
   document.body.appendChild(el);
  }
  el.textContent = txt; el.style.display = 'block';
 }
 function hidePill(delay){ setTimeout(function(){ const el = document.getElementById('ptrPill'); if(el) el.style.display = 'none'; }, delay || 0); }
 // ada mana-mana bekas atas laluan sentuhan yang DAH scroll ke bawah? (app ada inner scroller)
 function scrolledAny(el){
  let n = el;
  while(n && n !== document.documentElement){
   if(n.scrollTop > 2) return true;
   n = n.parentElement;
  }
  return (window.scrollY || document.documentElement.scrollTop || 0) > 2;
 }
 window.__posAppRefresh = async function(){
  if (window.__ptrBusy) return; window.__ptrBusy = true;
  pill('Menyegarkan…');
  try {
   try {
    const res = await fetch('/?ptr=' + Date.now(), { cache: 'no-store' });
    const m = /app\.js\?v=(\d+)/.exec(await res.text());
    const cartEmpty = !(typeof cart !== 'undefined' && Array.isArray(cart) && cart.length);
    if (m && parseInt(m[1], 10) > parseInt(window.__telAppV || '0', 10) && cartEmpty) { pill('Versi baru — memuat semula…'); location.reload(); return; }
   } catch(e){}
   const [prods, batches] = await Promise.all([
    window.__fetchAllRows('products_master', 'sku', true).catch(function(){ return null; }),
    window.__loadAllBatches().catch(function(){ return null; })
   ]);
   if (Array.isArray(prods) && prods.length) masterProducts = prods;
   if (Array.isArray(batches)) inventoryBatches = batches;
   try { if (typeof renderPOS === 'function') renderPOS(); } catch(e){}
   // render semula section yang sedang terbuka (ikut tab app yang nampak)
   [['checkSessionsSection','renderCheckSessions'], ['allOrdersSection','renderAllOrders'], ['commissionSection','renderCommission']].forEach(function(p){
    try { const s = document.getElementById(p[0]); if (s && getComputedStyle(s).display !== 'none' && typeof window[p[1]] === 'function') window[p[1]](); } catch(e){}
   });
   pill('Dah segar'); hidePill(900);
  } finally { window.__ptrBusy = false; }
 };
 document.addEventListener('touchstart', function(e){
  armed = false;
  if (!e.touches || !e.touches.length) return;
  if (scrolledAny(e.target)) return;                       // tengah scroll dlm senarai — jangan ganggu
  if (document.querySelector('#scsCountPopupOverlay, #skuLocOverlay, #niSendOverlay, #niBcOverlay, #mktContentModal')) return; // popup terbuka
  armed = true; pulling = false; lastDy = 0; startY = e.touches[0].clientY;
 }, { passive: true });
 document.addEventListener('touchmove', function(e){
  if (!armed || !e.touches || !e.touches.length) return;
  const dy = e.touches[0].clientY - startY;
  if (dy > 25) { pulling = true; lastDy = dy; pill(dy > THRESH ? 'Lepas untuk segar semula' : 'Tarik lagi…'); }
 }, { passive: true });
 document.addEventListener('touchend', function(){
  if (!armed) return;
  armed = false;
  if (pulling && lastDy > THRESH) window.__posAppRefresh();
  else if (pulling) hidePill(0);
  pulling = false; lastDy = 0;
 }, { passive: true });
})();

window.__tel = function(type, data){
 try {
  if(!window.currentUser) return; // hanya sesi staff
  const ev = {
   type: type, data: data || null,
   staff: (window.currentUser.name || ''),
   app_version: window.__telAppV,
   device: (navigator.userAgent || '').slice(0, 200),
   online: (typeof navigator.onLine === 'boolean') ? navigator.onLine : null
  };
  fetch('/.netlify/functions/client-telemetry', {
   method: 'POST', keepalive: true,
   headers: (window.__authHeaderSync ? window.__authHeaderSync({'Content-Type':'application/json'}) : {'Content-Type':'application/json'}),
   body: JSON.stringify({ events: [ev] })
  }).catch(function(){});
 } catch(e){}
};
// Tangkap ralat JS global (cap 10/sesi supaya tak banjir) — konteks section aktif disertakan.
window.__telErrCount = 0;
window.addEventListener('error', function(e){
 try {
  if(window.__telErrCount >= 10) return; window.__telErrCount++;
  window.__tel('js_error', { msg: String(e.message || '').slice(0, 300), src: String(e.filename || '').slice(0, 120), line: e.lineno || 0, col: e.colno || 0 });
 } catch(_){}
});
window.addEventListener('unhandledrejection', function(e){
 try {
  if(window.__telErrCount >= 10) return; window.__telErrCount++;
  const r = e && e.reason;
  window.__tel('js_error', { msg: 'unhandledrejection: ' + String((r && (r.message || r)) || '').slice(0, 300), stack: String(r && r.stack || '').slice(0, 400) });
 } catch(_){}
});

