// p1_1130 — TEBUS MATA → BARANG DEAD STOCK (Zaid setuju 20 Jul): mata dapat nilai tebusan,
// dibayar dengan barang stok mati (kos sebenar = kos modal, bukan harga jual). Kadar ikut tier
// (dorong naik tier). PAGAR: walk-in shj + troli ada belian ≥ RM50 dulu + mata BEKU kalau tiada
// belian 12 bulan + satu tebusan per resit (kongsi medan diskaun dgn tier_disc = auto-eksklusif).
// Katalog = definisi Ejen Dead Stock: published, stok>0, 0 jualan 60 hari, margin asal ≥ 35%.
// NOTA SYNC: kadar & peraturan DIDUPLIKAT di netlify/functions/loyalty-otp.js (payload portal) —
// ubah sini, ubah sana sekali.
window.LOYALTY_REDEEM_MIN_PURCHASE = 50;
window.LOYALTY_REDEEM_FREEZE_MONTHS = 12;
window.LOYALTY_REDEEM_MIN_MARGIN = 35;
window.LOYALTY_REDEEM_DEAD_DAYS = 60;
// Tier ikut total_spent (senarai disusun tinggi→rendah; ambil yang pertama layak)
window.__custTier = function(totalSpent){
 const s = Number(totalSpent) || 0;
 return window.LOYALTY_TIERS.find(t => s >= t.min) || window.LOYALTY_TIERS[window.LOYALTY_TIERS.length - 1];
};
// Mata BOLEH-GUNA = mata terkumpul (floor(belanja/10)) tolak mata yang dah ditebus
window.__custPointsAvail = function(c){
 if(!c) return 0;
 return Math.max(0, (Number(c.points) || 0) - (Number(c.points_redeemed) || 0));
};
window.__tierBadgeHtml = function(c){
 const t = window.__custTier(c && c.total_spent);
 return '<span style="background:' + t.bg + '; color:' + t.color + '; padding:1px 6px; border-radius:50px; font-size:9px; font-weight:800; letter-spacing:.3px; margin-left:4px;">' + t.name + '</span>';
};
// Redeem yang dipilih staf untuk transaksi semasa (mata ditolak bila bayar sahaja).
window.__pendingRedeem = null;
window.__cpRedeemCustomer = null;
// p1_1179 — kelayakan diskaun tier dikira SEKALI, dipakai 2 tempat: preview kad ganjaran
// (staf nampak AWAL item mana layak — isu Irfan 22 Jul: barang promo -50% kena block tapi
// staf tak faham kenapa) + __cpApplyRedeem (kiraan sebenar). Margin ikut cost_price.
window.__tierDiscEligibility = function(minMargin){
 const costMap = {};
 (Array.isArray(masterProducts) ? masterProducts : []).forEach(p => { if(p.sku) costMap[String(p.sku).toUpperCase()] = parseFloat(p.cost_price || 0) || 0; });
 const out = { eligibleTotal: 0, eligibleCount: 0, skipCount: 0, cartCount: 0 };
 (Array.isArray(cart) ? cart : []).forEach(it => {
 out.cartCount++;
 const price = Number(it.price) || 0, qty = Number(it.quantity) || 0;
 const cost = costMap[String(it.sku || '').toUpperCase()] || 0;
 const margin = (price > 0 && cost > 0) ? ((price - cost) / price * 100) : -1;
 if(margin >= (minMargin || 0)) { out.eligibleTotal += price * qty; out.eligibleCount++; }
 else out.skipCount++;
 });
 return out;
};
// Panel ganjaran dalam banner checkout: tier + mata + 3 butang redeem tier tu.
window.__cpRedeemPanelHtml = function(match, tier, pct){
 const tk = String(tier).toLowerCase();
 const avail = window.__custPointsAvail(match);
 const redeems = (window.LOYALTY_REDEEMS && window.LOYALTY_REDEEMS[tk]) || [];
 const col = window.getTierColor(tier);
 const pend = window.__pendingRedeem;
 const head = '<div style="display:flex; align-items:center; gap:6px; flex-wrap:wrap;">'
 + '<span style="background:' + col.bg + '; color:' + col.fg + '; padding:2px 8px; border-radius:50px; font-size:10px; font-weight:800;">' + hesc(tier) + '</span>'
 + '<strong style="font-size:12.5px;">' + hesc(match.name || '') + '</strong>'
 + '<span style="font-size:11px; color:#6B7280;">RM' + (Number(match.total_spent) || 0).toFixed(0) + ' belanja &middot; ' + avail + ' mata boleh guna</span>'
 + '</div>';
 const btns = redeems.map((r, i) => {
 const isPend = pend && pend.idx === i && pend.tier === tk;
 const costTxt = r.type === 'deadstock' ? 'mata ikut barang' : (r.cost > 0 ? (r.cost + ' mata') : 'percuma');
 const afford = r.cost <= 0 || avail >= r.cost;
 // p1_1179 — status kelayakan AWAL pada kad Diskaun tier (isu Irfan: baru tahu bila tekan).
 let enabled = afford, statusHtml = '';
 if(r.type === 'tier_disc'){
 const el = window.__tierDiscEligibility(r.minMargin);
 if(!el.cartCount){
 statusHtml = '<br><span style="font-weight:600; font-size:10px; color:#9CA3AF;">Troli kosong — masukkan barang dulu</span>';
 } else if(el.eligibleCount === 0){
 enabled = false;
 statusHtml = '<br><span style="font-weight:700; font-size:10px; color:#B23A2E;">✗ Tak layak — barang promo/margin nipis (' + el.skipCount + ' item)</span>';
 } else {
 const rmPrev = el.eligibleTotal * (r.pct || 0) / 100;
 statusHtml = '<br><span style="font-weight:700; font-size:10px; color:#168C50;">✓ ' + el.eligibleCount + ' item layak → −RM' + rmPrev.toFixed(2) + (el.skipCount ? ' · ' + el.skipCount + ' promo tak termasuk' : '') + '</span>';
 }
 }
 const bg = isPend ? '#4E7C4A' : (enabled ? '#fff' : '#F3F4F6');
 const fg = isPend ? '#fff' : (enabled ? '#374151' : '#9CA3AF');
 const bd = isPend ? '#4E7C4A' : '#E5E7EB';
 return '<button type="button" ' + (enabled ? '' : 'disabled') + ' onclick="window.__cpApplyRedeem(' + i + ')" style="text-align:left; flex:1; min-width:118px; padding:7px 9px; border:1px solid ' + bd + '; background:' + bg + '; color:' + fg + '; border-radius:9px; cursor:' + (enabled ? 'pointer' : 'not-allowed') + '; font-size:11.5px; font-weight:700;">' + (isPend ? '(dipilih) ' : '') + hesc(r.label) + '<br><span style="font-weight:600; font-size:10px; opacity:.85;">' + costTxt + '</span>' + statusHtml + '</button>';
 }).join('');
 const foot = pend ? '<button type="button" onclick="window.__cpClearRedeem()" style="margin-top:6px; background:none; border:0; color:#B23A2E; font-size:11px; font-weight:700; cursor:pointer;">Batal redeem</button>' : '';
 return head + '<div style="display:flex; gap:6px; flex-wrap:wrap; margin-top:8px;">' + btns + '</div>' + foot;
};
window.__cpApplyRedeem = function(idx){
 const match = window.__cpRedeemCustomer;
 if(!match){ if(typeof showToast === 'function') showToast('Attach customer dulu.', 'warn'); return; }
 const tk = String(window.getCustomerTier(match)).toLowerCase();
 const r = ((window.LOYALTY_REDEEMS && window.LOYALTY_REDEEMS[tk]) || [])[idx];
 if(!r) return;
 const avail = window.__custPointsAvail(match);
 if(r.cost > 0 && avail < r.cost){ if(typeof showToast === 'function') showToast('Mata tak cukup — perlu ' + r.cost + ', ada ' + avail + '.', 'warn'); return; }
 // p1_1060 — semua ganjaran tier = WALK-IN sahaja (tiada gateway online)
 if(r.type === 'tier_disc' || r.type === 'shirt' || r.type === 'deadstock'){
 const ch = (document.getElementById('cpChannel') || {}).value || 'POS Cashier';
 if(ch !== 'POS Cashier'){ if(typeof showToast === 'function') showToast('Ganjaran tier untuk WALK-IN sahaja (channel POS Cashier).', 'warn'); return; }
 }
 if(r.type === 'deadstock'){
 // p1_1130 — Tebus mata → barang dead stock. Pagar dulu, baru buka picker.
 (async function(){
 // Pagar 1: troli mesti dah ada belian ≥ RM50 (tebusan MESTI tarik jualan sekali)
 const cartTotal = (Array.isArray(cart) ? cart : []).reduce((s, it) => s + (Number(it.price) || 0) * (Number(it.quantity) || 0), 0);
 if(cartTotal < (window.LOYALTY_REDEEM_MIN_PURCHASE || 50)){
 if(typeof showToast === 'function') showToast('Tebusan mata perlukan belian RM' + (window.LOYALTY_REDEEM_MIN_PURCHASE || 50) + '+ dalam resit sama (troli sekarang RM ' + cartTotal.toFixed(2) + ').', 'warn');
 return;
 }
 // Pagar 2: mata beku kalau tiada belian 12 bulan
 const fr = await window.__dsLastPurchaseOk(match);
 if(!fr.ok){
 if(typeof showToast === 'function') showToast('Mata ' + (match.name || 'customer') + ' BEKU — ' + fr.why + '. Belian hari ini akan aktifkan semula (tebus lain kali).', 'warn');
 return;
 }
 // Pagar 3: data jualan cukup untuk kira dead stock (60 hari)
 if(!window.__fullSalesLoaded && !window.__isAppDataCapped()){
 if(typeof showToast === 'function') showToast('Data jualan penuh masih dimuat — cuba lagi dalam beberapa saat.', 'warn');
 return;
 }
 window.__dsOpenRedeemPicker(match, tk, r.rate || 0.5, avail);
 })();
 return;
 }
 if(r.type === 'tier_disc'){
 // p1_1060 — diskaun HANYA pada item terpilih = margin semasa >= minMargin (kira dari cost_price).
 // Item tiada kos / margin nipis TAK layak — lindung margin (arahan Zaid: VIP 45 / Silver 40 / Bronze 35).
 // p1_1179 — kiraan dipindah ke __tierDiscEligibility (kongsi dgn preview kad ganjaran).
 const el = window.__tierDiscEligibility(r.minMargin);
 if(el.eligibleCount === 0){ if(typeof showToast === 'function') showToast('Tiada item layak — barang promo / margin bawah ' + r.minMargin + '% / tiada kos dikecualikan dari diskaun tier. (Customer masih boleh tebus mata → barang.)', 'warn'); return; }
 const discRm = round2(el.eligibleTotal * (r.pct || 0) / 100);
 const dt = document.getElementById('cpDiscType'); if(dt) dt.value = 'rm';
 const da = document.getElementById('cpDiscAmt'); if(da) da.value = discRm.toFixed(2);
 const dr = document.getElementById('cpDiscReason'); if(dr) dr.value = 'Diskaun tier ' + r.pct + '% — ' + el.eligibleCount + ' item layak (walk-in)';
 window.__pendingRedeem = { customer_id: match.id, tier: tk, idx: idx, type: r.type, label: r.label, cost: 0, rm: discRm, pct: r.pct || 0 };
 if(typeof cpRecomputeTotal === 'function') cpRecomputeTotal();
 if(typeof window.cpVipLookup === 'function') window.cpVipLookup();
 if(typeof showToast === 'function') showToast('Diskaun ' + r.pct + '%: ' + el.eligibleCount + ' item layak → −RM ' + discRm.toFixed(2) + (el.skipCount ? ' (' + el.skipCount + ' item promo/margin nipis tak termasuk)' : ''), 'success');
 return;
 }
 if(r.type === 'shirt'){
 // p1_1060 — rekod claim baju: 1×/TAHUN per customer (unique DB), tiada kesan harga
 (async function(){
 try {
 const yr = new Date().getFullYear();
 const { data: ex } = await db.from('loyalty_shirt_claims').select('id,claimed_at').eq('customer_id', match.id).eq('claim_year', yr).limit(1);
 if(ex && ex.length){ if(typeof showToast === 'function') showToast((match.name || 'Customer') + ' dah claim baju tahun ' + yr + ' (' + new Date(ex[0].claimed_at).toLocaleDateString('en-MY') + ').', 'warn'); return; }
 const { error } = await db.from('loyalty_shirt_claims').insert([{ customer_id: match.id, claim_year: yr, tier: tk, staff_name: (window.currentUser || {}).name || 'Unknown' }]);
 if(error) throw error;
 if(typeof showToast === 'function') showToast('Claim baju ' + yr + ' direkod untuk ' + (match.name || 'customer') + ' — serahkan baju (saiz terhad, ikut stok).', 'success');
 } catch(e){ if(typeof showToast === 'function') showToast('Gagal rekod claim: ' + e.message, 'error'); }
 })();
 return;
 }
 if(r.type === 'disc'){
 const dt = document.getElementById('cpDiscType'); if(dt) dt.value = 'pct';
 const da = document.getElementById('cpDiscAmt'); if(da) da.value = r.pct;
 } else if(r.type === 'voucher'){
 const dt = document.getElementById('cpDiscType'); if(dt) dt.value = 'rm';
 const da = document.getElementById('cpDiscAmt'); if(da) da.value = r.rm;
 } // gift: tiada kesan harga
 window.__pendingRedeem = { customer_id: match.id, tier: tk, idx: idx, type: r.type, label: r.label, cost: r.cost || 0, rm: r.rm || 0, pct: r.pct || 0 };
 if(typeof cpRecomputeTotal === 'function') cpRecomputeTotal();
 if(typeof window.cpVipLookup === 'function') window.cpVipLookup();
 if(typeof showToast === 'function') showToast('Redeem: ' + r.label + (r.cost > 0 ? ' (−' + r.cost + ' mata bila bayar)' : '') + (r.type === 'gift' ? ' — ingat bagi pada customer!' : ''), 'success');
};
window.__cpClearRedeem = function(){
 window.__pendingRedeem = null;
 const da = document.getElementById('cpDiscAmt'); if(da) da.value = '';
 if(typeof cpRecomputeTotal === 'function') cpRecomputeTotal();
 if(typeof window.cpVipLookup === 'function') window.cpVipLookup();
};

// ============ p1_1130 — TEBUS MATA → BARANG DEAD STOCK ============
// Pagar 2: mata beku kalau customer tiada belian 12 bulan (proksi luput tanpa lejar mata —
// customers cuma simpan agregat points/points_redeemed, tiada tarikh per-mata).
window.__dsLastPurchaseOk = async function(match){
 try {
 let q = db.from('sales_history').select('created_at,status').order('created_at', { ascending: false }).limit(5);
 if(match.phone) q = q.eq('customer_phone', match.phone);
 else if(match.email) q = q.eq('customer_email', match.email); // p1_1136 — member email-sahaja (SOP pilih salah satu)
 else if(match.name && match.name.toLowerCase() !== 'walk-in') q = q.eq('customer_name', match.name);
 else return { ok: false, why: 'tiada telefon/nama utk semak sejarah' };
 const { data } = await withTimeout(q, 8000, 'semak belian terakhir');
 const VOIDS = ['voided','cancelled','canceled','refunded'];
 const live = (data || []).find(s => !VOIDS.includes(String(s.status || '').toLowerCase()));
 if(!live) return { ok: false, why: 'tiada rekod belian' };
 const days = Math.round((Date.now() - new Date(live.created_at).getTime()) / 86400000);
 const maxDays = (window.LOYALTY_REDEEM_FREEZE_MONTHS || 12) * 30;
 return days <= maxDays ? { ok: true } : { ok: false, why: 'belian terakhir ' + days + ' hari lalu (had ' + maxDays + ')' };
 } catch(e){ return { ok: true }; } // rangkaian gagal — jangan blok kaunter, staf yang nilai
};
// Katalog client-side — definisi SAMA dgn Ejen Dead Stock (deadstock-agent-background.js):
// published, stok>0, harga & kos wujud, margin asal >= 35%, 0 jualan 60 hari.
window.__dsRedeemCatalog = function(){
 const cutoff = Date.now() - (window.LOYALTY_REDEEM_DEAD_DAYS || 60) * 86400000;
 const VOIDS = ['voided','cancelled','canceled','refunded'];
 const sold = {};
 (Array.isArray(salesHistory) ? salesHistory : []).forEach(s => {
 if(!s || s.is_test) return;
 if(VOIDS.includes(String(s.status || '').toLowerCase())) return;
 if(!s.created_at || new Date(s.created_at).getTime() < cutoff) return;
 let items = s.items; if(typeof items === 'string'){ try { items = JSON.parse(items); } catch(e){ items = []; } }
 if(!Array.isArray(items)) return;
 items.forEach(it => { const k = String(it && it.sku || '').toUpperCase(); if(k) sold[k] = true; });
 });
 const stock = {};
 (Array.isArray(inventoryBatches) ? inventoryBatches : []).forEach(b => { if(b.sku) stock[String(b.sku).toUpperCase()] = (stock[String(b.sku).toUpperCase()] || 0) + (Number(b.qty_remaining) || 0); });
 const minM = window.LOYALTY_REDEEM_MIN_MARGIN || 35;
 return (Array.isArray(masterProducts) ? masterProducts : []).filter(p => {
 if(typeof isPublished === 'function' && !isPublished(p)) return false;
 const k = String(p.sku || '').toUpperCase();
 const price = parseFloat(p.price) || 0, cost = parseFloat(p.cost_price) || 0;
 if(!k || sold[k] || (stock[k] || 0) <= 0 || price <= 0 || cost <= 0) return false;
 return ((price - cost) / price * 100) >= minM;
 }).map(p => {
 // p1_1138 — gambar utk kad tebusan (Customer Display + picker staf)
 let img = ''; if(Array.isArray(p.images) && p.images[0]) img = p.images[0]; else if(typeof p.images === 'string' && p.images) img = p.images;
 return { sku: p.sku, name: p.name || p.sku, price: parseFloat(p.price) || 0, stok: stock[String(p.sku).toUpperCase()] || 0, image: img };
 }).sort((a, b) => a.price - b.price);
};
// p1_1137 — cache katalog dead stock 5 minit (kira sekali, dipakai picker + skrin customer).
// p1_1149 — KIRA DI LATAR SAHAJA utk laluan pasif (Zaid: app "lagging, scroll indicator je
// bergerak" + butang "Siap — resit…" lama): scan salesHistory + parse items atas MAIN THREAD
// pada tiap ketikan/selepas jualan = beku UI di iPhone. Kini: cache fresh → pulang terus;
// tiada/basi → jadualkan kiraan masa TERLUANG (requestIdleCallback) & pulangkan stale/kosong
// TANPA sekat UI; bila siap, refresh skrin customer sendiri. force=true (picker — tindakan
// eksplisit staf, sekali tekan) kekal kira segerak.
window.__dsCatalogCached = function(force){
 try {
 const c = window.__dsCatalogCacheV1;
 const fresh = c && (Date.now() - c.at) < 5 * 60000;
 if(fresh) return c.items;
 if(!window.__fullSalesLoaded && !window.__isAppDataCapped()) return c ? c.items : [];
 if(force){
 const items = window.__dsRedeemCatalog();
 window.__dsCatalogCacheV1 = { at: Date.now(), items: items };
 return items;
 }
 if(!window.__dsCatalogWarming){
 window.__dsCatalogWarming = true;
 const idle = window.requestIdleCallback ? function(f){ window.requestIdleCallback(f, { timeout: 4000 }); } : function(f){ setTimeout(f, 600); };
 idle(function(){
 try { window.__dsCatalogCacheV1 = { at: Date.now(), items: window.__dsRedeemCatalog() }; } catch(e){}
 window.__dsCatalogWarming = false;
 try { window.writeCustomerDisplayCart(); } catch(e){} // skrin customer dapat senarai bila siap
 });
 }
 return c ? c.items : []; // stale lebih baik dari beku
 } catch(e){ return []; }
};
// p1_1137 — blok loyalty utk Customer Display (Zaid: "customer pilih redeem SEBELUM bayar —
// display apa yang dia boleh redeem"): mata + top barang mampu-tebus + tebusan dipilih.
window.__cpDisplayLoyalty = function(){
 try {
 const m = window.__cpRedeemCustomer; if(!m) return null;
 const tk = String(window.getCustomerTier(m)).toLowerCase();
 const t = window.__custTier(m.total_spent);
 const avail = window.__custPointsAvail(m);
 const rate = ((window.LOYALTY_REDEEMS && window.LOYALTY_REDEEMS[tk]) || []).reduce((r, x) => x.type === 'deadstock' ? (x.rate || r) : r, 0.4);
 const afford = window.__dsCatalogCached().map(it => ({ name: it.name, price: it.price, mata: Math.ceil(it.price / rate), image: it.image || '' })).filter(x => x.mata <= avail);
 const pend = window.__pendingRedeem;
 return {
 name: m.name || '', tier: t.name, avail: avail, rate: rate,
 redeemables: afford.slice(0, 6),
 more: Math.max(0, afford.length - 6),
 chosen: (pend && pend.type === 'deadstock') ? { label: pend.label || '', cost: pend.cost || 0 } : null
 };
 } catch(e){ return null; }
};
window.__dsPickerCtx = null;
window.__dsOpenRedeemPicker = function(match, tierKey, rate, avail){
 const all = window.__dsCatalogCached(true); // p1_1149 — guna cache (force compute kalau basi — tindakan eksplisit)
 if(!all.length){ if(typeof showToast === 'function') showToast('Tiada barang dead stock layak dalam katalog sekarang.', 'warn'); return; }
 window.__dsPickerCtx = { match: match, tier: tierKey, rate: rate, avail: avail, all: all };
 const old = document.getElementById('dsRedeemOverlay'); if(old) old.remove();
 const ov = document.createElement('div');
 ov.id = 'dsRedeemOverlay';
 ov.style.cssText = 'position:fixed; inset:0; background:rgba(0,0,0,0.55); z-index:6010; display:flex; align-items:flex-start; justify-content:center; padding:20px; padding-top:calc(20px + env(safe-area-inset-top)); overflow-y:auto;';
 ov.onclick = function(e){ if(e.target === ov) window.__dsCloseRedeemPicker(); };
 ov.innerHTML = '<div style="background:#fff; max-width:560px; width:100%; border-radius:12px; padding:20px; margin:auto; font-family:var(--font-main,Poppins),sans-serif;">'
 + '<div style="display:flex; justify-content:space-between; align-items:center; gap:10px; margin-bottom:4px;">'
 + '<h2 style="margin:0; font-size:17px;">Tebus Mata — ' + (match.name ? String(match.name).replace(/</g,'&lt;') : 'Customer') + '</h2>'
 + '<button onclick="window.__dsCloseRedeemPicker()" style="background:none; border:none; font-size:22px; cursor:pointer; color:#999; padding:4px 8px;">×</button></div>'
 + '<div style="font-size:12px; color:#6B7280; margin-bottom:10px;">' + avail + ' mata boleh guna · kadar tier: 1 mata = RM ' + Number(rate).toFixed(2) + ' · <b>1 tebusan per resit</b></div>'
 + '<input id="dsRedeemSearch" type="search" placeholder="Cari SKU / nama…" oninput="window.__dsRenderPickerList(this.value)" style="width:100%; padding:10px 12px; border:1px solid var(--primary-300,#FDBA74); border-radius:8px; font-size:13px; margin-bottom:10px; font-family:inherit;">'
 + '<div id="dsRedeemList" style="max-height:52vh; overflow-y:auto; border:1px solid #F3F4F6; border-radius:8px;"></div>'
 + '</div>';
 document.body.appendChild(ov);
 window.__dsRenderPickerList('');
};
window.__dsRenderPickerList = function(q){
 const ctx = window.__dsPickerCtx, el = document.getElementById('dsRedeemList');
 if(!ctx || !el) return;
 q = String(q || '').trim().toLowerCase();
 const esc = (s) => String(s == null ? '' : s).replace(/&/g,'&amp;').replace(/</g,'&lt;');
 let shown = 0;
 const rows = ctx.all.filter(it => !q || (it.sku + ' ' + it.name).toLowerCase().indexOf(q) > -1).map(it => {
 const mata = Math.ceil(it.price / ctx.rate);
 const afford = mata <= ctx.avail;
 if(shown >= 80) return ''; shown++;
 return '<div style="display:flex; justify-content:space-between; align-items:center; gap:10px; padding:9px 12px; border-bottom:1px solid #F3F4F6; ' + (afford ? '' : 'opacity:.45;') + '">'
 // p1_1138 — thumbnail barang (staf sahkan barang betul sekali imbas)
 + (it.image ? '<img src="' + esc(it.image) + '" loading="lazy" style="width:38px; height:38px; object-fit:cover; border-radius:7px; flex:0 0 auto; background:#F3F4F6;" onerror="this.style.display=\'none\'">' : '<div style="width:38px; height:38px; border-radius:7px; flex:0 0 auto; background:#F3F4F6;"></div>')
 + '<div style="min-width:0; flex:1;"><div style="font-size:12.5px; font-weight:700; overflow:hidden; text-overflow:ellipsis; white-space:nowrap;">' + esc(it.name) + '</div>'
 + '<div style="font-size:10.5px; color:#9CA3AF;">' + esc(it.sku) + ' · RM ' + it.price.toFixed(2) + ' · stok ' + it.stok + '</div></div>'
 + (afford
 ? '<button onclick="window.__dsPickRedeem(\'' + String(it.sku).replace(/'/g, "\\'") + '\')" style="flex-shrink:0; background:var(--primary-500,#CD7C32); color:#fff; border:0; border-radius:8px; padding:8px 12px; font-size:11.5px; font-weight:800; cursor:pointer; font-family:inherit;">' + mata.toLocaleString() + ' mata</button>'
 : '<span style="flex-shrink:0; font-size:11px; font-weight:700; color:#9CA3AF;">' + mata.toLocaleString() + ' mata</span>')
 + '</div>';
 }).join('');
 el.innerHTML = rows || '<div style="padding:14px; text-align:center; color:#9CA3AF; font-size:12px;">Tiada padanan.</div>';
};
window.__dsCloseRedeemPicker = function(){ const ov = document.getElementById('dsRedeemOverlay'); if(ov) ov.remove(); window.__dsPickerCtx = null; };
window.__dsPickRedeem = function(sku){
 const ctx = window.__dsPickerCtx; if(!ctx) return;
 const it = ctx.all.find(x => x.sku === sku); if(!it) return;
 const mata = Math.ceil(it.price / ctx.rate);
 if(mata > ctx.avail){ if(typeof showToast === 'function') showToast('Mata tak cukup.', 'warn'); return; }
 window.addToCart(sku);
 // Zerokan harga barang tebusan guna medan diskaun resit (nilai = harga unit SEBENAR dlm cart,
 // jaga-jaga B2B repricing). Kongsi medan dgn tier_disc → auto satu-tebusan-per-resit.
 const line = (Array.isArray(cart) ? cart : []).find(c => c.sku === sku);
 const unitRm = line ? (Number(line.price) || it.price) : it.price;
 const dt = document.getElementById('cpDiscType'); if(dt) dt.value = 'rm';
 const da = document.getElementById('cpDiscAmt'); if(da) da.value = unitRm.toFixed(2);
 const dr = document.getElementById('cpDiscReason'); if(dr) dr.value = 'Tebus mata: ' + sku + ' (' + mata + ' mata)';
 window.__pendingRedeem = { customer_id: ctx.match.id, tier: ctx.tier, type: 'deadstock', label: 'Tebus ' + sku + ' — ' + (it.name || ''), cost: mata, rm: unitRm, sku: sku };
 window.__dsCloseRedeemPicker();
 if(typeof cpRecomputeTotal === 'function') cpRecomputeTotal();
 // p1_1162 BUGFIX (jumpa masa QA): cpVipLookup baca medan cpCust* (dlm PANEL BAYAR). Bila tebus
 // dari SHEET TROLI mobile (panel belum buka), medan kosong → no-match → cpVipLookup NULL-kan
 // __pendingRedeem yang baru diset = customer kena caj penuh + mata tak ditolak. Panggil HANYA
 // kalau panel bayar terbuka (medan terisi); sheet troli refresh sendiri.
 const __cpOpen = (document.getElementById('cpCustName') || {}).value && document.getElementById('checkoutPanel') && document.getElementById('checkoutPanel').classList.contains('is-open');
 if(__cpOpen && typeof window.cpVipLookup === 'function') window.cpVipLookup();
 else if(document.getElementById('posRedeemSheet') && typeof window.__posRedeemSheetRefresh === 'function') window.__posRedeemSheetRefresh();
 if(typeof showToast === 'function') showToast('Tebus ' + sku + ': −' + mata + ' mata bila bayar, barang RM ' + unitRm.toFixed(2) + ' percuma. Pastikan serahkan barang!', 'success');
};
