// Toast: non-blocking notification. Replaces alert() for soft messages.
window.showToast = function(msg, type) {
 type = type || 'info';
 const colors = {
 info: { bg:'var(--primary-500,#CD7C32)', icon:'i' },
 success: { bg:'#101010', icon:'' },
 warning: { bg:'#CE9420', icon:'' },
 warn: { bg:'#CE9420', icon:'' },
 error: { bg:'#B23A2E', icon:'' }
 };
 const c = colors[type] || colors.info;
 const el = document.createElement('div');
 el.style.cssText = 'position:fixed; top:20px; right:20px; background:'+c.bg+'; color:#fff; padding:12px 18px; border-radius:8px; z-index:9999; font-weight:600; box-shadow:0 4px 16px rgba(0,0,0,.2); max-width:340px; font-size:13.5px; display:flex; gap:10px; align-items:center; opacity:0; transform:translateX(20px); transition:opacity.25s, transform.25s;';
 el.innerHTML = '<span style="font-size:16px;">'+c.icon+'</span><span>'+String(msg).replace(/</g,'&lt;')+'</span>';
 document.body.appendChild(el);
 requestAnimationFrame(() => { el.style.opacity='1'; el.style.transform='translateX(0)'; });
 setTimeout(() => { el.style.opacity='0'; el.style.transform='translateX(20px)'; setTimeout(()=>el.remove(), 280); }, type==='error' ? 4500 : 2800);
 // p1_34: persist warnings/errors into notification center (success/info skipped — too noisy).
 if (window.notify && (type === 'warning' || type === 'warn' || type === 'error')) {
 try { window.notify.add({ title: type === 'error' ? 'Error' : 'Warning', body: String(msg), type: type === 'warn' ? 'warning' : type, silent: true }); } catch(e){}
 }
};

// p1_34: Global notification center. Persistent inbox for warnings/errors/system events.
// Storage key: notifications_v1 (cap 50, FIFO). Read state per-entry via .read flag.
(function(){
 const KEY = 'notifications_v1';
 const CAP = 50;
 let cache = null;
 let openState = false;
 let outsideHandler = null;
 let filter = 'unread'; // p1_779 — 'unread' | 'important' | 'all'
 try { filter = localStorage.getItem('nc_filter_v1') || 'unread'; } catch(e){}

 function load() {
 if (cache) return cache;
 try { cache = JSON.parse(localStorage.getItem(KEY)) || []; } catch(e) { cache = []; }
 // p1_779 — auto-buang lama supaya panel tak bertimbun (staff malas check bila banyak):
 // info >3 hari dibuang (rendah nilai), apa-apa yang dah dibaca >7 hari dibuang; warning/error belum baca kekal.
 const now = Date.now();
 const before = cache.length;
 cache = cache.filter(n => {
 const age = now - (n.ts || 0);
 if (n.type === 'info' && age > 3 * 86400000) return false;
 if (n.read && age > 7 * 86400000) return false;
 return true;
 });
 if (cache.length !== before) save();
 return cache;
 }
 function save() { try { localStorage.setItem(KEY, JSON.stringify(cache || [])); } catch(e){} }
 function fmtTime(ts) {
 const diff = Date.now() - ts;
 if (diff < 60000) return 'just now';
 if (diff < 3600000) return Math.floor(diff/60000) + 'm ago';
 if (diff < 86400000) return Math.floor(diff/3600000) + 'h ago';
 const d = new Date(ts);
 return d.getDate()+'/'+(d.getMonth()+1)+' '+String(d.getHours()).padStart(2,'0')+':'+String(d.getMinutes()).padStart(2,'0');
 }
 function escape(s) { return String(s == null ? '' : s).replace(/[&<>"']/g, c => ({'&':'&amp;','<':'&lt;','>':'&gt;','"':'&quot;',"'":'&#39;'}[c])); }
 function iconFor(type) {
 return ({ warning:'alert-triangle', error:'alert-octagon', success:'check-circle', info:'info' })[type] || 'info';
 }
 function dedupeRecent(item) {
 // p1_779 — skip kalau notifikasi sama (title+body) MASIH belum dibaca (apa-apa umur), atau ditambah dalam 30s.
 // Elak duplikat bertimbun: selagi staff belum baca yang sama, jangan tambah lagi satu.
 const now = Date.now();
 return load().some(n => n.title === item.title && n.body === item.body && (!n.read || (now - n.ts) < 30000));
 }

 const api = {
 add(item) {
 if (!item || !item.body) return;
 const entry = {
 id: 'n_' + Date.now() + '_' + Math.random().toString(36).slice(2,7),
 title: item.title || 'Notification',
 body: String(item.body),
 type: item.type || 'info',
 ts: Date.now(),
 read: false,
 action: item.action || null
 };
 if (dedupeRecent(entry)) return;
 const list = load();
 list.unshift(entry);
 if (list.length > CAP) list.length = CAP;
 cache = list;
 save();
 api.renderBadge();
 if (openState) api.renderList();
 return entry.id;
 },
 list() { return load().slice(); },
 unreadCount() { return load().filter(n => !n.read).length; },
 markRead(id) {
 const list = load();
 const n = list.find(x => x.id === id);
 if (n && !n.read) { n.read = true; save(); api.renderBadge(); api.renderList(); }
 },
 // p1_799 — klik notifikasi: tanda dibaca + bawa terus ke tempatnya (kalau ada action terdaftar).
 go(id) {
 const list = load();
 const n = list.find(x => x.id === id);
 if (n && !n.read) { n.read = true; save(); api.renderBadge(); }
 const handler = n && n.action && window.__notifyActions && window.__notifyActions[n.action];
 if (typeof handler === 'function') { api.close(); try { handler(); } catch(e){} }
 else { api.renderList(); }
 },
 markAllRead() {
 const list = load();
 let dirty = false;
 list.forEach(n => { if (!n.read) { n.read = true; dirty = true; } });
 if (dirty) { save(); api.renderBadge(); api.renderList(); }
 },
 setFilter(f) {
 filter = (f === 'all' || f === 'important') ? f : 'unread';
 try { localStorage.setItem('nc_filter_v1', filter); } catch(e){}
 api.renderList();
 },
 clear() {
 cache = []; save(); api.renderBadge(); api.renderList();
 },
 renderBadge() {
 const badge = document.getElementById('ncBadge');
 if (!badge) return;
 const n = api.unreadCount();
 if (n <= 0) { badge.hidden = true; badge.textContent = '0'; }
 else { badge.hidden = false; badge.textContent = n > 99 ? '99+' : String(n); }
 },
 renderList() {
 const wrap = document.getElementById('ncList');
 if (!wrap) return;
 const all = load();
 // p1_779 — kemaskini chip tapisan (aktif + kiraan) + tapis senarai ikut filter semasa
 const unreadN = all.filter(n => !n.read).length;
 const importantN = all.filter(n => (n.type === 'warning' || n.type === 'error') && !n.read).length;
 const fu = document.getElementById('ncfUnread'); if (fu) fu.textContent = unreadN > 99 ? '99+' : String(unreadN);
 const fi = document.getElementById('ncfImportant'); if (fi) fi.textContent = importantN > 0 ? String(importantN) : '';
 const chips = document.querySelectorAll('#ncFilters .nc-chip');
 chips.forEach(b => b.classList.toggle('is-on', b.getAttribute('data-ncf') === filter));
 let list;
 if (filter === 'important') list = all.filter(n => n.type === 'warning' || n.type === 'error');
 else if (filter === 'all') list = all;
 else list = all.filter(n => !n.read);
 if (list.length === 0) {
 const msg = filter === 'unread' ? 'Semua dah dibaca' : (filter === 'important' ? 'Tiada amaran penting' : 'Tiada notifikasi');
 wrap.innerHTML = '<div class="nc-empty"><i data-lucide="inbox" class="nc-empty__icon" style="width:32px; height:32px;"></i>' + msg + '</div>';
 } else {
 wrap.innerHTML = list.map(n => {
 const hasGo = !!(n.action && window.__notifyActions && window.__notifyActions[n.action]); // p1_799 — boleh navigate
 return '<div class="nc-item ' + (n.read ? '' : 'is-unread') + (hasGo ? ' nc-item--go' : '') + '" role="listitem" data-id="' + n.id + '" onclick="window.notify.go(\'' + n.id + '\')">' +
 '<div class="nc-item__icon nc-item__icon--' + escape(n.type) + '"><i data-lucide="' + iconFor(n.type) + '" style="width:14px; height:14px;"></i></div>' +
 '<div class="nc-item__body">' +
 '<p class="nc-item__title">' + escape(n.title) + '</p>' +
 '<p class="nc-item__msg">' + escape(n.body) + '</p>' +
 '<div class="nc-item__time">' + escape(fmtTime(n.ts)) + (hasGo ? '<span class="nc-item__go">Buka &rarr;</span>' : '') + '</div>' +
 '</div>' +
 '</div>';
 }).join('');
 }
 if (window.lucide && typeof window.lucide.createIcons === 'function') { try { window.lucide.createIcons(); } catch(e){} }
 },
 toggle() { openState ? api.close() : api.open(); },
 open() {
 const panel = document.getElementById('ncPanel');
 const bell = document.getElementById('ncBell');
 if (!panel || !bell) return;
 panel.hidden = false;
 bell.classList.add('is-open');
 bell.setAttribute('aria-expanded', 'true');
 openState = true;
 api.renderList();
 // Outside click → close
 setTimeout(() => {
 outsideHandler = (e) => {
 if (!panel.contains(e.target) && !bell.contains(e.target)) api.close();
 };
 document.addEventListener('click', outsideHandler);
 }, 0);
 },
 close() {
 const panel = document.getElementById('ncPanel');
 const bell = document.getElementById('ncBell');
 if (panel) panel.hidden = true;
 if (bell) { bell.classList.remove('is-open'); bell.setAttribute('aria-expanded', 'false'); }
 openState = false;
 if (outsideHandler) { document.removeEventListener('click', outsideHandler); outsideHandler = null; }
 }
 };

 window.notify = api;
 // p1_799 — destinasi notifikasi (whitelist; klik notifikasi ber-action bawa ke sini). Handler dipanggil
 // masa klik (runtime) jadi rujukan switchHub/render* yang ditakrif kemudian dalam fail OK.
 window.__notifyActions = {
  lowstock: function(){ try { if(typeof switchHub === 'function') switchHub(['reorderSection'], 'Reorder', null); if(typeof window.renderReorderSuggest === 'function') window.renderReorderSuggest(); } catch(e){} },
  apps: function(){ const el = document.querySelector('[data-tab="nav_apps"]'); if(el) return el.click(); try { if(typeof switchHub === 'function') switchHub(['appsSection'], 'Apps', null); if(typeof window.renderApps === 'function') window.renderApps(); } catch(e){} },
  invoice: function(){ const el = document.querySelector('[data-tab="admin_invoice"]'); if(el) return el.click(); try { if(typeof switchHub === 'function') switchHub(['invoiceSection'], 'Invoice & Quotation', null); } catch(e){} },
  bulkedit: function(){ const el = document.querySelector('[data-tab="admin_bulk_ops"]'); if(el) return el.click(); try { if(typeof switchHub === 'function') switchHub(['bulkOpsSection'], 'Bulk Product Edit', null); if(typeof window.renderBulkOps === 'function') window.renderBulkOps(); } catch(e){} },
  amaran: function(){ const el = document.querySelector('[data-ov-tab="aim"]'); const home = document.querySelector('[data-tab="overview"]'); if(home) home.click(); try { if(window.__ovTab) window.__ovTab('aim'); } catch(e){} } // p1_1047 — dulu sasar homeTab/nav_overview (dua-dua TAK wujud) = butang mati
 };
 // ESC closes panel
 document.addEventListener('keydown', (e) => { if (e.key === 'Escape' && openState) api.close(); });
 // Initial badge once DOM ready
 if (document.readyState === 'loading') {
 document.addEventListener('DOMContentLoaded', () => api.renderBadge());
 } else { api.renderBadge(); }
})();

// p1_35: Stock Take save-draft. Auto-persists typed Kiraan Fizikal + komen so user
// doesn't lose work on tab refresh / accidental close. Drafts older than 7d are pruned.
(function(){
 const KEY = 'stockTakeDraft_v1';
 const TTL_MS = 7 * 24 * 60 * 60 * 1000;
 const DEBOUNCE_MS = 500;
 let cache = null;
 let saveTimer = null;
 let pendingMutations = {};

 function readRaw() {
 try { return JSON.parse(localStorage.getItem(KEY)) || {}; } catch(e) { return {}; }
 }
 function writeRaw(map) {
 try { localStorage.setItem(KEY, JSON.stringify(map)); } catch(e){}
 }
 function load() {
 if (cache) return cache;
 const raw = readRaw();
 const now = Date.now();
 const fresh = {};
 Object.keys(raw).forEach(sku => {
 const e = raw[sku];
 if (e && (now - (e.ts || 0)) < TTL_MS) fresh[sku] = e;
 });
 if (Object.keys(fresh).length !== Object.keys(raw).length) writeRaw(fresh); // prune stale
 cache = fresh;
 return cache;
 }
 function flush() {
 const map = load();
 Object.keys(pendingMutations).forEach(sku => {
 const m = pendingMutations[sku];
 if (m === null) { delete map[sku]; }
 else { map[sku] = m; }
 });
 pendingMutations = {};
 writeRaw(map);
 if (typeof api.renderCounter === 'function') api.renderCounter();
 }
 function scheduleFlush() {
 if (saveTimer) clearTimeout(saveTimer);
 saveTimer = setTimeout(flush, DEBOUNCE_MS);
 }

 const api = {
 get(sku) { return load()[sku] || null; },
 all() { return load(); },
 count() { return Object.keys(load()).length; },
 save(sku, qty, note) {
 if (!sku) return;
 const qtyStr = (qty == null ? '' : String(qty)).trim();
 const noteStr = (note == null ? '' : String(note));
 if (qtyStr === '' && noteStr === '') { api.clear(sku); return; }
 pendingMutations[sku] = { qty: qtyStr, note: noteStr, ts: Date.now() };
 cache[sku] = pendingMutations[sku];
 scheduleFlush();
 },
 clear(sku) {
 if (!sku) return;
 const map = load();
 if (map[sku]) {
 delete map[sku];
 cache = map;
 writeRaw(map);
 api.renderCounter();
 }
 // also drop any pending mutation
 delete pendingMutations[sku];
 },
 clearAll() {
 if (!confirm('Buang semua draft Stock Take? Tindakan ini tidak boleh undo.')) return;
 cache = {}; pendingMutations = {}; writeRaw({});
 api.renderCounter();
 if (typeof window.renderAuditCards === 'function') window.renderAuditCards();
 if (typeof showToast === 'function') showToast('Semua draft Stock Take dibuang', 'success');
 },
 renderCounter() {
 const wrap = document.getElementById('stDraftBanner');
 if (!wrap) return;
 const n = api.count();
 if (n === 0) { wrap.hidden = true; wrap.innerHTML = ''; return; }
 wrap.hidden = false;
 wrap.innerHTML =
 '<div class="st-draft-banner">' +
 '<i data-lucide="save" style="width:14px; height:14px;"></i>' +
 '<span><strong>' + n + '</strong> draft kiraan disimpan auto. Boleh sambung bila-bila.</span>' +
 '<button type="button" class="st-draft-clear" onclick="window.stDraft.clearAll()">Buang semua</button>' +
 '</div>';
 if (window.lucide && typeof window.lucide.createIcons === 'function') { try { window.lucide.createIcons(); } catch(e){} }
 }
 };

 // Flush on tab close / visibility hidden (best-effort — protects against losing the last keystroke).
 window.addEventListener('beforeunload', () => { if (saveTimer) { clearTimeout(saveTimer); flush(); } });
 document.addEventListener('visibilitychange', () => { if (document.visibilityState === 'hidden' && saveTimer) { clearTimeout(saveTimer); flush(); } });

 window.stDraft = api;
 if (document.readyState === 'loading') {
 document.addEventListener('DOMContentLoaded', () => api.renderCounter());
 } else { api.renderCounter(); }
})();

// Global ESC handler: close any visible modal/overlay.
document.addEventListener('keydown', function(e){
 if (e.key !== 'Escape') return;
 // p1_459 — blind-count popup closes first if open
 const scsPop = document.getElementById('scsCountPopupOverlay');
 if (scsPop) { scsPop.remove(); return; }
 // Find topmost visible modal-like overlay
 const candidates = document.querySelectorAll([
 '#pinLoginOverlay', '#staffWelcomeModal', '#receiptModal',
 '#customerLoginGate', '#smModalOverlay.active', '.sh-modal-overlay.active',
 '.sy-conflict-modal-overlay.sy-modal-active'
].join(','));
 for (let i = candidates.length - 1; i>= 0; i--) {
 const el = candidates[i];
 const cs = window.getComputedStyle(el);
 if (cs.display !== 'none' && cs.visibility !== 'hidden') {
 if (el.classList.contains('active')) el.classList.remove('active');
 else el.style.display = 'none';
 return;
 }
 }
});

