window.__mktHubGo = function(hubKey, tabKey, el){
 const hub = window.__MKT_HUBS[hubKey] || window.__NAV_HUBS[hubKey]; if(!hub) return; // p1_1087 — generic
 const tab = hub.tabs.find(t => t.key === tabKey) || hub.tabs[0];
 // el = menu-item sidebar (untuk highlight aktif); bila tukar tab dlm hub, el tiada — kekalkan highlight
 if(typeof switchHub === 'function') switchHub([tab.section], hub.label, el || document.querySelector('[data-tab="nav_hub_' + hubKey + '"]'));
 try { if(typeof window[tab.render] === 'function') window[tab.render](); } catch(e){ console.warn('hub render gagal:', tab.render, e); }
 // Bar tab di ATAS section (section semua ada body-div dalaman; render fn sasar body, bar selamat)
 try {
  const sec = document.getElementById(tab.section); if(!sec) return;
  let bar = sec.querySelector(':scope > .mkt-hub-tabs');
  if(!bar){ bar = document.createElement('div'); bar.className = 'mkt-hub-tabs'; bar.style.cssText = 'display:flex; gap:8px; flex-wrap:wrap; margin:14px 0 4px;'; sec.insertBefore(bar, sec.firstChild); }
  bar.innerHTML = hub.tabs.map(t => {
   const on = t.key === tab.key;
   return '<button onclick="window.__mktHubGo(\'' + hubKey + '\',\'' + t.key + '\')" style="display:inline-flex; align-items:center; gap:6px; padding:8px 15px; border-radius:50px; font-size:12.5px; font-weight:700; cursor:pointer; border:1.5px solid ' + (on ? 'var(--primary)' : '#E5E7EB') + '; background:' + (on ? 'var(--primary)' : '#fff') + '; color:' + (on ? '#fff' : '#374151') + ';"><i data-lucide="' + t.icon + '" style="width:13px;height:13px;"></i>' + t.label + '</button>';
  }).join('');
  if(window.lucide && lucide.createIcons) try { lucide.createIcons(); } catch(e){}
 } catch(e){}
};
window.__navHubGo = window.__mktHubGo; // p1_1087 — alias generic (hub bukan marketing shj lagi)

// ============================================================================
// p1_1036 — DASHBOARD BACK-OFFICE dipindah ke backoffice-dash.js (lazy). Stub loader:
// (Returns/Supplier/Brand/Channel/Reorder/InvHistory — mobile 4-tab tak guna; web muat bila klik)
// ============================================================================
window.__ensureBackofficeDash = function(){
 if(window.__bodLoaded) return Promise.resolve();
 return window.__bodLoading || (window.__bodLoading = new Promise(function(res,rej){
  var s=document.createElement('script'); s.src='backoffice-dash.js?v=7'; // p1_1116
  s.onload=function(){ window.__bodLoaded=true; res(); };
  s.onerror=function(){ window.__bodLoading=null; rej(new Error('backoffice-dash.js gagal muat')); };
  document.head.appendChild(s);
 }));
};
['renderReturnsLog','renderSupplierPerf','renderBrandPerf','renderChannelProfit','renderReorderSuggest','renderInventoryHistory'].forEach(function(fn){
 window[fn] = function(){ var a=arguments; window.__ensureBackofficeDash().then(function(){ if(window[fn] && window[fn].__isBodStub!==true) window[fn].apply(null,a); }); };
 window[fn].__isBodStub = true;
});

// p1_117 — Margin Watcher: detect SKU sold below floor price dalam 24h terakhir
window.checkMarginWatcher = function() {
 const banner = document.getElementById('marginWatcherBanner');
 const msg = document.getElementById('mwMessage');
 if(!banner || !msg) return;
 // Respect dismissed state for current day
 const dismissedKey = 'mwDismissed_' + new Date().toISOString().slice(0, 10);
 if(localStorage.getItem(dismissedKey)) { banner.style.display = 'none'; return; }
 // Only show to mgmt / Bos
 const u = window.currentUser || {};
 const isMgmtOrBoss = u.role === 'mgmt' || (typeof window.isBoss === 'function' && window.isBoss(u));
 if(!isMgmtOrBoss) { banner.style.display = 'none'; return; }
 try {
 if(typeof masterProducts === 'undefined' || typeof salesHistory === 'undefined') return;
 // Build floor map
 const floorMap = {};
 masterProducts.forEach(p => {
 const sku = (p.sku || '').toUpperCase();
 const fp = Number(p.floor_price || 0);
 if(sku && fp > 0) floorMap[sku] = fp;
 });
 // Scan recent sales (24h)
 const cutoffMs = Date.now() - 24 * 3600 * 1000;
 const violators = new Set();
 salesHistory.forEach(sale => {
 const t = new Date(sale.timestamp || sale.created_at || 0).getTime();
 if(t < cutoffMs) return;
 const items = (() => { try { return JSON.parse(sale.items || '[]'); } catch(e) { return sale.items || []; } })();
 (Array.isArray(items) ? items : []).forEach(it => {
 const sku = (it.sku || '').toUpperCase();
 const sold = Number(it.price || 0);
 if(sku && floorMap[sku] && sold > 0 && sold < floorMap[sku]) violators.add(sku);
 });
 });
 if(violators.size === 0) { banner.style.display = 'none'; return; }
 msg.innerHTML = `Margin Watcher: <strong>${violators.size}</strong> SKU dijual bawah floor price dalam 24 jam terakhir.`;
 banner.style.display = '';
 if(window.lucide && lucide.createIcons) lucide.createIcons();
 } catch(e) { /* silent */ }
};
window.__mwDismiss = function() {
 const dismissedKey = 'mwDismissed_' + new Date().toISOString().slice(0, 10);
 localStorage.setItem(dismissedKey, '1');
 const banner = document.getElementById('marginWatcherBanner');
 if(banner) banner.style.display = 'none';
};

// Hook to auto-check after login + every 5 min while session active
(function(){
 const checkPeriodically = () => { if(document.hidden) return; /* p1_1025 pause bila app background */ if(typeof window.checkMarginWatcher === 'function') window.checkMarginWatcher(); };
 setTimeout(checkPeriodically, 2000); // initial after boot
 setInterval(checkPeriodically, 5 * 60 * 1000); // every 5 min
})();

