// p1_111 — Price History Report
window.__phRows = [];

window.renderPriceHistory = async function() {
 const wrap = document.getElementById('phTableWrap');
 if(!wrap) return;
 wrap.innerHTML = '<p style="color:#9CA3AF; padding:20px; text-align:center;">Memuatkan…</p>';
 try {
 if(typeof db === 'undefined' || !db) throw new Error('DB tak available');
 const period = document.getElementById('phPeriod').value || '30d';
 let sinceDate = null;
 const now = new Date();
 if(period === '7d') sinceDate = new Date(now.getTime() - 7 * 86400000);
 else if(period === '30d') sinceDate = new Date(now.getTime() - 30 * 86400000);
 else if(period === '90d') sinceDate = new Date(now.getTime() - 90 * 86400000);
 else if(period === 'ytd') sinceDate = new Date(now.getFullYear(), 0, 1);
 // else 'all' → null
 let q = db.from('product_price_history').select('*').order('changed_at', { ascending: false }).limit(500);
 if(sinceDate) q = q.gte('changed_at', sinceDate.toISOString());
 const { data, error } = await q;
 if(error) throw error;
 window.__phRows = data || [];
 window.__phApplyFilter();
 } catch(e) {
 wrap.innerHTML = '<p style="color:#B23A2E; padding:20px;">Error: ' + e.message + '</p>';
 }
};

window.__phApplyFilter = function() {
 const search = (document.getElementById('phSearchSku').value || '').toUpperCase().trim();
 const typeFilter = document.getElementById('phChangeType').value || 'all';
 const priceTypeFilter = (document.getElementById('phPriceType') || {}).value || 'all';
 let rows = window.__phRows.slice();
 if(search) rows = rows.filter(r => (r.sku || '').toUpperCase().includes(search) || (r.product_name || '').toUpperCase().includes(search));
 if(typeFilter === 'increase') rows = rows.filter(r => Number(r.delta || 0) > 0);
 if(typeFilter === 'decrease') rows = rows.filter(r => Number(r.delta || 0) < 0);
 // p1_699 — tapis ikut jenis harga (kedai/shopee/tiktok); baris lama tanpa price_type = kedai
 if(priceTypeFilter !== 'all') rows = rows.filter(r => (r.price_type || 'kedai') === priceTypeFilter);

 // KPI
 const total = rows.length;
 const inc = rows.filter(r => Number(r.delta || 0) > 0).length;
 const dec = rows.filter(r => Number(r.delta || 0) < 0).length;
 const avgDelta = total > 0
 ? (rows.reduce((s, r) => s + (Number(r.delta_pct) || 0), 0) / total).toFixed(1)
 : '0.0';
 document.getElementById('phTotalChanges').textContent = total;
 document.getElementById('phIncreases').textContent = inc;
 document.getElementById('phDecreases').textContent = dec;
 document.getElementById('phAvgDelta').textContent = avgDelta + '%';

 const wrap = document.getElementById('phTableWrap');
 if(!rows.length) { wrap.innerHTML = '<p style="color:#9CA3AF; padding:20px; text-align:center;">Tiada perubahan harga padan filter.</p>'; return; }
 const escAttr = (s) => String(s == null ? '' : s).replace(/"/g,'&quot;').replace(/</g,'&lt;');
 const fmtRM = (n) => (n == null || isNaN(Number(n))) ? '—' : 'RM ' + Number(n).toFixed(2);
 wrap.innerHTML = `<table class="rp-comm-table">
 <thead>
 <tr>
 <th>Tarikh</th>
 <th>SKU</th>
 <th>Nama</th>
 <th>Jenis</th>
 <th style="text-align:right;">Harga Lama</th>
 <th style="text-align:right;">Harga Baru</th>
 <th style="text-align:right;">Δ RM</th>
 <th style="text-align:right;">Δ %</th>
 <th>Oleh</th>
 </tr>
 </thead>
 <tbody>
 ${rows.slice(0, 100).map(r => {
 const delta = Number(r.delta || 0);
 const deltaColor = delta > 0 ? '#B23A2E' : (delta < 0 ? '#101010' : '#6B7280');
 const deltaSign = delta > 0 ? '+' : '';
 return `<tr>
 <td style="font-size:11px; color:#6B7280;">${new Date(r.changed_at).toLocaleString('en-MY', { dateStyle: 'short', timeStyle: 'short' })}</td>
 <td><strong>${escAttr(r.sku)}</strong></td>
 <td style="font-size:12px;">${escAttr(r.product_name || '')}</td>
 <td>${(function(){ const pt=(r.price_type||'kedai'); const m={kedai:['Kedai','#374151','#F3F4F6'], shopee:['Shopee','#fff','#EE4D2D'], tiktok:['TikTok','#fff','#111827']}; const c=m[pt]||m.kedai; return `<span style="font-size:10px; font-weight:800; padding:2px 7px; border-radius:5px; color:${c[1]}; background:${c[2]};">${c[0]}</span>`; })()}</td>
 <td style="text-align:right;">${fmtRM(r.old_price)}</td>
 <td style="text-align:right;"><strong>${fmtRM(r.new_price)}</strong></td>
 <td style="text-align:right; color:${deltaColor}; font-weight:700;">${deltaSign}${fmtRM(delta).replace('RM ','')}</td>
 <td style="text-align:right; color:${deltaColor}; font-weight:700;">${deltaSign}${(r.delta_pct == null) ? '—' : Number(r.delta_pct).toFixed(1) + '%'}</td>
 <td style="font-size:11px;">${(function(){ const by = r.changed_by || ''; if(!by || by.toLowerCase() === 'system') return '<span style="color:#9CA3AF; font-style:italic;">Sistem (auto)</span>'; return `<span style="color:#374151; font-weight:600;"><i data-lucide="user" style="width:11px;height:11px;vertical-align:-1px;"></i> ${escAttr(by)}</span>`; })()}</td>
 </tr>`;
 }).join('')}
 </tbody>
 </table>
 ${rows.length > 100 ? `<p style="font-size:11px; color:#9CA3AF; text-align:center; margin-top:10px;">Papar 100 pertama dari ${rows.length} rows. Narrow filter untuk lihat selebihnya.</p>` : ''}`;
 if(typeof lucide !== 'undefined') lucide.createIcons();
};

// ===== p1_701 — Chat Inbox (omnichannel). Shopee LIVE via shopee-chat fn; FB/IG perlu setup Meta. =====
window.__chatChannel = window.__chatChannel || 'shopee';
window.__CHAT_CHANNELS = [
 { key:'shopee', label:'Shopee', color:'#EE4D2D', live:true, provider:'shopee-chat' },
 { key:'tiktok', label:'TikTok', color:'#111827', live:false, pending:true, provider:'tiktok-chat' },
 { key:'fb',     label:'FB Messenger', color:'#1877F2', live:false, pending:true, provider:'messenger-chat' }, // p1_1079
 { key:'ig',     label:'Instagram', color:'#C13584', live:false, pending:true, provider:'messenger-chat' }  // p1_1079
];
window.__chatSetChannel = function(ch){ window.__chatChannel = ch; window.renderChatInbox(); };
window.renderChatInbox = function() {
 const tabs = document.getElementById('chatChannelTabs');
 const list = document.getElementById('chatConvList');
 const thread = document.getElementById('chatThread');
 if(!list || !thread) return;
 const esc = (typeof hesc === 'function') ? hesc : (x)=>String(x==null?'':x);
 if(tabs) {
  tabs.innerHTML = window.__CHAT_CHANNELS.map(c => {
   const active = c.key === window.__chatChannel;
   const dot = c.live?'#22C55E':(c.pending?'#F59E0B':'#D1D5DB');
   const suffix = c.live?'':(c.pending?' <span style="font-size:10px; opacity:0.7;">(auth)</span>':' <span style="font-size:10px; opacity:0.7;">(setup)</span>');
   return `<button onclick="window.__chatSetChannel('${c.key}')" style="display:inline-flex; align-items:center; gap:6px; padding:7px 14px; border-radius:8px; font-size:12.5px; font-weight:700; cursor:pointer; border:1px solid ${active?c.color:'#E5E7EB'}; background:${active?c.color:'#fff'}; color:${active?'#fff':'#374151'};"><span style="width:8px; height:8px; border-radius:50%; background:${dot};"></span>${c.label}${suffix}</button>`;
  }).join('') + `<button onclick="window.renderChatInbox()" style="margin-left:auto; padding:7px 12px; border-radius:8px; border:1px solid #E5E7EB; background:#fff; font-size:12px; font-weight:700; cursor:pointer; color:#374151;">Refresh</button>`;
 }
 thread.innerHTML = '<p style="color:#9CA3AF; margin:auto;">Pilih perbualan di kiri.</p>';
 const ch = window.__CHAT_CHANNELS.find(c => c.key === window.__chatChannel);
 // Saluran tanpa provider (FB/IG) — perlu setup Meta
 if(!ch || (!ch.live && !ch.provider)) {
  list.innerHTML = `<div style="padding:20px; color:#6B7280; font-size:13px; line-height:1.6;"><strong>${esc(ch?ch.label:'Saluran')}</strong> belum disambung.<br><br>Perlu setup Meta app + app review (permission messaging) + sambung Page/IG Business. Bagi creds pada admin, nanti disambung.</div>`;
  return;
 }
 // p1_730 — TikTok: guna tiktok-chat fn; handle 105005 (scope belum aktif) dengan mesej boleh-tindak
 if(window.__chatChannel === 'tiktok') { window.__chatLoadTiktok(list); return; }
 // p1_1079 — FB Messenger / IG DM: baca dari store meta_messages (diisi webhook)
 if(window.__chatChannel === 'fb' || window.__chatChannel === 'ig') { window.__chatLoadMeta(list, window.__chatChannel); return; }
 list.innerHTML = '<p style="color:#9CA3AF; padding:18px;">Memuatkan perbualan…</p>';
 fetch('/.netlify/functions/shopee-chat?mode=conversations&page_size=50', { headers: window.__authHeaderSync({}) }).then(r=>r.json()).then(r => {
  if(r.error) { list.innerHTML = '<p style="color:#B23A2E; padding:18px;">Shopee: '+esc(r.error)+'</p>'; return; }
  const convs = (r.response && r.response.conversations) || [];
  if(!convs.length) { list.innerHTML = '<p style="color:#9CA3AF; padding:18px;">Tiada perbualan.</p>'; return; }
  list.innerHTML = convs.map(c => {
   const snippet = (c.latest_message_content && c.latest_message_content.text) || ('['+(c.latest_message_type||'mesej')+']');
   const ts = Number(c.last_message_timestamp || 0);
   const t = ts ? new Date(ts*1000).toLocaleString('en-MY',{day:'2-digit',month:'short',hour:'2-digit',minute:'2-digit'}) : '';
   const unread = (c.unread_count>0) ? `<span style="background:#EE4D2D; color:#fff; font-size:10px; font-weight:800; padding:1px 7px; border-radius:999px;">${c.unread_count}</span>` : '';
   return `<div onclick="window.__chatOpen('${c.conversation_id}', ${c.to_id||0}, '${esc(c.to_name||'').replace(/'/g,"\\'")}')" style="padding:12px 14px; border-bottom:1px solid #F3F4F6; cursor:pointer;" onmouseover="this.style.background='#FAFAFA'" onmouseout="this.style.background='#fff'">
     <div style="display:flex; justify-content:space-between; gap:8px; align-items:center;"><strong style="font-size:13px;">${esc(c.to_name||'Pembeli')}</strong>${unread}</div>
     <div style="font-size:12px; color:#6B7280; overflow:hidden; text-overflow:ellipsis; white-space:nowrap; margin-top:2px;">${esc(snippet)}</div>
     <div style="font-size:10px; color:#9CA3AF; margin-top:3px;"><span style="color:#EE4D2D; font-weight:700;">Shopee</span> · ${t}</div>
    </div>`;
  }).join('');
 }).catch(e => { list.innerHTML = '<p style="color:#B23A2E; padding:18px;">Error: '+esc(e.message)+'</p>'; });
};
window.__chatOpen = function(cid, buyerId, name) {
 // p1_730 — route ikut channel aktif
 if(window.__chatChannel === 'tiktok') { return window.__chatOpenTiktok(cid, buyerId, name); }
 if(window.__chatChannel === 'fb' || window.__chatChannel === 'ig') { return window.__chatOpenMeta(cid, buyerId, name, window.__chatChannel); } // p1_1079
 const thread = document.getElementById('chatThread'); if(!thread) return;
 const esc = (typeof hesc === 'function') ? hesc : (x)=>String(x==null?'':x);
 // p1_1046 — simpan konteks perbualan semasa utk butang Hantar (reply)
 window.__chatCur = { cid: cid, buyerId: buyerId, name: name };
 thread.innerHTML = '<p style="color:#9CA3AF; margin:auto;">Memuatkan mesej…</p>';
 // p1_1046 — kotak balas (Fasa 2): sticky bawah thread; hanya bila ada buyerId (to_id Shopee)
 const composer = buyerId ? `<div style="position:sticky; bottom:0; background:#FAFAFA; padding:10px 0 2px; margin-top:10px; border-top:1px solid #E5E7EB; display:flex; gap:8px;">
   <input id="chatReplyInput" type="text" maxlength="1000" placeholder="Balas ${esc(name||'pembeli')}…" onkeydown="if(event.key==='Enter'){event.preventDefault(); window.__chatSend();}" style="flex:1; padding:10px 13px; border:1px solid #E5E7EB; border-radius:10px; font-size:13px; font-family:var(--font-main,Poppins),sans-serif; background:#fff;">
   <button id="chatReplyBtn" onclick="window.__chatSend()" style="padding:10px 18px; border:none; border-radius:10px; background:var(--primary-500,#CD7C32); color:#fff; font-size:13px; font-weight:700; cursor:pointer; font-family:var(--font-main,Poppins),sans-serif; white-space:nowrap;">Hantar</button>
  </div>` : '';
 fetch('/.netlify/functions/shopee-chat?mode=messages&conversation_id='+encodeURIComponent(cid)+'&page_size=50', { headers: window.__authHeaderSync({}) }).then(r=>r.json()).then(r => {
  if(r.error) { thread.innerHTML = '<p style="color:#B23A2E;">Shopee: '+esc(r.error)+'</p>'; return; }
  let msgs = (r.response && r.response.messages) || [];
  msgs = msgs.slice().reverse(); // papar lama→baru
  const head = `<div style="font-weight:800; padding-bottom:10px; border-bottom:1px solid #E5E7EB; margin-bottom:12px; position:sticky; top:0; background:#FAFAFA;">${esc(name||'Pembeli')} <span style="font-size:11px; color:#9CA3AF; font-weight:600;">· Shopee</span></div>`;
  if(!msgs.length) { thread.innerHTML = head + '<p style="color:#9CA3AF; margin:auto;">Tiada mesej.</p>' + composer; return; }
  thread.innerHTML = head + msgs.map(m => {
   const fromBuyer = String(m.from_id) === String(buyerId);
   const txt = (m.content && (m.content.text != null ? m.content.text : null));
   const body = txt != null ? esc(txt) : ('<em style="opacity:0.7;">['+esc(m.message_type||'mesej')+']</em>');
   const ts = Number(m.created_timestamp || m.create_time || 0);
   const t = ts ? new Date(ts*1000).toLocaleString('en-MY',{day:'2-digit',month:'short',hour:'2-digit',minute:'2-digit'}) : '';
   const align = fromBuyer ? 'flex-start' : 'flex-end';
   const bg = fromBuyer ? '#fff' : 'var(--primary-500,#CD7C32)';
   const col = fromBuyer ? '#111827' : '#fff';
   const brd = fromBuyer ? 'border:1px solid #E5E7EB;' : '';
   return `<div style="align-self:${align}; max-width:75%; margin-bottom:8px;">
     <div style="background:${bg}; color:${col}; ${brd} padding:8px 12px; border-radius:12px; font-size:13px; line-height:1.4; word-break:break-word;">${body}</div>
     <div style="font-size:10px; color:#9CA3AF; margin-top:2px; text-align:${fromBuyer?'left':'right'};">${t}</div>
    </div>`;
  }).join('') + composer;
  thread.scrollTop = thread.scrollHeight;
 }).catch(e => { thread.innerHTML = '<p style="color:#B23A2E;">Error: '+esc(e.message)+'</p>'; });
};

// p1_1046 — Chat Inbox Fasa 2: HANTAR balasan Shopee terus dari POS. Guna konteks __chatCur
// (diset oleh __chatOpen). Selepas berjaya → refetch thread (mesej sendiri muncul kanan bronze).
window.__chatSend = function() {
 const cur = window.__chatCur || {};
 const inp = document.getElementById('chatReplyInput');
 const btn = document.getElementById('chatReplyBtn');
 if(!inp) return;
 const msg = (inp.value || '').trim();
 if(!msg) return;
 if(!cur.buyerId) { if(typeof showToast === 'function') showToast('Tak jumpa ID pembeli untuk balas.', 'warn'); return; }
 if(btn) { btn.disabled = true; btn.textContent = 'Menghantar…'; btn.style.opacity = '0.6'; }
 // p1_1079 — FB/IG guna messenger-chat fn (Graph send), bukan shopee-chat
 if(cur.channel === 'fb' || cur.channel === 'ig') {
  fetch('/.netlify/functions/messenger-chat', {
   method: 'POST',
   headers: window.__authHeaderSync({ 'Content-Type': 'application/json' }),
   body: JSON.stringify({ to_id: cur.buyerId, message: msg, channel: cur.channel })
  }).then(r=>r.json()).then(r => {
   if(r && r.error) {
    if(typeof showToast === 'function') showToast('Meta: gagal hantar — ' + String(r.error).slice(0,140), 'error');
    if(btn) { btn.disabled = false; btn.textContent = 'Hantar'; btn.style.opacity = '1'; }
    return;
   }
   if(typeof showToast === 'function') showToast('Balasan dihantar ke ' + (cur.name || 'pelanggan') + '.', 'success');
   window.__chatOpenMeta(cur.cid, cur.buyerId, cur.name, cur.channel);
  }).catch(e => {
   if(typeof showToast === 'function') showToast('Gagal hantar: ' + e.message, 'error');
   if(btn) { btn.disabled = false; btn.textContent = 'Hantar'; btn.style.opacity = '1'; }
  });
  return;
 }
 fetch('/.netlify/functions/shopee-chat?mode=send', {
  method: 'POST',
  headers: window.__authHeaderSync({ 'Content-Type': 'application/json' }),
  body: JSON.stringify({ to_id: cur.buyerId, message: msg })
 }).then(r=>r.json()).then(r => {
  if(r && r.error) {
   if(typeof showToast === 'function') showToast('Shopee: gagal hantar — ' + String(r.error).slice(0,120), 'error');
   if(btn) { btn.disabled = false; btn.textContent = 'Hantar'; btn.style.opacity = '1'; }
   return;
  }
  if(typeof showToast === 'function') showToast('Balasan dihantar ke ' + (cur.name || 'pembeli') + '.', 'success');
  // refetch thread — mesej baru muncul; composer dirender semula (input kosong)
  window.__chatOpen(cur.cid, cur.buyerId, cur.name);
 }).catch(e => {
  if(typeof showToast === 'function') showToast('Gagal hantar: ' + e.message, 'error');
  if(btn) { btn.disabled = false; btn.textContent = 'Hantar'; btn.style.opacity = '1'; }
 });
};

