// p1_110 — Stock Check Reports workflow (Kael→Zack→Bos)
window.__scFilter = 'all';
window.__scReports = [];
window.__scActiveId = null;

window.renderStockCheck = async function() {
 const list = document.getElementById('stockCheckList');
 if(!list) return;
 list.innerHTML = '<p style="color:#9CA3AF; padding:40px; text-align:center;">Memuatkan…</p>';
 try {
 if(typeof db === 'undefined' || !db) { list.innerHTML = '<p style="color:#B23A2E; padding:20px;">DB tak available.</p>'; return; }
 const { data, error } = await db.from('stock_check_reports').select('*').order('submitted_at', { ascending: false }).limit(50);
 if(error) throw error;
 window.__scReports = data || [];
 window.__scRenderList();
 window.__scRefreshCounts();
 } catch(e) {
 list.innerHTML = '<p style="color:#B23A2E; padding:20px;">Error: ' + e.message + '</p>';
 }
};

window.__scRenderList = function() {
 const list = document.getElementById('stockCheckList');
 if(!list) return;
 const filter = window.__scFilter || 'all';
 const rows = window.__scReports.filter(r => filter === 'all' || r.status === filter);
 if(!rows.length) {
 list.innerHTML = '<p style="color:#9CA3AF; padding:40px; text-align:center;">Tiada report dengan filter ni.</p>';
 return;
 }
 const escAttr = (s) => String(s == null ? '' : s).replace(/"/g,'&quot;').replace(/</g,'&lt;');
 const u = window.currentUser || {};
 const isBoss = typeof window.isBoss === 'function' && window.isBoss(u);
 const isReviewer = u.staff_id === 'CMP005' || u.staff_id === 'CMP011' || isBoss; // Zack + Kael + Bos
 const statusBadge = (s) => {
 const cfg = {
 submitted: { bg:'#F8EFD7', fg:'#7A5410', label:'Menunggu Review' },
 reviewed: { bg:'var(--primary-100,#FFEDD5)', fg:'var(--primary-800,#7C4A1A)', label:'Direview · Pending Bos' },
 approved: { bg:'#E4EFE2', fg:'#345E43', label:'Bos Acknowledged' },
 rejected: { bg:'#F4E4DF', fg:'#7C2A20', label:'Rejected' }
 }[s] || { bg:'#E5E7EB', fg:'#374151', label:s };
 return `<span style="display:inline-block; padding:2px 10px; border-radius:50px; background:${cfg.bg}; color:${cfg.fg}; font-size:10.5px; font-weight:700;">${cfg.label}</span>`;
 };
 list.innerHTML = rows.map(r => `
 <div class="rp-section" style="cursor:${isReviewer ? 'pointer' : 'default'};" ${isReviewer ? `onclick="window.__scOpenReview(${r.id})"` : ''}>
 <div style="display:flex; justify-content:space-between; align-items:flex-start; gap:14px; flex-wrap:wrap;">
 <div style="flex:1; min-width:200px;">
 <div style="display:flex; align-items:center; gap:8px; margin-bottom:6px;">
 <strong style="font-size:14px;">${r.period_start} → ${r.period_end}</strong>
 ${statusBadge(r.status)}
 </div>
 <p style="font-size:12px; color:#6B7280; margin:0 0 6px;">By <strong>${escAttr(r.submitted_by_name)}</strong> · ${new Date(r.submitted_at).toLocaleString('en-MY')}</p>
 <div style="display:flex; gap:14px; font-size:12px; color:#374151;">
 <span><i data-lucide="package" style="width:11px;height:11px;vertical-align:-1px;"></i> ${r.items_checked} checked</span>
 <span style="${r.items_variance > 0 ? 'color:#C68A1A;' : ''}"><i data-lucide="alert-triangle" style="width:11px;height:11px;vertical-align:-1px;"></i> ${r.items_variance} variance</span>
 <span style="${r.rm_variance < 0 ? 'color:#B23A2E;' : ''}"><i data-lucide="dollar-sign" style="width:11px;height:11px;vertical-align:-1px;"></i> RM ${Number(r.rm_variance || 0).toFixed(2)}</span>
 </div>
 </div>
 </div>
 ${r.summary_text ? `<p style="margin:8px 0 0; padding:8px; background:#F9FAFB; border-radius:6px; font-size:12px; line-height:1.5; color:#374151; white-space:pre-wrap;">${escAttr(r.summary_text).slice(0, 300)}${r.summary_text.length > 300 ? '…' : ''}</p>` : ''}
 ${r.review_notes && r.status !== 'submitted' ? `<div style="margin-top:8px; padding:8px 10px; background:var(--primary-50,#FFF8F0); border-left:3px solid var(--primary-500,#CD7C32); border-radius:4px; font-size:11.5px;"><strong>${escAttr(r.reviewer_name || 'Zack')}:</strong> ${escAttr(r.review_notes)}</div>` : ''}
 ${isBoss && r.status === 'reviewed' ? `<div style="margin-top:10px; display:flex; gap:6px;"><button class="sy-btn fin-btn--gold" onclick="event.stopPropagation(); window.__scBosAck(${r.id})"><i data-lucide="check-circle" style="width:13px;height:13px;"></i> Acknowledge</button></div>` : ''}
 </div>`).join('');
 if(window.lucide && lucide.createIcons) lucide.createIcons();
};

window.__scRefreshCounts = function() {
 const pending = window.__scReports.filter(r => r.status === 'submitted').length;
 const el = document.getElementById('scCountSubmitted');
 if(el) el.textContent = pending;
 // Sidebar badge (visible to Zack + Bos)
 const u = window.currentUser || {};
 const showBadge = u.staff_id === 'CMP005' || (typeof window.isBoss === 'function' && window.isBoss(u));
 const badge = document.getElementById('stockCheckBadge');
 if(badge) {
 if(showBadge && pending > 0) { badge.style.display = ''; badge.textContent = pending; }
 else badge.style.display = 'none';
 }
};

window.__scSetFilter = function(s, btn) {
 window.__scFilter = s;
 document.querySelectorAll('[data-sc-status]').forEach(b => b.classList.toggle('sc-tab--active', b === btn));
 window.__scRenderList();
};

window.__scOpenSubmit = function() {
 const today = new Date();
 const firstOfMonth = new Date(today.getFullYear(), today.getMonth(), 1);
 document.getElementById('scPeriodStart').value = firstOfMonth.toISOString().slice(0, 10);
 document.getElementById('scPeriodEnd').value = today.toISOString().slice(0, 10);
 document.getElementById('scItemsChecked').value = '0';
 document.getElementById('scItemsVariance').value = '0';
 document.getElementById('scRmVariance').value = '0';
 document.getElementById('scSummary').value = '';
 document.getElementById('scAttachment').value = '';
 document.getElementById('scSubmitOverlay').style.display = 'flex';
};
window.__scCloseSubmit = function() {
 document.getElementById('scSubmitOverlay').style.display = 'none';
};
window.__scSubmit = async function() {
 const u = window.currentUser || {};
 const payload = {
 period_start: document.getElementById('scPeriodStart').value,
 period_end: document.getElementById('scPeriodEnd').value,
 submitted_by_id: u.staff_id || 'unknown',
 submitted_by_name: u.name || 'Unknown',
 items_checked: parseInt(document.getElementById('scItemsChecked').value || '0', 10),
 items_variance: parseInt(document.getElementById('scItemsVariance').value || '0', 10),
 rm_variance: parseFloat(document.getElementById('scRmVariance').value || '0'),
 summary_text: document.getElementById('scSummary').value.trim(),
 attachments: { url: document.getElementById('scAttachment').value.trim() || null },
 status: 'submitted'
 };
 if(!payload.period_start || !payload.period_end || !payload.summary_text) {
 if(typeof showToast === 'function') showToast('Period + Summary wajib.', 'warn');
 return;
 }
 try {
 const { error } = await db.from('stock_check_reports').insert([payload]);
 if(error) throw error;
 if(typeof showToast === 'function') showToast('Stock check report submitted. Tunggu Zack review.', 'success');
 window.__scCloseSubmit();
 setTimeout(() => window.renderStockCheck(), 200);
 } catch(e) {
 if(typeof showToast === 'function') showToast('Submit failed: ' + e.message, 'error');
 }
};

window.__scOpenReview = function(id) {
 const r = window.__scReports.find(x => x.id === id);
 if(!r) return;
 // Only Zack/Bos can review submitted; Bos can ack reviewed
 const u = window.currentUser || {};
 const isReviewer = u.staff_id === 'CMP005' || (typeof window.isBoss === 'function' && window.isBoss(u));
 if(!isReviewer || (r.status !== 'submitted' && r.status !== 'reviewed')) return;
 window.__scActiveId = id;
 const escAttr = (s) => String(s == null ? '' : s).replace(/"/g,'&quot;').replace(/</g,'&lt;');
 document.getElementById('scReviewBody').innerHTML = `
 <p style="margin:0 0 6px;"><strong>${r.period_start} → ${r.period_end}</strong> · oleh ${escAttr(r.submitted_by_name)}</p>
 <p style="font-size:11px; color:#6B7280; margin:0 0 8px;">Submitted: ${new Date(r.submitted_at).toLocaleString('en-MY')}</p>
 <div style="display:grid; grid-template-columns:1fr 1fr 1fr; gap:8px; margin-bottom:8px;">
 <div style="background:#FFF; padding:6px 10px; border-radius:6px; border:1px solid #E5E7EB; font-size:11px;"><strong>Checked:</strong> ${r.items_checked}</div>
 <div style="background:#FFF; padding:6px 10px; border-radius:6px; border:1px solid #E5E7EB; font-size:11px;"><strong>Variance:</strong> ${r.items_variance}</div>
 <div style="background:#FFF; padding:6px 10px; border-radius:6px; border:1px solid #E5E7EB; font-size:11px;"><strong>RM:</strong> ${Number(r.rm_variance || 0).toFixed(2)}</div>
 </div>
 <div style="background:#FFF; padding:8px 10px; border-radius:6px; border:1px solid #E5E7EB; font-size:12px; white-space:pre-wrap;">${escAttr(r.summary_text || '')}</div>
 ${r.attachments && r.attachments.url ? `<p style="margin:6px 0 0; font-size:11px;"><a href="${escAttr(r.attachments.url)}" target="_blank" rel="noopener">Attachment →</a></p>` : ''}`;
 document.getElementById('scReviewNotes').value = r.review_notes || '';
 document.getElementById('scReviewOverlay').style.display = 'flex';
};
window.__scCloseReview = function() {
 document.getElementById('scReviewOverlay').style.display = 'none';
 window.__scActiveId = null;
};
window.__scAction = async function(newStatus) {
 if(!window.__scActiveId) return;
 const u = window.currentUser || {};
 const payload = {
 status: newStatus,
 reviewer_id: u.staff_id || 'unknown',
 reviewer_name: u.name || 'Unknown',
 reviewed_at: new Date().toISOString(),
 review_notes: document.getElementById('scReviewNotes').value.trim()
 };
 try {
 const { error } = await db.from('stock_check_reports').update(payload).eq('id', window.__scActiveId);
 if(error) throw error;
 if(typeof showToast === 'function') showToast(newStatus === 'reviewed' ? 'Forwarded to Bos.' : 'Report rejected.', 'success');
 window.__scCloseReview();
 setTimeout(() => window.renderStockCheck(), 200);
 } catch(e) {
 if(typeof showToast === 'function') showToast('Action failed: ' + e.message, 'error');
 }
};

window.__scBosAck = async function(id) {
 try {
 const { error } = await db.from('stock_check_reports').update({
 status: 'approved',
 bos_seen_at: new Date().toISOString(),
 bos_action: 'acknowledged'
 }).eq('id', id);
 if(error) throw error;
 if(typeof showToast === 'function') showToast('Acknowledged.', 'success');
 setTimeout(() => window.renderStockCheck(), 200);
 } catch(e) {
 if(typeof showToast === 'function') showToast('Action failed: ' + e.message, 'error');
 }
};

// p1_109 — Floor Price Calculator handlers
// p1_922 — Calculator gabungan: satu menu "Calculator", dua view (Harga & Tier / Kos Shipment).
// Tukar view = tukar section yang switchHub papar (no DOM restructure). Sidebar item kekal highlight.
window.__calcShow = function(view, menuEl){
 if(['kos','harga','log','status'].indexOf(view) === -1) view = 'harga';
 const menu = menuEl || document.querySelector('.menu-item[data-tab="nav_sys_calc"]');
 if(view === 'kos'){
 switchHub(['shipmentCalcSection'], 'Calculator', menu);
 if(typeof renderShipmentCalc === 'function') try{ renderShipmentCalc(); }catch(e){}
 } else if(view === 'log'){
 switchHub(['calcLogSection'], 'Calculator', menu);
 if(typeof window.renderCalcLog === 'function') try{ window.renderCalcLog(); }catch(e){}
 } else if(view === 'status'){
 switchHub(['calcStatusSection'], 'Calculator', menu);
 if(typeof window.renderCalcStatus === 'function') try{ window.renderCalcStatus(); }catch(e){}
 } else {
 switchHub(['floorPriceSection'], 'Calculator', menu);
 if(typeof renderFloorPrice === 'function') try{ renderFloorPrice(); }catch(e){}
 }
 // Selaras butang sub-tab (semua salinan dalam tiap section)
 document.querySelectorAll('.calc-subtab').forEach(b => b.classList.toggle('calc-subtab--active', b.dataset.calcView === view));
 if(window.lucide && lucide.createIcons) try{ lucide.createIcons(); }catch(e){}
};

// p1_923 — FORMULA LOG (rekod kekal tiap pengiraan + tarikh; table calc_formula_log).
// Formula didefinisikan penuh dalam tiap rekod supaya boleh audit walaupun formula berubah satu hari.
window.__CALC_FORMULA_LANDED = 'Landed v1 — Landed/unit = Barang(RMB×ex) + SF%(ikut NILAI) + Shipping(ikut NILAI) + Part-timer(ikut KUANTITI)';
window.__CALC_FORMULA_PRICE  = 'Harga v1 — Cost Bersih = (RMB×ex) + Shipping + Hand% ; tier: RRP +30% · Kedai +60% lepas −20% · Marketplace +80% · Z\'s Proposal +35%';

// Tulis satu rekod log (append-only). Fire-and-forget — tak block apply kalau gagal.
window.__calcLogWrite = async function(entry){
 try {
 if(typeof db==='undefined'||!db) return;
 const u = window.currentUser||{};
 const payload = {
 calc_type: entry.calc_type || 'landed',
 action: entry.action || null,
 formula_version: entry.formula_version || '',
 ref_label: entry.ref_label || null,
 supplier: entry.supplier || null,
 source_docs: entry.source_docs || null,
 inputs: entry.inputs || {},
 results: entry.results || {},
 summary: entry.summary || '',
 created_by: u.name || 'System',
 staff_id: (u.staff_id || u.id || null)
 };
 const { error } = await db.from('calc_formula_log').insert([payload]);
 if(error) throw error;
 // Kalau view Log sedang terbuka, segarkan
 const sec = document.getElementById('calcLogSection');
 if(sec && sec.style.display!=='none' && typeof window.renderCalcLog==='function') window.renderCalcLog();
 } catch(e){ console.warn('calc_formula_log gagal:', e && e.message); }
};

// Snapshot pengiraan landed semasa (dari input shipment calc) untuk dilog.
window.__calcLandedSnapshot = function(){
 const P = window.__scParams ? window.__scParams() : null;
 if(!P) return { ex:0, sfPct:0, shipping:0, parttimer:0, totalQty:0, totalValue:0, rows:[] };
 const rows = (P.rows||[]).filter(r=> (r.sku||'').trim()).map(r=>{
 const rmb=parseFloat(r.rmb)||0, qty=parseInt(r.qty,10)||0;
 const goods=rmb*P.ex, sf=rmb*(P.sfPct/100)*P.ex, ship=P.shipPU(rmb), pt=P.ptPerUnit;
 return { sku:(r.sku||'').trim(), name:(r.name||''), rmb, qty,
 goods:+goods.toFixed(2), sf:+sf.toFixed(2), ship:+ship.toFixed(2), pt:+pt.toFixed(2),
 landed:+(goods+sf+ship+pt).toFixed(2) };
 });
 return { ex:P.ex, sfPct:P.sfPct, shipping:P.shipping, parttimer:P.pt, totalQty:P.totalQty, totalValue:+(P.totalValue||0).toFixed(2), rows };
};

// Log pengiraan landed (dipanggil auto masa apply, atau manual butang).
window.__calcLogLanded = function(action){
 const snap = window.__calcLandedSnapshot();
 if(!snap.rows.length){ if(action==='manual' && typeof showToast==='function') showToast('Tiada baris untuk dilog.','warn'); return; }
 const totLanded = snap.rows.reduce((s,r)=> s + r.landed*r.qty, 0);
 const ref = ((document.getElementById('scLabel')||{}).value||'').trim();
 const sup = ((document.getElementById('scSupplier')||{}).value||'').trim();
 window.__calcLogWrite({
 calc_type:'landed', action:action||'manual',
 formula_version: window.__CALC_FORMULA_LANDED,
 ref_label: ref || null, supplier: sup || null,
 source_docs: 'Barang ← PI · SF% ← PI · Shipping ← Invoice Shipment · Part-timer ← terima',
 inputs: { ex:snap.ex, sf_pct:snap.sfPct, shipping:snap.shipping, parttimer:snap.parttimer, total_qty:snap.totalQty, total_value:snap.totalValue },
 results: snap.rows,
 summary: `Landed ${snap.rows.length} SKU · ex ${snap.ex} · SF ${snap.sfPct}% · ship RM${(+snap.shipping||0).toFixed(2)} · p/timer RM${(+snap.parttimer||0).toFixed(2)} · jumlah landed RM${totLanded.toFixed(2)}`
 });
 if(action==='manual' && typeof showToast==='function') showToast('Pengiraan disimpan ke Log Formula.','success');
};

// ===== VIEW: Log Formula =====
window.__calcLogRows = [];
window.__calcLogFilter = 'all';
window.renderCalcLog = async function(){
 const tb = document.getElementById('calcLogBody'); if(!tb) return;
 if(typeof db==='undefined'||!db){ tb.innerHTML='<tr><td colspan="6" style="text-align:center; padding:20px; color:#B23A2E;">DB tak available.</td></tr>'; return; }
 tb.innerHTML='<tr><td colspan="6" style="text-align:center; padding:20px; color:#9CA3AF;">Memuatkan…</td></tr>';
 try {
 const { data, error } = await db.from('calc_formula_log').select('*').order('created_at',{ascending:false}).limit(500);
 if(error) throw error;
 window.__calcLogRows = data||[];
 window.__calcLogRender();
 } catch(e){ tb.innerHTML='<tr><td colspan="6" style="text-align:center; padding:20px; color:#B23A2E;">Error: '+hesc(e.message||String(e))+'</td></tr>'; }
};
window.__calcLogSetFilter = function(f, btn){
 window.__calcLogFilter = f;
 document.querySelectorAll('.calclog-fbtn').forEach(b=> b.classList.remove('ps-tab--active'));
 if(btn) btn.classList.add('ps-tab--active');
 window.__calcLogRender();
};
window.__calcLogRender = function(){
 const tb = document.getElementById('calcLogBody'); if(!tb) return;
 const q = ((document.getElementById('calcLogSearch')||{}).value||'').trim().toLowerCase();
 const f = window.__calcLogFilter || 'all';
 let rows = window.__calcLogRows || [];
 if(f!=='all') rows = rows.filter(r=> r.calc_type===f);
 if(q) rows = rows.filter(r=> JSON.stringify([r.ref_label,r.supplier,r.summary,r.results]).toLowerCase().includes(q));
 if(!rows.length){ tb.innerHTML='<tr><td colspan="6" style="text-align:center; padding:24px; color:#9CA3AF;">Tiada rekod log.</td></tr>'; const c=document.getElementById('calcLogCount'); if(c) c.textContent=''; return; }
 const typeChip = (t)=> t==='price'
 ? '<span style="font-size:10px; font-weight:700; background:#EDE3F0; color:#6D4C7A; padding:2px 8px; border-radius:20px;">HARGA</span>'
 : '<span style="font-size:10px; font-weight:700; background:#F3EEE7; color:#7A4A1E; padding:2px 8px; border-radius:20px;">LANDED</span>';
 tb.innerHTML = rows.map((r,i)=>{
 const dt = r.created_at ? new Date(r.created_at).toLocaleString('en-MY',{day:'2-digit',month:'short',year:'2-digit',hour:'2-digit',minute:'2-digit'}) : '—';
 const stripe = (i%2===0)?'#FFFFFF':'#FBF7F1';
 return `<tr class="sc-row" onclick="window.__calcLogToggle(${r.id})" style="cursor:pointer; background:${stripe};" title="Klik untuk butiran formula + input + hasil">
 <td style="white-space:nowrap;"><span id="clCaret_${r.id}" style="color:var(--primary-500,#CD7C32); font-size:10px;">&#9656;</span> ${hesc(dt)}</td>
 <td>${typeChip(r.calc_type)}</td>
 <td>${hesc(r.ref_label||'—')}${r.supplier?'<div style="font-size:10px; color:#9CA3AF;">'+hesc(r.supplier)+'</div>':''}</td>
 <td style="font-size:12px;">${hesc(r.summary||'')}</td>
 <td style="font-size:11px; color:#6B7280; white-space:nowrap;">${hesc(r.created_by||'—')}</td>
 <td style="font-size:10px; color:#9CA3AF;">${hesc((r.action||'').replace('_',' '))}</td>
 </tr>
 <tr id="clDetail_${r.id}" style="display:none;"><td colspan="6" style="padding:0; background:#FCFAF7;"><div style="padding:14px 16px;">${window.__calcLogDetail(r)}</div></td></tr>`;
 }).join('');
 const c=document.getElementById('calcLogCount'); if(c) c.textContent = `${rows.length} rekod`;
 if(window.lucide && lucide.createIcons) try{ lucide.createIcons(); }catch(e){}
};
window.__calcLogDetail = function(r){
 const fmt=(n)=>'RM'+(Number(n)||0).toFixed(2);
 let inp='';
 try { const I=r.inputs||{}; inp = Object.keys(I).map(k=> `<span style="display:inline-block; margin:0 10px 4px 0; font-size:11.5px; color:#4B5563;"><strong>${hesc(k)}:</strong> ${hesc(String(I[k]))}</span>`).join(''); } catch(e){}
 let res='';
 try {
 const R=r.results;
 if(Array.isArray(R)){
 res = `<table style="width:100%; border-collapse:collapse; font-size:11.5px; margin-top:8px;">
 <thead><tr style="background:#F3EEE7;"><th style="text-align:left; padding:6px;">SKU</th><th style="text-align:right; padding:6px;">RMB/u</th><th style="text-align:right; padding:6px;">Qty</th><th style="text-align:right; padding:6px;">Goods</th><th style="text-align:right; padding:6px;">SF</th><th style="text-align:right; padding:6px;">Ship</th><th style="text-align:right; padding:6px;">P/timer</th><th style="text-align:right; padding:6px;">Landed/u</th></tr></thead>
 <tbody>${R.map(x=>`<tr><td style="font-family:monospace; padding:5px 6px;">${hesc(x.sku||'-')}</td><td style="text-align:right; padding:5px 6px;">${(Number(x.rmb)||0).toFixed(2)}</td><td style="text-align:right; padding:5px 6px;">${x.qty||0}</td><td style="text-align:right; padding:5px 6px;">${fmt(x.goods)}</td><td style="text-align:right; padding:5px 6px;">${fmt(x.sf)}</td><td style="text-align:right; padding:5px 6px;">${fmt(x.ship)}</td><td style="text-align:right; padding:5px 6px;">${fmt(x.pt)}</td><td style="text-align:right; padding:5px 6px; font-weight:700;">${fmt(x.landed)}</td></tr>`).join('')}</tbody></table>`;
 } else if(R && typeof R==='object'){
 res = `<div style="font-size:12px; margin-top:6px;">SKU <strong>${hesc(R.sku||'-')}</strong> · tier <strong>${hesc(R.tier||'-')}</strong> · harga <strong>${fmt(R.final_price)}</strong>${R.compare_at?` · compare ${fmt(R.compare_at)}`:''}</div>`;
 }
 } catch(e){}
 return `<div style="font-size:12px; color:#7A4A1E; font-weight:700; margin-bottom:6px;">Formula</div>
 <div style="font-size:12px; color:#374151; background:#fff; border:1px solid #ECECEC; border-radius:8px; padding:8px 10px; margin-bottom:10px;">${hesc(r.formula_version||'—')}</div>
 ${r.source_docs?`<div style="font-size:11px; color:#6B7280; margin-bottom:10px;"><strong>Sumber:</strong> ${hesc(r.source_docs)}</div>`:''}
 <div style="font-size:12px; color:#7A4A1E; font-weight:700; margin-bottom:4px;">Input</div>
 <div style="margin-bottom:6px;">${inp||'<span style="color:#9CA3AF; font-size:11px;">—</span>'}</div>
 <div style="font-size:12px; color:#7A4A1E; font-weight:700;">Hasil</div>
 ${res||'<span style="color:#9CA3AF; font-size:11px;">—</span>'}`;
};
window.__calcLogToggle = function(id){
 const dr=document.getElementById('clDetail_'+id); if(!dr) return;
 const caret=document.getElementById('clCaret_'+id);
 const open=(dr.style.display==='none'||dr.style.display==='');
 dr.style.display = open ? 'table-row' : 'none';
 if(caret) caret.innerHTML = open ? '&#9662;' : '&#9656;';
};

// p1_924 — STATUS ORDER + dashboard "tersangkut".
// Tiap cost_shipment = satu order procurement. Jejak peringkat ikut flow Zaid:
// Katalog → PO → PI → SF 5% → Invoice Shipment → Transit → Sampai → Kos → Boleh Jual.
window.CALC_STAGES = [
 { key:'katalog',         label:'Katalog' },
 { key:'po_draft',        label:'PO Draf' },
 { key:'po_final',        label:'PO Final' },
 { key:'pi',              label:'Proforma Invoice' },
 { key:'sf_fee',          label:'SF Charge 5%' },
 { key:'ship_invoice',    label:'Invoice Shipment' },
 { key:'transit',         label:'Transit' },
 { key:'arrived_partial', label:'Sampai Sebahagian' },
 { key:'arrived',         label:'Sampai Penuh' },
 { key:'costed',          label:'Kos Siap' },
 { key:'on_sale',         label:'Boleh Jual' }
];
window.__calcStageIdx = function(key){ const i = window.CALC_STAGES.findIndex(s=>s.key===key); return i<0 ? 1 : i; };
window.__calcStageLabel = function(key){ const s = window.CALC_STAGES.find(x=>x.key===key); return s ? s.label : (key||'—'); };

// Tentukan sama ada order tersangkut + sebab.
window.__calcOrderStatus = function(o){
 const stage = o.stage || 'po_draft';
 const idx = window.__calcStageIdx(stage);
 const arrivedPartialIdx = window.__calcStageIdx('arrived_partial');
 const now = Date.now();
 const su = o.stage_updated_at ? new Date(o.stage_updated_at).getTime() : null;
 const daysInStage = su ? Math.floor((now - su)/86400000) : null;
 if(stage==='on_sale') return { level:'done', reasons:['Dah boleh jual'], daysInStage, idx };
 let level='ok'; const reasons=[];
 if(stage==='arrived' || stage==='arrived_partial'){ level='critical'; reasons.push('Barang dah sampai tapi belum boleh jual — kira kos + set harga'); }
 else if(stage==='costed'){ level='warn'; reasons.push('Kos dah siap tapi belum publish/jual'); }
 if(o.eta_date){ const eta = new Date(o.eta_date+'T00:00:00').getTime(); if(eta < now && idx < arrivedPartialIdx){ if(level==='ok') level='warn'; reasons.push('Lewat dari ETA ('+o.eta_date+')'); } }
 if(daysInStage!=null && daysInStage>=14){ if(level==='ok') level='warn'; reasons.push('Tersekat '+daysInStage+' hari di peringkat ni'); }
 if(o.cost_status==='provisional'){ if(level==='ok') level='warn'; reasons.unshift('Kos masih SEMENTARA — sahkan kos muktamad bila barang sampai'); }
 if(level==='ok') reasons.push('Bergerak lancar');
 return { level, reasons, daysInStage, idx };
};

window.__calcOrders = [];
window.renderCalcStatus = async function(){
 const host = document.getElementById('calcStatusBody'); if(!host) return;
 if(typeof db==='undefined'||!db){ host.innerHTML='<div style="padding:20px; color:#B23A2E;">DB tak available.</div>'; return; }
 host.innerHTML='<div style="padding:20px; color:#9CA3AF;">Memuatkan…</div>';
 try {
 const { data, error } = await db.from('cost_shipments').select('id,label,supplier,po_ref,order_date,eta_date,stage,stage_updated_at,stage_updated_by,updated_at,cost_status').order('order_date',{ascending:false, nullsFirst:false}).order('updated_at',{ascending:false}).limit(500);
 if(error) throw error;
 window.__calcOrders = (data||[]).map(o=> Object.assign({}, o, { _st: window.__calcOrderStatus(o) }));
 window.__calcStatusRender();
 } catch(e){ host.innerHTML='<div style="padding:20px; color:#B23A2E;">Error: '+hesc(e.message||String(e))+'</div>'; }
};

window.__calcStatusRender = function(){
 const host = document.getElementById('calcStatusBody'); if(!host) return;
 const orders = window.__calcOrders || [];
 if(!orders.length){ host.innerHTML='<div style="padding:24px; text-align:center; color:#9CA3AF;">Tiada order lagi. Buat satu di tab "Kos Shipment".</div>'; return; }
 const stageSel = (o)=> `<select onchange="window.__calcStageUpdate(${o.id}, this.value)" style="padding:5px 8px; border:1px solid #E5E7EB; border-radius:6px; font-size:11.5px; background:#fff; max-width:150px;">`
 + window.CALC_STAGES.map(s=> `<option value="${s.key}" ${o.stage===s.key?'selected':''}>${hesc(s.label)}</option>`).join('') + '</select>';
 const badge = (lvl)=>{
 if(lvl==='critical') return '<span style="font-size:10px; font-weight:800; background:#F6E2DE; color:#B23A2E; padding:3px 9px; border-radius:20px;">TERSANGKUT</span>';
 if(lvl==='warn') return '<span style="font-size:10px; font-weight:800; background:#FBEFD6; color:#9A6B12; padding:3px 9px; border-radius:20px;">PERLU TINDAKAN</span>';
 if(lvl==='done') return '<span style="font-size:10px; font-weight:800; background:#E2EFE0; color:#3C6438; padding:3px 9px; border-radius:20px;">SELESAI</span>';
 return '<span style="font-size:10px; font-weight:800; background:#EEF1F4; color:#5B6573; padding:3px 9px; border-radius:20px;">LANCAR</span>';
 };
 // ----- Panel TERSANGKUT (kritikal + warn) -----
 const stuck = orders.filter(o=> o._st.level==='critical' || o._st.level==='warn')
 .sort((a,b)=> (a._st.level==='critical'?0:1) - (b._st.level==='critical'?0:1));
 const crit = orders.filter(o=>o._st.level==='critical').length;
 const warn = orders.filter(o=>o._st.level==='warn').length;
 let stuckHtml='';
 if(stuck.length){
 stuckHtml = `<div style="border:1px solid #E7C77A; border-left:4px solid #CE9420; background:#FEF9EF; border-radius:12px; padding:14px 16px; margin-bottom:16px;">
 <div style="font-weight:800; font-size:13px; color:#7A5E12; margin-bottom:10px; display:flex; align-items:center; gap:7px;"><i data-lucide="alert-triangle" style="width:15px;height:15px;"></i> Tersangkut — perlu tindakan (${crit} kritikal · ${warn} amaran)</div>
 ${stuck.map(o=>{
 const c = o._st.level==='critical';
 return `<div style="display:flex; align-items:center; gap:10px; flex-wrap:wrap; padding:9px 0; border-top:1px solid #F0E6CF;">
 <span style="width:8px; height:8px; border-radius:50%; background:${c?'#B23A2E':'#C68A1A'}; flex:none;"></span>
 <strong style="font-size:13px; color:#101010;">${hesc(o.label||('Order #'+o.id))}</strong>
 <span style="font-size:11px; color:#6B7280;">${hesc(o.supplier||'—')}</span>
 <span style="font-size:11px; color:#7A4A1E; background:#F3EEE7; padding:2px 8px; border-radius:12px;">${hesc(window.__calcStageLabel(o.stage))}</span>
 <span style="font-size:11.5px; color:${c?'#B23A2E':'#9A6B12'}; flex:1; min-width:180px;">${hesc(o._st.reasons[0]||'')}</span>
 <button onclick="window.scOpenArchived(${o.id})" style="padding:5px 12px; font-size:11px; font-weight:700; background:var(--primary-500,#CD7C32); color:#fff; border:none; border-radius:7px; cursor:pointer;">Buka kira kos</button>
 </div>`;
 }).join('')}
 </div>`;
 } else {
 stuckHtml = `<div style="border:1px solid #CDE3C8; border-left:4px solid #4E7C4A; background:#F3F8F2; border-radius:12px; padding:14px 16px; margin-bottom:16px; font-size:13px; color:#3C6438; font-weight:700; display:flex; align-items:center; gap:8px;"><i data-lucide="check-circle-2" style="width:16px;height:16px;"></i> Tiada order tersangkut. Semua bergerak lancar.</div>`;
 }
 // ----- Pipeline chips (kiraan per peringkat) -----
 const counts = {}; orders.forEach(o=>{ counts[o.stage]=(counts[o.stage]||0)+1; });
 const pipeline = `<div style="display:flex; gap:6px; flex-wrap:wrap; margin-bottom:16px;">`
 + window.CALC_STAGES.map(s=>{ const n=counts[s.key]||0; const on=n>0;
 return `<span style="font-size:11px; font-weight:600; padding:5px 10px; border-radius:20px; border:1px solid ${on?'var(--primary-500,#CD7C32)':'#E5E7EB'}; background:${on?'#FFF1E2':'#FAFAFA'}; color:${on?'#7A4A1E':'#9CA3AF'};">${hesc(s.label)} <strong>${n}</strong></span>`;
 }).join('') + '</div>';
 // ----- Jadual semua order -----
 const fmtDt = (d)=> d ? d : '—';
 const rows = orders.map((o,i)=>{
 const st=o._st; const stripe=(i%2===0)?'#FFFFFF':'#FBF7F1';
 const dStage = st.daysInStage!=null ? st.daysInStage+'h' : '—';
 const dColor = (st.daysInStage!=null && st.daysInStage>=14) ? '#B23A2E' : '#6B7280';
 return `<tr style="background:${stripe};">
 <td><strong style="font-size:12.5px;">${hesc(o.label||('Order #'+o.id))}</strong>${o.po_ref?'<div style="font-size:10px; color:#9CA3AF;">'+hesc(o.po_ref)+'</div>':''}</td>
 <td style="font-size:12px;">${hesc(o.supplier||'—')}</td>
 <td style="font-size:11.5px; color:#6B7280; white-space:nowrap;">${hesc(fmtDt(o.order_date))}</td>
 <td><input type="date" value="${hesc(o.eta_date||'')}" onchange="window.__calcEtaUpdate(${o.id}, this.value)" style="padding:4px 6px; border:1px solid #E5E7EB; border-radius:6px; font-size:11px;"></td>
 <td>${stageSel(o)}</td>
 <td style="text-align:center; font-size:11.5px; color:${dColor}; font-weight:600;">${dStage}</td>
 <td style="text-align:center;">${badge(st.level)}</td>
 <td style="text-align:center;"><button onclick="window.scOpenArchived(${o.id})" style="padding:4px 10px; font-size:11px; font-weight:600; background:#FFF1E2; color:var(--primary-700,#A05F22); border:1px solid var(--primary-500,#CD7C32); border-radius:6px; cursor:pointer;">Buka</button></td>
 </tr>`;
 }).join('');
 host.innerHTML = stuckHtml + pipeline + `<div class="admin-card" style="padding:0; overflow:hidden;"><div class="table-responsive"><table class="data-table sc-arch" style="font-size:12px;">
 <thead><tr><th>Order / PO</th><th>Supplier</th><th>Tarikh Order</th><th>ETA</th><th>Peringkat</th><th style="text-align:center;">Umur</th><th style="text-align:center;">Status</th><th></th></tr></thead>
 <tbody>${rows}</tbody></table></div></div>`;
 const c=document.getElementById('calcStatusCount'); if(c) c.textContent = `${orders.length} order · ${crit} tersangkut · ${warn} perlu tindakan`;
 if(window.lucide && lucide.createIcons) try{ lucide.createIcons(); }catch(e){}
};

window.__calcStageUpdate = async function(id, stage){
 try {
 if(typeof db==='undefined'||!db) return;
 const u = window.currentUser||{};
 const { error } = await db.from('cost_shipments').update({ stage, stage_updated_at:new Date().toISOString(), stage_updated_by:(u.name||'System') }).eq('id', id);
 if(error) throw error;
 if(typeof showToast==='function') showToast('Peringkat dikemaskini → '+window.__calcStageLabel(stage),'success');
 window.renderCalcStatus();
 } catch(e){ if(typeof showToast==='function') showToast('Gagal: '+e.message,'error'); }
};
window.__calcEtaUpdate = async function(id, val){
 try {
 if(typeof db==='undefined'||!db) return;
 const { error } = await db.from('cost_shipments').update({ eta_date: val||null }).eq('id', id);
 if(error) throw error;
 window.renderCalcStatus();
 } catch(e){ if(typeof showToast==='function') showToast('Gagal set ETA: '+e.message,'error'); }
};

// p1_391 — Cost Calculator (Shipment landed-cost).
// Landed/unit = goods(RMB*ex) + SF(RMB*sf%*ex, by value) + shipping(RM/qty) + part-timer(RM/qty).
window.__scRows = [];
window.__scId = null;

window.scAddRow = function(){
 (window.__scRows = window.__scRows || []).push({ sku:'', name:'', rmb:'', qty:'' });
 scRenderItems(); scCompute();
};
window.scRemoveRow = function(i){ (window.__scRows||[]).splice(i,1); scRenderItems(); scCompute(); };
window.scUpdateRow = function(i, field, val){ if(window.__scRows && window.__scRows[i]){ window.__scRows[i][field] = val; scCompute(); } };

// p1_927 — Import Katalog (CSV): supplier bagi katalog dulu; parse + peta lajur + import jadi rows.
// Parser ringkas: auto-detect pembatas (, ; tab), sokong field berquote ("a,b").
window.__csvParse = function(text){
 text = String(text||'').replace(/^﻿/,'').replace(/\r\n/g,'\n').replace(/\r/g,'\n');
 const firstLine = (text.split('\n')[0]||'');
 const counts = { ',':(firstLine.match(/,/g)||[]).length, ';':(firstLine.match(/;/g)||[]).length, '\t':(firstLine.match(/\t/g)||[]).length };
 let delim = ','; if(counts[';']>counts[delim]) delim=';'; if(counts['\t']>counts[delim]) delim='\t';
 const rows=[]; let row=[]; let field=''; let inQ=false;
 for(let i=0;i<text.length;i++){ const c=text[i];
 if(inQ){ if(c==='"'){ if(text[i+1]==='"'){ field+='"'; i++; } else inQ=false; } else field+=c; }
 else { if(c==='"') inQ=true; else if(c===delim){ row.push(field); field=''; } else if(c==='\n'){ row.push(field); rows.push(row); row=[]; field=''; } else field+=c; }
 }
 if(field!==''||row.length){ row.push(field); rows.push(row); }
 return rows.filter(r=> r.length && r.some(c=> String(c).trim()!==''));
};

window.__scCatalog = { headers:[], rows:[] };
window.scCatalogPick = function(input){
 const file = input && input.files && input.files[0]; if(!file) return;
 const reader = new FileReader();
 reader.onload = function(e){
 try {
 const parsed = window.__csvParse(e.target.result);
 if(parsed.length < 2){ if(typeof showToast==='function') showToast('Fail kosong atau tiada data.','warn'); input.value=''; return; }
 const headers = parsed[0].map(h=> String(h).trim());
 const rows = parsed.slice(1);
 const det = window.__scAutoDetect(headers, rows);
 window.__scCatalog = { headers, rows, det };
 if(det.confident){
 // Auto: terus import, tak payah pilih lajur
 const mapped = window.__scCatalogMapWith(det.sku, det.name, det.rmb, det.qty);
 window.__scCatalogImportRows(mapped, true);
 } else {
 // Tak yakin (jarang) → buka modal biar staf betulkan
 if(typeof showToast==='function') showToast('Tak pasti lajur mana — pilih sekejap.','warn');
 window.scCatalogOpen();
 }
 } catch(err){ if(typeof showToast==='function') showToast('Gagal baca CSV: '+(err.message||err),'error'); }
 input.value='';
 };
 reader.onerror = function(){ if(typeof showToast==='function') showToast('Gagal buka fail.','error'); input.value=''; };
 reader.readAsText(file);
};

window.__scGuessCol = function(headers, keys, exclude){
 const ex = exclude||[];
 const low = headers.map(h=> String(h).toLowerCase());
 for(const k of keys){ const i = low.findIndex((h,idx)=> ex.indexOf(idx)<0 && h.includes(k)); if(i>=0) return i; }
 return -1;
};
window.__scColNum = function(v){ const n = parseFloat(String(v==null?'':v).replace(/[^0-9.\-]/g,'')); return isNaN(n)?'':n; };

// Auto-detect lajur SKU/Nama/Kos/Qty — header dulu (ikut turutan, elak lajur yg dah diambil),
// kalau gagal guna corak DATA. Qty header-sahaja (pilihan; staf isi sendiri kalau tiada).
window.__scAutoDetect = function(headers, rows){
 let sku=-1, name=-1, rmb=-1, qty=-1;
 const ex = ()=> [sku,name,rmb,qty].filter(x=>x>=0);
 sku = window.__scGuessCol(headers, ['sku','item code','itemno','item no','art no','kod','code','article','model','barcode'], ex());
 name = window.__scGuessCol(headers, ['product name','description','name','nama','product','desc','keterangan','barang','title','item'], ex());
 rmb = window.__scGuessCol(headers, ['unit price','rmb','cny','¥','元','fob','cost','kos','price','harga','u/price'], ex());
 qty = window.__scGuessCol(headers, ['order qty','quantity','q\'ty','qty','kuantiti','pcs','bilangan'], ex());
 // Statistik kandungan (sampel 60 baris) untuk isi sku/name/rmb yang header tak jumpa
 const n = headers.length; const sample = (rows||[]).slice(0,60); const st=[];
 for(let c=0;c<n;c++){
 let total=0, numCount=0, sumLen=0, skuLike=0, sumVal=0;
 for(const r of sample){ let v=String(r[c]==null?'':r[c]).trim(); if(v==='') continue; total++; sumLen+=v.length;
 const num = window.__scColNum(v); const isNum = num!=='' && /^[\sRM$¥元rm]*[\d.,\-]+[\s%]*$/i.test(v);
 if(isNum){ numCount++; sumVal+=num; }
 if(/^[A-Za-z]{1,6}[-_ ]?\d{2,}/.test(v) || /^\d{5,}$/.test(v)) skuLike++;
 }
 st.push({ c, total, pctNum: total?numCount/total:0, avgLen: total?sumLen/total:0, pctSku: total?skuLike/total:0, avgVal: numCount?sumVal/numCount:0 });
 }
 if(sku<0){ let b=-1,bs=0.45; st.forEach(s=>{ if(ex().indexOf(s.c)<0 && s.pctSku>bs){ bs=s.pctSku; b=s.c; }}); sku=b; }
 if(rmb<0){ let b=-1,bv=-1; st.forEach(s=>{ if(ex().indexOf(s.c)<0 && s.pctNum>=0.6 && s.avgVal>bv){ bv=s.avgVal; b=s.c; }}); rmb=b; }
 if(name<0){ let b=-1,bl=2; st.forEach(s=>{ if(ex().indexOf(s.c)<0 && s.pctNum<0.4 && s.avgLen>bl){ bl=s.avgLen; b=s.c; }}); name=b; }
 const confident = (sku>=0 || name>=0) && rmb>=0;
 return { sku, name, rmb, qty, confident };
};

window.scCatalogOpen = function(){
 const { headers, det } = window.__scCatalog;
 const opts = (sel)=> '<option value="-1">— tiada —</option>' + headers.map((h,i)=>`<option value="${i}"${i===sel?' selected':''}>${hesc(h||('Lajur '+(i+1)))}</option>`).join('');
 const d = det || window.__scAutoDetect(headers, window.__scCatalog.rows||[]);
 const set=(id,html,sel)=>{ const el=document.getElementById(id); if(el){ el.innerHTML=html; el.value=String(sel); } };
 set('scMapSku', opts(d.sku), d.sku); set('scMapName', opts(d.name), d.name);
 set('scMapRmb', opts(d.rmb), d.rmb); set('scMapQty', opts(d.qty), d.qty);
 const modal=document.getElementById('scCatalogModal'); if(modal) modal.style.display='flex';
 window.scCatalogPreview();
 if(window.lucide && lucide.createIcons) try{ lucide.createIcons(); }catch(e){}
};
window.scCatalogClose = function(){ const m=document.getElementById('scCatalogModal'); if(m) m.style.display='none'; };

// Peta rows ikut index lajur (dipakai auto + modal).
window.__scCatalogMapWith = function(si,ni,ri,qi){
 const { rows } = window.__scCatalog; const num = window.__scColNum;
 return (rows||[]).map(r=>({
 sku: si>=0 ? String(r[si]==null?'':r[si]).trim() : '',
 name: ni>=0 ? String(r[ni]==null?'':r[ni]).trim() : '',
 rmb: ri>=0 ? num(r[ri]) : '',
 qty: qi>=0 ? (num(r[qi])===''?'':parseInt(num(r[qi]),10)) : ''
 })).filter(x=> x.sku || x.name || x.rmb!=='');
};
window.__scCatalogMapped = function(){
 const ci = (id)=> parseInt((document.getElementById(id)||{}).value, 10);
 return window.__scCatalogMapWith(ci('scMapSku'), ci('scMapName'), ci('scMapRmb'), ci('scMapQty'));
};
// Import sebenar (auto=true tunjuk pesan auto + offer betulkan).
window.__scCatalogImportRows = function(mapped, auto){
 if(!mapped || !mapped.length){ if(typeof showToast==='function') showToast('Tiada baris untuk import.','warn'); return; }
 const newRows = mapped.map(r=>({ sku:r.sku||'', name:r.name||'', rmb:r.rmb!==''?r.rmb:'', qty:r.qty!==''?r.qty:'', received:'' }));
 const cur = (window.__scRows||[]).filter(r=> (r.sku||'').trim() || (r.name||'').trim() || r.rmb || r.qty);
 window.__scRows = cur.length ? cur.concat(newRows) : newRows;   // ada data → tambah; kosong → ganti
 if(typeof scRenderItems==='function') scRenderItems();
 if(typeof scCompute==='function') scCompute();
 const note = document.getElementById('scCatalogNote');
 if(auto){
 const d = (window.__scCatalog||{}).det||{}; const h = (window.__scCatalog||{}).headers||[];
 const lbl = (i)=> i>=0 ? hesc(h[i]||('Lajur '+(i+1))) : '—';
 if(note) note.innerHTML = `<span style="color:#3C6438;">Auto-import: SKU=<strong>${lbl(d.sku)}</strong> · Nama=<strong>${lbl(d.name)}</strong> · Kos=<strong>${lbl(d.rmb)}</strong></span> · <button onclick="window.scCatalogOpen()" style="background:none; border:none; color:#7A4A1E; text-decoration:underline; cursor:pointer; font-size:11px; padding:0;">lajur silap? betulkan</button>`;
 if(typeof showToast==='function') showToast(`${newRows.length} produk diimport auto dari katalog. Semak kos + isi qty.`,'success');
 } else {
 if(note) note.innerHTML='';
 if(typeof showToast==='function') showToast(`${newRows.length} produk diimport dari katalog.`,'success');
 }
};
window.scCatalogPreview = function(){
 const mapped = window.__scCatalogMapped();
 const tb = document.getElementById('scCatalogPreviewBody'); if(!tb) return;
 const c=document.getElementById('scCatalogCount'); if(c) c.textContent = '· '+mapped.length+' baris';
 if(!mapped.length){ tb.innerHTML='<tr><td colspan="4" style="text-align:center; padding:16px; color:#9CA3AF;">Tiada baris padan — semak peta lajur.</td></tr>'; return; }
 tb.innerHTML = mapped.slice(0,30).map(r=>`<tr><td style="font-family:monospace;">${hesc(r.sku||'-')}</td><td>${hesc((r.name||'').slice(0,60))}</td><td style="text-align:right;">${r.rmb!==''?r.rmb:'—'}</td><td style="text-align:right;">${r.qty!==''?r.qty:'—'}</td></tr>`).join('')
 + (mapped.length>30?`<tr><td colspan="4" style="text-align:center; padding:8px; color:#9CA3AF;">… +${mapped.length-30} lagi</td></tr>`:'');
};
window.scCatalogImport = function(mode){
 const mapped = window.__scCatalogMapped();
 if(!mapped.length){ if(typeof showToast==='function') showToast('Tiada baris untuk import.','warn'); return; }
 const newRows = mapped.map(r=>({ sku:r.sku||'', name:r.name||'', rmb:r.rmb!==''?r.rmb:'', qty:r.qty!==''?r.qty:'', received:'' }));
 if(mode==='replace'){ window.__scRows = newRows; }
 else {
 const cur = (window.__scRows||[]).filter(r=> (r.sku||'').trim() || (r.name||'').trim() || r.rmb || r.qty);
 window.__scRows = cur.concat(newRows);
 }
 window.scCatalogClose();
 const note=document.getElementById('scCatalogNote'); if(note) note.innerHTML='';
 scRenderItems(); scCompute();
 if(typeof showToast==='function') showToast(`${newRows.length} produk diimport dari katalog${mode==='replace'?' (ganti)':''}. Semak kos + isi qty.`,'success');
};

window.scRenderItems = function(){
 const tb = document.getElementById('scItemsBody'); if(!tb) return;
 const rows = window.__scRows || [];
 if(!rows.length){ tb.innerHTML = '<tr><td colspan="7" style="text-align:center; padding:18px; color:#9CA3AF;">Tiada produk. Tekan "Tambah Produk".</td></tr>'; return; }
 tb.innerHTML = rows.map((r,i) => `
 <tr>
 <td><input value="${hesc(r.sku||'')}" oninput="scUpdateRow(${i},'sku',this.value)" style="width:120px; padding:4px 6px; border:1px solid #E5E7EB; border-radius:5px; font-size:11px; font-family:monospace;"></td>
 <td><input value="${hesc(r.name||'')}" oninput="scUpdateRow(${i},'name',this.value)" style="width:160px; padding:4px 6px; border:1px solid #E5E7EB; border-radius:5px; font-size:12px;"></td>
 <td><input type="number" step="0.01" value="${r.rmb!=null?r.rmb:''}" oninput="scUpdateRow(${i},'rmb',this.value)" style="width:90px; padding:4px 6px; border:1px solid #E5E7EB; border-radius:5px; font-size:12px; text-align:right;"></td>
 <td><input type="number" step="1" value="${r.qty!=null?r.qty:''}" oninput="scUpdateRow(${i},'qty',this.value)" style="width:64px; padding:4px 6px; border:1px solid #E5E7EB; border-radius:5px; font-size:12px; text-align:right;"></td>
 <td style="text-align:right;"><span id="sc_goods_${i}">RM0.00</span></td>
 <td style="text-align:right;"><span id="sc_sf_${i}">RM0.00</span></td>
 <td style="text-align:center;"><button onclick="scRemoveRow(${i})" title="Buang" style="border:none; background:none; color:#B23A2E; cursor:pointer; font-size:16px; line-height:1;">&times;</button></td>
 </tr>`).join('');
};

window.__scParams = function(){
 const ex = parseFloat((document.getElementById('scExchange')||{}).value) || 0;
 const sfPct = parseFloat((document.getElementById('scSfPct')||{}).value) || 0;
 const shipping = parseFloat((document.getElementById('scShipping')||{}).value) || 0;
 const pt = parseFloat((document.getElementById('scParttimer')||{}).value) || 0;
 const rows = window.__scRows || [];
 const totalQty = rows.reduce((s,r)=> s + (parseInt(r.qty,10)||0), 0);
 // p1_393 — Shipping diagih ikut NILAI (goods RM share); Part-timer ikut KUANTITI (rata/unit).
 const totalValue = rows.reduce((s,r)=> s + (parseFloat(r.rmb)||0)*ex*(parseInt(r.qty,10)||0), 0);
 return { ex, sfPct, shipping, pt, rows, totalQty, totalValue,
 ptPerUnit: totalQty>0 ? pt/totalQty : 0,
 // shipping per unit untuk satu baris = (goods unit / jumlah nilai) × kos shipping
 shipPU: (rmb)=> totalValue>0 ? (((parseFloat(rmb)||0)*ex) / totalValue) * shipping : 0 };
};

window.scCompute = function(){
 const P = window.__scParams();
 const fmt = (n)=> 'RM' + (Number(n)||0).toFixed(2);
 P.rows.forEach((r,i)=>{
 const rmb = parseFloat(r.rmb)||0;
 const g = document.getElementById('sc_goods_'+i); if(g) g.textContent = fmt(rmb*P.ex);
 const s = document.getElementById('sc_sf_'+i); if(s) s.textContent = fmt(rmb*(P.sfPct/100)*P.ex);
 });
 const tq = document.getElementById('scTotalQty'); if(tq) tq.textContent = 'Jumlah Qty: ' + P.totalQty;
 const sp = document.getElementById('scShipPerUnit'); if(sp) sp.textContent = 'Shipping: ' + fmt(P.shipping) + ' · diagih ikut NILAI produk (mahal tanggung lebih)';
 const pp = document.getElementById('scPtPerUnit'); if(pp) pp.textContent = 'Part-timer/unit: ' + fmt(P.ptPerUnit) + ' · rata ikut kuantiti';
 const lb = document.getElementById('scLandedBody');
 if(lb){
 if(!P.rows.length){ lb.innerHTML = '<tr><td colspan="7" style="text-align:center; padding:18px; color:#9CA3AF;">—</td></tr>'; }
 else lb.innerHTML = P.rows.map(r=>{
 const rmb = parseFloat(r.rmb)||0; const qty = parseInt(r.qty,10)||0;
 const goods = rmb*P.ex; const sf = rmb*(P.sfPct/100)*P.ex; const ship = P.shipPU(rmb);
 const landed = goods + sf + ship + P.ptPerUnit;
 return `<tr><td style="font-family:monospace; font-size:11px;">${hesc(r.sku||'-')}</td><td style="text-align:right;">${fmt(goods)}</td><td style="text-align:right;">${fmt(sf)}</td><td style="text-align:right;">${fmt(ship)}</td><td style="text-align:right;">${fmt(P.ptPerUnit)}</td><td style="text-align:right; font-weight:800; color:#101010;">${fmt(landed)}</td><td style="text-align:right;">${qty}</td></tr>`;
 }).join('');
 }
 if(typeof window.scRenderProvisional==='function') window.scRenderProvisional();
 if(typeof window.scRenderReceiving==='function') window.scRenderReceiving();
 if(typeof window.scRenderFx==='function') window.scRenderFx();
};

// p1_925 — KIRA AWAL (provisional cost): kira kos hampir penuh sebelum carton sampai.
// Masa dapat Invoice Shipment, Barang+SF+Shipping dah diketahui; part-timer kecil boleh dianggar.
window.__scPtPerUnitEst = function(){ try{ const v=parseFloat(localStorage.getItem('calc_pt_per_unit_est')); return (!isNaN(v)&&v>=0)?v:2; }catch(e){ return 2; } };
window.__scSetPtPerUnitEst = function(v){ try{ localStorage.setItem('calc_pt_per_unit_est', String(parseFloat(v)||0)); }catch(e){} };

window.scEstimatePartTimer = function(){
 const P = window.__scParams ? window.__scParams() : null; if(!P) return;
 const per = window.__scPtPerUnitEst();
 const est = +(per*(P.totalQty||0)).toFixed(2);
 const el = document.getElementById('scParttimer'); if(el) el.value = est;
 if(typeof showToast==='function') showToast('Part-timer dianggar: '+(P.totalQty||0)+' unit × RM'+per+' = RM'+est+' (boleh ubah).','success');
 scCompute();
};

window.__scProvisional = function(){
 const P = window.__scParams ? window.__scParams() : null; if(!P) return null;
 let goodsTot=0, sfTot=0;
 (P.rows||[]).forEach(r=>{ const rmb=parseFloat(r.rmb)||0, qty=parseInt(r.qty,10)||0; goodsTot += rmb*P.ex*qty; sfTot += rmb*(P.sfPct/100)*P.ex*qty; });
 const shipTot = P.shipping||0;
 const ptActual = P.pt||0;
 const ptEst = ptActual>0 ? ptActual : +(window.__scPtPerUnitEst()*(P.totalQty||0)).toFixed(2);
 const denom = goodsTot + sfTot + shipTot + ptEst;
 const confirmed = (goodsTot>0?goodsTot:0) + (sfTot>0?sfTot:0) + (shipTot>0?shipTot:0) + (ptActual>0?ptActual:0);
 const lockedPct = denom>0 ? Math.min(100, Math.round(confirmed/denom*100)) : 0;
 return { goodsTot:+goodsTot.toFixed(2), sfTot:+sfTot.toFixed(2), shipTot:+shipTot.toFixed(2),
 ptActual:+ptActual.toFixed(2), ptEst, ptIsEstimate:!(ptActual>0),
 totalProvisional:+denom.toFixed(2), lockedPct, sfPct:P.sfPct,
 comp:{ barang:goodsTot>0, sf:sfTot>0, shipping:shipTot>0, parttimer:ptActual>0 } };
};

window.scRenderProvisional = function(){
 const host = document.getElementById('scProvisionalBody'); if(!host) return;
 const pv = window.__scProvisional();
 if(!pv || pv.totalProvisional<=0){ host.innerHTML='<div style="font-size:12px; color:#9CA3AF;">Masuk produk + kos RMB dulu untuk kira awal.</div>'; return; }
 const fmt=(n)=>'RM'+(Number(n)||0).toFixed(2);
 const tick=(ok,label,src)=> `<div style="display:flex; align-items:center; gap:7px; font-size:12px; padding:3px 0;">
 <span style="width:16px;height:16px; border-radius:50%; display:inline-flex; align-items:center; justify-content:center; background:${ok?'#E2EFE0':'#EEF1F4'}; flex:none;"><i data-lucide="${ok?'check':'minus'}" style="width:11px;height:11px; color:${ok?'#3C6438':'#9CA3AF'};"></i></span>
 <span style="color:${ok?'#101010':'#9CA3AF'};">${label}</span> <span style="font-size:10px; color:#9CA3AF;">${src}</span></div>`;
 const barColor = pv.lockedPct>=95 ? '#4E7C4A' : (pv.lockedPct>=70?'#C68A1A':'#B23A2E');
 host.innerHTML = `
 <div style="display:flex; gap:24px; flex-wrap:wrap; align-items:center; margin-bottom:12px;">
 <div style="flex:1; min-width:220px;">
 <div style="display:flex; justify-content:space-between; font-size:12px; margin-bottom:5px;"><span style="font-weight:700; color:#101010;">Kos dah dikunci</span><span style="font-weight:800; color:${barColor};">${pv.lockedPct}%</span></div>
 <div style="height:9px; background:#EEF1F4; border-radius:20px; overflow:hidden;"><div style="height:100%; width:${pv.lockedPct}%; background:${barColor}; border-radius:20px;"></div></div>
 <div style="font-size:11px; color:#6B7280; margin-top:6px;">${pv.lockedPct>=95?'Hampir penuh — boleh set harga jualan awal sekarang.':'Tinggal '+(pv.comp.parttimer?'':'part-timer + ')+'sahkan qty bila barang sampai.'}</div>
 </div>
 <div style="min-width:180px;">
 ${tick(pv.comp.barang,'Barang (RMB×ex)','← PI')}
 ${tick(pv.comp.sf,'SF % (ikut nilai)','← PI')}
 ${tick(pv.comp.shipping,'Shipping','← Invoice Shipment')}
 ${tick(pv.comp.parttimer,'Part-timer'+(pv.ptIsEstimate&&pv.ptEst>0?' (dianggar)':''),'← masa terima')}
 </div>
 </div>
 <div style="display:flex; gap:14px; flex-wrap:wrap; align-items:end; padding-top:10px; border-top:1px solid #F0EAE2;">
 <div><div style="font-size:11px; color:#6B7280;">Jumlah kos sementara</div><div style="font-size:18px; font-weight:800; color:#101010;">${fmt(pv.totalProvisional)}</div></div>
 <div style="display:flex; align-items:end; gap:6px;">
 <div><label class="small-lbl">Anggar part-timer/unit (RM)</label><input id="scPtEstInput" type="number" step="0.5" value="${window.__scPtPerUnitEst()}" onchange="window.__scSetPtPerUnitEst(this.value)" style="width:120px; padding:6px 8px; border:1px solid #E5E7EB; border-radius:6px; font-size:12px;"></div>
 <button onclick="scEstimatePartTimer()" style="padding:8px 12px; font-size:12px; font-weight:700; background:#F3EEE7; color:#7A4A1E; border:1px solid var(--primary-500,#CD7C32); border-radius:7px; cursor:pointer; white-space:nowrap;">Anggar part-timer</button>
 </div>
 <button onclick="scApplyProvisional()" style="padding:9px 16px; font-size:13px; font-weight:700; background:var(--primary-500,#CD7C32); color:#fff; border:none; border-radius:8px; cursor:pointer; white-space:nowrap;"><i data-lucide="flag" style="width:14px;height:14px;vertical-align:-2px;"></i> Apply Kos Sementara</button>
 </div>
 <div style="font-size:11px; color:#9CA3AF; margin-top:8px;">"Apply Kos Sementara" isi cost_price (kos kerja) + tanda order ini SEMENTARA. Lepas tu pergi tab Harga &amp; Tier set harga jualan awal. Bila carton sampai: masuk part-timer + qty sebenar, tekan "Apply ke cost_price" untuk muktamadkan.</div>`;
 if(window.lucide && lucide.createIcons) try{ lucide.createIcons(); }catch(e){}
};

window.scApplyProvisional = async function(){
 if(typeof db==='undefined'||!db) return;
 const rows = window.__scLanded().filter(r=> r.sku && r.landed>0);
 if(!rows.length){ if(typeof showToast==='function') showToast('Tiada baris dengan SKU + landed.','warn'); return; }
 if(!confirm(`Apply KOS SEMENTARA untuk ${rows.length} produk?\n\ncost_price diisi + ditanda sementara. Sahkan semula bila barang sampai.`)) return;
 const uName=(window.currentUser||{}).name||'System';
 let ok=0; const errs=[];
 for(const r of rows){ try{
 const { error } = await db.from('products_master').update({ cost_price:r.landed, last_modified_by:uName+' (kos sementara)' }).eq('sku', r.sku);
 if(error) throw error; const p=(masterProducts||[]).find(x=>x.sku===r.sku); if(p) p.cost_price=r.landed; ok++;
 }catch(e){ errs.push(r.sku+': '+e.message); } }
 if(window.__scId){ try{ await db.from('cost_shipments').update({ cost_status:'provisional', cost_status_at:new Date().toISOString(), cost_status_by:uName, stage:'ship_invoice', stage_updated_at:new Date().toISOString(), stage_updated_by:uName }).eq('id', window.__scId); }catch(e){} }
 if(ok>0 && typeof window.__calcLogLanded==='function') window.__calcLogLanded('provisional');
 if(typeof showToast==='function') showToast(`Kos sementara di-apply: ${ok}${errs.length?'. Ralat: '+errs[0]:''}. Set harga awal di tab Harga & Tier.`, errs.length?'warn':'success');
};

// p1_930 — LAMPIRAN DOKUMEN order (PI / Packing List / DO / Invoice Shipment) → bucket cost-docs, simpan dlm cost_shipments.docs jsonb.
window.__scDocTypes = [
 { key:'pi',    label:'Proforma Invoice' },
 { key:'pack',  label:'Packing List' },
 { key:'do',    label:'Delivery Order' },
 { key:'ship',  label:'Invoice Shipment' },
 { key:'other', label:'Lain-lain' }
];
window.__scDocLabel = function(k){ const t=(window.__scDocTypes||[]).find(x=>x.key===k); return t?t.label:(k||'Dokumen'); };
window.__scDocs = function(){ const o=(window.__scArchive||[]); /* not used */ return Array.isArray(window.__scDocCache)?window.__scDocCache:[]; };

window.scDocAdd = function(type){
 if(!window.__scId){ if(typeof showToast==='function') showToast('Simpan shipment dulu sebelum lampir dokumen.','warn'); return; }
 const inp=document.createElement('input'); inp.type='file'; inp.accept='application/pdf,image/*';
 inp.onchange=function(){ const f=inp.files&&inp.files[0]; if(f) window.scDocUpload(type, f); };
 inp.click();
};
window.scDocUpload = async function(type, f){
 if(typeof db==='undefined'||!db) return;
 if(!window.__scId){ if(typeof showToast==='function') showToast('Simpan shipment dulu.','warn'); return; }
 try {
 if(typeof showToast==='function') showToast('Memuat naik dokumen…','info');
 const ext=(String(f.name||'').split('.').pop()||'bin').toLowerCase();
 const fileName='shipment/'+window.__scId+'/'+type+'_'+Date.now()+'_'+Math.random().toString(36).slice(2,7)+'.'+ext;
 const up=await db.storage.from('cost-docs').upload(fileName, f, { cacheControl:'3600', upsert:false, contentType:f.type||'application/octet-stream' });
 if(up.error) throw up.error;
 const pub=db.storage.from('cost-docs').getPublicUrl(up.data.path);
 // baca docs semasa dari DB (elak tindih), tambah, simpan
 const { data: cur } = await db.from('cost_shipments').select('docs').eq('id', window.__scId).single();
 const docs = (cur && Array.isArray(cur.docs)) ? cur.docs.slice() : [];
 docs.push({ type, label:window.__scDocLabel(type), url:(pub&&pub.data&&pub.data.publicUrl)||'', path:up.data.path, name:f.name, mime:f.type||ext, uploaded_at:new Date().toISOString(), by:(window.currentUser||{}).name||'System' });
 const { error } = await db.from('cost_shipments').update({ docs }).eq('id', window.__scId);
 if(error) throw error;
 window.__scDocCache = docs;
 if(typeof showToast==='function') showToast(window.__scDocLabel(type)+' dilampir.','success');
 window.scRenderDocs();
 } catch(e){ if(typeof showToast==='function') showToast('Gagal upload: '+((e&&e.message)||e),'warn'); }
};
window.scDocRemove = async function(idx){
 if(typeof db==='undefined'||!db||!window.__scId) return;
 if(!confirm('Buang lampiran ni?')) return;
 try {
 const { data: cur } = await db.from('cost_shipments').select('docs').eq('id', window.__scId).single();
 const docs = (cur && Array.isArray(cur.docs)) ? cur.docs.slice() : [];
 const removed = docs.splice(idx,1)[0];
 const { error } = await db.from('cost_shipments').update({ docs }).eq('id', window.__scId);
 if(error) throw error;
 if(removed && removed.path){ try{ await db.storage.from('cost-docs').remove([removed.path]); }catch(_){} }
 window.__scDocCache = docs;
 if(typeof showToast==='function') showToast('Lampiran dibuang.','success');
 window.scRenderDocs();
 } catch(e){ if(typeof showToast==='function') showToast('Gagal buang: '+((e&&e.message)||e),'warn'); }
};
window.scLoadDocs = async function(){
 window.__scDocCache = [];
 if(typeof db==='undefined'||!db||!window.__scId){ window.scRenderDocs(); return; }
 try { const { data } = await db.from('cost_shipments').select('docs').eq('id', window.__scId).single(); window.__scDocCache = (data && Array.isArray(data.docs))?data.docs:[]; } catch(e){ window.__scDocCache=[]; }
 window.scRenderDocs();
};
window.scRenderDocs = function(){
 const host=document.getElementById('scDocsBody'); if(!host) return;
 if(!window.__scId){ host.innerHTML='<div style="font-size:12px; color:#9CA3AF;">Simpan shipment dulu untuk lampir dokumen (PI, Packing List, DO, Invoice Shipment).</div>'; return; }
 const docs = Array.isArray(window.__scDocCache)?window.__scDocCache:[];
 const btns = (window.__scDocTypes||[]).map(t=>{
 const n = docs.filter(d=>d.type===t.key).length;
 return `<button onclick="window.scDocAdd('${t.key}')" style="padding:7px 12px; font-size:12px; font-weight:600; background:#F3EEE7; color:#7A4A1E; border:1px solid var(--primary-500,#CD7C32); border-radius:7px; cursor:pointer;"><i data-lucide="paperclip" style="width:13px;height:13px;vertical-align:-2px;"></i> ${hesc(t.label)}${n?` <span style="background:var(--primary-500,#CD7C32); color:#fff; border-radius:10px; padding:0 6px; font-size:10px;">${n}</span>`:''}</button>`;
 }).join('');
 let list;
 if(!docs.length){ list='<div style="font-size:12px; color:#9CA3AF; padding:8px 0;">Belum ada lampiran. Tekan jenis dokumen di atas untuk upload (PDF atau gambar).</div>'; }
 else {
 list = '<div style="display:flex; flex-direction:column; gap:6px; margin-top:10px;">'+docs.map((d,i)=>{
 const isPdf=(d.mime||'').indexOf('pdf')>=0 || /\.pdf$/i.test(d.name||'');
 const dt = d.uploaded_at ? new Date(d.uploaded_at).toLocaleDateString('en-MY',{day:'2-digit',month:'short',year:'2-digit'}) : '';
 return `<div style="display:flex; align-items:center; gap:10px; padding:8px 12px; background:#fff; border:1px solid #ECECEC; border-radius:8px;">
 <i data-lucide="${isPdf?'file-text':'image'}" style="width:16px;height:16px; color:var(--primary-500,#CD7C32); flex:none;"></i>
 <span style="font-size:11px; font-weight:700; color:#7A4A1E; background:#F3EEE7; padding:2px 8px; border-radius:12px; white-space:nowrap;">${hesc(d.label||window.__scDocLabel(d.type))}</span>
 <a href="${hesc(d.url||'#')}" target="_blank" rel="noopener" style="font-size:12.5px; color:#101010; text-decoration:none; flex:1; min-width:120px; overflow:hidden; text-overflow:ellipsis; white-space:nowrap;">${hesc(d.name||'dokumen')}</a>
 <span style="font-size:10px; color:#9CA3AF; white-space:nowrap;">${hesc(dt)} · ${hesc(d.by||'')}</span>
 <a href="${hesc(d.url||'#')}" target="_blank" rel="noopener" style="font-size:11px; font-weight:600; color:#3C6438; text-decoration:none;">Buka</a>
 <button onclick="window.scDocRemove(${i})" style="background:none; border:none; color:#B23A2E; cursor:pointer; font-size:16px; line-height:1;">&times;</button>
 </div>`;
 }).join('')+'</div>';
 }
 host.innerHTML = `<div style="display:flex; gap:8px; flex-wrap:wrap;">${btns}</div>${list}`;
 if(window.lucide && lucide.createIcons) try{ lucide.createIcons(); }catch(e){}
};

// p1_932 — FX UNTUNG/RUGI: banding kadar order vs kadar sebenar bayar ke bank.
// rate_paid = kadar RMB→RM sebenar masa wire transfer; exchange_rate = kadar pakai masa kira kos.
// Untung bila ratePaid < exchange_rate (MYR menguat, bayar kurang); Rugi bila sebaliknya.
window.scRenderFx = function(){
 const host = document.getElementById('scFxBody'); if(!host) return;
 const ex = parseFloat((document.getElementById('scExchange')||{}).value) || 0;
 const ratePaid = parseFloat((document.getElementById('scRatePaid')||{}).value) || 0;
 const totalRmb = (window.__scRows||[]).reduce((sum,r)=> sum + (parseFloat(r.rmb)||0)*(parseInt(r.qty,10)||0), 0);
 if(!ex || !totalRmb){
  host.innerHTML = '<div style="font-size:12px; color:#9CA3AF;">' + (!ex ? 'Masuk kadar order (Exchange) dulu.' : 'Masuk produk + qty dulu.') + '</div>';
  return;
 }
 if(!ratePaid){
  host.innerHTML = '<div style="font-size:12px; color:#9CA3AF;">Masuk kadar sebenar dibayar ke bank untuk lihat untung/rugi FX.</div>';
  return;
 }
 const fmt = n => 'RM' + (Number(n)||0).toFixed(2);
 const fxDiff = (ex - ratePaid) * totalRmb;
 const isUntung = fxDiff >= 0;
 const diffPct = ex > 0 ? Math.abs((ratePaid - ex)/ex*100).toFixed(2) : '0.00';
 const color = isUntung ? '#3C6438' : '#B23A2E';
 const bg = isUntung ? '#E2EFE0' : '#FDECEA';
 const label = isUntung ? 'UNTUNG FX' : 'RUGI FX';
 host.innerHTML = `
 <div style="display:flex; gap:18px; flex-wrap:wrap; align-items:start;">
  <div style="flex:1; min-width:240px;">
   <table style="font-size:12px; width:100%; border-collapse:collapse;">
    <tr><td style="padding:4px 0; color:#6B7280;">Jumlah nilai goods (RMB)</td><td style="text-align:right; font-weight:700;">¥${totalRmb.toFixed(2)}</td></tr>
    <tr><td style="padding:4px 0; color:#6B7280;">Kadar kira (masa order)</td><td style="text-align:right;">RM${ex.toFixed(4)}/RMB</td></tr>
    <tr><td style="padding:4px 0; color:#6B7280;">Kadar sebenar (bayar bank)</td><td style="text-align:right;">RM${ratePaid.toFixed(4)}/RMB</td></tr>
    <tr style="border-top:1px solid #F0EAE2;"><td style="padding:6px 0 4px; color:#6B7280;">Kos dianggar (kira)</td><td style="text-align:right;">${fmt(totalRmb * ex)}</td></tr>
    <tr><td style="padding:4px 0; color:#6B7280;">Kos sebenar (bayar)</td><td style="text-align:right;">${fmt(totalRmb * ratePaid)}</td></tr>
   </table>
  </div>
  <div style="background:${bg}; border-radius:10px; padding:16px 20px; min-width:190px; text-align:center; flex:none;">
   <div style="font-size:11px; font-weight:800; color:${color}; letter-spacing:.6px;">${label}</div>
   <div style="font-size:26px; font-weight:900; color:${color}; margin:6px 0;">${isUntung ? '+' : ''}${fmt(fxDiff)}</div>
   <div style="font-size:11.5px; color:${color}; font-weight:600;">${diffPct}% ${isUntung ? 'lebih jimat' : 'lebih bayar'}</div>
   <div style="font-size:11px; color:#6B7280; margin-top:5px;">${isUntung ? 'MYR menguat — bayar kurang dari anggar' : 'MYR melemah — bayar lebih dari anggar'}</div>
  </div>
 </div>`;
};

window.scSaveFx = async function(){
 if(!window.__scId){ if(typeof showToast==='function') showToast('Simpan shipment dulu sebelum simpan kadar FX.','warn'); return; }
 if(typeof db==='undefined'||!db) return;
 const ratePaid = parseFloat((document.getElementById('scRatePaid')||{}).value) || null;
 try {
  const { error } = await db.from('cost_shipments').update({ rate_paid: ratePaid }).eq('id', window.__scId);
  if(error) throw error;
  if(typeof showToast==='function') showToast('Kadar sebenar disimpan.','success');
 } catch(e){ if(typeof showToast==='function') showToast('Simpan gagal: '+e.message,'error'); }
};

// p1_931 — BANDING HARGA SUPPLIER: kumpul kos RMB tiap SKU merentas semua shipment lalu,
// kumpul ikut supplier (ambil harga terkini per supplier), tunjuk mana paling murah.
window.__scSupplierIdx = null;
window.scLoadSupplierPrices = async function(){
 if(typeof db==='undefined'||!db) return null;
 try {
 const { data: ships } = await db.from('cost_shipments').select('id,supplier,order_date,label,updated_at').limit(2000);
 const items = await window.__fetchAllRows('cost_shipment_items', 'id', true, { select: 'shipment_id,sku,product_name,cost_rmb,id' }); // p1_1092 — paged: dah 1,042 baris, limit besar dipotong server pada 1000
 const shipMap={}; (ships||[]).forEach(s=>{ shipMap[s.id]=s; });
 const idx={};
 (items||[]).forEach(it=>{
 const sku=(it.sku||'').trim().toUpperCase(); const rmb=parseFloat(it.cost_rmb)||0;
 if(!sku || rmb<=0) return;
 const s=shipMap[it.shipment_id]||{};
 const supplier=(s.supplier||'').trim()||'(tak dinyatakan)';
 const date=s.order_date||s.updated_at||null;
 (idx[sku]=idx[sku]||{ name:'', entries:[] });
 if(!idx[sku].name && it.product_name) idx[sku].name=it.product_name;
 idx[sku].entries.push({ supplier, rmb, date, label:s.label||('Shipment #'+it.shipment_id) });
 });
 window.__scSupplierIdx=idx;
 return idx;
 } catch(e){ if(typeof showToast==='function') showToast('Gagal muat harga supplier: '+(e.message||e),'warn'); return null; }
};
// dedupe ikut supplier (ambil entry tarikh terkini), susun termurah dulu
window.__scSupplierRows = function(sku){
 const idx=window.__scSupplierIdx||{}; const rec=idx[(sku||'').trim().toUpperCase()]; if(!rec) return null;
 const bySup={};
 rec.entries.forEach(e=>{ const k=(e.supplier||'').trim().toLowerCase(); const cur=bySup[k];   // gabung nama sama (abai huruf besar/kecil)
 const t=e.date?new Date(e.date).getTime():0; const ct=cur&&cur.date?new Date(cur.date).getTime():-1;
 if(!cur || t>=ct) bySup[k]=e; });   // ambil harga terkini per supplier
 const rows=Object.values(bySup).sort((a,b)=> a.rmb-b.rmb);
 return { name:rec.name, rows };
};
window.scCompareCurrentOrder = async function(){
 const skus=[...new Set((window.__scRows||[]).map(r=>(r.sku||'').trim().toUpperCase()).filter(Boolean))];
 if(!skus.length){ if(typeof showToast==='function') showToast('Tiada SKU dalam order ni.','warn'); return; }
 await window.scLoadSupplierPrices(); window.__scCompareRender(skus,'produk dalam order ni');
};
window.scCompareSearch = async function(){
 const q=((document.getElementById('scCompareSearch')||{}).value||'').trim().toLowerCase();
 if(!q){ const b=document.getElementById('scCompareBody'); if(b) b.innerHTML='<div style="font-size:12px; color:#9CA3AF;">Taip SKU atau nama produk untuk banding.</div>'; return; }
 if(!window.__scSupplierIdx) await window.scLoadSupplierPrices();
 const idx=window.__scSupplierIdx||{};
 const skus=Object.keys(idx).filter(sku=> sku.toLowerCase().includes(q) || (idx[sku].name||'').toLowerCase().includes(q)).slice(0,40);
 window.__scCompareRender(skus, q);
};
window.__scCompareRender = function(skus, label){
 const host=document.getElementById('scCompareBody'); if(!host) return;
 const fmt=(n)=>'¥'+(Number(n)||0).toFixed(2);
 const multi=[], single=[];
 skus.forEach(sku=>{ const r=window.__scSupplierRows(sku); if(!r) return; (r.rows.length>1?multi:single).push({sku,...r}); });
 if(!multi.length && !single.length){ host.innerHTML='<div style="font-size:12px; color:#9CA3AF;">Tiada rekod harga untuk produk ni dalam shipment lalu.</div>'; return; }
 let html='';
 if(multi.length){
 html += '<div style="font-size:12px; font-weight:700; color:#101010; margin:4px 0 8px;">Ada lebih satu supplier ('+multi.length+') — banding:</div>';
 html += multi.map(m=>{
 const cheapest=m.rows[0].rmb, dearest=m.rows[m.rows.length-1].rmb;
 const saveAbs=dearest-cheapest; const savePct=dearest>0?Math.round(saveAbs/dearest*100):0;
 const dt=(d)=> d?new Date(d).toLocaleDateString('en-MY',{day:'2-digit',month:'short',year:'2-digit'}):'—';
 return `<div style="border:1px solid #ECECEC; border-radius:10px; padding:12px 14px; margin-bottom:10px; background:#fff;">
 <div style="font-size:13px; font-weight:700; color:#101010;">${hesc(m.sku)}${m.name?' · <span style="font-weight:500; color:#6B7280;">'+hesc((m.name||'').slice(0,50))+'</span>':''}</div>
 <div style="margin-top:8px; display:flex; flex-direction:column; gap:4px;">
 ${m.rows.map((e,i)=>`<div style="display:flex; align-items:center; gap:10px; font-size:12.5px;">
 <span style="flex:1; min-width:120px; color:#101010;">${hesc(e.supplier)}</span>
 <span style="font-weight:700; color:${i===0?'#3C6438':'#101010'};">${fmt(e.rmb)}</span>
 <span style="font-size:10px; color:#9CA3AF; white-space:nowrap;">${dt(e.date)}</span>
 ${i===0?'<span style="font-size:10px; font-weight:800; background:#E2EFE0; color:#3C6438; padding:2px 8px; border-radius:12px;">PALING MURAH</span>':'<span style="font-size:10px; color:#B23A2E;">+'+fmt(e.rmb-cheapest)+'</span>'}
 </div>`).join('')}
 </div>
 ${saveAbs>0?`<div style="font-size:11px; color:#3C6438; margin-top:8px;">Jimat sehingga <strong>${fmt(saveAbs)}/unit (${savePct}%)</strong> kalau pilih ${hesc(m.rows[0].supplier)}.</div>`:''}
 </div>`;
 }).join('');
 }
 if(single.length){
 html += '<div style="font-size:11.5px; color:#9CA3AF; margin:10px 0 6px;">1 supplier sahaja (tiada banding): '+single.map(s=>`${hesc(s.sku)} <span style="color:#7A4A1E;">${hesc(s.rows[0].supplier)}</span> ${fmt(s.rows[0].rmb)}`).join(' · ')+'</div>';
 }
 host.innerHTML=html;
 if(window.lucide && lucide.createIcons) try{ lucide.createIcons(); }catch(e){}
};

// p1_926 — TERIMA CARTON + reconcile + lampu hijau jual.
// Rekod qty SEBENAR sampai, banding vs qty order; per-SKU gate: kos + qty + harga lengkap → boleh publish.
window.scSetReceived = function(i, val){ if(window.__scRows && window.__scRows[i]){ window.__scRows[i].received = (val===''?'':(parseInt(val,10)||0)); if(typeof window.scRenderReceiving==='function') window.scRenderReceiving(); } };

window.__scReadiness = function(row){
 const sku = (row.sku||'').trim();
 const p = sku ? (masterProducts||[]).find(x=> (x.sku||'').toUpperCase()===sku.toUpperCase()) : null;
 const cost = p ? (Number(p.cost_price)||0) : 0;
 const price = p ? (Number(p.price)||0) : 0;
 const published = p ? !!(p.is_published) : false;
 const recv = (row.received===''||row.received==null) ? null : (parseInt(row.received,10)||0);
 const okCost = cost>0, okPrice = price>0, qtyOk = recv!=null;
 return { p, sku, cost, price, published, recv, qtyOk, okCost, okPrice, ready:(okCost&&okPrice&&qtyOk) };
};

window.scRenderReceiving = function(){
 const host = document.getElementById('scReceivingBody'); if(!host) return;
 const rows = (window.__scRows||[]).filter(r=> (r.sku||'').trim());
 if(!rows.length){ host.innerHTML='<div style="font-size:12px; color:#9CA3AF;">Masuk produk dengan SKU dulu.</div>'; return; }
 const dot=(ok)=> `<span title="${ok?'OK':'Belum'}" style="width:10px;height:10px;border-radius:50%;display:inline-block;background:${ok?'#4E7C4A':'#E5E7EB'};vertical-align:middle;"></span>`;
 let readyCount=0;
 const body = rows.map((r)=>{
 const i = window.__scRows.indexOf(r);
 const rd = window.__scReadiness(r); if(rd.ready) readyCount++;
 const ordered = parseInt(r.qty,10)||0;
 const v = rd.recv==null ? null : (rd.recv - ordered);
 let vBadge='<span style="color:#9CA3AF; font-size:11px;">—</span>';
 if(v!=null){ if(v===0) vBadge='<span style="font-size:10px; font-weight:700; background:#E2EFE0; color:#3C6438; padding:2px 7px; border-radius:12px;">PADAN</span>';
 else if(v<0) vBadge='<span style="font-size:10px; font-weight:700; background:#FBEFD6; color:#9A6B12; padding:2px 7px; border-radius:12px;">KURANG '+Math.abs(v)+'</span>';
 else vBadge='<span style="font-size:10px; font-weight:700; background:#EEF1F4; color:#5B6573; padding:2px 7px; border-radius:12px;">LEBIH '+v+'</span>'; }
 let action;
 if(rd.published) action='<span style="font-size:10px; font-weight:800; background:#E2EFE0; color:#3C6438; padding:3px 9px; border-radius:20px;">LIVE</span>';
 else if(rd.ready) action=`<button onclick="window.scPublishSku('${hesc(rd.sku)}')" style="padding:4px 12px; font-size:11px; font-weight:700; background:#4E7C4A; color:#fff; border:none; border-radius:7px; cursor:pointer;">Publish</button>`;
 else action='<span style="font-size:10.5px; color:#9A6B12;">'+( !rd.okCost?'kos':(!rd.qtyOk?'qty':'harga') )+' belum</span>';
 return `<tr>
 <td style="font-family:monospace; font-size:11px;">${hesc(r.sku||'-')}</td>
 <td style="text-align:right;">${ordered}</td>
 <td style="text-align:center;"><input type="number" min="0" value="${rd.recv!=null?rd.recv:''}" onchange="window.scSetReceived(${i}, this.value)" style="width:64px; padding:4px 6px; border:1px solid #E5E7EB; border-radius:5px; font-size:12px; text-align:right;"></td>
 <td style="text-align:center;">${vBadge}</td>
 <td style="text-align:center; white-space:nowrap;">${dot(rd.okCost)} <span style="font-size:10px; color:#9CA3AF;">kos</span> &nbsp; ${dot(rd.qtyOk)} <span style="font-size:10px; color:#9CA3AF;">qty</span> &nbsp; ${dot(rd.okPrice)} <span style="font-size:10px; color:#9CA3AF;">harga</span></td>
 <td style="text-align:center;">${action}</td>
 </tr>`;
 }).join('');
 host.innerHTML = `<div style="font-size:12px; color:#374151; margin-bottom:8px;"><strong style="color:${readyCount===rows.length?'#3C6438':'#101010'};">${readyCount}/${rows.length}</strong> SKU dah boleh jual (kos + qty terima + harga lengkap).</div>
 <div class="table-responsive"><table class="data-table" style="font-size:12px;">
 <thead style="background:#FAFAFA;"><tr><th>SKU</th><th style="text-align:right;">Qty Order</th><th style="text-align:center;">Qty Terima</th><th style="text-align:center;">Beza</th><th style="text-align:center;">Lampu Hijau Jual</th><th style="text-align:center;">Tindakan</th></tr></thead>
 <tbody>${body}</tbody></table></div>
 <div style="display:flex; gap:10px; margin-top:12px; flex-wrap:wrap;">
 <button onclick="window.scSaveShipment()" style="padding:8px 14px; font-size:12px; font-weight:700; background:#F3EEE7; color:#7A4A1E; border:1px solid var(--primary-500,#CD7C32); border-radius:7px; cursor:pointer;"><i data-lucide="save" style="width:13px;height:13px;vertical-align:-2px;"></i> Simpan Qty Terima</button>
 <button onclick="window.scApplyBatchReceived()" style="padding:8px 14px; font-size:12px; font-weight:700; background:#101010; color:#fff; border:none; border-radius:7px; cursor:pointer;"><i data-lucide="package-plus" style="width:13px;height:13px;vertical-align:-2px;"></i> Stock-in ikut Qty Terima</button>
 <button onclick="window.scPublishAllReady()" style="padding:8px 14px; font-size:12px; font-weight:700; background:#4E7C4A; color:#fff; border:none; border-radius:7px; cursor:pointer;"><i data-lucide="check-circle-2" style="width:13px;height:13px;vertical-align:-2px;"></i> Publish semua yang hijau</button>
 </div>
 <p style="font-size:11px; color:#9CA3AF; margin:8px 0 0;">Masuk qty sebenar yang sampai → sistem banding dengan qty order (PADAN / KURANG / LEBIH). Bila kos + qty + harga lengkap, SKU jadi hijau dan boleh Publish (is_published). "Stock-in ikut Qty Terima" tambah stok guna qty sebenar, bukan qty order.</p>`;
 if(window.lucide && lucide.createIcons) try{ lucide.createIcons(); }catch(e){}
};

window.scPublishSku = async function(sku){
 if(typeof db==='undefined'||!db) return;
 try {
 const { error } = await db.from('products_master').update({ is_published:true }).eq('sku', sku);
 if(error) throw error;
 const p=(masterProducts||[]).find(x=> (x.sku||'').toUpperCase()===String(sku).toUpperCase()); if(p) p.is_published=true;
 if(typeof showToast==='function') showToast(sku+' dah LIVE — boleh jual.','success');
 window.scRenderReceiving();
 } catch(e){ if(typeof showToast==='function') showToast('Publish gagal: '+e.message,'error'); }
};

window.scPublishAllReady = async function(){
 if(typeof db==='undefined'||!db) return;
 const rows=(window.__scRows||[]).filter(r=> (r.sku||'').trim());
 const ready = rows.map(r=> window.__scReadiness(r)).filter(rd=> rd.ready && !rd.published);
 if(!ready.length){ if(typeof showToast==='function') showToast('Tiada SKU baru yang lengkap kos+qty+harga.','warn'); return; }
 if(!confirm(`Publish ${ready.length} SKU yang dah lengkap (boleh jual)?`)) return;
 const uN=(window.currentUser||{}).name||'System';
 let ok=0; const errs=[];
 for(const rd of ready){ try{ const { error } = await db.from('products_master').update({ is_published:true }).eq('sku', rd.sku); if(error) throw error; if(rd.p) rd.p.is_published=true; ok++; }catch(e){ errs.push(rd.sku+': '+e.message); } }
 // Kalau SEMUA SKU dalam order ni dah ready+published → order jadi "Boleh Jual"
 const allReady = rows.every(r=>{ const rd=window.__scReadiness(r); return rd.ready && rd.published; });
 if(allReady && window.__scId){ try{ await db.from('cost_shipments').update({ stage:'on_sale', cost_status:'final', stage_updated_at:new Date().toISOString(), stage_updated_by:uN }).eq('id', window.__scId); }catch(e){} }
 if(typeof showToast==='function') showToast(`${ok} SKU dah LIVE${allReady?' · order ditanda Boleh Jual':''}${errs.length?'. Ralat: '+errs[0]:''}.`, errs.length?'warn':'success');
 window.scRenderReceiving();
};

window.scApplyBatchReceived = async function(){
 if(typeof db==='undefined'||!db) return;
 const landed = window.__scLanded();
 const rows = (window.__scRows||[]).map((r,idx)=>{
 const rd = window.__scReadiness(r); const l = landed[idx]||{};
 const recv = rd.recv!=null ? rd.recv : (parseInt(r.qty,10)||0);
 return { sku:(r.sku||'').trim(), qty:recv, landed:l.landed||0 };
 }).filter(x=> x.sku && x.qty>0 && x.landed>0);
 if(!rows.length){ if(typeof showToast==='function') showToast('Tiada SKU dengan qty terima + landed.','warn'); return; }
 if(!confirm(`Stock-in ${rows.length} produk ikut QTY TERIMA (bukan qty order)? Ini TAMBAH stok.`)) return;
 const uName=(window.currentUser||{}).name||'System'; const label=(document.getElementById('scLabel').value||'').trim();
 let ok=0; const errs=[];
 for(const r of rows){ try{ const { error } = await db.from('inventory_batches').insert([{ sku:r.sku, qty_received:r.qty, qty_remaining:r.qty, cost_price:r.landed, inbound_date:new Date().toISOString(), notes:'Terima carton'+(label?' ('+label+')':'')+' by '+uName }]); if(error) throw error; ok++; }catch(e){ errs.push(r.sku+': '+e.message); } }
 try { inventoryBatches = await window.__loadAllBatches(); } catch(e){} // p1_1092 — paged (cap 1000)
 if(ok>0 && window.__scId){ const uN=uName; try{ await db.from('cost_shipments').update({ stage:'arrived', stage_updated_at:new Date().toISOString(), stage_updated_by:uN }).eq('id', window.__scId); }catch(e){} }
 if(ok>0 && typeof window.__calcLogLanded==='function') window.__calcLogLanded('apply_batch');
 if(typeof showToast==='function') showToast(`Stock-in ikut terima: ${ok}${errs.length?'. Ralat: '+errs[0]:''}.`, errs.length?'warn':'success');
};

window.__scLanded = function(){
 const P = window.__scParams();
 return P.rows.map(r=>{
 const rmb = parseFloat(r.rmb)||0; const qty = parseInt(r.qty,10)||0;
 const goods = rmb*P.ex; const sf = rmb*(P.sfPct/100)*P.ex; const ship = P.shipPU(rmb);
 return { sku:(r.sku||'').trim(), qty, landed: +(goods+sf+ship+P.ptPerUnit).toFixed(2) };
 });
};

window.scNewShipment = function(){
 window.__scId = null;
 ['scLabel','scShipping','scParttimer','scSupplier','scOrderDate','scExchange','scRatePaid'].forEach(id=>{ const el=document.getElementById(id); if(el) el.value=''; });
 const sf=document.getElementById('scSfPct'); if(sf) sf.value='5';
 const picker=document.getElementById('scShipmentPicker'); if(picker) picker.value='';
 window.__scRows = [{ sku:'', name:'', rmb:'', qty:'' }];
 window.__scDocCache = [];
 scRenderItems(); scCompute();
 if(typeof window.scRenderDocs==='function') window.scRenderDocs();
};

window.scLoadList = async function(){
 const picker = document.getElementById('scShipmentPicker'); if(!picker || typeof db==='undefined' || !db) return;
 try {
 const { data } = await db.from('cost_shipments').select('id,label,updated_at').order('updated_at',{ascending:false}).limit(200);
 const cur = window.__scId;
 picker.innerHTML = '<option value="">— Pilih shipment —</option>' + (data||[]).map(s=>`<option value="${s.id}"${String(cur)===String(s.id)?' selected':''}>${hesc(s.label||('Shipment #'+s.id))}</option>`).join('');
 } catch(e){}
};

window.scLoadSelected = async function(){
 const picker = document.getElementById('scShipmentPicker'); if(!picker) return;
 const id = picker.value; if(!id) return;
 if(typeof db==='undefined'||!db) return;
 try {
 const { data: s } = await db.from('cost_shipments').select('*').eq('id', id).single();
 const { data: items } = await db.from('cost_shipment_items').select('*').eq('shipment_id', id).order('sort_idx',{ascending:true});
 if(!s) return;
 window.__scId = s.id;
 document.getElementById('scLabel').value = s.label||'';
 const supEl=document.getElementById('scSupplier'); if(supEl) supEl.value = s.supplier||'';
 const odEl=document.getElementById('scOrderDate'); if(odEl) odEl.value = s.order_date||'';
 document.getElementById('scExchange').value = s.exchange_rate!=null?s.exchange_rate:'';
 document.getElementById('scSfPct').value = s.sf_pct!=null?s.sf_pct:5;
 document.getElementById('scShipping').value = s.shipping_cost_rm!=null?s.shipping_cost_rm:'';
 document.getElementById('scParttimer').value = s.parttimer_cost_rm!=null?s.parttimer_cost_rm:'';
 const rpEl=document.getElementById('scRatePaid'); if(rpEl) rpEl.value = s.rate_paid!=null?s.rate_paid:'';
 window.__scRows = (items||[]).map(it=>({ sku:it.sku||'', name:it.product_name||'', rmb:it.cost_rmb!=null?it.cost_rmb:'', qty:it.qty!=null?it.qty:'', received:it.qty_received!=null?it.qty_received:'' }));
 if(!window.__scRows.length) window.__scRows = [{sku:'',name:'',rmb:'',qty:''}];
 window.__scDocCache = (s && Array.isArray(s.docs)) ? s.docs : [];
 scRenderItems(); scCompute();
 if(typeof window.scRenderDocs==='function') window.scRenderDocs();
 } catch(e){ if(typeof showToast==='function') showToast('Load gagal: '+e.message,'error'); }
};

window.scSaveShipment = async function(){
 if(typeof db==='undefined'||!db){ if(typeof showToast==='function') showToast('DB tak available','error'); return; }
 const u = window.currentUser||{};
 const payload = {
 label: (document.getElementById('scLabel').value||'').trim() || null,
 supplier: ((document.getElementById('scSupplier')||{}).value||'').trim() || null,
 order_date: ((document.getElementById('scOrderDate')||{}).value||'').trim() || null,
 exchange_rate: parseFloat(document.getElementById('scExchange').value)||0,
 sf_pct: parseFloat(document.getElementById('scSfPct').value)||0,
 shipping_cost_rm: parseFloat(document.getElementById('scShipping').value)||0,
 parttimer_cost_rm: parseFloat(document.getElementById('scParttimer').value)||0,
 rate_paid: parseFloat((document.getElementById('scRatePaid')||{}).value)||null,
 updated_at: new Date().toISOString()
 };
 try {
 let id = window.__scId;
 if(id){ const { error } = await db.from('cost_shipments').update(payload).eq('id', id); if(error) throw error; }
 else { payload.created_by = u.name||'System'; const { data, error } = await db.from('cost_shipments').insert([payload]).select('id').single(); if(error) throw error; id = data.id; window.__scId = id; }
 await db.from('cost_shipment_items').delete().eq('shipment_id', id);
 const rows = (window.__scRows||[]).filter(r=> (r.sku||'').trim() || (r.name||'').trim() || r.rmb || r.qty);
 if(rows.length){
 const ins = rows.map((r,idx)=>({ shipment_id:id, sku:(r.sku||'').trim()||null, product_name:(r.name||'').trim()||null, cost_rmb:parseFloat(r.rmb)||0, qty:parseInt(r.qty,10)||0, qty_received:(r.received===''||r.received==null)?null:(parseInt(r.received,10)||0), sort_idx:idx }));
 const { error } = await db.from('cost_shipment_items').insert(ins); if(error) throw error;
 }
 if(typeof showToast==='function') showToast('Shipment disimpan.','success');
 await scLoadList();
 if(typeof window.scRenderDocs==='function') window.scRenderDocs();   // buka kad lampiran lepas ada __scId
 } catch(e){ if(typeof showToast==='function') showToast('Simpan gagal: '+e.message,'error'); }
};

window.scDeleteShipment = async function(){
 if(!window.__scId){ if(typeof showToast==='function') showToast('Takde shipment dipilih.','warn'); return; }
 if(!confirm('Padam shipment ni? (kos yang dah di-apply ke produk TAK terjejas)')) return;
 try { await db.from('cost_shipments').delete().eq('id', window.__scId); if(typeof showToast==='function') showToast('Shipment dipadam.','success'); scNewShipment(); await scLoadList(); }
 catch(e){ if(typeof showToast==='function') showToast('Padam gagal: '+e.message,'error'); }
};

window.scApplyCostPrice = async function(){
 if(typeof db==='undefined'||!db) return;
 const rows = window.__scLanded().filter(r=> r.sku && r.landed>0);
 if(!rows.length){ if(typeof showToast==='function') showToast('Tiada baris dengan SKU + landed cost.','warn'); return; }
 if(!confirm(`Set cost_price untuk ${rows.length} produk ikut landed cost? (akan terekod dalam Price History)`)) return;
 const uName = (window.currentUser||{}).name||'System';
 let ok=0; const errs=[];
 for(const r of rows){
 try {
 const { error } = await db.from('products_master').update({ cost_price: r.landed, last_modified_by: uName }).eq('sku', r.sku);
 if(error) throw error;
 const p = (masterProducts||[]).find(x=>x.sku===r.sku); if(p) p.cost_price = r.landed;
 ok++;
 } catch(e){ errs.push(r.sku+': '+e.message); }
 }
 if(ok>0 && typeof window.__calcLogLanded==='function') window.__calcLogLanded('apply_cost');
 // p1_926 — apply muktamad: tanda kos FINAL + maju peringkat ke "Kos Siap"
 if(ok>0 && window.__scId){ const uN=(window.currentUser||{}).name||'System'; try{ await db.from('cost_shipments').update({ cost_status:'final', cost_status_at:new Date().toISOString(), cost_status_by:uN, stage:'costed', stage_updated_at:new Date().toISOString(), stage_updated_by:uN }).eq('id', window.__scId); }catch(e){} }
 if(typeof showToast==='function') showToast(`cost_price dikemaskini: ${ok}${errs.length?'. Ralat: '+errs[0]:''}.`, errs.length?'warn':'success');
};

window.scApplyBatch = async function(){
 if(typeof db==='undefined'||!db) return;
 const rows = window.__scLanded().filter(r=> r.sku && r.qty>0);
 if(!rows.length){ if(typeof showToast==='function') showToast('Tiada baris dengan SKU + qty.','warn'); return; }
 if(!confirm(`Stock-in ${rows.length} produk jadi batch baru (FIFO) ikut landed cost? Ini akan TAMBAH stok.`)) return;
 const uName = (window.currentUser||{}).name||'System';
 const label = (document.getElementById('scLabel').value||'').trim();
 let ok=0; const errs=[];
 for(const r of rows){
 try {
 const { error } = await db.from('inventory_batches').insert([{ sku:r.sku, qty_received:r.qty, qty_remaining:r.qty, cost_price:r.landed, inbound_date:new Date().toISOString(), notes:'Cost Calc shipment'+(label?' ('+label+')':'')+' by '+uName }]);
 if(error) throw error;
 ok++;
 } catch(e){ errs.push(r.sku+': '+e.message); }
 }
 try { inventoryBatches = await window.__loadAllBatches(); } catch(e){} // p1_1092 — paged (cap 1000)
 if(ok>0 && typeof window.__calcLogLanded==='function') window.__calcLogLanded('apply_batch');
 if(typeof showToast==='function') showToast(`Stock-in batch: ${ok}${errs.length?'. Ralat: '+errs[0]:''}.`, errs.length?'warn':'success');
};

// p1_392 — tab switch (Kira vs Arkib) + past order/shipment archive
window.scSetTab = function(tab, btn){
 const calc = document.getElementById('scPaneCalc');
 const arch = document.getElementById('scPaneArchive');
 const bc = document.getElementById('scTabCalcBtn');
 const ba = document.getElementById('scTabArchiveBtn');
 if(calc) calc.style.display = (tab==='calc') ? '' : 'none';
 if(arch) arch.style.display = (tab==='archive') ? '' : 'none';
 [bc,ba].forEach(b=>{ if(b) b.classList.remove('ps-tab--active'); });
 const active = btn || (tab==='archive'?ba:bc); if(active) active.classList.add('ps-tab--active');
 if(tab==='archive') scLoadArchive();
};

window.__scArchive = [];
window.scLoadArchive = async function(){
 const tb = document.getElementById('scArchiveBody'); if(!tb) return;
 if(typeof db==='undefined'||!db){ tb.innerHTML='<tr><td colspan="8" style="text-align:center; padding:20px; color:#B23A2E;">DB tak available.</td></tr>'; return; }
 tb.innerHTML='<tr><td colspan="8" style="text-align:center; padding:20px; color:#9CA3AF;">Memuatkan…</td></tr>';
 try {
 const { data: ships } = await db.from('cost_shipments').select('*').order('order_date',{ascending:false, nullsFirst:false}).order('updated_at',{ascending:false}).limit(500);
 const items = await window.__fetchAllRows('cost_shipment_items', 'id', true, { select: 'shipment_id,sku,cost_rmb,qty,sort_idx,id' }); // p1_1092 — paged (1,042 baris); susun sort_idx dlm JS (page ikut id unik, elak skip/dup)
 items.sort((a,b)=>(a.sort_idx==null?1e9:a.sort_idx)-(b.sort_idx==null?1e9:b.sort_idx));
 const byShip = {};
 (items||[]).forEach(it=>{ (byShip[it.shipment_id] = byShip[it.shipment_id] || []).push(it); });
 window.__scArchive = (ships||[]).map(s=>{
 const its = byShip[s.id] || [];
 const ex = Number(s.exchange_rate)||0, sfp = Number(s.sf_pct)||0;
 const ship = Number(s.shipping_cost_rm)||0, pt = Number(s.parttimer_cost_rm)||0;
 const goodsRmb = its.reduce((sum,it)=> sum + (Number(it.cost_rmb)||0)*(parseInt(it.qty,10)||0), 0);
 const goods = goodsRmb * ex;
 const sf = goods * sfp/100;
 const landed = goods + sf + ship + pt;
 return { id:s.id, label:s.label, supplier:s.supplier, order_date:s.order_date, updated_at:s.updated_at, created_by:s.created_by,
 items:its.length, goods, landed, ex, sf_pct:sfp, shipping:ship, parttimer:pt,
 rows: its.map(it=>({ sku:it.sku||'', rmb:Number(it.cost_rmb)||0, qty:parseInt(it.qty,10)||0 })) };
 });
 scRenderArchive();
 } catch(e){ tb.innerHTML='<tr><td colspan="8" style="text-align:center; padding:20px; color:#B23A2E;">Error: '+(e.message||e)+'</td></tr>'; }
};

window.scRenderArchive = function(){
 const tb = document.getElementById('scArchiveBody'); if(!tb) return;
 const q = ((document.getElementById('scArchiveSearch')||{}).value||'').trim().toLowerCase();
 let rows = window.__scArchive || [];
 if(q) rows = rows.filter(r=> (`${r.supplier||''} ${r.label||''}`).toLowerCase().includes(q));
 const fmt = (n)=> 'RM' + (Number(n)||0).toFixed(2);
 if(!rows.length){ tb.innerHTML='<tr><td colspan="11" style="text-align:center; padding:24px; color:#9CA3AF;">Tiada rekod.</td></tr>'; const sum=document.getElementById('scArchiveSummary'); if(sum) sum.textContent=''; return; }
 const unitsOf = (r)=> (r.rows||[]).reduce((s,it)=> s + (it.qty||0), 0);
 const fmtEx = (n)=> { const v = Number(n); if(!v) return '—'; return (Math.round(v*10000)/10000).toString(); };
 const shortBy = (s)=> { s = String(s||'—'); const i = s.indexOf('('); return i>0 ? s.slice(0,i).trim() : s; };
 tb.innerHTML = rows.map((r,i)=>{
 const dt = r.order_date ? r.order_date : (r.updated_at ? new Date(r.updated_at).toLocaleDateString('en-MY') : '—');
 const stripe = (i % 2 === 0) ? '#FFFFFF' : '#FBF7F1';
 return `<tr class="sc-row" onclick="scToggleArchiveDetail(${r.id})" style="cursor:pointer; background:${stripe};" title="Klik untuk buka detail item">
 <td style="white-space:nowrap;"><span id="scCaret_${r.id}" style="color:var(--primary-500,#CD7C32); font-size:10px;">&#9656;</span> ${hesc(dt)}</td>
 <td>${hesc(r.supplier||'—')}</td>
 <td>${hesc(r.label||('Shipment #'+r.id))}</td>
 <td style="text-align:right;">${r.items}</td>
 <td style="text-align:right;">${unitsOf(r)}</td>
 <td style="text-align:right; color:#6B7280;">${fmtEx(r.ex)}</td>
 <td style="text-align:right;">${fmt(r.goods)}</td>
 <td style="text-align:right;">${fmt(r.shipping)}</td>
 <td style="text-align:right;">${fmt(r.parttimer)}</td>
 <td style="text-align:right; font-weight:700; color:#101010;">${fmt(r.landed)}</td>
 <td style="font-size:11px; color:#6B7280; white-space:nowrap;" title="${hesc(r.created_by||'')}">${hesc(shortBy(r.created_by))}</td>
 <td style="text-align:center; white-space:nowrap;">
 <button onclick="event.stopPropagation(); scOpenArchived(${r.id})" style="padding:4px 10px; font-size:11px; font-weight:600; background:#FFF1E2; color:var(--primary-700,#A05F22); border:1px solid var(--primary-500,#CD7C32); border-radius:6px; cursor:pointer;">Buka</button>
 <button onclick="event.stopPropagation(); scDeleteArchived(${r.id})" style="padding:4px 8px; font-size:11px; font-weight:600; background:#fff; color:#B23A2E; border:1px solid #ECD2CA; border-radius:6px; cursor:pointer; margin-left:4px;">Padam</button>
 </td>
 </tr>
 <tr id="scDetail_${r.id}" style="display:none;"><td colspan="11" style="padding:0; background:#FCFAF7;"><div id="scDetailBody_${r.id}" style="padding:12px 16px;"></div></td></tr>`;
 }).join('');
 // p1_395 — baris Jumlah (totals) supaya table elok tersusun
 const tot = rows.reduce((a,r)=>({ items:a.items+(r.items||0), units:a.units+unitsOf(r), goods:a.goods+(r.goods||0), shipping:a.shipping+(r.shipping||0), parttimer:a.parttimer+(r.parttimer||0), landed:a.landed+(r.landed||0) }), {items:0,units:0,goods:0,shipping:0,parttimer:0,landed:0});
 tb.innerHTML += `<tr style="background:#F3EEE7; font-weight:700; border-top:2px solid var(--primary-500,#CD7C32);">
 <td colspan="3" style="text-align:right;">JUMLAH (${rows.length} rekod)</td>
 <td style="text-align:right;">${tot.items}</td>
 <td style="text-align:right;">${tot.units}</td>
 <td></td>
 <td style="text-align:right;">${fmt(tot.goods)}</td>
 <td style="text-align:right;">${fmt(tot.shipping)}</td>
 <td style="text-align:right;">${fmt(tot.parttimer)}</td>
 <td style="text-align:right; color:#101010;">${fmt(tot.landed)}</td>
 <td colspan="2"></td>
 </tr>`;
 const sum=document.getElementById('scArchiveSummary'); if(sum) sum.textContent = `${rows.length} rekod · jumlah landed semua: ${fmt(tot.landed)}`;
};

// p1_394 — grid detail item untuk satu shipment (expand dalam Arkib)
window.scArchiveDetailGrid = function(a){
 const fmt = (n)=> 'RM' + (Number(n)||0).toFixed(2);
 const totalQty = a.rows.reduce((s,r)=> s + (r.qty||0), 0);
 const totalValue = a.rows.reduce((s,r)=> s + (r.rmb||0)*a.ex*(r.qty||0), 0);
 const ptPU = totalQty>0 ? a.parttimer/totalQty : 0;
 if(!a.rows.length) return '<div style="color:#9CA3AF; font-size:12px;">Tiada item dalam shipment ni.</div>';
 const body = a.rows.map(r=>{
 const goods = (r.rmb||0)*a.ex;
 const sf = (r.rmb||0)*(a.sf_pct/100)*a.ex;
 const ship = totalValue>0 ? (goods/totalValue)*a.shipping : 0;
 const landed = goods + sf + ship + ptPU;
 return `<tr>
 <td style="font-family:monospace; font-size:11px;">${hesc(r.sku||'-')}</td>
 <td style="text-align:right;">${(r.rmb||0).toFixed(2)}</td>
 <td style="text-align:right;">${r.qty||0}</td>
 <td style="text-align:right;">${fmt(goods)}</td>
 <td style="text-align:right;">${fmt(sf)}</td>
 <td style="text-align:right;">${fmt(ship)}</td>
 <td style="text-align:right;">${fmt(ptPU)}</td>
 <td style="text-align:right; font-weight:800; color:#101010;">${fmt(landed)}</td>
 </tr>`;
 }).join('');
 return `<div style="font-size:11px; color:#6B7280; margin-bottom:8px;">Exchange ${a.ex} · SF ${a.sf_pct}% (ikut nilai) · Shipping ${fmt(a.shipping)} (ikut nilai) · Part-timer ${fmt(a.parttimer)} (ikut kuantiti) · ${totalQty} unit</div>
 <table style="width:100%; border-collapse:collapse; font-size:11.5px;">
 <thead><tr style="background:#F3EEE7;">
 <th style="text-align:left; padding:6px;">SKU</th><th style="text-align:right; padding:6px;">RMB/u</th><th style="text-align:right; padding:6px;">Qty</th><th style="text-align:right; padding:6px;">Goods</th><th style="text-align:right; padding:6px;">SF</th><th style="text-align:right; padding:6px;">Shipping</th><th style="text-align:right; padding:6px;">P/timer</th><th style="text-align:right; padding:6px;">Landed/u</th>
 </tr></thead><tbody>${body}</tbody></table>`;
};

window.scToggleArchiveDetail = function(id){
 const dr = document.getElementById('scDetail_'+id); if(!dr) return;
 const caret = document.getElementById('scCaret_'+id);
 const open = (dr.style.display === 'none' || dr.style.display === '');
 dr.style.display = open ? 'table-row' : 'none';
 if(caret) caret.innerHTML = open ? '&#9662;' : '&#9656;';
 if(open && !dr.dataset.filled){
 const a = (window.__scArchive||[]).find(x=> String(x.id) === String(id));
 const body = document.getElementById('scDetailBody_'+id);
 if(a && body){ body.innerHTML = window.scArchiveDetailGrid(a); dr.dataset.filled = '1'; }
 }
};

