// p1_180 — Payment Proofs monitor
window.renderPaymentProofs = async function() {
 const listWrap = document.getElementById('ppListWrap');
 const statsEl = document.getElementById('ppStats');
 if(!listWrap) return;
 // Defaults: from = -30 days, to = today (only set once on first open)
 const fromEl = document.getElementById('ppFromDate');
 const toEl = document.getElementById('ppToDate');
 if(fromEl && !fromEl.value && !fromEl.dataset.ppInit) {
 const d = new Date(); d.setDate(d.getDate() - 30);
 fromEl.value = d.toISOString().slice(0,10);
 fromEl.dataset.ppInit = '1';
 }
 if(toEl && !toEl.value && !toEl.dataset.ppInit) {
 toEl.value = new Date().toISOString().slice(0,10);
 toEl.dataset.ppInit = '1';
 }
 const from = (fromEl && fromEl.value) || '';
 const to = (toEl && toEl.value) || '';
 const method = (document.getElementById('ppMethod') || {}).value || '';
 const channel = (document.getElementById('ppChannel') || {}).value || '';
 const proofStatus = (document.getElementById('ppProofStatus') || {}).value || '';
 try {
 if(typeof db === 'undefined' || !db) throw new Error('DB tak available');
 let q = db.from('sales_history').select('id,created_at,customer_name,customer_phone,channel,payment_method,total_amount,total,payment_proof_url,payment_proof_urls,payment_proof_uploaded_at,payment_proof_uploaded_by,staff_name').order('created_at', { ascending: false }).limit(500);
 if(from) q = q.gte('created_at', from + 'T00:00:00');
 if(to) q = q.lte('created_at', to + 'T23:59:59');
 if(channel) q = q.eq('channel', channel);
 const { data, error } = await q;
 if(error) throw error;
 let rows = data || [];
 // Method filter — match by prefix (E-Wallet may include ref)
 if(method) rows = rows.filter(r => (r.payment_method || '').startsWith(method));
 if(proofStatus === 'has') rows = rows.filter(r => !!r.payment_proof_url);
 if(proofStatus === 'missing') rows = rows.filter(r => (r.payment_method || 'Cash') !== 'Cash' && !r.payment_proof_url);
 // Stats
 const total = rows.length;
 const withProof = rows.filter(r => !!r.payment_proof_url).length;
 const nonCash = rows.filter(r => (r.payment_method || 'Cash') !== 'Cash').length;
 const missing = rows.filter(r => (r.payment_method || 'Cash') !== 'Cash' && !r.payment_proof_url).length;
 const totalRm = rows.reduce((s, r) => s + Number(r.total_amount || r.total || 0), 0);
 if(statsEl) {
 statsEl.innerHTML = `
 <div class="rp-kpi-card"><div class="rp-kpi-card__label">Jualan Senarai</div><div class="rp-kpi-card__value">${total.toLocaleString()}</div><div class="rp-kpi-card__sub">RM ${totalRm.toLocaleString(undefined,{maximumFractionDigits:2})} jumlah</div></div>
 <div class="rp-kpi-card"><div class="rp-kpi-card__label">Ada Resit</div><div class="rp-kpi-card__value" style="color:#101010;">${withProof.toLocaleString()}</div><div class="rp-kpi-card__sub">${nonCash > 0 ? Math.round(withProof / nonCash * 100) : 0}% bukan-Cash dah upload</div></div>
 <div class="rp-kpi-card"><div class="rp-kpi-card__label">Tiada Resit</div><div class="rp-kpi-card__value" style="color:${missing > 0 ? '#B23A2E' : '#9CA3AF'};">${missing.toLocaleString()}</div><div class="rp-kpi-card__sub">bukan-Cash · belum upload</div></div>
 `;
 }
 if(!rows.length) { listWrap.innerHTML = '<p style="padding:24px; text-align:center; color:#9CA3AF;">Tiada jualan dalam julat ni.</p>'; return; }
 const escHtml = (s) => String(s == null ? '' : s).replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/"/g,'&quot;');
 const body = rows.map(r => {
 const amt = Number(r.total_amount || r.total || 0);
 const dt = r.created_at ? new Date(r.created_at).toLocaleString('en-MY', { dateStyle:'short', timeStyle:'short' }) : '—';
 const pm = r.payment_method || 'Cash';
 const isCash = pm === 'Cash';
 const urlLower = (r.payment_proof_url || '').toLowerCase();
 const isPdf = urlLower.endsWith('.pdf');
 const isHeic = urlLower.endsWith('.heic') || urlLower.endsWith('.heif');
 let thumbCell = '';
 if(r.payment_proof_url) {
 if(isPdf) {
 thumbCell = `<a href="${escHtml(r.payment_proof_url)}" target="_blank" rel="noopener" style="display:inline-flex; align-items:center; gap:4px; color:var(--primary); font-weight:700; font-size:11.5px;"><i data-lucide="file-text" style="width:14px;height:14px;"></i> PDF</a>`;
 } else if(isHeic) {
 // p1_255 — HEIC tak render inline. Link je.
 thumbCell = `<a href="${escHtml(r.payment_proof_url)}" target="_blank" rel="noopener" title="HEIC format — klik untuk download/buka external" style="display:inline-flex; align-items:center; gap:4px; color:var(--primary-500,#CD7C32); font-weight:700; font-size:11.5px;"><i data-lucide="image-down" style="width:14px;height:14px;"></i> HEIC</a>`;
 } else {
 // p1_255 — guna this.src + onerror fallback (was raw URL escape bug)
 thumbCell = `<img src="${escHtml(r.payment_proof_url)}" loading="lazy" onclick="window.__ppOpenImg(this.src)" onerror="this.outerHTML='<a href=&quot;${escHtml(r.payment_proof_url)}&quot; target=_blank rel=noopener style=&quot;display:inline-flex; align-items:center; gap:3px; color:#B23A2E; font-size:11px; font-weight:700; text-decoration:none;&quot;><i data-lucide=image-off style=&quot;width:12px;height:12px;&quot;></i> broken</a>'" style="width:54px; height:54px; object-fit:cover; border-radius:6px; border:1px solid #E5E7EB; cursor:zoom-in;">`;
 }
 } else {
 thumbCell = isCash ? '<span style="font-size:11px; color:#9CA3AF;">— (Cash)</span>' : '<span style="font-size:11px; color:#B23A2E; font-weight:700;">tiada</span>';
 }
 const uploadedBy = r.payment_proof_uploaded_by ? `<br><span style="font-size:10px; color:#9CA3AF;">${escHtml(r.payment_proof_uploaded_by)}</span>` : '';
 return `<tr style="border-bottom:1px solid #F3F4F6;">
 <td style="padding:8px 10px;">${dt}</td>
 <td style="padding:8px 10px; font-family:'SF Mono',Menlo,monospace; font-size:11.5px;">#${r.id}</td>
 <td style="padding:8px 10px;"><strong>${escHtml(r.customer_name || 'Walk-in')}</strong>${r.customer_phone ? `<br><span style="font-size:11px; color:#6B7280;">${escHtml(r.customer_phone)}</span>` : ''}</td>
 <td style="padding:8px 10px;">${escHtml(pm)}</td>
 <td style="padding:8px 10px;">${escHtml(r.channel || '—')}</td>
 <td style="padding:8px 10px; text-align:right; font-weight:700;">RM ${amt.toFixed(2)}</td>
 <td style="padding:8px 10px; text-align:center;">${thumbCell}${uploadedBy}</td>
 <td style="padding:8px 10px; white-space:nowrap;">
 <button onclick="window.__openReceiptPDF(${r.id})" title="Buka resit official (preview + send)" style="background:#FEF7ED; border:1px solid #E7C66A; color:#7A5410; padding:5px 10px; border-radius:6px; cursor:pointer; font-size:11px; font-weight:700; margin-right:4px;"><i data-lucide="file-text" style="width:11px;height:11px;vertical-align:-1px;"></i> Resit</button>
 <button onclick="window.__sendReceiptPdfWhatsApp(${r.id})" title="Hantar resit PDF via WhatsApp" style="background:#E6F0E4; border:1px solid #ABC6A0; color:#34522F; padding:5px 10px; border-radius:6px; cursor:pointer; font-size:11px; font-weight:700; margin-right:4px;"><i data-lucide="message-circle" style="width:11px;height:11px;vertical-align:-1px;"></i> WhatsApp</button>
 <button onclick="window.__sendReceiptPdfEmail(${r.id})" title="Hantar resit PDF via Email" style="background:var(--primary-50,#FFF8F0); border:1px solid #A5B4FC; color:var(--primary-800,#7C4A1A); padding:5px 10px; border-radius:6px; cursor:pointer; font-size:11px; font-weight:700; margin-right:4px;"><i data-lucide="mail" style="width:11px;height:11px;vertical-align:-1px;"></i> Email</button>
 <button onclick="window.__ppManageProofs(${r.id})" title="Urus bukti bayar — sehingga 3 gambar" style="background:var(--primary-50,#FFF8F0); border:1px solid var(--primary-200,#FED7AA); color:var(--primary-800,#7C4A1A); padding:5px 10px; border-radius:6px; cursor:pointer; font-size:11px; font-weight:700; margin-right:4px;"><i data-lucide="images" style="width:11px;height:11px;vertical-align:-1px;"></i> Resit (${(window.__ppGetProofs ? window.__ppGetProofs(r).length : (r.payment_proof_url ? 1 : 0))}/3)</button>
 <button onclick="window.__ppEditSale(${r.id})" title="Edit maklumat customer / method / amount" style="background:var(--primary-50,#FFF8F0); border:1px solid var(--primary-300,#FDBA74); color:var(--primary-800,#7C4A1A); padding:5px 10px; border-radius:6px; cursor:pointer; font-size:11px; font-weight:700; margin-right:4px;"><i data-lucide="edit-3" style="width:11px;height:11px;vertical-align:-1px;"></i> Edit</button>
 <button onclick="window.__ppResendEmail(${r.id})" title="${r.email_status === 'sent' ? 'Hantar semula email receipt' : 'Hantar email receipt'}" style="background:var(--primary-100,#FFEDD5); border:1px solid var(--primary-300,#FDBA74); color:#101010; padding:5px 10px; border-radius:6px; cursor:pointer; font-size:11px; font-weight:700;"><i data-lucide="${r.email_status === 'sent' ? 'mail-check' : 'send'}" style="width:11px;height:11px;vertical-align:-1px;"></i> ${r.email_status === 'sent' ? 'Resend' : 'Send'}</button>
 </td>
 </tr>`;
 }).join('');
 listWrap.innerHTML = `<table style="width:100%; border-collapse:collapse; font-size:12.5px;">
 <thead style="background:#F9FAFB;"><tr>
 <th style="text-align:left; padding:8px 10px;">Tarikh</th>
 <th style="text-align:left; padding:8px 10px;">Sale</th>
 <th style="text-align:left; padding:8px 10px;">Pelanggan</th>
 <th style="text-align:left; padding:8px 10px;">Kaedah</th>
 <th style="text-align:left; padding:8px 10px;">Channel</th>
 <th style="text-align:right; padding:8px 10px;">RM</th>
 <th style="text-align:center; padding:8px 10px;">Resit Bayar</th>
 <th style="padding:8px 10px;">Hantar Resit</th>
 </tr></thead><tbody>${body}</tbody></table>`;
 if(window.lucide && lucide.createIcons) lucide.createIcons();
 } catch(e) {
 listWrap.innerHTML = '<p style="color:#B23A2E; padding:20px;">Error: ' + e.message + '</p>';
 }
};

// p1_253 — Zoom state + handlers
window.__ppImgZoomLevel = 1;
// p1_375 — Zoom resit guna transform:scale + pan (pinch/seret/wheel/butang) supaya
// jalan betul atas iPad/phone. Ganti engine lama (width:% + flexbox yg buggy).
window.__ppZoom = { scale: 1, tx: 0, ty: 0 };
window.__ppApplyZoom = function() {
 const img = document.getElementById('ppImgModalImg');
 if(!img) return;
 const z = window.__ppZoom;
 img.style.transform = `translate(${z.tx}px, ${z.ty}px) scale(${z.scale})`;
 img.style.cursor = z.scale > 1 ? 'grab' : 'zoom-in';
 const lbl = document.getElementById('ppImgZoomLabel');
 if(lbl) lbl.textContent = z.scale <= 1.01 ? 'Fit' : (z.scale.toFixed(1) + 'x');
};
window.__ppImgZoomReset = function() { window.__ppZoom = { scale: 1, tx: 0, ty: 0 }; window.__ppApplyZoom(); };
window.__ppImgZoomBy = function(delta) {
 const z = window.__ppZoom;
 z.scale = Math.min(6, Math.max(1, +(z.scale + delta).toFixed(2)));
 if(z.scale === 1) { z.tx = 0; z.ty = 0; }
 window.__ppApplyZoom();
};
// Tap gambar: toggle masuk/keluar — Fit → 2.5x, kalau dah zoom → reset. Jamin jalan
// atas SEMUA device walau pinch tak disokong (cuma satu tap).
window.__ppImgTapZoom = function() {
 const z = window.__ppZoom;
 if(z.scale <= 1.01) { z.scale = 2.5; }
 else { z.scale = 1; z.tx = 0; z.ty = 0; }
 window.__ppApplyZoom();
};
// Bind gesture sekali sahaja (pinch 2-jari, seret 1-jari/mouse, wheel)
window.__ppBindZoomGestures = function() {
 if(window.__ppZoomBound) return;
 const scroll = document.getElementById('ppImgScroll');
 const img = document.getElementById('ppImgModalImg');
 if(!scroll || !img) return;
 window.__ppZoomBound = true;
 let mode = null, startDist = 0, startScale = 1, lastX = 0, lastY = 0, startTx = 0, startTy = 0;
 // Tap detection (iOS standalone PWA selalu TAK trigger onclick pada <img>; handle via touch)
 let tapX = 0, tapY = 0, tapT = 0, tapValid = false, lastTouchTap = 0;
 const dist = (t) => Math.hypot(t[0].clientX - t[1].clientX, t[0].clientY - t[1].clientY);
 scroll.addEventListener('touchstart', (e) => {
 if(e.touches.length === 2) { mode = 'pinch'; startDist = dist(e.touches) || 1; startScale = window.__ppZoom.scale; tapValid = false; }
 else if(e.touches.length === 1) {
 tapX = e.touches[0].clientX; tapY = e.touches[0].clientY; tapT = Date.now(); tapValid = true;
 if(window.__ppZoom.scale > 1) { mode = 'pan'; lastX = tapX; lastY = tapY; startTx = window.__ppZoom.tx; startTy = window.__ppZoom.ty; }
 }
 }, { passive: false });
 scroll.addEventListener('touchmove', (e) => {
 if(e.touches.length === 1 && (Math.abs(e.touches[0].clientX - tapX) > 10 || Math.abs(e.touches[0].clientY - tapY) > 10)) tapValid = false;
 if(mode === 'pinch' && e.touches.length === 2) { e.preventDefault(); const z = window.__ppZoom; z.scale = Math.min(6, Math.max(1, startScale * (dist(e.touches) / startDist))); if(z.scale === 1) { z.tx = 0; z.ty = 0; } window.__ppApplyZoom(); }
 else if(mode === 'pan' && e.touches.length === 1) { e.preventDefault(); const z = window.__ppZoom; z.tx = startTx + (e.touches[0].clientX - lastX); z.ty = startTy + (e.touches[0].clientY - lastY); window.__ppApplyZoom(); }
 }, { passive: false });
 scroll.addEventListener('touchend', (e) => {
 // Tap pendek tanpa gerak = toggle zoom (jamin jalan iPad walau onclick tak fire)
 if(tapValid && mode !== 'pinch' && (Date.now() - tapT) < 350) {
 e.preventDefault();
 lastTouchTap = Date.now();
 window.__ppImgTapZoom();
 }
 mode = null; tapValid = false;
 }, { passive: false });
 // Desktop click (guard supaya tap touch tak double-fire dgn synthetic click)
 img.addEventListener('click', (e) => { e.stopPropagation(); if(Date.now() - lastTouchTap > 500) window.__ppImgTapZoom(); });
 scroll.addEventListener('wheel', (e) => { e.preventDefault(); window.__ppImgZoomBy(e.deltaY < 0 ? 0.3 : -0.3); }, { passive: false });
 // iOS Safari guna gesture events untuk pinch (touchmove 2-jari tak reliable + Safari
 // rampas jadi page-zoom). Handle sini + preventDefault supaya page tak zoom.
 let gStartScale = 1;
 const modalOpen = () => { const m = document.getElementById('ppImgModal'); return m && m.style.display !== 'none'; };
 scroll.addEventListener('gesturestart', (e) => { e.preventDefault(); gStartScale = window.__ppZoom.scale; }, { passive: false });
 scroll.addEventListener('gesturechange', (e) => { e.preventDefault(); const z = window.__ppZoom; z.scale = Math.min(6, Math.max(1, gStartScale * e.scale)); if(z.scale === 1) { z.tx = 0; z.ty = 0; } window.__ppApplyZoom(); }, { passive: false });
 scroll.addEventListener('gestureend', (e) => { e.preventDefault(); }, { passive: false });
 // Halang Safari page-zoom global SEMASA modal resit terbuka (iPad)
 document.addEventListener('gesturestart', (e) => { if(modalOpen()) e.preventDefault(); }, { passive: false });
 document.addEventListener('gesturechange', (e) => { if(modalOpen()) e.preventDefault(); }, { passive: false });
 // Mouse drag pan (desktop)
 let dragging = false, mX = 0, mY = 0, mTx = 0, mTy = 0;
 img.addEventListener('mousedown', (e) => { if(window.__ppZoom.scale > 1) { dragging = true; mX = e.clientX; mY = e.clientY; mTx = window.__ppZoom.tx; mTy = window.__ppZoom.ty; e.preventDefault(); } });
 window.addEventListener('mousemove', (e) => { if(dragging) { const z = window.__ppZoom; z.tx = mTx + (e.clientX - mX); z.ty = mTy + (e.clientY - mY); window.__ppApplyZoom(); } });
 window.addEventListener('mouseup', () => { dragging = false; });
};
// p1_378 — build stamp visible dalam modal supaya boleh sahkan iPad jalan versi mana
// (diagnostik cache PWA). Naikkan bila tukar kod zoom.
window.__ZOOM_BUILD = '455';
window.__ppOpenImg = function(url) {
 const m = document.getElementById('ppImgModal');
 const img = document.getElementById('ppImgModalImg');
 const nt = document.getElementById('ppImgNewTab');
 if(m && img) {
 img.src = url;
 if(nt) nt.href = url;
 window.__ppImgZoomReset();
 m.style.display = 'flex';
 window.__ppBindZoomGestures();
 const bv = document.getElementById('ppZoomBuild'); if(bv) bv.textContent = 'zoom build ' + window.__ZOOM_BUILD;
 if(window.lucide && lucide.createIcons) try { lucide.createIcons(); } catch(e){}
 }
};
// Back-compat: panggilan lama __ppImgZoom(level)/__ppImgCycleZoom kekal berfungsi
window.__ppImgZoom = function(level) { window.__ppZoom = { scale: Math.max(1, level || 1), tx: 0, ty: 0 }; window.__ppApplyZoom(); };
window.__ppImgCycleZoom = function() { window.__ppImgTapZoom(); };

// p1_197 — Build receipt text from sales_history row + send via WhatsApp.
// Called per-row from Payment Proofs (and reusable from anywhere with saleId).
window.__buildReceiptText = function(sale) {
 const shop = (typeof window.getShopInfo === 'function') ? window.getShopInfo() : { name: '10 CAMP', footer: 'Terima kasih!' };
 const dt = sale.created_at ? new Date(sale.created_at).toLocaleString('en-MY', { dateStyle: 'medium', timeStyle: 'short' }) : '-';
 const items = Array.isArray(sale.items) ? sale.items : [];
 const itemsList = items.map(c => {
 const qty = c.quantity || c.qty || 1;
 const price = c.price || 0;
 const lineTotal = price * qty;
 return '• ' + qty + 'x ' + (c.name || c.sku || 'Item') + ' — RM ' + lineTotal.toFixed(2);
 }).join('\n');
 const total = Number(sale.total_amount || sale.total || 0);
 const lines = [
 'Hi ' + (sale.customer_name || 'there') + ',',
 '',
 'Terima kasih beli barang dari *' + shop.name + '*!',
 '',
 'Resit: *#' + sale.id + '*',
 dt,
 '',
 '*Items:*',
 itemsList || '(tiada items dalam record)',
 '',
 '*TOTAL: RM ' + total.toFixed(2) + '*',
 'Kaedah: ' + (sale.payment_method || 'Cash'),
 sale.channel ? 'Channel: ' + sale.channel : '',
 '',
 shop.footer || 'Hope to see you again!'
 ].filter(Boolean);
 return lines.join('\n');
};

// p1_199 — Send PDF receipt via WhatsApp. Generates PDF + uploads + opens
// wa.me with download link.
window.__sendReceiptPdfWhatsApp = async function(saleId) {
 if(!saleId) return;
 const toast = (m, t) => { if(typeof showToast === 'function') showToast(m, t || 'info'); };
 try {
 toast('Sediakan resit PDF…', 'info');
 const { sale, url, cached } = await window.__ensureReceiptPdfUrl(saleId);
 let phone = (sale.customer_phone || '').replace(/[^\d+]/g, '');
 if(!phone) {
 const ask = prompt('Customer tak ada phone number. Masukkan WhatsApp number (cth: 0134567890):', '');
 if(!ask) return;
 phone = ask.replace(/[^\d+]/g, '');
 if(!phone) { toast('Phone invalid', 'warn'); return; }
 try { await db.from('sales_history').update({ customer_phone: phone }).eq('id', saleId); } catch(_) {}
 }
 // Normalize to international: 0XXXXXXX → 60XXXXXXX
 if(phone.startsWith('0')) phone = '60' + phone.slice(1);
 else if(phone.startsWith('+')) phone = phone.slice(1);
 const shop = (typeof window.getShopInfo === 'function') ? window.getShopInfo() : { name: '10 CAMP' };
 const total = Number(sale.total_amount || sale.total || 0);
 const text = [
 'Hi ' + (sale.customer_name || 'there') + ',',
 '',
 'Terima kasih sudi beli barang dari *' + shop.name + '*!',
 '',
 'Resit: *#' + sale.id + '*',
 'Jumlah: *RM ' + total.toFixed(2) + '*',
 '',
 'Download resit PDF:',
 url,
 '',
 'Sila simpan untuk rekod anda.',
 '',
 'Terima kasih!'
 ].join('\n');
 const waUrl = 'https://wa.me/' + phone + '?text=' + encodeURIComponent(text);
 window.open(waUrl, '_blank');
 try { await db.from('sales_history').update({ receipt_sent_whatsapp_at: new Date().toISOString() }).eq('id', saleId); } catch(_) {}
 toast('WhatsApp dibuka — resit ' + (cached ? 'reuse' : 'fresh') + ' PDF link siap.', 'success');
 } catch(e) {
 toast('Hantar WhatsApp gagal: ' + e.message, 'error');
 }
};

// p1_199 — Send PDF receipt via Email (mailto fallback until Resend setup).
window.__sendReceiptPdfEmail = async function(saleId) {
 if(!saleId) return;
 const toast = (m, t) => { if(typeof showToast === 'function') showToast(m, t || 'info'); };
 try {
 toast('Sediakan resit PDF…', 'info');
 const { sale, url } = await window.__ensureReceiptPdfUrl(saleId);
 const shop = (typeof window.getShopInfo === 'function') ? window.getShopInfo() : { name: '10 CAMP' };
 let email = (sale.customer_email || '').trim();
 if(!email) {
 const ask = prompt('Customer tak ada email simpan. Masukkan email (atau cancel):', '');
 if(!ask) return;
 email = ask.trim();
 if(!email || !email.includes('@')) { toast('Email invalid', 'warn'); return; }
 try { await db.from('sales_history').update({ customer_email: email }).eq('id', saleId); } catch(_) {}
 }
 const total = Number(sale.total_amount || sale.total || 0);
 const subject = 'Resit Pembelian #' + sale.id + ' — ' + shop.name;
 const body = [
 'Hi ' + (sale.customer_name || 'there') + ',',
 '',
 'Terima kasih sudi beli barang dari ' + shop.name + '!',
 '',
 'Butiran resit:',
 '- Nombor: #' + sale.id,
 '- Jumlah: RM ' + total.toFixed(2),
 '- Kaedah: ' + (sale.payment_method || 'Cash'),
 '',
 'Download resit PDF (klik link):',
 url,
 '',
 'Sila simpan untuk rekod anda. Untuk pulangan, hubungi kami dalam 7 hari.',
 '',
 'Terima kasih,',
 shop.name
 ].join('\n');
 const mailtoUrl = 'mailto:' + encodeURIComponent(email) + '?subject=' + encodeURIComponent(subject) + '&body=' + encodeURIComponent(body);
 window.location.href = mailtoUrl;
 try { await db.from('sales_history').update({ receipt_sent_email_at: new Date().toISOString() }).eq('id', saleId); } catch(_) {}
 toast('Email client dibuka untuk ' + email, 'success');
 } catch(e) {
 toast('Hantar email gagal: ' + e.message, 'error');
 }
};

