// Dashboard date range state — default Today
window.__dashRange = window.__dashRange || 'today';
window.__setDashRange = function(range, btn) {
 window.__dashRange = range;
 document.querySelectorAll('.dash-pill').forEach(p => p.classList.toggle('active', p === btn));
 const customWrap = document.getElementById('dashCustomWrap');
 if (customWrap) customWrap.classList.toggle('active', range === 'custom');
 if (range !== 'custom') renderDashboard();
};
window.__dashGoto = function(tab) {
 const item = document.querySelector('.menu-item[data-tab="'+tab+'"]');
 if (item) item.click();
 else if (typeof showToast === 'function') showToast('Menu "'+tab+'" tak dijumpai', 'warning');
};
function __getDashDateRange() {
 const r = window.__dashRange || 'today';
 const now = new Date();
 const startOf = (d) => { const x = new Date(d); x.setHours(0,0,0,0); return x; };
 const endOf = (d) => { const x = new Date(d); x.setHours(23,59,59,999); return x; };
 // p1_78 fix #3: locale-aware range labels via window.t() (fallback to EN if i18n not ready)
 const T = (key, fallback) => (typeof window.t === 'function') ? (window.t(key) || fallback) : fallback;
 if (r === 'today') return { start: startOf(now), end: endOf(now), label: T('hs_range_today', 'Today') };
 if (r === 'yesterday') { const y = new Date(now); y.setDate(y.getDate()-1); return { start: startOf(y), end: endOf(y), label: T('hs_range_yesterday', 'Yesterday') }; }
 if (r === '7d') { const s = new Date(now); s.setDate(s.getDate()-6); return { start: startOf(s), end: endOf(now), label: T('hs_range_7d', '7 days') }; }
 if (r === '30d') { const s = new Date(now); s.setDate(s.getDate()-29); return { start: startOf(s), end: endOf(now), label: T('hs_range_30d', '30 days') }; }
 if (r === 'mtd') { const s = new Date(now.getFullYear(), now.getMonth(), 1); return { start: startOf(s), end: endOf(now), label: T('hs_range_mtd', 'MTD') }; }
 if (r === 'all') return { start: null, end: null, label: T('hs_range_all', 'All time') };
 if (r === 'custom') {
 const ss = document.getElementById('dashStartDate')?.value;
 const ee = document.getElementById('dashEndDate')?.value;
 return { start: ss ? startOf(new Date(ss)) : null, end: ee ? endOf(new Date(ee)) : null, label: (ss||'?')+' → '+(ee||'?') };
 }
 return { start: null, end: null, label: '—' };
}

// p1_834 — Greeting strip: sapaan ikut waktu + nama + ringkasan plain-language.
// Baca nombor terus dari badge DOM (sudah diisi __setAlert) supaya decoupled & selamat.
window.__renderDashGreet = function(){
 try {
 const hiEl = document.getElementById('dashGreetHi');
 if(!hiEl) return;
 const subEl = document.getElementById('dashGreetSub');
 const dateEl = document.getElementById('dashGreetDate');
 const iconEl = document.getElementById('dashGreetIcon');
 const now = new Date();
 const hr = now.getHours();
 const g = hr < 5  ? ['Malam tenang','moon'] :
          hr < 12 ? ['Selamat pagi','sunrise'] :
          hr < 15 ? ['Selamat tengahari','sun'] :
          hr < 19 ? ['Selamat petang','sunset'] :
                    ['Selamat malam','moon'];
 const u = window.currentUser || {};
 const first = ((u.name || '').trim().split(/\s+/)[0]) || '';
 hiEl.textContent = g[0] + (first ? ', ' + first : '');
 if(iconEl) iconEl.innerHTML = '<i data-lucide="'+g[1]+'"></i>';
 const readNum = id => { const e = document.getElementById(id); return e ? (parseInt((e.textContent||'').replace(/[^\d-]/g,''),10) || 0) : 0; };
 const oos = readNum('badgeOos'), low = readNum('badgeLow'), ret = readNum('badgeReturn');
 const parts = [];
 if(oos) parts.push('<b>'+oos+'</b> stok habis');
 if(ret) parts.push('<b>'+ret+'</b> minta pulangan');
 if(low) parts.push('<b>'+low+'</b> stok rendah');
 if(subEl) subEl.innerHTML = parts.length ? ('Ada ' + parts.join(' · ') + ' nak kau tengok.') : 'Semua terkawal — takde benda urgent setakat ni. Kerja elok!';
 if(dateEl){ try { dateEl.textContent = now.toLocaleDateString('ms-MY', { weekday:'long', day:'numeric', month:'long' }); } catch(e){ dateEl.textContent = now.toLocaleDateString(); } }
 if(window.lucide && window.lucide.createIcons) { try { window.lucide.createIcons(); } catch(e){} }
 } catch(e){}
};

window.renderDashboard = function() {
 const range = __getDashDateRange();
 let filteredSales = salesHistory;
 if (range.start && range.end) {
 filteredSales = salesHistory.filter(s => {
 const sd = new Date(s.created_at);
 return sd>= range.start && sd <= range.end;
 });
 }
 // p1_449 — JUALAN TEPAT: buang order test + void/cancel/refund dari KPI hero.
 // Dulu hero kira mentah → terlebih ~RM10k vs jualan sebenar (Zaid: "perlukan data sales tepat").
 // Tapisan SAMA dgn blok Analisis Jualan supaya hero & analisis padan.
 filteredSales = filteredSales.filter(s => {
 if(!s || s.is_test) return false;
 const st = (s.status || '').toLowerCase();
 if(st.includes('void') || st.includes('cancel') || st.includes('refund')) return false;
 return true;
 });
 const rangeLabelEl = document.getElementById('dashRangeLabel');
 if (rangeLabelEl) rangeLabelEl.textContent = '— ' + range.label;

 // 2. Compute Core Metrics
 let totalSales = 0;
 let channelFreq = {};
 let itemCounts = {};

 let statusToFulfil = 0; let statusUnpaid = 0; let statusProcessing = 0; let statusReturn = 0;

 filteredSales.forEach(sale => {
 let rev = Number(sale.total || sale.total_amount || 0);
 totalSales = round2(totalSales + rev);
 
 // Channels
 let ch = sale.channel || 'POS Cashier';
 channelFreq[ch] = (channelFreq[ch] || 0) + rev;

 // Status
 let st = sale.status || 'Completed';
 if(st === 'To Fulfil') statusToFulfil++;
 if(st === 'Unpaid') statusUnpaid++;
 if(st === 'Processing') statusProcessing++;
 if(st === 'Return Request') statusReturn++;

 // Best Sellers parsing
 const itemsList = typeof sale.items === 'string' ? JSON.parse(sale.items) : sale.items;
 if(Array.isArray(itemsList)) {
 itemsList.forEach(item => {
 let sKey = item.sku || item.name || '??';
 if(!itemCounts[sKey]) itemCounts[sKey] = { sku: item.sku || '', name: item.name, qty: 0, revenue: 0 }; // p1_1056 — simpan sku utk thumbnail
 // p1_1051 — item POS guna `quantity`, item marketplace (TikTok/Shopee) guna `qty`.
 // Dulu baca `quantity` sahaja → Number(undefined) = NaN meracuni SKU tu KEKAL ("NaN sold",
 // RM pelik) + sort ranking jadi karut (NaN tak boleh dibanding). Corak normalize sama
 // macam 15+ tempat lain dlm codebase (cth skuTally line ~2041).
 const __q = Number(item.quantity != null ? item.quantity : item.qty) || 0;
 itemCounts[sKey].qty += __q;
 itemCounts[sKey].revenue = round2(itemCounts[sKey].revenue + (Number(item.price) || 0) * __q);
 });
 }
 });

 const fmtMoney = (n) => Number(n).toLocaleString('en-MY', { minimumFractionDigits: 2, maximumFractionDigits: 2 });
 document.getElementById("dashTotalSales").textContent = fmtMoney(totalSales);
 document.getElementById("dashTotalOrders").textContent = filteredSales.length;

 // Average Order Value
 const aov = filteredSales.length ? round2(totalSales / filteredSales.length) : 0;
 const aovEl = document.getElementById("dashAOV");
 if (aovEl) aovEl.textContent = 'RM ' + fmtMoney(aov);

 // p1_1052 — DELTA PINTAR (isi dashSalesDelta yang selama ni "—" kekal — div dijanjikan tapi
 // TIADA siapa pernah tulis). Banding tempoh semasa vs tempoh setara sebelum:
 // today/yesterday → HARI SAMA MINGGU LEPAS (retail ada rentak mingguan — Sabtu vs Sabtu, adil);
 // today di-cap pada jam sama (hari separuh vs hari penuh = tak adil). 7d/30d/custom → tetingkap
 // sama panjang sebelum. mtd → bulan lepas setakat hari sama. all → tiada banding.
 try {
 const deltaEl = document.getElementById('dashSalesDelta');
 if (deltaEl) {
 const r = window.__dashRange || 'today';
 let pStart = null, pEnd = null, pLabel = '';
 const D = 86400000;
 if (r === 'today' || r === 'yesterday') {
 pStart = new Date(range.start.getTime() - 7 * D);
 pEnd = new Date(Math.min(range.end.getTime(), Date.now()) - 7 * D); // today: cap jam sama minggu lepas
 try { pLabel = 'vs ' + pStart.toLocaleDateString('ms-MY', { weekday: 'long' }) + ' lepas'; } catch(e){ pLabel = 'vs minggu lepas'; }
 } else if (r === '7d' || r === '30d' || r === 'custom') {
 if (range.start && range.end) {
 const span = range.end.getTime() - range.start.getTime();
 pEnd = new Date(range.start.getTime() - 1);
 pStart = new Date(range.start.getTime() - span);
 pLabel = 'vs tempoh sebelum';
 }
 } else if (r === 'mtd') {
 const now = new Date();
 const prevDays = new Date(now.getFullYear(), now.getMonth(), 0).getDate(); // hari dlm bulan lepas
 pStart = new Date(now.getFullYear(), now.getMonth() - 1, 1);
 pEnd = new Date(now.getFullYear(), now.getMonth() - 1, Math.min(now.getDate(), prevDays), now.getHours(), now.getMinutes());
 pLabel = 'vs bulan lepas (setakat sama)';
 }
 if (pStart && pEnd) {
 let prevTotal = 0;
 salesHistory.forEach(s => {
 if (!s || s.is_test) return;
 const st = (s.status || '').toLowerCase();
 if (st.includes('void') || st.includes('cancel') || st.includes('refund')) return;
 const sd = new Date(s.created_at);
 if (sd >= pStart && sd <= pEnd) prevTotal += Number(s.total || s.total_amount || 0);
 });
 if (prevTotal > 0) {
 const dp = ((totalSales - prevTotal) / prevTotal) * 100;
 const up = dp >= 0;
 deltaEl.innerHTML = '<span style="font-weight:800; color:' + (up ? '#8FD19E' : '#F3A08C') + ';">' + (up ? '▲' : '▼') + ' ' + (up ? '+' : '') + dp.toFixed(0) + '%</span> <span style="opacity:.85;">' + pLabel + '</span>';
 } else {
 deltaEl.textContent = 'tiada data banding (' + pLabel.replace('vs ', '') + ')';
 }
 } else {
 deltaEl.textContent = '';
 }
 }
 } catch(e) { console.warn('dash delta:', e); }

 // p1_1052 — SASARAN BULAN (ganti Top Channel — maklumat mati "POS Cashier ~50%" tiap hari;
 // channel split penuh masih ada dlm Dashboard donut). Guna sasaran bulanan sedia ada
 // (dashMonthlyTarget_v1, sumber sama dgn banner cashier p1_559) + jualan SEBENAR bulan ini.
 try {
 const pctEl = document.getElementById('dashTargetHomePct');
 const subEl2 = document.getElementById('dashTargetHomeSub');
 const fillEl = document.getElementById('dashTargetHomeFill');
 if (pctEl && subEl2) {
 let tgt = 0; try { tgt = parseFloat(localStorage.getItem('dashMonthlyTarget_v1')) || 0; } catch(e){}
 if (!tgt && window.__getSetting) tgt = Number(window.__getSetting('sales.monthly_target', 0)) || 0;
 if (tgt > 0) {
 const now = new Date();
 const mStart = new Date(now.getFullYear(), now.getMonth(), 1);
 let mSales = 0;
 salesHistory.forEach(s => {
 if (!s || s.is_test) return;
 const st = (s.status || '').toLowerCase();
 if (st.includes('void') || st.includes('cancel') || st.includes('refund')) return;
 const sd = new Date(s.created_at);
 if (sd >= mStart) mSales += Number(s.total || s.total_amount || 0);
 });
 const pct = Math.min(999, Math.round(mSales / tgt * 100));
 const baki = Math.max(0, tgt - mSales);
 const daysInM = new Date(now.getFullYear(), now.getMonth() + 1, 0).getDate();
 const daysLeft = Math.max(1, daysInM - now.getDate() + 1);
 pctEl.textContent = pct + '%';
 if (fillEl) fillEl.style.width = Math.min(100, pct) + '%';
 subEl2.textContent = baki > 0
 ? ('RM ' + fmtMoney(baki) + ' lagi · RM ' + fmtMoney(baki / daysLeft) + '/hari (' + daysLeft + ' hari)')
 : 'Sasaran CAPAI! RM ' + fmtMoney(mSales - tgt) + ' lebihan';
 } else {
 pctEl.textContent = '—';
 subEl2.textContent = 'Sasaran belum diset — Settings › Customization';
 if (fillEl) fillEl.style.width = '0%';
 }
 }
 } catch(e) { console.warn('dash target:', e); }

 // p1_1053 — PECAHAN CHANNEL (ganti sparkline trajectory — hiasan tanpa nombor). Guna channelFreq
 // yang DAH dikira utk tempoh dipilih. Label mesra + warna platform yang dibenarkan brand
 // (Shopee #EE4D2D / TikTok hitam / walk-in bronze — rule "never sweep Shopee/WA colors").
 try {
 const chBox = document.getElementById('dashChannelRows');
 if (chBox) {
 const LABEL = { 'POS Cashier': 'Walk-in', 'TikTok Shop': 'TikTok', 'Shopee': 'Shopee' };
 const COLOR = { 'POS Cashier': 'var(--primary-500,#CD7C32)', 'TikTok Shop': '#101010', 'Shopee': '#EE4D2D' };
 const rows = Object.entries(channelFreq).sort((a, b) => b[1] - a[1]).slice(0, 4);
 const maxV = rows.length ? rows[0][1] : 0;
 chBox.innerHTML = !rows.length
 ? '<div class="sub">Tiada jualan dlm tempoh ni</div>'
 : rows.map(([ch, v]) => {
 const w = maxV > 0 ? Math.max(4, Math.round(v / maxV * 100)) : 0;
 const nm = LABEL[ch] || ch;
 const cl = COLOR[ch] || '#9CA3AF';
 return '<div style="display:flex; align-items:center; gap:8px; font-size:11.5px;">'
 + '<span style="width:52px; flex:none; font-weight:700; color:#374151; overflow:hidden; text-overflow:ellipsis; white-space:nowrap;">' + nm + '</span>'
 + '<span style="flex:1; height:7px; background:rgba(16,16,16,0.06); border-radius:99px; overflow:hidden;"><span style="display:block; height:100%; width:' + w + '%; background:' + cl + '; border-radius:99px;"></span></span>'
 + '<span style="flex:none; font-weight:700; color:#101010;">RM ' + fmtMoney(v) + '</span>'
 + '</div>';
 }).join('');
 }
 } catch(e) { console.warn('dash channel:', e); }

 // p1_78 fix #8: helper — set badge value + hide parent .dash-alert when 0
 // (alerts with 0 count are noise; collapse them so Bos focuses on actionable items)
 const __setAlert = (id, val) => {
 const el = document.getElementById(id);
 if(!el) return;
 el.textContent = val;
 const card = el.closest('.dash-alert');
 if(card) card.style.display = (parseInt(val) > 0) ? '' : 'none';
 };

 // Status Board Update
 __setAlert('badgeToFulfil', statusToFulfil);
 __setAlert('badgeUnpaid', statusUnpaid);
 __setAlert('badgeProcessing', statusProcessing);
 __setAlert('badgeReturn', statusReturn);

 // 3. Inventory Stock Health
 let activeP=0; let draftP=0; let oosP=0; let lowP=0;
 masterProducts.forEach(p => {
 if(!isPublished(p)) { draftP++; return; }
 activeP++;

 let qty = inventoryBatches.filter(b=>b.sku===p.sku).reduce((sum, b)=>sum+b.qty_remaining,0);
 if(qty === 0) oosP++;
 else if(qty < 5) lowP++;
 });

 // Active Products is in Snapshot card (mini-row, not alert) — keep as-is
 document.getElementById("badgeActive").textContent = activeP;
 __setAlert('badgeDraft', draftP);
 __setAlert('badgeOos', oosP);
 __setAlert('badgeLow', lowP);

 // 4. CRM Customer Metrics
 // Calculate new buyers based on how many unique names are in filteredSales vs customersData. 
 // Simplified for MVP:
 let repeatC = customersData.filter(c => c.points> 0).length; // Assumption: points means repeated
 let membersC = customersData.filter(c => c.is_member === true).length;
 document.getElementById("dashNewBuyers").textContent = customersData.length; // Total saved unique customers
 document.getElementById("badgeRepeat").textContent = repeatC;
 document.getElementById("badgeMembers").textContent = membersC;

 // 5. Draw Top 10 List
 const topArr = Object.values(itemCounts).sort((a,b) => b.qty - a.qty).slice(0, 10);
 const tbodyLines = document.getElementById("topSellingList");
 tbodyLines.innerHTML = "";
 if(topArr.length === 0) tbodyLines.innerHTML = "<tr><td>No sales data</td></tr>";
 
 if (topArr.length === 0) {
 tbodyLines.innerHTML = '<tr><td colspan="4" style="padding:18px; text-align:center; color:var(--text-muted); font-size:12.5px;">Belum ada sales dalam range ni. Pilih range lebih luas atau buat sale pertama.</td></tr>';
 } else {
 // p1_158 — was innerHTML += in loop (O(n²) DOM reflow per push, crashed Safari).
 tbodyLines.innerHTML = topArr.map((o, i) => `<tr style="cursor:pointer;" onclick="window.__dashGoto('inv_database')">
 <td style="width:24px; font-weight:bold; color:#888;">#${i+1}</td>
 <td><div style="display:flex; align-items:center; gap:9px;">${window.__skuThumbHtml ? window.__skuThumbHtml(o.sku, 38) : ''}<strong>${o.name}</strong></div></td>
 <td style="color:#101010; font-weight:700;">${o.qty} sold</td>
 <td style="text-align:right; font-weight:600;">RM ${fmtMoney(o.revenue)}</td>
 </tr>`).join('');
 }

 // p1_1053 — panggilan renderSalesTrajectory + renderSalesAnalytics DIBUANG dari sini:
 // sparkline diganti Pecahan Channel (atas), dan pane Sales disorok kekal sejak p1_1050 —
 // render ke elemen tersembunyi = bazir kitaran. Fungsi kekal wujud (dorman, ada guard).

 // Freshness timestamp
 const stamp = document.getElementById('dashFreshStamp');
 if (stamp) stamp.textContent = new Date().toLocaleTimeString('en-MY', { hour:'2-digit', minute:'2-digit' });

 // p1_834 — greeting strip (badges sudah diisi di atas)
 if(typeof window.__renderDashGreet === 'function') window.__renderDashGreet();
}

// p1_439 — Sales Trajectory: Daily / Weekly / Monthly / Custom analytic graph
window.__stMode = window.__stMode || 'daily';
// p1_448 — Sales Trajectory + Analisis Jualan KONGSI satu tempoh tarikh.
// Dulu dua kawalan berasingan (#stMode vs #saMode) boleh tunjuk tempoh berlainan
// jadi angka tak sepadan (Farhan: atas 12k bawah 6k). Setter ni segerak kedua-dua.
window.__salesSetPeriod = function(mode) {
 mode = mode || 'daily';
 window.__stMode = mode;
 window.__saMode = mode;
 ['stMode','saMode'].forEach(id => { const e = document.getElementById(id); if(e && e.value !== mode) e.value = mode; });
 ['stCustomRow','saCustomRow'].forEach(id => { const e = document.getElementById(id); if(e) e.style.display = (mode === 'custom') ? 'flex' : 'none'; });
 if(window.renderSalesTrajectory) window.renderSalesTrajectory();
 if(window.renderSalesAnalytics) window.renderSalesAnalytics();
};
// Segerak input tarikh custom merentas kedua-dua pasang (stFrom<->saFrom, stTo<->saTo)
window.__salesSetDates = function(srcEl) {
 if(srcEl && srcEl.id) {
 const v = srcEl.value;
 const targets = /From$/.test(srcEl.id) ? ['stFrom','saFrom'] : ['stTo','saTo'];
 targets.forEach(id => { const e = document.getElementById(id); if(e && e.value !== v) e.value = v; });
 }
 if(window.renderSalesTrajectory) window.renderSalesTrajectory();
 if(window.renderSalesAnalytics) window.renderSalesAnalytics();
};
window.__stSetMode = function(mode) { window.__salesSetPeriod(mode); };
window.renderSalesTrajectory = function() {
 const ctx = document.getElementById('salesChart');
 if(!ctx || typeof Chart === 'undefined') return;
 const mode = window.__stMode || 'daily';
 const sales = (typeof salesHistory !== 'undefined' && Array.isArray(salesHistory) ? salesHistory : []).filter(s => {
 if(!s || !s.created_at || s.is_test) return false;
 const st = (s.status || '').toLowerCase();
 if(st.includes('void') || st.includes('cancel') || st.includes('refund')) return false;
 return true;
 });
 // p1_449 — tetingkap selaras kalendar penuh (start-of-day → end-of-day) supaya
 // "Harian (30 hari)" = hero pill "30 days" (dulu rolling 29×24jam jadi tak padan).
 const now = new Date();
 const _sod = (d) => { const x = new Date(d); x.setHours(0,0,0,0); return x; };
 const _eod = (d) => { const x = new Date(d); x.setHours(23,59,59,999); return x; };
 let from, to = _eod(now);
 if(mode === 'custom') {
 const f = document.getElementById('stFrom'), t = document.getElementById('stTo');
 from = (f && f.value) ? new Date(f.value + 'T00:00:00') : _sod(new Date(now.getTime() - 29*864e5));
 to = (t && t.value) ? new Date(t.value + 'T23:59:59') : _eod(now);
 } else if(mode === 'weekly') { const s = new Date(now); s.setDate(s.getDate() - 7*11); from = _sod(s); }
 else if(mode === 'monthly') { from = _sod(new Date(now.getFullYear(), now.getMonth() - 11, 1)); }
 else { const s = new Date(now); s.setDate(s.getDate() - 29); from = _sod(s); } // daily = 30 hari kalendar
 const fromMs = from.getTime(), toMs = to.getTime();
 const pad = (n) => String(n).padStart(2, '0');
 const keyOf = (d) => {
 if(mode === 'monthly') return d.getFullYear() + '-' + pad(d.getMonth() + 1);
 if(mode === 'weekly') { const x = new Date(d); const day = (x.getDay() + 6) % 7; x.setDate(x.getDate() - day); x.setHours(0,0,0,0); return x.getFullYear() + '-' + pad(x.getMonth()+1) + '-' + pad(x.getDate()); }
 return d.getFullYear() + '-' + pad(d.getMonth()+1) + '-' + pad(d.getDate());
 };
 const bucket = {};
 sales.forEach(s => {
 const d = new Date(s.created_at); const t = d.getTime();
 if(t < fromMs || t > toMs) return;
 const k = keyOf(d);
 bucket[k] = round2((bucket[k] || 0) + Number(s.total || s.total_amount || 0));
 });
 const keys = Object.keys(bucket).sort();
 const labelOf = (k) => {
 const p = k.split('-');
 if(mode === 'monthly') return new Date(+p[0], +p[1]-1, 1).toLocaleDateString('en-MY', { month:'short', year:'2-digit' });
 return (mode === 'weekly' ? 'mgg ' : '') + p[2] + '/' + p[1];
 };
 const labels = keys.map(labelOf);
 const data = keys.map(k => bucket[k]);
 if(salesChartInst) salesChartInst.destroy();
 salesChartInst = new Chart(ctx.getContext('2d'), {
 type: 'line',
 data: { labels, datasets: [{ label: 'RM', data, backgroundColor: 'rgba(205, 124, 50, 0.12)', borderColor: '#CD7C32', borderWidth: 2, fill: true, tension: 0.35, pointRadius: data.length > 14 ? 0 : 2, pointHoverRadius: 4 }] },
 options: {
 responsive: true, maintainAspectRatio: false,
 plugins: { legend: { display: false }, tooltip: { callbacks: { label: (c) => 'RM ' + Number(c.parsed.y).toLocaleString('en-MY', {minimumFractionDigits:2, maximumFractionDigits:2}) } } },
 scales: { x: { display: false }, y: { display: false, beginAtZero: true } }
 }
 });
};

// p1_440 — Sales Analytics: readable trend + sales-by-channel + channel share
window.__saTrendInst = window.__saTrendInst || null;
window.__saChannelInst = window.__saChannelInst || null;
window.__saShareInst = window.__saShareInst || null;
window.__saPayInst = window.__saPayInst || null;
window.__saAovInst = window.__saAovInst || null;
window.__saHourInst = window.__saHourInst || null;
window.__saDowInst = window.__saDowInst || null;
window.__saTopProdInst = window.__saTopProdInst || null;
window.__saTopBrandInst = window.__saTopBrandInst || null;
window.__saMode = window.__saMode || 'daily';
