window.__scsSetFilter = function(s, btn) {
 window.__scsFilter = s;
 document.querySelectorAll('[data-scs-filter]').forEach(b => b.classList.toggle('rm-pill--active', b.dataset.scsFilter === s));
 window.renderCheckSessions();
};

