window.removeFromCart = function(sku) { cart = cart.filter(c => c.sku !== sku); renderCart(); }

function renderCart() {
 const container = document.getElementById("cartItems");
 const label = document.getElementById("totalPrice");
 const subLabel = document.getElementById("cartSubtotalVal");
 const btnPay = document.getElementById("btnOpenPayment");
 if(!container) return; container.innerHTML = ""; let total = 0; let totalItems = 0;
 if(typeof window.__renderCartTabs === 'function') window.__renderCartTabs(); // p1_557 — tab multi-cart
 if(typeof window.__cartProofRefresh === 'function') window.__cartProofRefresh(); // p1_383 — snap-resit row
 
 // safe update helper for mobile bar
 const updateMobileBar = (t, i) => {
 const tEl = document.getElementById("mobileCartTotal");
 const iEl = document.getElementById("mobileCartItemCount");
 if(tEl) tEl.textContent = t.toFixed(2);
 if(iEl) iEl.textContent = i.toString();
 // p1_239 — disable mobile floating BAYAR SEKARANG button when cart empty
 const bayarBtn = document.getElementById("mobileCartBayarBtn");
 if(bayarBtn) {
 if(i === 0) {
 bayarBtn.disabled = true;
 bayarBtn.style.opacity = '0.5';
 bayarBtn.style.cursor = 'not-allowed';
 bayarBtn.style.boxShadow = 'none';
 } else {
 bayarBtn.disabled = false;
 bayarBtn.style.opacity = '';
 bayarBtn.style.cursor = 'pointer';
 bayarBtn.style.boxShadow = '0 6px 20px rgba(16, 16, 16,0.35)';
 }
 }
 };

 if(cart.length === 0) {
 // p1_131 — Better empty cart state
 container.innerHTML = `<div style="padding:24px 12px; text-align:center; color:#9CA3AF;">
 <i data-lucide="shopping-cart" style="width:48px; height:48px; opacity:0.3;"></i>
 <p style="margin:10px 0 4px; font-size:13px; font-weight:600; color:#6B7280;">Troli kosong</p>
 <p style="margin:0; font-size:11.5px; line-height:1.5;">Imbas barcode atau klik produk dari katalog kanan. Tekan <kbd style="background:#F3F4F6; padding:1px 5px; border-radius:3px; font-family:monospace; font-size:10px;">/</kbd> untuk focus search.</p>
 </div>`;
 if(window.lucide && lucide.createIcons) try { lucide.createIcons(); } catch(e){}
 label.textContent = "0.00";
 if(subLabel) subLabel.textContent = "0.00";
 const __bbt = document.getElementById('bayarBtnTotal'); if(__bbt) __bbt.textContent = '0.00';
 if(btnPay) btnPay.disabled = true;
 updateMobileBar(0, 0);
 return;
 }

 // p1_129 — Floor Price guard: build SKU→floor map for cart items
 const floorMap = {};
 try {
 if(typeof masterProducts !== 'undefined' && Array.isArray(masterProducts)) {
 masterProducts.forEach(p => {
 const sku = (p.sku || '').toUpperCase();
 const fp = Number(p.floor_price || 0);
 if(sku && fp > 0) floorMap[sku] = fp;
 });
 }
 } catch(e){}

 // p1_384 — sku -> gambar produk (untuk thumbnail dalam cart). Ambik dari masterProducts.
 const __cartImg = {};
 try {
 if(typeof masterProducts !== 'undefined' && Array.isArray(masterProducts)) {
 masterProducts.forEach(p => {
 const sku = (p.sku || '').toUpperCase();
 if(!sku) return;
 let img = '';
 if(Array.isArray(p.images) && p.images[0]) img = p.images[0];
 else if(typeof p.images === 'string' && p.images) img = p.images;
 if(img) __cartImg[sku] = img;
 });
 }
 } catch(e){}
 if(!window.__cartNoImg) window.__cartNoImg = "data:image/svg+xml;utf8,<svg xmlns='http://www.w3.org/2000/svg' width='48' height='48' viewBox='0 0 48 48'><rect width='48' height='48' rx='8' fill='%23F3F4F6'/><path d='M14 30l6-7 4 5 4-5 6 7z' fill='%23D1D5DB'/><circle cx='18' cy='17' r='3' fill='%23D1D5DB'/></svg>";

 // p1_158 — was innerHTML += in cart loop (Safari OOM trigger; CASHIER hot path — fires every add/remove)
 container.innerHTML = cart.map(item => {
 total = round2(total + item.price * item.quantity);
 totalItems += item.quantity;
 const skuU = (item.sku || '').toUpperCase();
 const floor = floorMap[skuU];
 const belowFloor = floor && item.price < floor;
 const lineTotal = round2(item.price * item.quantity); // p1_917 — jumlah per-baris jelas utk customer double-check
 const realImg = __cartImg[skuU] || ''; // p1_918 — gambar sebenar (bukan placeholder) → boleh zoom
 const __img = realImg || window.__cartNoImg;
 const imgJs = realImg ? hesc(realImg).replace(/'/g, "\\'") : '';
 const thumb = `<div style="position:relative; flex-shrink:0; width:68px; height:68px;">
 <img src="${__img}" loading="lazy" onerror="this.onerror=null;this.src=window.__cartNoImg;" ${realImg ? `onclick="window.__ppOpenImg('${imgJs}')"` : ''} style="width:68px; height:68px; object-fit:cover; border-radius:10px; border:1px solid #E5E7EB;${realImg ? ' cursor:zoom-in;' : ''}" alt="">
 ${realImg ? `<div onclick="window.__ppOpenImg('${imgJs}')" title="Zoom gambar" style="position:absolute; bottom:3px; right:3px; background:rgba(16,16,16,.72); color:#fff; width:20px; height:20px; border-radius:6px; display:flex; align-items:center; justify-content:center; cursor:zoom-in;"><i data-lucide="zoom-in" style="width:12px;height:12px;"></i></div>` : ''}
 </div>`;
 const floorBadge = belowFloor
 ? `<span style="display:inline-block; padding:2px 7px; background:#F4E4DF; color:#7C2A20; border-radius:50px; font-size:9.5px; font-weight:700; letter-spacing:0.3px;">BAWAH FLOOR (RM ${floor.toFixed(2)})</span>`
 : '';
 // 2026-06-25 — B2B: tanda harga rundingan + retail dicoret
 const __b2bPriced = !!item.b2b_priced && item.retail_price != null && Number(item.retail_price) > Number(item.price);
 const b2bBadge = __b2bPriced
 ? `<span style="display:inline-block; padding:2px 7px; background:#EEF3EC; color:#34522F; border-radius:50px; font-size:9.5px; font-weight:700; letter-spacing:0.3px;" title="Harga rundingan B2B">HARGA B2B</span>`
 : '';
 const discBadge = (item.discount_amount && item.discount_amount > 0)
 ? `<span style="display:inline-block; padding:2px 7px; background:#F8EFD7; color:#7A5410; border-radius:50px; font-size:10px; font-weight:700;" title="${item.discount_reason || 'Diskaun manual'}">−RM ${item.discount_amount.toFixed(2)}</span>`
 : '';
 const unitLine = (item.discount_amount && item.original_price)
 ? `<s style="color:#B6B0A6;">RM${item.original_price.toFixed(2)}</s> RM${item.price.toFixed(2)} × ${item.quantity}`
 : (__b2bPriced
 ? `<s style="color:#B6B0A6;">RM${Number(item.retail_price).toFixed(2)}</s> RM${item.price.toFixed(2)} × ${item.quantity}`
 : `RM${item.price.toFixed(2)} × ${item.quantity}`);
 // strip leading "SKU | " prefix from product name for cleaner cart display
 const i = item.name.indexOf(' | ');
 const displayName = hesc((i >= 0 ? item.name.slice(i + 3) : item.name).replace(/ _ /g, ' ').trim());
 const discBtn = (item.discount_amount > 0)
   ? `<button onclick="openCartItemDiscount('${item.sku}')" title="Edit diskaun -RM${item.discount_amount.toFixed(2)}" class="cart-tactile" style="background:#FBF3E2; color:#7A5410; border:1px solid #E8C97A; width:40px; height:40px; border-radius:10px; cursor:pointer; display:flex; align-items:center; justify-content:center; flex-shrink:0; position:relative;"><i data-lucide="tag" style="width:15px;height:15px;pointer-events:none;"></i><span style="position:absolute; bottom:-2px; right:-2px; background:#CE9420; color:#fff; font-size:9px; font-weight:800; border-radius:8px; padding:1px 4px; line-height:1.4; pointer-events:none;">-${item.discount_amount.toFixed(0)}</span></button>`
   : `<button onclick="openCartItemDiscount('${item.sku}')" title="Tambah diskaun" class="cart-tactile" style="background:#F5F5F5; color:#9CA3AF; border:1px solid #E0DCDC; width:40px; height:40px; border-radius:10px; cursor:pointer; display:flex; align-items:center; justify-content:center; flex-shrink:0;"><i data-lucide="tag" style="width:15px;height:15px;pointer-events:none;"></i></button>`;
 return `
 <div class="cart-item" style="flex-direction:row; align-items:flex-start; gap:12px; padding:14px 0; background:none; border:none; border-bottom:1px solid #F0EDE8; border-radius:0; margin:0; ${belowFloor ? 'border-left:3px solid #E87060; padding-left:9px;' : ''}">
 ${thumb}
 <div style="flex:1; min-width:0;">
 <div style="display:flex; align-items:flex-start; gap:8px; justify-content:space-between;">
 <div style="flex:1; min-width:0;">
 <div style="font-size:14px; font-weight:700; color:#101010; line-height:1.35; display:-webkit-box; -webkit-line-clamp:2; -webkit-box-orient:vertical; overflow:hidden;">${displayName}</div>
 <div style="font-size:10.5px; color:#B0A898; font-family:'SF Mono',Menlo,monospace; margin-top:2px;">${hesc(item.sku)}</div>
 ${(discBadge || floorBadge || b2bBadge) ? `<div style="margin-top:4px; display:flex; flex-wrap:wrap; gap:4px;">${discBadge}${floorBadge}${b2bBadge}</div>` : ''}
 </div>
 <div style="text-align:right; flex-shrink:0;">
 <div style="font-size:16px; font-weight:800; color:#101010; font-variant-numeric:tabular-nums; letter-spacing:-0.3px;">RM ${lineTotal.toFixed(2)}</div>
 <div style="font-size:10px; color:#9CA3AF; font-variant-numeric:tabular-nums; margin-top:2px;">${unitLine}</div>
 </div>
 </div>
 <div style="display:flex; align-items:center; gap:10px; margin-top:10px;">
 <button onclick="decreaseQuantity('${item.sku}')" aria-label="Kurang kuantiti" class="cart-tactile" style="width:40px; height:40px; min-height:0; border-radius:50%; background:var(--primary-500,#CD7C32); color:#FAF6EF; border:none; font-size:22px; font-weight:800; line-height:1; cursor:pointer; display:flex; align-items:center; justify-content:center; flex-shrink:0; padding:0;">−</button>
 <span style="font-weight:800; min-width:24px; text-align:center; font-variant-numeric:tabular-nums; font-size:16px; color:#101010;">${item.quantity}</span>
 <button onclick="addToCart('${item.sku}')" aria-label="Tambah kuantiti" class="cart-tactile" style="width:40px; height:40px; min-height:0; border-radius:50%; background:var(--primary-500,#CD7C32); color:#FAF6EF; border:none; font-size:22px; font-weight:800; line-height:1; cursor:pointer; display:flex; align-items:center; justify-content:center; flex-shrink:0; padding:0;">+</button>
 ${discBtn}
 <button onclick="removeFromCart('${item.sku}')" aria-label="Buang dari troli" title="Buang dari troli" class="cart-tactile" style="color:#B23A2E; background:none; border:none; min-height:0; width:40px; height:40px; cursor:pointer; display:flex; align-items:center; justify-content:center; flex-shrink:0; padding:0; margin-left:auto;"><i data-lucide="trash-2" style="width:18px;height:18px;pointer-events:none;"></i></button>
 </div>
 </div>
 </div>`;
 }).join('');
 if(window.lucide && lucide.createIcons) try { lucide.createIcons(); } catch(e){}
 if(subLabel) subLabel.textContent = total.toFixed(2);

 // p1_79 fix #3: apply VIP discount preview if posCustomer is a member
 // p1_369 — Zaid: tak nak auto-discount. Gated oleh window.VIP_AUTO_DISCOUNT (default OFF).
 // VIP masih dikenali (badge papar), tapi harga TAK ditolak automatik — staff bagi diskaun manual.
 let discount = 0;
 const cust = window.posCustomer;
 const discLine = document.getElementById('cartDiscountLine');
 if(window.VIP_AUTO_DISCOUNT && cust && cust.is_member && typeof getVipDiscountPercent === 'function') {
 try {
 const pct = parseFloat(getVipDiscountPercent()) || 0;
 if(pct > 0) {
 discount = round2(total * pct / 100);
 const pctEl = document.getElementById('cartDiscountPct');
 const amtEl = document.getElementById('cartDiscountAmt');
 if(pctEl) pctEl.textContent = pct;
 if(amtEl) amtEl.textContent = discount.toFixed(2);
 if(discLine) discLine.style.display = 'flex';
 }
 } catch(e) { discount = 0; }
 }
 if(discount === 0 && discLine) discLine.style.display = 'none';
 const subtotalRow = document.getElementById('cartSubtotalRow');
 if(subtotalRow) subtotalRow.style.display = discount > 0 ? 'flex' : 'none';
 const finalTotal = round2(total - discount);
 label.textContent = finalTotal.toFixed(2);
 const bayarTotalEl = document.getElementById('bayarBtnTotal');
 if(bayarTotalEl) bayarTotalEl.textContent = finalTotal.toFixed(2);
 if(btnPay) btnPay.disabled = false;
 updateMobileBar(finalTotal, totalItems);
 // p4_7 Customer-facing display: broadcast cart for second screen
 if(typeof writeCustomerDisplayCart === 'function') writeCustomerDisplayCart();
}

// p4_7 Customer-facing display sync
window.writeCustomerDisplayCart = function() {
 try {
 const __c = window.posCustomer || null;
 // p1_919 — perkaya item dgn URL gambar (customer display tunjuk gambar + zoom)
 // p1_1149 — imgMap di-CACHE (dulu bina semula 3k produk pada TIAP panggilan — dan fungsi ni
 // dipanggil tiap ketikan medan customer via cpVipLookup); invalidate bila bilangan produk berubah
 let __imgMap = {};
 try {
 if(typeof masterProducts !== 'undefined' && Array.isArray(masterProducts)) {
 if(window.__cdImgMapCache && window.__cdImgMapCache.n === masterProducts.length){
 __imgMap = window.__cdImgMapCache.map;
 } else {
 masterProducts.forEach(p => { const s = (p.sku || '').toUpperCase(); if(!s) return; let im = ''; if(Array.isArray(p.images) && p.images[0]) im = p.images[0]; else if(typeof p.images === 'string' && p.images) im = p.images; if(im) __imgMap[s] = im; });
 window.__cdImgMapCache = { n: masterProducts.length, map: __imgMap };
 }
 }
 } catch(e){}
 const __items = (Array.isArray(cart) ? cart : []).map(it => Object.assign({}, it, { image: __imgMap[(it.sku || '').toUpperCase()] || '' }));
 const payload = {
 items: __items,
 // p1_402 — nama customer untuk greeting skrin pelanggan (sense of belonging)
 customer: __c ? { name: __c.name || null, is_member: !!__c.is_member, tier: __c.tier || __c.member_tier || null } : null,
 vip: window.__currentCheckoutVip || null,
 autoDiscount: !!window.VIP_AUTO_DISCOUNT, // p1_369 — skrin pelanggan ikut flag yang sama
 loyalty: (typeof window.__cpDisplayLoyalty === 'function') ? window.__cpDisplayLoyalty() : null, // p1_1137
 updatedAt: new Date().toISOString()
 };
 localStorage.setItem('customerDisplayCart_v1', JSON.stringify(payload));
 } catch(e) {}
};

