// Payment Modal Logics
window.openPaymentModal = function() {
 if(cart.length === 0) return;
 let total = round2(cart.reduce((sum, c) => sum + (c.price * c.quantity), 0));
 document.getElementById('paymentTotalDisplay').textContent = total.toFixed(2);
 document.getElementById('checkoutPaymentModal').style.display = 'flex';
 // Reset VIP state from any previous session
 window.__currentCheckoutVip = null;
 const vb = document.getElementById('checkoutVipBadge'); if(vb) vb.style.display = 'none';
 // p1_201 — reset custom discount inputs + preview
 const dAmt = document.getElementById('checkoutDiscAmt'); if(dAmt) dAmt.value = '';
 const dType = document.getElementById('checkoutDiscType'); if(dType) dType.value = 'rm';
 const dReason = document.getElementById('checkoutDiscReason'); if(dReason) dReason.value = '';
 const preview = document.getElementById('checkoutTotalPreview'); if(preview) preview.style.display = 'none';
 const vl = document.getElementById('checkoutVipDiscountLine'); if(vl) vl.remove();
 // p1_79 fix #2: pre-fill customer fields if widget has an attached customer
 if(window.posCustomer) {
 const nm = document.getElementById('customerName'); if(nm && !nm.value) nm.value = window.posCustomer.name || '';
 const ph = document.getElementById('customerPhone'); if(ph && !ph.value) ph.value = window.posCustomer.phone || '';
 const em = document.getElementById('customerEmail'); if(em && !em.value) em.value = window.posCustomer.email || '';
 }
 // Auto-lookup if customer name/phone already filled
 if(typeof checkoutVipLookup === 'function') checkoutVipLookup();
}

window.setPaymentMethod = function(method, btnElement) {
 document.getElementById('paymentMethod').value = method;
 // p1_185 — selector was '#checkoutPaymentModal.pay-btn' (compound class) → matched
 // nothing. Should be descendant: '#checkoutPaymentModal .pay-btn'. Visual feedback
 // broken: tapping a payment button never deactivated siblings.
 let btns = document.querySelectorAll('#checkoutPaymentModal .pay-btn');
 btns.forEach(b => {
 b.classList.remove('active');
 b.style.border = "1px solid var(--border-color)";
 b.style.background = "#FFF";
 b.style.color = "var(--text-muted)";
 });
 btnElement.classList.add('active');
 btnElement.style.border = "2px solid var(--primary)";
 btnElement.style.background = "#FFF5eb";
 btnElement.style.color = "var(--text-main)";

 // E-Wallet sub-panel: show & populate dropdown of enabled wallets
 const sub = document.getElementById('ewalletSubPanel');
 if (sub) {
 if (method === 'E-Wallet') {
 sub.style.display = 'block';
 const sel = document.getElementById('ewalletProvider');
 const emptyMsg = document.getElementById('ewalletEmptyMsg');
 if (sel) {
 let settings = {};
 try { settings = JSON.parse(localStorage.getItem('complianceSettings_v1')) || {}; } catch(e){}
 const ew = (settings && settings.ewallet) || {};
 const wallets = [
 { id:'tng', name:'Touch \'n Go eWallet', refPattern: /^\d{16,20}$/, refHint:'16-20 digit' },
 { id:'boost', name:'Boost', refPattern: /^[A-Za-z0-9]{8,}$/, refHint:'min 8 alphanumeric' },
 { id:'grabpay', name:'GrabPay', refPattern: /^[A-Z0-9]{10,}$/i, refHint:'min 10 alphanumeric' },
 { id:'shopeepay', name:'ShopeePay', refPattern: /^[A-Z0-9-]{10,}$/i, refHint:'min 10 alphanumeric' },
 { id:'mae', name:'MAE by Maybank', refPattern: /^\d{6,}$/, refHint:'min 6 digit' }
];
 const enabled = wallets.filter(w => ew[w.id] && ew[w.id].enabled);
 if (enabled.length === 0) {
 // B12: show empty state instead of fallback
 sel.innerHTML = '<option value="">— Configure e-wallets dulu di Compliance —</option>';
 sel.disabled = true;
 if (emptyMsg) emptyMsg.style.display = 'block';
 window.__ewalletPatterns = {};
 } else {
 sel.disabled = false;
 if (emptyMsg) emptyMsg.style.display = 'none';
 sel.innerHTML = '<option value="">— Pilih e-wallet —</option>'
 + enabled.map(w => '<option value="'+w.name+'" data-pattern="'+w.refPattern.source+'" data-hint="'+w.refHint+'">'+w.name+'</option>').join('');
 // Stash patterns for validation in checkout
 window.__ewalletPatterns = {};
 enabled.forEach(w => { window.__ewalletPatterns[w.name] = { pattern: w.refPattern, hint: w.refHint }; });
 }
 }
 const ref = document.getElementById('ewalletRef'); if (ref) ref.value = '';
 } else {
 sub.style.display = 'none';
 }
 }

 // p1_180 — show payment proof upload for any non-Cash method
 const proofSec = document.getElementById('proofUploadSection');
 if(proofSec) {
 proofSec.style.display = (method === 'Cash') ? 'none' : 'block';
 if(method === 'Cash') {
 // Cash → also clear any pending file
 if(typeof window.__proofClearFile === 'function') window.__proofClearFile();
 }
 }
 // p1_230 — Snap Resit camera button manual (Zaid recall: "tak nak auto buka camera, sediakan button je")
 if(window.lucide && lucide.createIcons) lucide.createIcons();
}

// p1_180 — Payment proof file upload state
window.__proofState = { file: null, dataUrl: null };

// p1_920 — KOMPRES gambar resit sebelum upload (3MB foto kamera → ~300KB). Root-cause checkout lambat.
// Resize ke maxDim + JPEG quality; skip PDF/HEIC (canvas tak boleh decode HEIC) — fallback fail asal.
window.__compressImageFile = function(file, maxDim, quality) {
 return new Promise((resolve) => {
  try {
   const t = (file && file.type) || '';
   if(!file || t.indexOf('image/') !== 0 || t === 'image/heic' || t === 'image/heif') { resolve(file); return; }
   maxDim = maxDim || 1600; quality = quality || 0.72;
   const url = URL.createObjectURL(file);
   const img = new Image();
   img.onload = function() {
    try {
     const w = img.naturalWidth, h = img.naturalHeight;
     if(!w || !h) { URL.revokeObjectURL(url); resolve(file); return; }
     const scale = Math.min(1, maxDim / Math.max(w, h));
     const nw = Math.max(1, Math.round(w * scale)), nh = Math.max(1, Math.round(h * scale));
     const canvas = document.createElement('canvas');
     canvas.width = nw; canvas.height = nh;
     const ctx = canvas.getContext('2d');
     ctx.drawImage(img, 0, 0, nw, nh);
     URL.revokeObjectURL(url);
     canvas.toBlob(function(blob) {
      if(!blob || blob.size >= file.size) { resolve(file); return; } // jangan guna kalau jadi lebih besar
      resolve(new File([blob], (file.name || 'resit').replace(/\.[^.]+$/, '') + '.jpg', { type: 'image/jpeg' }));
     }, 'image/jpeg', quality);
    } catch(e) { try { URL.revokeObjectURL(url); } catch(_){} resolve(file); }
   };
   img.onerror = function() { try { URL.revokeObjectURL(url); } catch(_){} resolve(file); };
   img.src = url;
  } catch(e) { resolve(file); }
 });
};

window.__proofPickFile = function(inputEl) {
 // p1_230 — accept input element argument; default to proofFileInput (file picker)
 // Camera input (#proofCameraInput) passes its own ref via onchange="window.__proofPickFile(this)"
 const input = inputEl || document.getElementById('proofFileInput');
 const preview = document.getElementById('proofPreview');
 const img = document.getElementById('proofPreviewImg');
 const meta = document.getElementById('proofPreviewMeta');
 if(!input || !input.files || !input.files[0]) {
 if(preview) preview.style.display = 'none';
 window.__proofState = { file: null, dataUrl: null };
 return;
 }
 const raw = input.files[0];
 // p1_374 — had 10MB (foto iPad/iPhone resolusi tinggi selalu 5-8MB) — semak SEBELUM kompres
 if(raw.size > 10 * 1024 * 1024) {
 if(typeof showToast === 'function') showToast('Saiz fail lebih 10MB. Compress dulu.', 'warn');
 input.value = '';
 return;
 }
 // p1_920 — kompres gambar dulu (3MB → ~300KB) supaya upload checkout laju; PDF/HEIC kekal asal
 const __finish = (f) => {
 const isPdf = (f.type === 'application/pdf');
 window.__proofState.file = f;
 const reader = new FileReader();
 reader.onload = (e) => {
 window.__proofState.dataUrl = e.target.result;
 if(preview && img && meta) {
 if(isPdf) {
 img.style.display = 'none';
 meta.innerHTML = '<i data-lucide="file-text" style="width:14px;height:14px;vertical-align:-2px;"></i> ' + f.name + ' (' + (f.size / 1024).toFixed(0) + ' KB)';
 } else {
 img.src = e.target.result;
 img.style.display = 'block';
 meta.textContent = f.name + ' · ' + (f.size / 1024).toFixed(0) + ' KB';
 }
 preview.style.display = 'block';
 if(window.lucide && lucide.createIcons) lucide.createIcons();
 }
 if(typeof window.cpRefreshProofBadge === 'function') window.cpRefreshProofBadge();
 if(typeof window.__cartProofRefresh === 'function') window.__cartProofRefresh(); // p1_383 cart-screen row
 if(typeof showToast === 'function') showToast(`Resit ditangkap: ${f.name} (${(f.size / 1024).toFixed(0)} KB)`, 'success');
 };
 reader.readAsDataURL(f);
 };
 if(raw.type === 'application/pdf' || typeof window.__compressImageFile !== 'function') { __finish(raw); }
 else { window.__compressImageFile(raw).then(__finish).catch(() => __finish(raw)); }
};

