// Upload to Supabase Storage payment-proofs bucket. Returns public URL or null.
window.__proofUploadToStorage = async function(saleId, fileArg) {
 const f = fileArg || (window.__proofState && window.__proofState.file); // p1_920 — boleh terima fail eksplisit (background)
 if(!f) return null;
 if(typeof db === 'undefined' || !db) return null;
 try {
 const ext = (f.name.split('.').pop() || 'jpg').toLowerCase();
 const ts = new Date().toISOString().replace(/[:.]/g, '-');
 const fileName = (saleId || 'pending') + '_' + ts + '.' + ext;
 // p1_373 — bucket payment-proofs enforce allowed_mime_types; kalau f.type kosong
 // (sesetengah kamera phone), octet-stream akan DITOLAK. Teka dari extension.
 const extMime = { jpg:'image/jpeg', jpeg:'image/jpeg', png:'image/png', webp:'image/webp', heic:'image/heic', heif:'image/heic', pdf:'application/pdf' };
 const contentType = f.type || extMime[ext] || 'image/jpeg';
 const { data, error } = await db.storage.from('payment-proofs').upload(fileName, f, {
 cacheControl: '3600',
 upsert: false,
 contentType: contentType
 });
 if(error) throw error;
 const { data: pub } = db.storage.from('payment-proofs').getPublicUrl(data.path);
 return pub && pub.publicUrl ? pub.publicUrl : null;
 } catch(e) {
 if(typeof showToast === 'function') showToast('Upload resit gagal: ' + e.message, 'warn');
 return null;
 }
};

// p1_920 — Upload resit di BACKGROUND lepas sale commit, kemudian UPDATE row sale.
// Checkout "Processing…" TAK tunggu upload (laju walau wifi teruk). Gagal = staff upload semula dari Reports.
window.__proofUploadAttach = async function(saleId, file) {
 if(!saleId || !file || typeof db === 'undefined' || !db) return;
 try {
  const url = await window.__proofUploadToStorage(saleId, file);
  if(!url) { if(typeof showToast === 'function') showToast('Resit lambat/gagal upload — upload manual dari Reports → Payment Proofs.', 'warn'); return; }
  await db.from('sales_history').update({
   payment_proof_url: url,
   payment_proof_uploaded_at: new Date().toISOString(),
   payment_proof_uploaded_by: (currentUser && currentUser.name) ? currentUser.name : 'Unknown'
  }).eq('id', saleId);
  // kemas-kini in-memori supaya Orders/Reports cermin
  try { if(Array.isArray(salesHistory)) { const r = salesHistory.find(s => s && s.id === saleId); if(r) r.payment_proof_url = url; } } catch(e){}
  if(typeof window.__triggerHeicConvertIfNeeded === 'function') window.__triggerHeicConvertIfNeeded(saleId, url);
  try { if(typeof window.renderPaymentProofs === 'function' && document.getElementById('paymentProofsSection') && document.getElementById('paymentProofsSection').style.display !== 'none') window.renderPaymentProofs(); } catch(e){}
  if(typeof showToast === 'function') showToast('Resit dah dilampirkan ke jualan.', 'success');
 } catch(e) { if(typeof showToast === 'function') showToast('Resit gagal lampir: ' + (e.message || e), 'warn'); }
};

// p1_257 — Auto-trigger HEIC conversion lepas upload (fire-and-forget).
// Function /api/heic-convert detect HEIC + decode → JPEG + UPDATE sales_history.
// UI render initially tunjuk HEIC link (p1_255), pastu lepas conversion (~3-5s) DB
// auto-update ke JPEG URL. Next render tunjuk thumb biasa.
window.__triggerHeicConvertIfNeeded = function(saleId, proofUrl) {
 if(!saleId || !proofUrl) return;
 const urlLower = String(proofUrl).toLowerCase();
 if(!urlLower.endsWith('.heic') && !urlLower.endsWith('.heif')) return;
 console.log('[heic-convert] HEIC detected for sale #' + saleId + ', triggering conversion...');
 if(typeof showToast === 'function') showToast('HEIC detected — auto-convert ke JPEG dalam background (~5s).', 'info');
 try {
 fetch('/api/heic-convert', {
 method: 'POST',
 headers: { 'Content-Type': 'application/json' },
 body: JSON.stringify({ sale_id: saleId })
 }).then(r => r.json()).then(d => {
 if(d.converted) {
 console.log('[heic-convert] converted sale #' + saleId + ' — reduction ' + d.reduction_pct + '%');
 if(typeof showToast === 'function') showToast(`HEIC → JPEG dah convert (reduction ${d.reduction_pct}%). Refresh untuk lihat thumb baru.`, 'success');
 // Auto-refresh Reports/All Orders kalau visible
 if(typeof window.renderPaymentProofs === 'function' && document.getElementById('paymentProofsSection')?.style.display !== 'none') window.renderPaymentProofs();
 if(typeof window.renderAllOrders === 'function' && document.getElementById('allOrdersSection')?.style.display !== 'none') window.renderAllOrders();
 } else if(d.skipped) {
 console.log('[heic-convert] skipped:', d.reason);
 } else if(d.error) {
 console.warn('[heic-convert] failed:', d.error);
 if(typeof showToast === 'function') showToast('HEIC convert gagal: ' + d.error.slice(0, 80), 'warn');
 }
 }).catch(e => console.warn('[heic-convert] fetch error:', e));
 } catch(e) { console.warn('[heic-convert] trigger error:', e); }
};

