// p1_229 — Filter customer list as Zaid types in picker
window.cpkFilterCustomers = function(q) {
 const res = document.getElementById('cpkResults');
 if(!res) return;
 const list = (typeof customersData !== 'undefined' && Array.isArray(customersData)) ? customersData : [];
 const query = (q || '').trim().toLowerCase();
 if(!query) { res.innerHTML = '<p style="color:#9CA3AF; font-size:13px; padding:12px; text-align:center; margin:0;">Taip untuk cari pelanggan...</p>'; return; }
 // p1_482/p1_485 — cari ikut PERKATAAN (token, tak kira susunan) + email + phone normalize.
 // Elak "aliff irfan" gagal padan "Irfan Aliff"; phone 0123/60123/012-345 semua padan.
 const tokens = query.split(/\s+/).filter(Boolean);
 const custMatch = (c) => {
 // 2026-06-25 — masuk company_name + pic_phone supaya B2B boleh dicari ikut nama syarikat di cashier
 const hay = ((c.name || '') + ' ' + (c.company_name || '') + ' ' + (c.phone || '') + ' ' + (c.pic_phone || '') + ' ' + (c.email || '')).toLowerCase();
 const phoneDigits = ((c.phone || '') + (c.pic_phone || '')).replace(/\D/g, '');
 return tokens.every(t => {
  if(hay.includes(t)) return true;
  const td = t.replace(/\D/g, '');
  return td.length >= 3 && phoneDigits && phoneDigits.includes(td); // padan phone walau beza format
 });
 };
 const matches = list.filter(custMatch).slice(0, 30);
 const escHtml = (s) => String(s == null ? '' : s).replace(/&/g,'&amp;').replace(/</g,'&lt;');
 // p1_481 — carian sejarah jualan: pelanggan lama yang TAK wujud dalam CRM pun muncul
 const past = (typeof window.__getPastCustomers === 'function' ? window.__getPastCustomers() : []).filter(custMatch).slice(0, 12);
 window.__pastMatchList = past;
 if(!matches.length && !past.length) { res.innerHTML = `<p style="color:#B23A2E; font-size:13px; padding:12px; text-align:center; margin:0;">Tiada match untuk "${query}". Daftar baru di bawah.</p>`; return; }
 const crmHtml = matches.map(c => {
 const pts = parseInt(c.points || 0);
 const badge = (typeof window.__tierBadgeHtml === 'function' ? window.__tierBadgeHtml(c) : '') + (c.is_member ? '<span style="background:#F8EFD7; color:#7A5410; padding:2px 6px; border-radius:4px; font-size:10px; font-weight:700; margin-left:6px;">VIP</span>' : '') + (c.is_b2b ? '<span style="background:#EEF3EC; color:#34522F; padding:2px 6px; border-radius:4px; font-size:10px; font-weight:700; margin-left:6px;">B2B</span>' : '');
 return `<div onclick="window.cpkPickCustomer(${c.id})" style="padding:10px 14px; border-bottom:1px solid #F3F4F6; cursor:pointer; display:flex; justify-content:space-between; align-items:center;" onmouseover="this.style.background='#F9FAFB'" onmouseout="this.style.background=''">
 <div>
 <div style="font-size:13.5px; font-weight:700; color:#111;">${escHtml(c.is_b2b ? (c.company_name || c.name || '(no name)') : (c.name || '(no name)'))}${badge}</div>
 <div style="font-size:11.5px; color:#6B7280; margin-top:2px;">${escHtml((c.is_b2b ? (c.pic_phone || c.phone) : c.phone) || '-')} · ${pts} pts · RM ${Number(c.total_spent || 0).toFixed(2)} spent</div>
 </div>
 <i data-lucide="chevron-right" style="width:14px; height:14px; color:#9CA3AF;"></i>
 </div>`;
 }).join('');
 const pastHtml = past.length ? (
  '<div style="padding:7px 14px; background:#FAF2E6; font-size:10px; font-weight:800; color:#9A3412; text-transform:uppercase; letter-spacing:0.4px;">Dari jualan lepas (belum dalam CRM)</div>' +
  past.map((c, idx) => {
   const lastStr = c.last ? new Date(c.last).toLocaleDateString('en-MY', { day:'2-digit', month:'short', year:'numeric' }) : '';
   const histLine = `Pernah beli: <strong>${c.orders || 0} order</strong> · RM ${Number(c.spent || 0).toFixed(2)}${lastStr ? ' · akhir ' + lastStr : ''}`;
   return `<div onclick="window.cpkPickPastCustomer(${idx})" style="padding:10px 14px; border-bottom:1px solid #F3F4F6; cursor:pointer; display:flex; justify-content:space-between; align-items:center;" onmouseover="this.style.background='#FFFBF5'" onmouseout="this.style.background=''">
 <div>
 <div style="font-size:13.5px; font-weight:700; color:#111;">${escHtml(c.name || '(tiada nama)')} <span style="background:#F8EFD7; color:#7A5410; padding:1px 6px; border-radius:4px; font-size:9.5px; font-weight:700;">Jualan Lepas</span></div>
 <div style="font-size:11.5px; color:#6B7280; margin-top:2px;">${escHtml(c.phone || '-')}${c.email ? ' · ' + escHtml(c.email) : ''}${c.channel ? ' · ' + escHtml(c.channel) : ''}</div>
 <div style="font-size:11px; color:#3C6438; margin-top:2px;"><i data-lucide="repeat" style="width:11px;height:11px;vertical-align:-1px;"></i> ${histLine}</div>
 </div>
 <i data-lucide="chevron-right" style="width:14px; height:14px; color:#9CA3AF;"></i>
 </div>`;
  }).join('')
 ) : '';
 res.innerHTML = crmHtml + pastHtml;
 if(window.lucide && lucide.createIcons) try { lucide.createIcons(); } catch(e){}
};

window.cpkPickCustomer = function(id) {
 const list = (typeof customersData !== 'undefined' && Array.isArray(customersData)) ? customersData : [];
 const c = list.find(x => x.id === id);
 if(!c) return;
 // p1_235 — kalau picker dibuka dari Edit Sale modal, sync ke ppEdit fields (bukan posCustomer)
 if(window.__ppEditPickerActive) {
 const set = (id, v) => { const el = document.getElementById(id); if(el) el.value = (v == null ? '' : String(v)); };
 set('ppEditCustName', c.name);
 set('ppEditCustPhone', c.phone);
 set('ppEditCustEmail', c.email);
 window.__ppEditPickerActive = false;
 document.getElementById('customerPickerModal').style.display = 'none';
 if(typeof showToast === 'function') showToast(`Customer loaded: ${c.name || c.phone || '-'}`, 'success');
 return;
 }
 window.posSetCustomer(c);
 // p1_234 — kalau checkout panel terbuka, sync ke cpCustName/Phone/Email terus
 if(typeof window.cpSyncCustomerFromPos === 'function') window.cpSyncCustomerFromPos();
 document.getElementById('customerPickerModal').style.display = 'none';
 if(typeof showToast === 'function') showToast(`Customer attached: ${c.name || c.phone || '-'}`, 'success');
};

// p1_481 — bina senarai pelanggan dari SEJARAH JUALAN yang belum wujud dalam CRM
// (walk-in/marketplace yang tak pernah didaftar). Dedup ikut phone (atau nama kalau
// takde phone), ambil detail terkini. Cache per-buka-picker (reset di posAttachCustomer).
window.__pastCustomersCache = window.__pastCustomersCache || null;
window.__getPastCustomers = function() {
 if(window.__pastCustomersCache) return window.__pastCustomersCache;
 const crmPhones = new Set((typeof customersData !== 'undefined' ? customersData : []).map(c => (c.phone || '').replace(/[^0-9]/g, '')).filter(Boolean));
 const sales = (typeof salesHistory !== 'undefined' && Array.isArray(salesHistory)) ? salesHistory : [];
 const map = new Map(); // key → {name, phone, email, channel, last, lastT, orders, spent}
 sales.forEach(s => {
  if(s.is_test) return;
  const md = s.metadata || {};
  const name = (s.customer_name || '').trim();
  const phone = (s.customer_phone || '').trim();
  const email = (s.customer_email || md.buyer_email || '').trim();
  if(!name && !phone) return;
  const phoneNorm = phone.replace(/[^0-9]/g, '');
  if(phoneNorm && crmPhones.has(phoneNorm)) return; // dah ada dalam CRM
  const key = phoneNorm || ('nm:' + name.toLowerCase());
  const t = new Date(s.created_at || 0).getTime();
  const real = (typeof window.__isRealSale === 'function') ? window.__isRealSale(s) : !s.is_test;
  let e = map.get(key);
  if(!e) { e = { name, phone, email, channel: s.channel || '', last: s.created_at || null, lastT: t, orders: 0, spent: 0 }; map.set(key, e); }
  // simpan detail PALING TERKINI (nama/phone/email/channel)
  if(t >= e.lastT) { e.lastT = t; e.last = s.created_at || null; if(s.channel) e.channel = s.channel; if(name) e.name = name; if(phone) e.phone = phone; if(email) e.email = email; }
  if(real) { e.orders += 1; e.spent += (Number(s.total_amount || s.total || 0) || 0); }
 });
 const out = Array.from(map.values()).sort((a, b) => b.lastT - a.lastT);
 window.__pastCustomersCache = out;
 return out;
};

// p1_481 — pilih pelanggan dari hasil carian jualan lepas → attach detail (synthetic, tiada CRM id)
