// Apply capability-based mode tab visibility
window.applyRoleCapabilities = function(allowedModes) {
 document.querySelectorAll('.mode-tab').forEach(tab => {
 const m = tab.getAttribute('data-mode-set');
 const allowed = !allowedModes || allowedModes.includes(m);
 tab.style.display = allowed ? '' : 'none';
 tab.disabled = !allowed;
 });
};

// p1_162 — Preview landing page while logged in (view as customer)
window.previewLanding = function() {
 const shop = document.getElementById('shopAppLayout');
 const pos = document.getElementById('posAppLayout');
 if(!shop || !pos) return;
 shop.style.display = 'block';
 pos.style.display = 'none';
 // p1_656 — some back-office .tab-section (e.g. managerDashboardSection/analytics) sit OUTSIDE
 // posAppLayout due to a pre-existing HTML div imbalance, so pos=none doesn't hide them and they
 // LEAK below the landing in preview. Hide every .tab-section here; remember the active one to restore.
 window.__previewPrevSection = null;
 document.querySelectorAll('.tab-section').forEach(el => {
  if(el.style.display && el.style.display !== 'none') window.__previewPrevSection = el.id;
  el.style.display = 'none';
 });
 // Inject floating "Back to POS" banner
 let banner = document.getElementById('previewBackBanner');
 if(!banner) {
 banner = document.createElement('div');
 banner.id = 'previewBackBanner';
 banner.innerHTML = `<div style="position:fixed; top:0; left:0; right:0; z-index:99999; background:linear-gradient(135deg, var(--primary) 0%, var(--primary-700,#A05F22) 100%); color:#FFF; padding:10px 16px; display:flex; align-items:center; justify-content:space-between; gap:12px; box-shadow:0 2px 8px rgba(0,0,0,.2); font-size:13px;">
 <div style="display:flex; align-items:center; gap:8px;">
 <i data-lucide="eye" style="width:14px; height:14px;"></i>
 <strong>Preview Mode</strong> — Tengok landing page macam customer
 </div>
 <button onclick="window.backToPOS()" style="background:#FFF; color:var(--primary); border:none; padding:7px 16px; border-radius:6px; font-size:12px; font-weight:800; cursor:pointer; display:inline-flex; align-items:center; gap:6px;"><i data-lucide="arrow-left" style="width:12px; height:12px;"></i> Kembali ke POS</button>
 </div>`;
 document.body.appendChild(banner);
 }
 banner.style.display = 'block';
 // Add top padding to landing so banner doesn't overlap content
 shop.style.paddingTop = '50px';
 try { if(typeof window.__caShow === 'function') window.__caShow(true); } catch(e){} // p1_812 — preview = tunjuk widget AI customer
 window.scrollTo({ top: 0, behavior: 'smooth' });
 if(window.lucide && lucide.createIcons) lucide.createIcons();
};

window.backToPOS = function() {
 const shop = document.getElementById('shopAppLayout');
 const pos = document.getElementById('posAppLayout');
 const banner = document.getElementById('previewBackBanner');
 if(shop) { shop.style.display = 'none'; shop.style.paddingTop = ''; }
 if(pos) pos.style.display = 'block';
 try { if(typeof window.__caShow === 'function') window.__caShow(false); } catch(e){} // p1_812 — balik POS = sorok widget AI customer
 // p1_656 — restore the section that was active before preview
 if(window.__previewPrevSection){ const sec = document.getElementById(window.__previewPrevSection); if(sec) sec.style.display = 'block'; }
 if(banner) banner.style.display = 'none';
 window.scrollTo({ top: 0 });
};

function handleLogout() {
 // p1_71: also sign out of Supabase Auth so email/password session cleared
 // p1_1090 — scope 'local' WAJIB: default supabase-js ialah 'global' yang revoke sesi akaun
 // yang sama di SEMUA device (Tukar Staf kat iPad = staf tercampak keluar kat phone sendiri,
 // nampak macam "site down"). 'local' padam sesi device ini sahaja.
 try { window.__expectSignOut = Date.now(); } catch(e){}
 try { if(db && db.auth && db.auth.signOut) db.auth.signOut({ scope: 'local' }); } catch(e){}
 // p1_1089 — logout = batal status peranti peribadi (device balik jadi kongsi, wajib PIN)
 try { if(typeof window.__clearPersonalDevice === 'function') window.__clearPersonalDevice(); } catch(e){}
 try { if(typeof window.__saShow === 'function') { window.__saShow(false); window.__saHistory = []; } } catch(e){} // p1_795 — sorok widget AI + reset bila logout
 try { if(typeof window.__caShow === 'function') window.__caShow(true); } catch(e){} // p1_812 — landing balik = tunjuk widget AI customer
 currentUser = null;
 currentUserRole = null;
 try { window.currentUser = null; } catch(e){} // p1_1090 — jangan tinggal rujukan basi selepas logout
 // p1_1011 — dalam app (iPad kaunter): JANGAN hempas ke storefront customer. Sorok kedua-dua
 // layout, biar skrin kunci PIN (dibuka di hujung fungsi) yang jadi paparan. Web/desktop kekal.
 if(window.__isPOSApp) {
  document.getElementById("shopAppLayout").style.display = "none";
  document.getElementById("posAppLayout").style.display = "none";
 } else {
  document.getElementById("shopAppLayout").style.display = "block";
  document.getElementById("posAppLayout").style.display = "none";
 }
 document.body.classList.remove('pos-app-scoped'); // p1_545 — sorok top/bottom bar native bila logout
 // p1_554 — kunci semula laporan sulit (PIN 1999) supaya staf seterusnya tak warisi unlock
 try { sessionStorage.removeItem('confUnlocked_v1'); } catch(e){}
 window.__confUnlockedMem = false;
 const sessEl = document.getElementById("sessionUsername");
 if(sessEl) sessEl.textContent = "POS10C";
 try { const whoEl = document.getElementById('posAppWho'); if(whoEl) whoEl.style.display = 'none'; } catch(e){} // p1_1010
 document.getElementById("appSidebar")?.classList.remove('open');
 document.getElementById("sidebarOverlay")?.classList.remove('active');

 document.querySelectorAll(".tab-section").forEach(el => el.style.display = "none");

 // Reset all role-style inline hides (next login starts fresh)
 document.querySelectorAll(".sales-only,.inv-only,.mgmt-only,.boss-only")
.forEach(el => el.style.display = "");
 document.body.classList.remove('is-boss-user'); // p1_1176 — staf seterusnya tak warisi papan Bos

 // Reset mode-tab capability gating
 document.querySelectorAll('.mode-tab').forEach(tab => { tab.style.display = ''; tab.disabled = false; });

 // Close panels/modals that may be lingering
 ['checkoutPanel','staffWelcomeModal','cmdkOverlay','onboardingOverlay','pinLoginOverlay']
.forEach(id => { const el = document.getElementById(id); if(el) el.style.display = 'none'; });
 document.getElementById('checkoutPanelOverlay')?.classList.remove('is-open');
 document.getElementById('checkoutPanel')?.classList.remove('is-open');

 // Reset cart
 if(typeof cart !== 'undefined') { cart.length = 0; if(typeof renderCart === 'function') renderCart(); }

 // p1_1011 — dalam app: terus tunjuk skrin kunci PIN (bukan storefront). Dipanggil AKHIR sebab
 // blok atas baru sorok pinLoginOverlay. Web/desktop: storefront dah dipapar, tak buka auto.
 if(window.__isPOSApp && typeof handleLogin === 'function') { try { handleLogin(); } catch(e){} }
}

