// p1_337 — tukar status order belum bayar (Dah Bayar / Batal)
window.__abSetStatus = async function(id, newStatus) {
 if(typeof db === 'undefined' || !db) return;
 if(!confirm(`Tukar order #${id} kepada "${newStatus}"?`)) return;
 try {
 const { error } = await db.from('sales_history').update({ status: newStatus }).eq('id', id);
 if(error) throw error;
 const s = (typeof salesHistory !== 'undefined') ? salesHistory.find(x => x.id === id) : null;
 if(s) s.status = newStatus;
 // p1_554 (#3) — pulangkan stok kalau order jadi dead-status (abaikan kalau memang belum pernah deduct; helper idempotent)
 if(s && typeof window.__restockSaleIfVoided === 'function') await window.__restockSaleIfVoided(s, newStatus);
 if(typeof showToast === 'function') showToast(`Order #${id} → ${newStatus}.`, 'success');
 window.renderAbandonedCheckouts();
 window.__aoUpdateOrderBadge && window.__aoUpdateOrderBadge();
 } catch(e) { if(typeof showToast === 'function') showToast('Gagal: ' + (e.message || e), 'error'); }
};

// p1_341 — FIFO Listing: batch stok aktif disusun ikut inbound_date (lama dulu = FIFO)
window.renderFifoListing = function() {
 const tbody = document.getElementById('fifoTbody');
 if(!tbody) return;
 if(typeof inventoryBatches === 'undefined' || !Array.isArray(inventoryBatches)) {
 tbody.innerHTML = '<tr><td colspan="8" style="text-align:center; color:#999; padding:32px;">Loading...</td></tr>';
 return;
 }
 const esc = (v) => String(v == null ? '' : v).replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;').replace(/"/g,'&quot;');
 const q = (document.getElementById('fifoSearch')?.value || '').trim().toLowerCase();
 const nameOf = (sku) => { const p = (typeof masterProducts !== 'undefined' && Array.isArray(masterProducts)) ? masterProducts.find(x => x.sku === sku) : null; return p ? (p.name || '') : ''; };
 const ageDays = (iso) => iso ? Math.floor((Date.now() - new Date(iso).getTime()) / 86400000) : 0;
 let rows = inventoryBatches.filter(b => (Number(b.qty_remaining) || 0) > 0);
 if(q) rows = rows.filter(b => (b.sku || '').toLowerCase().includes(q) || nameOf(b.sku).toLowerCase().includes(q));
 rows.sort((a, b) => (a.inbound_date || '').localeCompare(b.inbound_date || '')); // lama dahulu = FIFO
 // p1_885 — nombor batch SEBENAR per SKU = urutan shipment ikut tarikh, dikira ATAS SEMUA batch
 // (termasuk yang dah habis) supaya #1 = kali PERTAMA produk masuk. Paparan #B/1–N: B=shipment,
 // 1–N = julat unit individu (1..qty_received). Tiap unit = SKU #B/u.
 const __batchNoAll = new Map(); const __cntBySku = {};
 inventoryBatches.slice().sort((a, b) => (String(a.sku||'')).localeCompare(String(b.sku||'')) || (a.inbound_date || '').localeCompare(b.inbound_date || '') || ((a.id||0) - (b.id||0)))
   .forEach(b => { __cntBySku[b.sku] = (__cntBySku[b.sku] || 0) + 1; __batchNoAll.set(b.id, __cntBySku[b.sku]); });
 const totalUnits = rows.reduce((s, b) => s + (Number(b.qty_remaining) || 0), 0);
 const totalValue = rows.reduce((s, b) => s + (Number(b.qty_remaining) || 0) * (Number(b.cost_price || b.landed_cost) || 0), 0);
 const aging = rows.filter(b => ageDays(b.inbound_date) >= 180).length;
 document.getElementById('fifoStats').innerHTML = `
 <div class="stat-card" style="border-left-color:var(--primary);"><div class="stat-card__label"><i data-lucide="layers" style="width:13px;height:13px; color:var(--primary);"></i> Batch Aktif</div><div class="stat-card__value">${rows.length.toLocaleString()}</div></div>
 <div class="stat-card" style="border-left-color:#4E7C4A;"><div class="stat-card__label"><i data-lucide="boxes" style="width:13px;height:13px; color:#4E7C4A;"></i> Jumlah Unit</div><div class="stat-card__value">${totalUnits.toLocaleString()}</div></div>
 <div class="stat-card" style="border-left-color:var(--primary-500,#CD7C32);"><div class="stat-card__label"><i data-lucide="banknote" style="width:13px;height:13px; color:var(--primary-500,#CD7C32);"></i> Nilai Kos</div><div class="stat-card__value">RM ${totalValue.toLocaleString(undefined,{minimumFractionDigits:2,maximumFractionDigits:2})}</div></div>
 <div class="stat-card" style="border-left-color:#B23A2E;" title="Batch lebih 180 hari — patut diutamakan jual / clearance"><div class="stat-card__label"><i data-lucide="alert-triangle" style="width:13px;height:13px; color:#B23A2E;"></i> Batch Lama (>180h)</div><div class="stat-card__value">${aging.toLocaleString()}</div></div>
 `;
 if(!rows.length) {
 tbody.innerHTML = '<tr><td colspan="9" style="text-align:center; color:#999; padding:32px;">Tiada batch stok aktif' + (q ? ' untuk carian ni' : '') + '.</td></tr>';
 document.getElementById('fifoSummaryLine').textContent = '';
 if(window.lucide && lucide.createIcons) try { lucide.createIcons(); } catch(e){}
 return;
 }
 tbody.innerHTML = rows.slice(0, 500).map(b => {
 const age = ageDays(b.inbound_date);
 const ageColor = age >= 180 ? '#B23A2E' : (age >= 90 ? '#7A5410' : '#6B7280');
 const dt = b.inbound_date ? new Date(b.inbound_date).toLocaleDateString('en-MY', {day:'2-digit', month:'short', year:'numeric'}) : '-';
 const cost = Number(b.cost_price || b.landed_cost) || 0;
 const poSup = [b.po_number, b.supplier_name].filter(Boolean).join(' · ');
 const bn = __batchNoAll.get(b.id) || 1;
 const recv = Number(b.qty_received) || 0;
 const skuJs = String(b.sku || '').replace(/'/g, "\\'");
 return `<tr>
 <td style="padding:10px; text-align:center; white-space:nowrap;" title="Shipment ke-${bn} (ikut tarikh) · unit 1 hingga ${recv}. Tiap unit = ${esc(b.sku||'')} #${bn}/u">
   <div style="font-weight:800; color:#7A5410;">#${bn}/1–${recv}</div>
   <button onclick="event.stopPropagation(); window.__unitLabelsPrint('${skuJs}', ${bn}, ${recv})" title="Cetak label barcode tiap unit batch ni" style="margin-top:4px; background:#FBEFE2; border:1px solid #E7C8A8; color:#7A5410; border-radius:5px; font-size:10px; font-weight:700; padding:2px 7px; cursor:pointer;"><i data-lucide="tag" style="width:10px;height:10px;vertical-align:-1px;"></i> Label</button>
 </td>
 <td style="padding:10px; white-space:nowrap;">${esc(dt)}</td>
 <td style="padding:10px; font-family:'SF Mono',Menlo,monospace; font-size:11.5px;"><div style="display:flex;align-items:center;gap:7px;">${window.__skuThumbHtml ? window.__skuThumbHtml(b.sku, 28) : ''}${esc(b.sku || '-')}</div></td>
 <td style="padding:10px;">${esc(nameOf(b.sku).slice(0, 45) || '-')}</td>
 <td style="padding:10px; text-align:right; font-weight:700;">${Number(b.qty_remaining) || 0}</td>
 <td style="padding:10px; text-align:right; color:#6B7280;">${Number(b.qty_received) || 0}</td>
 <td style="padding:10px; text-align:right;">RM ${cost.toFixed(2)}</td>
 <td style="padding:10px; text-align:center; font-weight:700; color:${ageColor};">${age}h</td>
 <td style="padding:10px; font-size:11.5px; color:#6B7280;">${esc(poSup || '-')}${(b.do_link_assumed && poSup) ? ' <span style="color:#7A5410; cursor:help;" title="SKU ada dalam beberapa shipment — diandaikan shipment terkini (FIFO)">~</span>' : ''}</td>
 </tr>`;
 }).join('');
 document.getElementById('fifoSummaryLine').innerHTML = `${rows.length.toLocaleString()} batch aktif${rows.length > 500 ? ' (papar 500 teratas)' : ''}. Disusun lama dahulu (FIFO).`;
 if(window.lucide && lucide.createIcons) try { lucide.createIcons(); } catch(e){}
};

// =============================================================
// p1_882 — Terima Stok (Receive): cipta batch ikut TARIKH MENDARAT (FIFO).
// Ringkas: pilih SKU → qty + kos (auto dari product_landed_cost) + tarikh mendarat → batch.
// =============================================================
window.__receiveOpen = function(){
 const m = document.getElementById('receiveStockModal'); if(!m) return;
 const dl = document.getElementById('receiveSkuList');
 if(dl && typeof masterProducts !== 'undefined' && Array.isArray(masterProducts)){
  dl.innerHTML = masterProducts.slice(0, 2500).map(p => '<option value="' + String(p.sku||'').replace(/"/g,'&quot;') + '">' + String(p.name||'').replace(/"/g,'&quot;').slice(0,52) + '</option>').join('');
 }
 ['receiveSku','receiveQty','receiveCost','receiveSupplier','receiveRef'].forEach(id => { const e = document.getElementById(id); if(e) e.value = ''; });
 const d = document.getElementById('receiveDate'); if(d) d.value = new Date().toISOString().split('T')[0];
 const info = document.getElementById('receiveSkuInfo'); if(info) info.textContent = '';
 const ch = document.getElementById('receiveCostHint'); if(ch) ch.textContent = '';
 m.style.display = 'flex';
 if(window.lucide && lucide.createIcons) try { lucide.createIcons(); } catch(e){}
};
window.__receiveClose = function(){ const m = document.getElementById('receiveStockModal'); if(m) m.style.display = 'none'; };
window.__receiveSkuPick = async function(){
 const sku = (document.getElementById('receiveSku').value || '').trim();
 const info = document.getElementById('receiveSkuInfo');
 const costHint = document.getElementById('receiveCostHint');
 if(!info) return;
 if(!sku){ info.textContent = ''; return; }
 const prod = (typeof masterProducts !== 'undefined') ? masterProducts.find(p => p.sku === sku) : null;
 if(!prod){ info.innerHTML = '<span style="color:#B23A2E;">SKU tak wujud dalam Master Produk.</span>'; return; }
 const date = (document.getElementById('receiveDate').value || '').trim();
 const batches = (typeof inventoryBatches !== 'undefined' ? inventoryBatches : []).filter(b => b.sku === sku);
 const liveQty = batches.filter(b => (Number(b.qty_remaining)||0) > 0).reduce((s,b) => s + (Number(b.qty_remaining)||0), 0);
 // nombor batch ikut tarikh mendarat: berapa batch SKU ni yang mendarat SEBELUM/SAMA tarikh dipilih, +1
 const rankByDate = date ? (batches.filter(b => (b.inbound_date||'') <= date).length + 1) : (batches.length + 1);
 info.innerHTML = '<strong>' + String(prod.name||'').slice(0,46) + '</strong> · stok kini ' + liveQty + ' · akan jadi <strong style="color:#7A5410;">Batch #' + rankByDate + '</strong> (ikut tarikh)';
 // auto-isi kos sekali (kalau belum diisi) — dari product_landed_cost, fallback master cost
 const costEl = document.getElementById('receiveCost');
 if(costEl && !costEl.value && typeof db !== 'undefined' && db){
  try {
   const { data } = await db.from('product_landed_cost').select('cost_rm').eq('sku', sku).maybeSingle();
   if(data && data.cost_rm){ costEl.value = Number(data.cost_rm).toFixed(2); if(costHint) costHint.textContent = 'Kos auto dari rekod landed cost (boleh ubah).'; }
   else { const fb = Number(prod.cost_price || 0); if(fb > 0){ costEl.value = fb.toFixed(2); if(costHint) costHint.textContent = 'Kos auto dari Master Produk (boleh ubah).'; } else if(costHint) costHint.textContent = 'Tiada kos tersimpan — sila isi manual.'; }
  } catch(e){}
 }
};
window.__receiveSave = async function(){
 const sku = (document.getElementById('receiveSku').value || '').trim();
 const qty = parseInt(document.getElementById('receiveQty').value) || 0;
 const cost = parseFloat(document.getElementById('receiveCost').value);
 const date = (document.getElementById('receiveDate').value || '').trim();
 const supplier = (document.getElementById('receiveSupplier').value || '').trim();
 const ref = (document.getElementById('receiveRef').value || '').trim();
 if(!sku || qty <= 0) return showToast('SKU & kuantiti wajib.', 'warn');
 if(!date) return showToast('Tarikh mendarat wajib (tentukan urutan batch).', 'warn');
 const prod = (typeof masterProducts !== 'undefined') ? masterProducts.find(p => p.sku === sku) : null;
 if(!prod) return showToast('SKU tak wujud dalam Master Produk.', 'warn');
 if(typeof db === 'undefined' || !db) return showToast('Tiada sambungan.', 'error');
 const btn = document.getElementById('receiveSaveBtn'); if(btn){ btn.disabled = true; btn.textContent = '…'; }
 try {
  const payload = { sku, qty_received: qty, qty_remaining: qty, inbound_date: date, batch_year: parseInt(date.slice(0,4)) || null };
  if(!isNaN(cost) && cost > 0){ payload.cost_price = cost; payload.landed_cost = cost; }
  if(supplier) payload.supplier_name = supplier;
  if(ref){ payload.notes = ref; payload.delivery_order_ref = ref; }
  const { data, error } = await db.from('inventory_batches').insert([payload]).select();
  if(error) throw error;
  // kemaskini global supaya stok + FIFO + Cashier update tanpa reload penuh
  if(Array.isArray(data) && data[0] && typeof inventoryBatches !== 'undefined' && Array.isArray(inventoryBatches)) inventoryBatches.push(data[0]);
  try {
   await db.from('inventory_transactions').insert([{ sku, transaction_type: 'IN', qty_change: qty, reason: 'Terima Stok' + (supplier ? ' from ' + supplier : '') + (ref ? ' (' + ref + ')' : '') + (cost ? ' @ RM' + cost.toFixed(2) : '') + ' · landed ' + date, staff_name: (typeof currentUser !== 'undefined' && currentUser) ? currentUser.name : 'System', created_at: new Date().toISOString() }]);
  } catch(e){}
  showToast('+' + qty + ' ' + sku + ' diterima — batch ' + date + (cost ? ' @ RM' + cost.toFixed(2) : ''), 'success');
  window.__receiveClose();
  if(typeof renderFifoListing === 'function') renderFifoListing();
  try { if(typeof renderStockLevels === 'function') renderStockLevels(); } catch(e){}
  try { if(typeof renderPOS === 'function') renderPOS((document.getElementById('searchInput')||{}).value || ''); } catch(e){}
 } catch(e){ showToast('Ralat Terima Stok: ' + e.message, 'error'); }
 finally { if(btn){ btn.disabled = false; btn.innerHTML = '<i data-lucide="check" style="width:15px;height:15px;vertical-align:-2px;"></i> Terima &amp; Cipta Batch'; if(window.lucide && lucide.createIcons) try { lucide.createIcons(); } catch(e){} } }
};

// =============================================================
// p1_883 — Rekonsiliasi Stok: ke mana stok pergi? Asas = lejar batch.
// Diterima(Σqty_received) − Stok kini(Σqty_remaining) = Consumed. Consumed dijelaskan oleh
// Jualan(OUTBOUND_SALE) + pergerakan keluar (Display/Rental/SCUD/Return-Rosak/Lain dari
// inventory_transactions) + returns_log. Baki tak terjelas = belum direkod / hilang.
// FASA 1: guna data POS sedia ada. Tepat penuh selepas import DO + sejarah CUD/CUR/SCUD/R&R (Fasa 2).
// =============================================================
window.__reconRows = [];
window.renderStockRecon = async function(){
 const tbody = document.getElementById('reconTbody'); if(!tbody) return;
 if(typeof inventoryBatches === 'undefined' || !Array.isArray(inventoryBatches)){ tbody.innerHTML = '<tr><td colspan="12" style="text-align:center;color:#999;padding:32px;">Loading...</td></tr>'; return; }
 // fetch movements + returns (cache 90s supaya tak fetch tiap taip carian)
 const now = Date.now();
 if(!window.__reconCache || (now - (window.__reconCacheAt||0)) > 90000){
  tbody.innerHTML = '<tr><td colspan="12" style="text-align:center;color:#999;padding:32px;">Mengira pergerakan stok…</td></tr>';
  let txns = [], rets = [], doItems = [];
  try { if(typeof db !== 'undefined' && db){
   // p1_1092 — paged: inventory_transactions 1,503 + delivery_order_items 1,050 baris —
   // .limit(besar) dipotong server pada 1000, recon Diterima/CUD kurang senyap.
   txns = await window.__fetchAllRows('inventory_transactions', 'id', true, { select: 'sku,transaction_type,qty_change,reason' });
   rets = await window.__fetchAllRows('returns_log', 'id', true, { select: 'sku,qty' });
   doItems = await window.__fetchAllRows('delivery_order_items', 'id', true, { select: 'sku,qty' });
  }} catch(e){ console.warn('recon fetch', e); }
  window.__reconCache = { txns, rets, doItems }; window.__reconCacheAt = now;
 }
 const { txns, rets, doItems } = window.__reconCache;
 // p1_886 — Diterima = JUMLAH DO sebenar (sepanjang hayat); fallback batch qty_received kalau takde DO.
 const doTotal = {};
 (doItems||[]).forEach(d => { if(!d.sku) return; doTotal[d.sku] = (doTotal[d.sku]||0) + (Number(d.qty)||0); });
 // Jualan = sepanjang hayat dari salesHistory (real sales sahaja)
 const salesBySku = {};
 (typeof salesHistory !== 'undefined' && Array.isArray(salesHistory) ? salesHistory : []).forEach(s => {
  if(typeof window.__isRealSale === 'function' && !window.__isRealSale(s)) return;
  let items = s.items; if(typeof items === 'string'){ try { items = JSON.parse(items); } catch(e){ items = []; } }
  (Array.isArray(items) ? items : []).forEach(it => { const sk = it.sku; if(!sk) return; const qy = parseInt(it.qty || it.quantity || 1) || 0; salesBySku[sk] = (salesBySku[sk]||0) + qy; });
 });
 const nameOf = (sku) => { const p = (typeof masterProducts !== 'undefined' && Array.isArray(masterProducts)) ? masterProducts.find(x => x.sku === sku) : null; return p ? (p.name || '') : ''; };
 const agg = {};
 const ensure = (sku) => agg[sku] || (agg[sku] = { sku, received:0, onhand:0, costSum:0, costQty:0, sales:0, display:0, rental:0, scud:0, retdmg:0, lost:0, other:0 });
 inventoryBatches.forEach(b => { if(!b.sku) return; const a = ensure(b.sku); const qr = Number(b.qty_received)||0, rem = Number(b.qty_remaining)||0; a.received += qr; a.onhand += rem; const c = Number(b.cost_price || b.landed_cost)||0; if(c>0 && qr>0){ a.costSum += c*qr; a.costQty += qr; } });
 (txns||[]).forEach(t => {
  if(!t.sku || !agg[t.sku]) { if(!t.sku) return; }
  const a = ensure(t.sku);
  const qc = Number(t.qty_change)||0; const tt = (t.transaction_type||'').toUpperCase(); const rs = (t.reason||'').toLowerCase();
  if(tt === 'OUTBOUND_SALE') return; // jualan dikira dari salesHistory (sepanjang hayat), elak double
  if(qc >= 0) return; // IN / receiving / pelarasan-tambah — jangan kira (received dari DO/batch)
  const out = Math.abs(qc);
  if(/hilang|lost/.test(rs)) a.lost += out;
  else if(/scud/.test(rs)) a.scud += out;
  else if(/display|cud/.test(rs)) a.display += out;
  else if(/rental|sewa|\bcur\b|\bcr\b/.test(rs)) a.rental += out;
  else if(/rosak|defect|return|refund|r&r|pulangan|pecah/.test(rs)) a.retdmg += out;
  else a.other += out;
 });
 (rets||[]).forEach(r => { if(!r.sku) return; const a = ensure(r.sku); a.retdmg += Math.abs(Number(r.qty)||0); });
 // pastikan SKU yang ada DO (diterima sebenar) turut masuk walau tiada batch
 Object.keys(doTotal).forEach(sku => ensure(sku));
 const q = (document.getElementById('reconSearch')?.value || '').trim().toLowerCase();
 const gapOnly = !!(document.getElementById('reconGapOnly')?.checked);
 // p1_886 — finalisasi: Diterima = DO total (fallback batch qty_received), Jualan = sepanjang hayat
 const finalize = (a) => {
  const sales = salesBySku[a.sku] || 0;
  const movements = a.display + a.rental + a.scud + a.retdmg + a.lost + a.other;
  // p1_888 — Diterima MUSTAHIL kurang dari (jualan + pergerakan + stok kini) — tak boleh jual/guna/simpan
  // lebih dari yang diterima. Floor di situ supaya takde "Tak Terjelas" negatif palsu (cth DO tak lengkap).
  // Tak Terjelas = berapa LEBIH diterima (DO/batch) dari yang dikira keluar = kerugian sebenar belum direkod (>=0).
  const impliedReceived = sales + movements + a.onhand;
  // p1_889 — JANGAN guna batch qty_received sbg "Diterima": ia DIGELEMBUNG oleh batch stock-check
  // (stock take cipta batch BARU utk padan kiraan fizikal, batch lama kekal qty_received tapi baki 0
  // → sum qty_received jadi 2x). Guna DO total + floor (jualan+pergerakan+stok) sahaja.
  const received = Math.max(doTotal[a.sku] || 0, impliedReceived);
  const unexplained = received - sales - movements - a.onhand;
  const avgCost = a.costQty ? (a.costSum / a.costQty) : 0;
  return Object.assign(a, { received, sales, unexplained, avgCost, name: nameOf(a.sku) });
 };
 let rows = Object.values(agg).map(finalize);
 if(q) rows = rows.filter(r => (r.sku||'').toLowerCase().includes(q) || (r.name||'').toLowerCase().includes(q));
 if(gapOnly) rows = rows.filter(r => r.unexplained !== 0);
 rows.sort((x,y) => Math.abs(y.unexplained) - Math.abs(x.unexplained) || (x.sku||'').localeCompare(y.sku||''));
 window.__reconRows = rows;
 // KPIs (atas SEMUA SKU, bukan ikut carian)
 const all = Object.values(agg);
 const withGap = all.filter(r => r.unexplained !== 0);
 const totalGapUnits = all.reduce((s,r) => s + Math.abs(r.unexplained), 0);
 const totalGapVal = all.reduce((s,r) => s + Math.abs(r.unexplained) * (r.avgCost||0), 0);
 const totalLost = all.reduce((s,r) => s + (r.lost||0), 0);
 const kpis = document.getElementById('reconKpis');
 if(kpis) kpis.innerHTML =
   '<div class="stat-card" style="border-left-color:var(--primary);"><div class="stat-card__label"><i data-lucide="package" style="width:13px;height:13px;color:var(--primary);"></i> SKU Dipantau</div><div class="stat-card__value">' + all.length.toLocaleString() + '</div></div>'
 + '<div class="stat-card" style="border-left-color:#B23A2E;"><div class="stat-card__label"><i data-lucide="search-x" style="width:13px;height:13px;color:#B23A2E;"></i> Hilang (Lost Count)</div><div class="stat-card__value" style="color:#B23A2E;">' + totalLost.toLocaleString() + '</div></div>'
 + '<div class="stat-card" style="border-left-color:#B23A2E;"><div class="stat-card__label"><i data-lucide="alert-triangle" style="width:13px;height:13px;color:#B23A2E;"></i> SKU Ada Beza</div><div class="stat-card__value">' + withGap.length.toLocaleString() + '</div></div>'
 + '<div class="stat-card" style="border-left-color:#B23A2E;"><div class="stat-card__label"><i data-lucide="boxes" style="width:13px;height:13px;color:#B23A2E;"></i> Unit Tak Terjelas</div><div class="stat-card__value">' + totalGapUnits.toLocaleString() + '</div></div>'
 + '<div class="stat-card" style="border-left-color:#7A5410;"><div class="stat-card__label"><i data-lucide="banknote" style="width:13px;height:13px;color:#7A5410;"></i> Nilai (anggaran)</div><div class="stat-card__value">RM ' + totalGapVal.toLocaleString(undefined,{minimumFractionDigits:2,maximumFractionDigits:2}) + '</div></div>';
 if(!rows.length){ tbody.innerHTML = '<tr><td colspan="12" style="text-align:center;color:#999;padding:32px;">Tiada SKU' + (q||gapOnly ? ' padan tapisan' : '') + '.</td></tr>'; }
 else {
  const cell = (v) => v ? v.toLocaleString() : '<span style="color:#D1D5DB;">·</span>';
  tbody.innerHTML = rows.slice(0, 600).map(r => {
   const gapColor = r.unexplained > 0 ? '#B23A2E' : (r.unexplained < 0 ? '#7A5410' : '#345E43');
   const gapTxt = r.unexplained === 0 ? '<span style="color:#345E43;">0 ✓</span>' : (r.unexplained > 0 ? '−' + r.unexplained : '+' + Math.abs(r.unexplained));
   return '<tr>'
    + '<td class="l" style="font-family:\'SF Mono\',Menlo,monospace;font-weight:700;font-size:11.5px;"><div style="display:flex;align-items:center;gap:7px;">' + (window.__skuThumbHtml ? window.__skuThumbHtml(r.sku, 26) : '') + (r.sku||'-') + '</div></td>'
    + '<td class="l" style="color:#374151;">' + (String(r.name||'').slice(0,38) || '-') + '</td>'
    + '<td style="font-weight:600;">' + cell(r.received) + '</td>'
    + '<td>' + cell(r.sales) + '</td>'
    + '<td>' + cell(r.display) + '</td>'
    + '<td>' + cell(r.rental) + '</td>'
    + '<td>' + cell(r.scud) + '</td>'
    + '<td>' + cell(r.retdmg) + '</td>'
    + '<td style="' + (r.lost ? 'color:#B23A2E;font-weight:800;' : '') + '">' + cell(r.lost) + '</td>'
    + '<td>' + cell(r.other) + '</td>'
    + '<td style="font-weight:700;">' + cell(r.onhand) + '</td>'
    + '<td class="recon-gap" style="color:' + gapColor + ';">' + gapTxt + '</td>'
    + '</tr>';
  }).join('');
 }
 const sum = document.getElementById('reconSummary');
 if(sum) sum.innerHTML = rows.length.toLocaleString() + ' SKU' + (rows.length > 600 ? ' (papar 600 teratas ikut beza terbesar)' : '') + '. <strong>Tak Terjelas</strong> = unit diterima yang TAK dapat dikira (kerugian sebenar belum direkod). <span style="color:#9a948b;">Diterima = MAX(DO total, jualan+pergerakan+stok) — mustahil kurang dari yang dah keluar/ada, jadi takde negatif palsu. SKU habis-jual = 0 (semua terjelas). Batch qty_received tak diguna (digelembung stock-check).</span>';
 if(window.lucide && lucide.createIcons) try { lucide.createIcons(); } catch(e){}
};
window.__reconExport = function(){
 const rows = window.__reconRows || [];
 if(!rows.length) return (typeof showToast==='function') && showToast('Tiada data untuk eksport.', 'warn');
 const head = ['SKU','Produk','Diterima','Jualan','Display_CUD','Rental_CUR','SCUD','Return_Rosak','Hilang','Lain','Stok_Kini','Tak_Terjelas'];
 const esc = (v) => '"' + String(v==null?'':v).replace(/"/g,'""') + '"';
 const lines = [head.join(',')].concat(rows.map(r => [r.sku, r.name, r.received, r.sales, r.display, r.rental, r.scud, r.retdmg, r.lost, r.other, r.onhand, r.unexplained].map(esc).join(',')));
 const blob = new Blob([lines.join('\n')], { type:'text/csv;charset=utf-8;' });
 const url = URL.createObjectURL(blob); const a = document.createElement('a');
 a.href = url; a.download = 'rekonsiliasi-stok.csv'; a.click(); URL.revokeObjectURL(url);
};

// =============================================================
// p1_885 — Label barcode PER UNIT: SKU #batch/unit (cth MG012 #1/1 .. #1/22).
// Tiap unit fizikal dapat identiti sendiri (SKU + shipment# + nombor unit). Cetak sticker barcode.
// Kod barcode = SKU-B-U (scanner-safe); teks manusia = SKU #B/u.
// =============================================================
window.__unitLabelsPrint = function(sku, batchNo, qty){
 qty = Number(qty) || 0; batchNo = Number(batchNo) || 1;
 if(qty <= 0) return (typeof showToast==='function') && showToast('Batch ni tiada unit diterima.', 'warn');
 if(qty > 300 && !window.confirm(qty + ' label akan dijana untuk ' + sku + ' batch #' + batchNo + '. Teruskan?')) return;
 const prod = (typeof masterProducts !== 'undefined') ? masterProducts.find(p => p.sku === sku) : null;
 let nm = prod ? (prod.name || '') : '';
 nm = nm.replace(/^[A-Z0-9-]+\s*[|_]\s*/i, '').split(/\s*\|\s*/)[0].replace(/\s*[_]\s*/g,' ').trim().slice(0, 40);
 const esc = (s) => String(s==null?'':s).replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;').replace(/"/g,'&quot;');
 const w = window.open('', '_blank');
 if(!w) return (typeof showToast==='function') && showToast('Popup disekat — benarkan popup untuk cetak label.', 'warn');
 let cards = '';
 for(let u = 1; u <= qty; u++){
  const code = sku + '-' + batchNo + '-' + u;           // scannable (CODE128)
  const human = esc(sku) + ' #' + batchNo + '/' + u;    // identiti unit (papar)
  cards += '<div class="lbl"><div class="h">10 CAMP</div><div class="nm">' + esc(nm) + '</div><svg class="bc" data-code="' + esc(code) + '"></svg><div class="uid">' + human + '</div></div>';
 }
 w.document.write('<html><head><title>Label ' + esc(sku) + ' #' + batchNo + '</title>'
  + '<scr' + 'ipt src="https://cdn.jsdelivr.net/npm/jsbarcode@3.11.6/dist/JsBarcode.all.min.js"></scr' + 'ipt>'
  + '<style>'
  + 'body{font-family:sans-serif;margin:0;padding:10px;}'
  + '.bar{position:fixed;top:8px;right:8px;z-index:9;}'
  + '@media print{.bar{display:none;}}'
  + '.info{font-size:12px;color:#444;margin:0 0 10px;}'
  + '.grid{display:flex;flex-wrap:wrap;gap:6px;}'
  + '.lbl{width:48mm;height:30mm;border:1px solid #ccc;box-sizing:border-box;padding:3px;display:flex;flex-direction:column;align-items:center;justify-content:center;text-align:center;page-break-inside:avoid;}'
  + '.h{font-weight:900;font-size:11px;line-height:1.1;}'
  + '.nm{font-size:8px;font-weight:bold;line-height:1.1;max-height:20px;overflow:hidden;}'
  + '.bc{max-width:92%;height:auto;}'
  + '.uid{font-size:11px;font-weight:800;letter-spacing:.3px;line-height:1.1;}'
  + '</style></head><body>'
  + '<button class="bar" onclick="window.print()" style="padding:9px 18px;background:var(--primary-500,#CD7C32);color:#fff;border:0;border-radius:6px;font-weight:bold;cursor:pointer;">Print</button>'
  + '<p class="info">' + esc(sku) + (nm ? ' — ' + esc(nm) : '') + ' · Batch #' + batchNo + ' · ' + qty + ' unit (' + esc(sku) + ' #' + batchNo + '/1 … #' + batchNo + '/' + qty + ')</p>'
  + '<div class="grid">' + cards + '</div>'
  + '<scr' + 'ipt>window.onload=function(){document.querySelectorAll("svg.bc").forEach(function(s){try{JsBarcode(s,s.getAttribute("data-code"),{format:"CODE128",width:1.3,height:30,displayValue:false,margin:2});}catch(e){}});setTimeout(function(){window.print();},600);};</scr' + 'ipt>'
  + '</body></html>');
 w.document.close();
};

