// p1_280 — Collapsible nav groups (toggle + persistence)
window.toggleNavGroup = function(name, event) {
 if(event && event.stopPropagation) event.stopPropagation();
 const parent = document.querySelector('[data-nav-parent="' + name + '"]');
 if(!parent) return;
 const isExpanded = parent.classList.toggle('is-expanded');
 try {
 const state = JSON.parse(localStorage.getItem('navGroupState') || '{}');
 state[name] = isExpanded;
 localStorage.setItem('navGroupState', JSON.stringify(state));
 } catch(e){}
};

// p1_286 — tapping the "Orders" parent jumps straight to All Orders (Zaid:
// "bila tekan order, aku nak kau terus visiblekan all order"). Unlike other
// nav parents (toggle-only since p1_281), the Orders parent expands its submenu
// AND opens the All Orders section in a single tap.
window.openOrdersHub = function(event) {
 if(event && event.stopPropagation) event.stopPropagation();
 const parent = document.querySelector('[data-nav-parent="orders"]');
 // p1_316 — toggle: if already open, just COLLAPSE (so Orders can be closed);
 // if closed, expand + jump to All Orders.
 const willOpen = !(parent && parent.classList.contains('is-expanded'));
 if(parent) {
 parent.classList.toggle('is-expanded', willOpen);
 try {
 const st = JSON.parse(localStorage.getItem('navGroupState') || '{}');
 st.orders = willOpen;
 localStorage.setItem('navGroupState', JSON.stringify(st));
 } catch(e){}
 }
 if(!willOpen) return; // collapsing — don't navigate
 const aoItem = document.querySelector('[data-tab="sales_all_orders"]');
 if(typeof switchHub === 'function') switchHub(['allOrdersSection'], 'All Orders', aoItem || null);
 if(typeof window.renderAllOrders === 'function') window.renderAllOrders();
};

// p1_371 — Cashier parent: tekan = buka POS register + expand sub-items (POS / Commission);
// tekan lagi = collapse je (boleh tutup/buka). Corak sama macam openOrdersHub.
window.openCashierHub = function(event) {
 if(event && event.stopPropagation) event.stopPropagation();
 const parent = document.querySelector('[data-nav-parent="cashier"]');
 const willOpen = !(parent && parent.classList.contains('is-expanded'));
 if(parent) {
 parent.classList.toggle('is-expanded', willOpen);
 try {
 const st = JSON.parse(localStorage.getItem('navGroupState') || '{}');
 st.cashier = willOpen;
 localStorage.setItem('navGroupState', JSON.stringify(st));
 } catch(e){}
 }
 if(!willOpen) return; // collapsing — don't navigate
 const posItem = document.querySelector('[data-nav-children="cashier"] [data-tab="nav_cashier"]');
 if(typeof switchHub === 'function') switchHub(['posSection'], 'POS / Cashier', posItem || null);
};

window.restoreNavGroupState = function() {
 let state = {};
 try { state = JSON.parse(localStorage.getItem('navGroupState') || '{}'); } catch(e){}
 const groups = document.querySelectorAll('[data-nav-parent]');
 groups.forEach(function(p) {
 const n = p.getAttribute('data-nav-parent');
 // p1_281 — All collapsed by default; only persisted expand state restores
 if(state[n] === true) p.classList.add('is-expanded');
 else p.classList.remove('is-expanded');
 });
};

// Restore on DOM ready + a fallback after a tick (icons load after main parse)
if(typeof document !== 'undefined') {
 document.addEventListener('DOMContentLoaded', function() {
 setTimeout(window.restoreNavGroupState, 50);
 setTimeout(window.restoreNavGroupState, 500);
 });
}
// p1_272 — _p271_void removed (orphan body had `await` outside async, broke parse)
async function _p271_void() {
 if(!currentUser) return;
 const btn = document.getElementById("floatingClockBtn");
 const lbl = document.getElementById("lblClockFace");
 if(!btn || !lbl) return;
 btn.style.display = "flex";

 const today = new Date().toISOString().split('T')[0];

 const setState = (state, text, title, locked) => {
 btn.setAttribute('data-state', state);
 lbl.textContent = text;
 btn.title = title;
 btn.style.pointerEvents = locked ? 'none' : '';
 btn.style.opacity = locked ? '0.6' : '';
 };

 if(db) {
 let { data, error } = await db.from('staff_attendance').select('*').eq('staff_name', currentUser.name).eq('date', today);
 if(data && data.length > 0) {
 let record = data[0];
 if(record.clock_out_time) {
 currentAttendanceStatus = "OUT";
 setState('done', 'Done', 'Anda dah clock-out hari ini', true);
 } else {
 currentAttendanceStatus = "IN";
 setState('working', 'Clock Out', 'Sedang bekerja — click untuk clock out', false);
 }
 } else {
 currentAttendanceStatus = null;
 setState('idle', 'Clock In', 'Click untuk clock in', false);
 }
 }
}

window.setPremiseLocation = function() {
 if(!navigator.geolocation) return alert("Browser tak support GPS.");
 navigator.geolocation.getCurrentPosition(pos => {
 let lat = pos.coords.latitude;
 let lng = pos.coords.longitude;
 localStorage.setItem("premise_lat", lat);
 localStorage.setItem("premise_lng", lng);
 alert(`Koordinat Kedai diset pada:\nLat: ${lat}\nLng: ${lng}`);
 document.getElementById("txtPremiseDist").textContent = "400";
 }, err => alert("Gagal dpt GPS: " + err.message));
}

window.openClockModal = function() {
 let pLat = localStorage.getItem("premise_lat") || 2.9250;
 let pLng = localStorage.getItem("premise_lng") || 101.6570;
 let radius = 400; // 400 meters

 document.getElementById("clockInOutModal").style.display = "flex";
 const statusTxt = document.getElementById("clockModalStatus");
 const btn = document.getElementById("btnSubmitAttendance");
 const video = document.getElementById("clockVideoFeed");
 const loadTxt = document.getElementById("cameraLoadingText");

 statusTxt.textContent = " Mengesan koordinat GPS anda...";
 statusTxt.style.color = "var(--primary-700,#A05F22)";
 statusTxt.style.background = "var(--primary-50,#FFF8F0)";
 btn.style.display = "none";
 video.style.display = "none";
 loadTxt.style.display = "block";

 navigator.geolocation.getCurrentPosition(pos => {
 let cLat = pos.coords.latitude;
 let cLng = pos.coords.longitude;
 let dist = calculateDistance(pLat, pLng, cLat, cLng);

 if(dist <= radius) {
 statusTxt.textContent = ` Disahkan: Anda berada ${Math.round(dist)}m dari Premis. Mengaktifkan Kamera...`;
 statusTxt.style.color = "#345E43";
 statusTxt.style.background = "#E4EFE2";
 
 // Invoke Camera
 navigator.mediaDevices.getUserMedia({ video: { facingMode: "user" }, audio: false })
.then(stream => {
 clockStream = stream;
 video.srcObject = stream;
 video.style.display = "block";
 loadTxt.style.display = "none";
 btn.style.display = "block";
 btn.disabled = false;
 })
.catch(err => {
 statusTxt.textContent = " Kamera Gagal Diakses. Sila allow permission.";
 statusTxt.style.color = "#7C2A20";
 statusTxt.style.background = "#F4E4DF";
 loadTxt.textContent = "Akses Ditolak";
 });

 } else {
 statusTxt.textContent = ` Terkeluar Jarak! Anda sejauh ${Math.round(dist)}m (Maksima ${radius}m).`;
 statusTxt.style.color = "#7C2A20";
 statusTxt.style.background = "#F4E4DF";
 loadTxt.textContent = "Kamera tidak diperlukan";
 }

 }, err => {
 statusTxt.textContent = " Gagal mengesan GPS anda. Pastikan Location dibenarkan.";
 statusTxt.style.color = "#7C2A20";
 statusTxt.style.background = "#F4E4DF";
 }, { enableHighAccuracy: true });
}

window.closeClockModal = function() {
 if(clockStream) {
 clockStream.getTracks().forEach(t => t.stop());
 }
 document.getElementById("clockInOutModal").style.display = "none";
}

window.submitAttendance = async function() {
 const video = document.getElementById("clockVideoFeed");
 const canvas = document.getElementById("clockSnapshotCanvas");
 const btn = document.getElementById("btnSubmitAttendance");
 
 btn.textContent = " Memproses Rekod...";
 btn.disabled = true;

 // Squeeze Image
 canvas.width = 300;
 canvas.height = 300;
 let ctx = canvas.getContext("2d");
 
 // Crop center
 let size = Math.min(video.videoWidth, video.videoHeight);
 let sx = (video.videoWidth - size) / 2;
 let sy = (video.videoHeight - size) / 2;
 ctx.drawImage(video, sx, sy, size, size, 0, 0, 300, 300);
 
 // Convert base64
 let b64 = canvas.toDataURL("image/jpeg", 0.5); 
 
 let timeStr = new Date().toTimeString().split(' ')[0];
 let today = new Date().toISOString().split('T')[0];

 if(!db) { alert("Tiada akses DB."); closeClockModal(); return; }

 if(currentAttendanceStatus === "IN") {
 // Must Clock Out
 let { error } = await db.from('staff_attendance')
.update({ clock_out_time: timeStr, clock_out_photo: b64 })
.eq('staff_name', currentUser.name).eq('date', today);
 
 if(!error) { alert("Berjaya Clock-Out!"); }
 else { alert("Gagal Clock-Out: " + (error.message || JSON.stringify(error))); }
 } else {
 // Must Clock In
 let { error } = await db.from('staff_attendance')
.insert([{ staff_name: currentUser.name, date: today, clock_in_time: timeStr, clock_in_photo: b64 }]);
 
 if(!error) { alert("Berjaya Clock-In. Mulakan kerja anda!"); }
 else { alert("Gagal Clock-In: " + (error.message || JSON.stringify(error))); }
 }
 
 closeClockModal();
 checkMyAttendanceStatus();
 if(typeof loadAdminAttendance === 'function') loadAdminAttendance();
}

window.loadAdminAttendance = async function() {
 const tbody = document.getElementById("attendanceAdminTbody");
 const distT = document.getElementById("txtPremiseDist");
 if(distT) distT.textContent = (localStorage.getItem("premise_lat") ? "400" : "400");
 
 if(!tbody || !db) return;
 
 const today = new Date().toISOString().split('T')[0];
 let { data, error } = await db.from('staff_attendance').select('*').eq('date', today);
 
 if(error) {
 tbody.innerHTML = `<tr><td colspan="6" style="text-align:center; padding:10px; color:red;">RALAT PANGKALAN DATA: ${error.message}. Adakah jadual ini belum dicipta?</td></tr>`;
 return;
 }
 
 if(!data || data.length === 0) {
 tbody.innerHTML = '<tr><td colspan="6" style="text-align:center; padding:10px;">Belum ada staf clock in hari ini.</td></tr>';
 return;
 }
 
 let html = "";
 data.forEach(r => {
 let p1 = r.clock_in_photo ? `<img src="${r.clock_in_photo}" style="width:40px; height:40px; border-radius:50%; object-fit:cover;">` : "-";
 let p2 = r.clock_out_photo ? `<img src="${r.clock_out_photo}" style="width:40px; height:40px; border-radius:50%; object-fit:cover;">` : "-";
 
 let warnAuto = r.is_auto_clockout ? `<br><small style="color:red;">(Auto 8PM)</small>` : "";
 let cout = r.clock_out_time ? (r.clock_out_time + warnAuto) : "-";

 html += `
 <tr>
 <td style="font-weight:bold;">${r.staff_name}</td>
 <td>${r.date}</td>
 <td style="color:#101010;">${r.clock_in_time}</td>
 <td>${p1}</td>
 <td style="color:#B23A2E;">${cout}</td>
 <td>${p2}</td>
 </tr>
 `;
 });
 tbody.innerHTML = html;
}

// p1_1169 (Zaid 21 Jul) — kadar komisen DEFAULT ikut tarikh jualan: 5% sebelum 1 Sep 2026,
// 3% mulai jualan 1 Sep 2026 (dibayar gaji Okt). Berlaku KEDUA-DUA channel (in-store + live).
// 3% BUKAN muktamad — akan dinilai semula bila data cukup. Tukar cutover/kadar di sini sahaja.
window.__COMM_RATE_CUTOVER_YM = '2026-09'; // jualan mulai bulan ni = kadar baru
window.__COMM_RATE_BEFORE = 5;             // sebelum cutover
window.__COMM_RATE_AFTER  = 3;             // mulai cutover
window.__commDefaultRate = function(forDate){
 let ym;
 try {
  if(forDate == null){ const n=new Date(); ym = n.getFullYear()+'-'+String(n.getMonth()+1).padStart(2,'0'); }
  else if(typeof forDate === 'string'){ const m = forDate.match(/^(\d{4})-(\d{2})/); if(m){ ym = m[1]+'-'+m[2]; } else { const d=new Date(forDate); ym = d.getFullYear()+'-'+String(d.getMonth()+1).padStart(2,'0'); } }
  else { const d = (forDate instanceof Date)?forDate:new Date(forDate); ym = d.getFullYear()+'-'+String(d.getMonth()+1).padStart(2,'0'); }
 } catch(e){ ym = '2026-01'; }
 return ym >= window.__COMM_RATE_CUTOVER_YM ? window.__COMM_RATE_AFTER : window.__COMM_RATE_BEFORE;
};
// p4_1: per-staff commission rate lookup with fallback chain (forDate → kadar default ikut tarikh)
function __getCommissionRate(staffName, forDate) {
 const u = (typeof authUsers !== 'undefined' && Array.isArray(authUsers))
 ? authUsers.find(a => a.name === staffName) : null;
 const sid = u ? u.staff_id : null;
 // p1_729 — Commission Report = TUNJANG: kadar dari server (cache merentas peranti) jadi
 // sumber utama. Cashier "My Commission" baca kadar sama ni (view sahaja).
 const server = window.__commissionRatesServer || {};
 if (sid && server[sid] !== undefined && server[sid] !== null && server[sid] !== '') return parseFloat(server[sid])||0;
 // fallback: localStorage (offline / belum sync), lepas tu kadar statik user, lepas tu global
 let rates = {}; try { rates = JSON.parse(localStorage.getItem('staffCommissionRates_v1')||'{}'); } catch(e){}
 if (sid && rates[sid] !== undefined) return parseFloat(rates[sid])||0;
 if (u && u.commission_rate !== undefined) return parseFloat(u.commission_rate)||0;
 // p1_1169 — TIADA override staf: default ikut tarikh jualan (5% sebelum Sep 2026, 3% mulai Sep 2026)
 return window.__commDefaultRate ? window.__commDefaultRate(forDate) : 5;
}
// p1_729 — Muat peta kadar komisen dari server (staff_report_submissions, satu baris config).
// Report yang tulis; semua view (termasuk cashier My Commission) baca dari sini = single source.
window.__commissionRatesServer = window.__commissionRatesServer || {};
window.__loadCommissionRates = async function() {
 try {
 if(typeof db === 'undefined' || !db) { window.__commissionRatesLoaded = true; return; }
 const { data } = await db.from('staff_report_submissions')
 .select('payload').eq('submission_type','commission_rates').eq('period_key','global').maybeSingle();
 if(data && data.payload && data.payload.rates) {
 window.__commissionRatesServer = data.payload.rates;
 try { localStorage.setItem('staffCommissionRates_v1', JSON.stringify(data.payload.rates)); } catch(e){}
 } else {
 // Belum ada config server — migrate kadar localStorage sedia ada (one-time) supaya tak hilang
 let local = {}; try { local = JSON.parse(localStorage.getItem('staffCommissionRates_v1')||'{}'); } catch(e){}
 window.__commissionRatesServer = local;
 if(Object.keys(local).length) {
 try { await db.from('staff_report_submissions').upsert({
 staff_id:'__commission_rates', staff_name:'Commission Rates Config',
 submission_type:'commission_rates', period_key:'global',
 payload:{ rates: local, migrated:true }, submitted_at:new Date().toISOString(), bos_read_at:null
 }, { onConflict:'staff_id,submission_type,period_key' }); } catch(e){}
 }
 }
 } catch(e) { console.warn('load commission rates failed:', e.message); }
 window.__commissionRatesLoaded = true;
};

// p1_451 — Base komisen = UNIT SKU berjaya terjual (harga sebenar dibayar), Zaid:
// "komisen 5% pada setiap 1 unit sku berjaya terjual, BUKAN 5% pada total resit".
// Base = jumlah (harga × qty − diskaun item) merentas semua item produk.
// SENGAJA buang shipping/tax/caj peringkat-resit (bukan unit SKU).
// Pulangan bertanda negatif utk baris refund (total resit negatif) supaya komisen dipatah balik.
window.__saleCommissionBase = function(s) {
 if (!s) return 0;
 let items = s.items;
 if (typeof items === 'string') { try { items = JSON.parse(items); } catch(e){ items = null; } }
 if (!Array.isArray(items)) return 0;
 let base = 0;
 items.forEach(it => {
 const price = Number(it.price || 0) || 0;
 const qty = Number(it.qty != null ? it.qty : (it.quantity != null ? it.quantity : 1)) || 0;
 const disc = Number(it.discount || 0) || 0;
 base += (price * qty - disc);
 });
 // p1_554 — tolak diskaun peringkat-ORDER (custom + VIP) dari metadata. Diskaun ni tak dibahagi
 // ke item, jadi tanpa potongan ni komisen dikira atas hasil yang bisnes tak terima (#24).
 let __meta = s.metadata;
 if (typeof __meta === 'string') { try { __meta = JSON.parse(__meta); } catch(e){ __meta = null; } }
 if (__meta) base -= (Number(__meta.custom_discount_amount) || 0) + (Number(__meta.vip_discount_amount) || 0);
 if (base < 0) base = 0;
 base = round2(base);
 const recv = parseFloat(s.total_amount || s.total || 0) || 0;
 return recv < 0 ? -base : base;
};

// Commission period state
window.__cmRange = window.__cmRange || 'month';
window.__cmSetRange = function(range, btn) {
 window.__cmRange = range;
 document.querySelectorAll('.cm-pill').forEach(p => p.classList.toggle('active', p === btn));
 renderPersonalCommission();
};

function __cmGetDateRange() {
 const now = new Date();
 const startOf = (d) => { const x = new Date(d); x.setHours(0,0,0,0); return x; };
 const endOf = (d) => { const x = new Date(d); x.setHours(23,59,59,999); return x; };
 const r = window.__cmRange || 'month';
 if (r === 'month') { const s = new Date(now.getFullYear(), now.getMonth(), 1); return { start:startOf(s), end:endOf(now), label: now.toLocaleDateString('en-MY', {month:'long', year:'numeric'}) }; }
 if (r === 'lastmonth') { const s = new Date(now.getFullYear(), now.getMonth()-1, 1); const e = new Date(now.getFullYear(), now.getMonth(), 0); return { start:startOf(s), end:endOf(e), label: s.toLocaleDateString('en-MY', {month:'long', year:'numeric'}) }; }
 if (r === 'week') { const s = new Date(now); s.setDate(s.getDate() - s.getDay()); return { start:startOf(s), end:endOf(now), label: 'This week' }; }
 if (r === 'ytd') { const s = new Date(now.getFullYear(), 0, 1); return { start:startOf(s), end:endOf(now), label: now.getFullYear() + ' YTD' }; }
 return { start: null, end: null, label: 'All time' };
}

// p1_458 — Komisen SEMUA staf hanya boleh dilihat oleh role 'mgmt' (Zaid, Aliff,
// Farhan, Zack — Zaid sahkan Zack & Farhan OK). Staf sales/inventory (Ariff/Irfan/
// Tarmizi/Fahmi) hanya nampak komisen SENDIRI sahaja.
window.__cmCanViewAll = function(u) {
 u = u || (typeof currentUser !== 'undefined' ? currentUser : null);
 if (!u) return false;
 return u.role === 'mgmt';
};
// p1_622 — Export transaksi komisen tempoh semasa ke CSV. Manager+PIN unlock = semua staff; lain = sendiri.
window.__cmExport = function(forceOwn) {
 if (!currentUser) return;
 // p1_734 — forceOwn=true (cth dari My Commission) → export SENDIRI sahaja walau Bos
 const isMgr = !forceOwn && (window.__cmCanViewAll && window.__cmCanViewAll(currentUser)) && (window.__confIsUnlocked && window.__confIsUnlocked());
 const range = __cmGetDateRange();
 const all = (Array.isArray(salesHistory) ? salesHistory : []).filter(s => {
   if (s.is_test) return false;
   const st = (s.status || '').toLowerCase();
   if (st.indexOf('cancel') !== -1 || st.indexOf('void') !== -1) return false;
   if (!range.start || !range.end) return true;
   const t = s.created_at ? new Date(s.created_at).getTime() : 0;
   return t >= range.start.getTime() && t <= range.end.getTime();
 });
 const rows = isMgr ? all : all.filter(s => s.staff_name === currentUser.name);
 if (!rows.length) return (window.showToast || alert)('Tiada transaksi komisen untuk tempoh ni.', 'warn');
 const esc = (v) => { const s = String(v == null ? '' : v); return /[",\n]/.test(s) ? '"' + s.replace(/"/g, '""') + '"' : s; };
 rows.sort((a, b) => new Date(a.created_at || 0) - new Date(b.created_at || 0));
 const lines = [['Tarikh','Order #','Staff','Customer','Channel','Jenis','Base (RM)','Rate (%)','Komisen (RM)'].join(',')];
 let sumBase = 0, sumComm = 0;
 rows.forEach(s => {
   const recv = parseFloat(s.total_amount || s.total || 0) || 0;
   const base = Math.abs(window.__saleCommissionBase(s));
   const isRefund = recv < 0;
   const signedBase = isRefund ? -base : base;
   const rate = __getCommissionRate(s.staff_name || '', s.created_at); // p1_1169 — kadar ikut tarikh jualan
   const comm = round2(signedBase * rate / 100);
   sumBase = round2(sumBase + signedBase); sumComm = round2(sumComm + comm);
   const dt = s.created_at ? new Date(s.created_at).toLocaleString('en-MY', {day:'2-digit',month:'short',year:'numeric',hour:'2-digit',minute:'2-digit'}) : '';
   lines.push([esc(dt), esc(s.order_no || s.order_number || s.id || ''), esc(s.staff_name || ''), esc(s.customer_name || ''), esc(s.channel || ''), isRefund ? 'Refund' : 'Jualan', signedBase.toFixed(2), rate, comm.toFixed(2)].join(','));
 });
 lines.push('');
 lines.push([esc(''),esc(''),esc(''),esc(''),esc(''),esc('JUMLAH'),sumBase.toFixed(2),esc(''),sumComm.toFixed(2)].join(','));
 const blob = new Blob(['﻿' + lines.join('\n')], {type:'text/csv;charset=utf-8;'});
 const url = URL.createObjectURL(blob);
 const a = document.createElement('a');
 const who = isMgr ? 'SemuaStaff' : (currentUser.name || 'staff').replace(/[^A-Za-z0-9]/g, '');
 a.href = url; a.download = 'Komisen_' + who + '_' + String(range.label || '').replace(/[^A-Za-z0-9]/g, '') + '.csv';
 document.body.appendChild(a); a.click(); document.body.removeChild(a); URL.revokeObjectURL(url);
 (window.showToast || function(){})('Export ' + rows.length + ' transaksi komisen siap.', 'success');
};

