window.__crLoadUnclaimed = async function() {
 const host = document.getElementById('crUnclaimList'); if(!host) return;
 if(typeof db === 'undefined' || !db) { host.innerHTML = 'DB tak tersedia.'; return; }
 const esc = (typeof hesc === 'function') ? hesc : (s)=>String(s==null?'':s);
 const ym = window.__crUnclaimMonth || '2026-05';
 const parts = ym.split('-'); const y = Number(parts[0]); const mo = Number(parts[1]);
 const start = ym + '-01';
 const end = (mo>=12 ? (y+1)+'-01-01' : y+'-'+String(mo+1).padStart(2,'0')+'-01');
 host.style.textAlign='center'; host.style.padding='18px'; host.innerHTML = 'Memuatkan…';
 let data;
 try {
  const r = await db.from('sales_history').select('id,created_at,customer_name,total_amount,total,channel,staff_name,status').gte('created_at', start).lt('created_at', end).order('created_at',{ascending:true}).limit(3000);
  if(r.error) throw r.error; data = r.data || [];
 } catch(e) { host.innerHTML = '<span style="color:#B23A2E;">Gagal muat: ' + esc(e.message) + '</span>'; return; }
 const rows = data.filter(o => {
  const ch=(o.channel||'').toLowerCase(); const isWalk = ch.indexOf('cashier')!==-1 || ch.indexOf('walk')!==-1;
  const noStaff = !o.staff_name || !String(o.staff_name).trim();
  const st=(o.status||'').toLowerCase(); const okStatus = !(st.indexOf('cancel')!==-1 || st.indexOf('void')!==-1);
  return isWalk && noStaff && okStatus;
 });
 if(!rows.length) { host.innerHTML = '<i data-lucide="check-circle" style="width:26px;height:26px;color:#345E43;"></i><p style="margin:8px 0 0; font-size:13px; color:#374151;">Tiada jualan walk-in tak dituntut untuk ' + esc(ym) + '. Semua dah ada staf.</p>'; if(window.lucide) try{lucide.createIcons();}catch(e){} return; }
 const opts = window.__crStaffOptions();
 const optHtml = (uid) => '<select data-uid="' + uid + '" style="padding:5px 7px; border:1px solid var(--primary-500,#CD7C32); border-radius:6px; font-size:12px; min-width:130px;"><option value="">— pilih staf —</option>' + opts.map(n=>'<option value="'+esc(n)+'">'+esc(n)+'</option>').join('') + '</select>';
 let total=0; let body='';
 rows.forEach(o => {
  const rm = parseFloat(o.total_amount||o.total||0)||0; total+=rm;
  const dt = o.created_at ? new Date(o.created_at).toLocaleDateString('en-MY',{day:'2-digit',month:'short'}) : '-';
  body += '<tr style="border-bottom:1px solid #F3F4F6;"><td style="padding:7px 9px; white-space:nowrap; color:#6B7280;">' + dt + '</td>'
   + '<td style="padding:7px 9px; font-family:monospace; font-size:11px; color:var(--primary-600,#B86A26);">#' + o.id + '</td>'
   + '<td style="padding:7px 9px;">' + esc(String(o.customer_name||'Walk-In').slice(0,28)) + '</td>'
   + '<td style="padding:7px 9px; text-align:right; font-weight:700; white-space:nowrap;">RM ' + rm.toFixed(2) + '</td>'
   + '<td style="padding:7px 9px;">' + optHtml(o.id) + '</td></tr>';
 });
 host.style.textAlign='left'; host.style.padding='0';
 host.innerHTML = '<div style="overflow-x:auto;"><table style="width:100%; border-collapse:collapse; font-size:12px;"><thead><tr style="background:#FAFAF9; border-bottom:1px solid #EEE;"><th style="padding:7px 9px; text-align:left; font-size:10px; color:#6B7280; text-transform:uppercase;">Tarikh</th><th style="padding:7px 9px; text-align:left; font-size:10px; color:#6B7280; text-transform:uppercase;">Order</th><th style="padding:7px 9px; text-align:left; font-size:10px; color:#6B7280; text-transform:uppercase;">Customer</th><th style="padding:7px 9px; text-align:right; font-size:10px; color:#6B7280; text-transform:uppercase;">RM</th><th style="padding:7px 9px; text-align:left; font-size:10px; color:#6B7280; text-transform:uppercase;">Staf Jual</th></tr></thead><tbody>' + body + '</tbody></table></div>'
  + '<div style="display:flex; justify-content:space-between; align-items:center; flex-wrap:wrap; gap:10px; padding:14px;"><span style="font-size:12px; color:#6B7280;">' + rows.length + ' order · RM ' + total.toFixed(2) + ' · komisen 5% = RM ' + (total*0.05).toFixed(2) + '</span><button onclick="window.__crSaveUnclaimed()" class="btn-brand-primary" style="padding:9px 20px; font-size:13px;"><i data-lucide="save" style="width:14px;height:14px;vertical-align:-2px;"></i> Simpan Tugasan Staf</button></div>';
 if(window.lucide) try{lucide.createIcons();}catch(e){}
};
window.__crSaveUnclaimed = async function() {
 const sels = document.querySelectorAll('#crUnclaimList select[data-uid]');
 const updates = [];
 sels.forEach(s => { const v=(s.value||'').trim(); if(v) updates.push({ id: parseInt(s.getAttribute('data-uid'),10), staff: v }); });
 if(!updates.length) { if(typeof showToast==='function') showToast('Tiada staf dipilih lagi.','warn'); return; }
 if(!confirm('Simpan ' + updates.length + ' tugasan staf?\n\nKemaskini staff_name pada order — All Orders + kiraan komisen (Kaedah B / My Commission) akan reflek.')) return;
 let ok=0; const errs=[];
 for(const u of updates) {
  try { const { error } = await db.from('sales_history').update({ staff_name: u.staff }).eq('id', u.id); if(error) throw error;
   const idx=(Array.isArray(salesHistory)?salesHistory:[]).findIndex(x=>x.id===u.id); if(idx>=0) salesHistory[idx].staff_name=u.staff;
   ok++;
  } catch(e){ errs.push(u.id+': '+e.message); }
 }
 if(typeof showToast==='function') showToast('Disimpan ' + ok + ' order' + (errs.length?'. Ralat: '+errs[0]:'') + '. All Orders + komisen dikemaskini.', errs.length?'warn':'success');
 try { if(window.renderAllOrders) window.renderAllOrders(); } catch(e){}
 if(window.__crLoadUnclaimed) window.__crLoadUnclaimed();
};
// p1_742 — AI Calculation: kiraan sistem (sales+live × 5%) per staf × bulan, dari commission_history method='AI'
window.__crRenderAI = function() {
 const esc = (typeof hesc === 'function') ? hesc : (s)=> String(s==null?'':s);
 const yr = window.__crHistYear || 2026;
 const rows = (window.__commHist || []).filter(r => r.method === 'AI' && r.period_year === yr);
 const yrBtn = (y) => '<button onclick="window.__crSetHistYear(' + y + ')" style="background:' + (yr===y?'var(--primary-500,#CD7C32)':'#fff') + '; color:' + (yr===y?'#fff':'#374151') + '; border:1px solid ' + (yr===y?'var(--primary-500,#CD7C32)':'#E5E7EB') + '; padding:5px 14px; border-radius:999px; font-size:12px; font-weight:700; cursor:pointer; margin-right:6px;">' + y + '</button>';
 const head = '<div style="display:flex; justify-content:space-between; align-items:center; flex-wrap:wrap; gap:8px; margin-bottom:6px;"><div style="font-weight:800; font-size:14px;">AI Calculation — kiraan sistem</div><div>' + yrBtn(2025) + yrBtn(2026) + '</div></div>' +
 '<p style="font-size:11.5px; color:#9CA3AF; margin:0 0 14px;">Kiraan automatik dari data sebenar: (jualan staff-attribute + live TikTok) × 5%. Bebas dari kiraan manual Aliff — guna untuk semak silang. 2025 attribution mungkin tak lengkap (sebahagian Shopify).</p>';
 if(!rows.length) return head + '<div class="admin-card" style="padding:24px; text-align:center; color:#9CA3AF;">Tiada AI calc untuk ' + yr + '.</div>';
 const MON = ['','Jan','Feb','Mac','Apr','Mei','Jun','Jul','Ogos','Sep','Okt','Nov','Dis'];
 const staff = [...new Set(rows.map(r => r.staff_name))].sort();
 const months = [...new Set(rows.map(r => r.period_month))].sort((a,b)=>a-b);
 const get = (s,m) => { const r = rows.find(x => x.staff_name===s && x.period_month===m); return r ? Number(r.amount_rm) : null; };
 const cell = (v, bold) => '<td style="padding:7px 9px; text-align:right; white-space:nowrap;' + (bold?' font-weight:800;':'') + '">' + (v==null?'–':v.toFixed(2)) + '</td>';
 let body = '', grand = 0;
 staff.forEach(s => {
 let tot = 0, tds = '';
 months.forEach(m => { const v = get(s,m); if(v!=null) tot += v; tds += cell(v); });
 grand += tot;
 body += '<tr style="border-bottom:1px solid #F3F4F6;"><td style="padding:7px 9px; font-weight:700; white-space:nowrap; position:sticky; left:0; background:#fff;">' + esc(s) + '</td>' + tds + cell(round2(tot), true) + '</tr>';
 });
 const hcells = months.map(m => '<th style="padding:7px 9px; text-align:right; font-size:10px; color:#6B7280;">' + MON[m] + '</th>').join('');
 return head + '<div class="admin-card" style="padding:0; overflow-x:auto;"><table style="width:100%; border-collapse:collapse; font-size:12px;"><thead><tr style="background:#FAFAF9; border-bottom:1px solid #EEEEEE;"><th style="padding:7px 9px; text-align:left; font-size:10px; color:#6B7280; position:sticky; left:0; background:#FAFAFA;">Staf</th>' + hcells + '<th style="padding:7px 9px; text-align:right; font-size:10px; color:#6B7280;">Total</th></tr></thead><tbody>' + body + '</tbody></table></div>' +
 '<p style="font-size:12px; margin:12px 2px 0;"><strong>Jumlah AI ' + yr + ': RM ' + grand.toLocaleString('en-MY',{minimumFractionDigits:2,maximumFractionDigits:2}) + '</strong></p>';
};
// p1_742 — Banding A vs AI (cari human error)
window.__crRenderCompare = function() {
 const esc = (typeof hesc === 'function') ? hesc : (s)=> String(s==null?'':s);
 const yr = window.__crHistYear || 2026;
 const hist = (window.__commHist || []).filter(r => r.period_year === yr && !/house/i.test(r.staff_name||''));
 const yrBtn = (y) => '<button onclick="window.__crSetHistYear(' + y + ')" style="background:' + (yr===y?'var(--primary-500,#CD7C32)':'#fff') + '; color:' + (yr===y?'#fff':'#374151') + '; border:1px solid ' + (yr===y?'var(--primary-500,#CD7C32)':'#E5E7EB') + '; padding:5px 14px; border-radius:999px; font-size:12px; font-weight:700; cursor:pointer; margin-right:6px;">' + y + '</button>';
 const A = {}, AI = {};
 hist.forEach(r => { const m = r.method==='A'?A:(r.method==='AI'?AI:null); if(m) m[r.staff_name] = round2((m[r.staff_name]||0) + Number(r.amount_rm||0)); });
 const staff = [...new Set([...Object.keys(A), ...Object.keys(AI)])].sort();
 const fmt = (n) => 'RM ' + Number(n).toLocaleString('en-MY',{minimumFractionDigits:2,maximumFractionDigits:2});
 const head = '<div style="display:flex; justify-content:space-between; align-items:center; flex-wrap:wrap; gap:8px; margin-bottom:6px;"><div style="font-weight:800; font-size:14px;">Banding — Aliff (Kaedah A) vs AI Calculation</div><div>' + yrBtn(2025) + yrBtn(2026) + '</div></div>' +
 '<p style="font-size:11.5px; color:#9CA3AF; margin:0 0 14px;">Selisih besar (merah) = mungkin human error dalam kiraan manual, ATAU data attribution tak lengkap (cth 2025 separa Shopify). Semak baris merah dengan Aliff.</p>';
 if(!staff.length) return head + '<div class="admin-card" style="padding:24px; text-align:center; color:#9CA3AF;">Tiada data untuk ' + yr + '.</div>';
 let body = '', tA=0, tAI=0;
 staff.forEach(s => {
 const a = round2(A[s]||0), ai = round2(AI[s]||0), d = round2(a - ai);
 tA += a; tAI += ai;
 const big = Math.abs(d) > 50 && (Math.abs(d) > 0.1*Math.max(Math.abs(a),Math.abs(ai)));
 const dcol = big ? '#B23A2E' : '#15803D';
 body += '<tr style="border-bottom:1px solid #F3F4F6;' + (big?' background:#FEF2F2;':'') + '">' +
 '<td style="padding:9px 11px; font-weight:700;">' + esc(s) + '</td>' +
 '<td style="padding:9px 11px; text-align:right;">' + fmt(a) + '</td>' +
 '<td style="padding:9px 11px; text-align:right;">' + fmt(ai) + '</td>' +
 '<td style="padding:9px 11px; text-align:right; font-weight:800; color:' + dcol + ';">' + (d>=0?'+':'') + fmt(d) + (big?' <i data-lucide="alert-triangle" style="width:12px;height:12px;vertical-align:-2px;"></i>':'') + '</td>' +
 '</tr>';
 });
 return head + '<div class="admin-card" style="padding:0; overflow:hidden;"><table style="width:100%; border-collapse:collapse; font-size:13px;"><thead><tr style="background:#FAFAF9; border-bottom:1px solid #EEEEEE;"><th style="padding:9px 11px; text-align:left; font-size:10px; color:#6B7280;">Staf</th><th style="padding:9px 11px; text-align:right; font-size:10px; color:#6B7280;">Aliff (A)</th><th style="padding:9px 11px; text-align:right; font-size:10px; color:#6B7280;">AI Calc</th><th style="padding:9px 11px; text-align:right; font-size:10px; color:#6B7280;">Selisih (A−AI)</th></tr></thead><tbody>' + body + '</tbody>' +
 '<tfoot><tr style="border-top:2px solid #EEEEEE; background:#FAFAF9; font-weight:800;"><td style="padding:10px 11px;">JUMLAH</td><td style="padding:10px 11px; text-align:right;">' + fmt(round2(tA)) + '</td><td style="padding:10px 11px; text-align:right;">' + fmt(round2(tAI)) + '</td><td style="padding:10px 11px; text-align:right; color:' + (Math.abs(tA-tAI)>50?'#B23A2E':'#15803D') + ';">' + ((tA-tAI)>=0?'+':'') + fmt(round2(tA-tAI)) + '</td></tr></tfoot>' +
 '</table></div>';
};

// p1_733 — Sesi Live TikTok: log tetingkap masa Ariff live → jualan TikTok dlm tempoh = komisen dia (Kaedah B)
window.__liveSessions = window.__liveSessions || [];
window.__loadLiveSessions = async function() {
 try {
 if(typeof db === 'undefined' || !db) { window.__liveLoaded = true; return; }
 const { data } = await db.from('live_sessions').select('*').order('start_at', { ascending: false }).limit(300);
 window.__liveSessions = data || [];
 } catch(e) { console.warn('load live_sessions:', e.message); }
 window.__liveLoaded = true;
};
window.__crSaveLiveSession = async function() {
 const d = document.getElementById('lsDate')?.value;
 // p1_1164 — host default = staf semasa (bukan hardcode Ariff) supaya komisen Tarmizi auto-attribute
 const __defHost = (window.currentUser && window.currentUser.name) || 'Ariff';
 const host = (document.getElementById('lsHost')?.value || __defHost).trim() || __defHost;
 const salesV = document.getElementById('lsSales')?.value;
 const itemsV = document.getElementById('lsItems')?.value;
 const sales = salesV === '' || salesV == null ? null : parseFloat(salesV);
 if(!d) { if(window.showToast) showToast('Isi tarikh sesi.', 'warn'); return; }
 if(sales == null || isNaN(sales)) { if(window.showToast) showToast('Isi GMV live (RM) dari rekod TikTok.', 'warn'); return; }
 try {
 const { error } = await db.from('live_sessions').insert([{
 session_date: d, host_name: host, channel: 'TikTok',
 live_sales_rm: sales, items_sold: (itemsV ? parseInt(itemsV) : null),
 created_by: (currentUser && currentUser.name) || '?'
 }]);
 if(error) throw error;
 await window.__loadLiveSessions(); window.renderCommissionReport();
 if(window.showToast) showToast('Sesi live disimpan — komisen dikira semula.', 'success');
 } catch(err) { if(window.showToast) showToast('Gagal simpan: ' + err.message, 'error'); }
};
window.__crDeleteLiveSession = async function(id) {
 if(!confirm('Padam sesi live ni?')) return;
 try { await db.from('live_sessions').delete().eq('id', id); await window.__loadLiveSessions(); window.renderCommissionReport(); if(window.showToast) showToast('Sesi dipadam.', 'success'); }
 catch(e) { if(window.showToast) showToast('Gagal padam: ' + e.message, 'error'); }
};
