window.calculateEditableTotal = function() {
 let subtotal = 0;
 const rows = document.querySelectorAll('#quoteItemsTableBody tr');
 
 rows.forEach(row => {
 let qtyEl = row.querySelector('.editable-qty');
 let priceEl = row.querySelector('.editable-price');
 let rowTotalEl = row.querySelector('.row-total');
 
 if(qtyEl && priceEl && rowTotalEl) {
 let q = parseFloat(qtyEl.innerText.replace(/[^0-9.-]+/g,"")) || 0;
 let p = parseFloat(priceEl.innerText.replace(/[^0-9.-]+/g,"")) || 0;
 let lineTotal = round2(q * p);
 subtotal = round2(subtotal + lineTotal);
 rowTotalEl.innerText = lineTotal.toFixed(2);
 }
 });

 let depositEl = document.getElementById("quotePreviewValDeposit");
 let deposit = 0;
 if(depositEl) deposit = parseFloat(depositEl.innerText.replace(/[^0-9.-]+/g,"")) || 0;

 let discountEl = document.getElementById("quoteValDiscount");
 let discount = 0;
 if(discountEl) discount = parseFloat(discountEl.innerText.replace(/[^0-9.-]+/g,"")) || 0;

 let grandTotal = round2(subtotal + deposit - discount);
 let gtEl = document.getElementById("quotePreviewGrandTotal");
 if(gtEl) gtEl.innerText = grandTotal.toFixed(2);
 
 let subEl2 = document.getElementById("quoteValSubtotal");
 if(subEl2) subEl2.innerText = subtotal.toFixed(2);
 
 // Hidden inputs update
 let subEl = document.getElementById("quoteSubtotal");
 if(subEl) subEl.innerText = subtotal.toFixed(2);
 let gtEl2 = document.getElementById("quoteGrandTotal");
 if(gtEl2) gtEl2.innerText = grandTotal.toFixed(2);
};
// ===================================
// PRODUCT REGISTRATION MODE
// ===================================
// p1_226 — All Master Product form field IDs (for clear/load/save loops)
window.__mpAllFieldIds = [
 'mpName','mpSku','mpBrand','mpCategory','mpModelNo','mpParentSku','mpUnit','mpPrice','mpCompareAt','mpCostPrice','mpInitQty','mpShopeePrice','mpTiktokPrice',
 'mpVariantColor','mpVariantSize','mpErpBarcode','mpVariantOptions','mpHasVariants','mpDefaultVariantSku',
 'mpWeightKg','mpLengthCm','mpWidthCm','mpHeightCm','mpLocationBin',
 'mpDescription','mpImageUrl','mpImageUrls','mpCommissionRate','mpIsPublished',
 'mpVendor','mpCollection','mpTags','mpNotes',
 'mpSeoTitle','mpSeoDescription','mpSeoSlug',
 'mpReorderPoint','mpReorderQty','mpLeadTimeDays'
];

// p1_226 — Parse variant options textarea ("Name: v1, v2, v3" per line) → array
window.__mpParseVariantOptions = function(raw) {
 if(!raw || !raw.trim()) return [];
 return raw.split('\n').map(line => {
 const i = line.indexOf(':');
 if(i < 0) return null;
 const name = line.slice(0, i).trim();
 const values = line.slice(i + 1).split(',').map(v => v.trim()).filter(Boolean);
 if(!name || !values.length) return null;
 return { name, values };
 }).filter(Boolean);
};

// p1_226 — Serialize variant options array back to textarea text (for Load)
window.__mpStringifyVariantOptions = function(arr) {
 if(!Array.isArray(arr) || !arr.length) return '';
 return arr.map(o => `${o.name}: ${(o.values || []).join(', ')}`).join('\n');
};

window.saveMasterProduct = async function() {
 const get = (id) => (document.getElementById(id)?.value || '').trim();
 const getNum = (id) => {
 const v = document.getElementById(id)?.value;
 return v === '' || v == null ? null : parseFloat(v);
 };

 const name = get('mpName');
 const sku = get('mpSku').toUpperCase();
 const price = getNum('mpPrice');

 // p1_731 — mandatory bergantung mod. ADA variant (Option Type terisi) → wajib = SKU + Price
 // SETIAP baris jadual; base SKU/Harga TIDAK wajib (jadi parent grouping je). SINGLE item →
 // base SKU + Harga Jualan wajib.
 const __vrows = (window.__mpCollectVariantRows ? window.__mpCollectVariantRows() : []);
 const hasVariants = (get('mpHasVariants') === 'true') && __vrows.length > 0;

 document.querySelectorAll('#masterProductFormCard .mp-invalid').forEach(el => el.classList.remove('mp-invalid'));
 const __mark = (el, scrollTo) => {
 if(!el) return;
 el.classList.add('mp-invalid');
 el.addEventListener('input', function __c(){ el.classList.remove('mp-invalid'); el.removeEventListener('input', __c); });
 if(scrollTo) { el.scrollIntoView({ behavior:'smooth', block:'center' }); try { el.focus({ preventScroll:true }); } catch(e){} }
 };

 // Nama sentiasa wajib
 if(!name) { __mark(document.getElementById('mpName'), true); return showToast('Nama Produk wajib diisi.', 'warn'); }

 if(hasVariants) {
 // Wajib: tiap baris variant ada SKU + Price
 const wrap = document.getElementById('mpVariantTableWrap');
 const trs = wrap ? [...wrap.querySelectorAll('tbody tr')] : [];
 let firstBad = null;
 trs.forEach(tr => {
 const skuEl = tr.querySelector('.mpv-sku'), prEl = tr.querySelector('.mpv-price');
 if(!(skuEl && skuEl.value.trim())) { if(skuEl) skuEl.classList.add('mp-invalid'); if(!firstBad) firstBad = skuEl; }
 if(!prEl || isNaN(parseFloat(prEl.value))) { if(prEl) prEl.classList.add('mp-invalid'); if(!firstBad) firstBad = prEl; }
 });
 if(firstBad) { firstBad.scrollIntoView({ behavior:'smooth', block:'center' }); try { firstBad.focus({ preventScroll:true }); } catch(e){} return showToast('Setiap variant wajib ada SKU + Price (MYR).', 'warn'); }
 } else {
 // Single item: base SKU + Harga Jualan wajib
 const miss = [];
 if(!sku) { __mark(document.getElementById('mpSku')); miss.push('SKU'); }
 if(price == null || isNaN(price)) { __mark(document.getElementById('mpPrice')); miss.push('Harga Jualan'); }
 if(miss.length) {
 const f = document.getElementById(!sku ? 'mpSku' : 'mpPrice');
 if(f) { f.scrollIntoView({ behavior:'smooth', block:'center' }); try { f.focus({ preventScroll:true }); } catch(e){} }
 return showToast('Sila isi field wajib (*): Nama, ' + miss.join(', '), 'warn');
 }
 }

 // Parent grouping key — bila ada variant & base SKU kosong, derive dari nama (slug)
 const __slug = (s) => String(s||'').toUpperCase().replace(/[^A-Z0-9]+/g,'-').replace(/^-+|-+$/g,'').slice(0,60);
 const parentKey = hasVariants ? (sku || __slug(name)) : sku;

 const existingProd = sku ? masterProducts.find(p => p.sku === sku) : null;
 const isEdit = !!existingProd && !hasVariants;

 // p1_724 #1 — guard SKU pendua (hanya single item + base SKU diisi + bukan mode edit)
 const __skuLocked = document.getElementById('mpSku')?.readOnly === true;
 if(existingProd && !__skuLocked && !hasVariants) {
 const ok = confirm('SKU "' + sku + '" DAH WUJUD' + (existingProd.name ? ' (' + existingProd.name + ')' : '') +
 '.\n\nSave akan TINDIH / UPDATE produk sedia ada ini, BUKAN cipta baru.\n\nTeruskan?');
 if(!ok) return;
 }

 const imageUrl = get('mpImageUrl');
 // p1_718 — sokong banyak gambar (mpImageUrls CSV); fallback ke mpImageUrl tunggal
 const __imgCsv = get('mpImageUrls');
 const imagesArr = __imgCsv ? __imgCsv.split(',').map(s => s.trim()).filter(Boolean) : (imageUrl ? [imageUrl] : []);
 // p1_226 — pack extra fields into metadata JSONB (preserves any existing keys via merge)
 const prevMeta = (existingProd && existingProd.metadata && typeof existingProd.metadata === 'object') ? existingProd.metadata : {};
 const tagsArr = get('mpTags').split(',').map(t => t.trim()).filter(Boolean);
 const metadata = {
 ...prevMeta,
 vendor: get('mpVendor') || null,
 collection: get('mpCollection') || null,
 tags: tagsArr.length ? tagsArr : null,
 notes: get('mpNotes') || null,
 seo: {
 title: get('mpSeoTitle') || null,
 description: get('mpSeoDescription') || null,
 slug: get('mpSeoSlug') || null
 },
 variants: window.__mpParseVariantOptions(get('mpVariantOptions')),
 has_variants: get('mpHasVariants') === 'true',
 default_variant_sku: get('mpDefaultVariantSku').toUpperCase() || null
 };

 const payload = {
 sku, name,
 unit: get('mpUnit') || 'pcs',
 price,
 compare_at_price: getNum('mpCompareAt'),
 cost_price: getNum('mpCostPrice'),
 shopee_price: getNum('mpShopeePrice'),
 tiktok_price: getNum('mpTiktokPrice'),
 category: get('mpCategory') || null,
 brand: get('mpBrand') || null,
 model_no: get('mpModelNo') || null,
 parent_sku: get('mpParentSku').toUpperCase() || null,
 erp_barcode: get('mpErpBarcode') || null,
 variant_color: get('mpVariantColor') || null,
 variant_size: get('mpVariantSize') || null,
 weight_kg: getNum('mpWeightKg'),
 length_cm: getNum('mpLengthCm'),
 width_cm: getNum('mpWidthCm'),
 height_cm: getNum('mpHeightCm'),
 location_bin: get('mpLocationBin') || null,
 description: get('mpDescription') || null,
 commission_rate: getNum('mpCommissionRate'),
 reorder_point: getNum('mpReorderPoint'),
 reorder_qty: getNum('mpReorderQty'),
 lead_time_days: getNum('mpLeadTimeDays'),
 images: imagesArr.length ? imagesArr : null,
 is_published: get('mpIsPublished') === 'true',
 metadata
 };

 // Strip null fields so PG defaults / nulls land cleanly (but keep metadata even if internal keys null)
 const cleaned = {};
 for(const [k, v] of Object.entries(payload)) {
 if(k === 'metadata') { cleaned[k] = v; continue; }
 if(v !== null && v !== '' && !(typeof v === 'number' && isNaN(v))) cleaned[k] = v;
 }

 let savedProd = null;
 // p1_731 — base/parent row hanya disimpan untuk SINGLE item. Bila ada variant, parent_sku
 // cuma grouping (tiada base row dijual) — tiap variant = row sendiri (lihat blok bawah).
 if(!hasVariants) {
 let saveError = null;
 if(isEdit) {
 const { data, error } = await db.from('products_master').update(cleaned).eq('sku', sku).select();
 saveError = error; savedProd = data && data[0];
 } else {
 const { data, error } = await db.from('products_master').insert([cleaned]).select();
 saveError = error; savedProd = data && data[0];
 }
 if(saveError) {
 console.error('Master Product save error:', saveError);
 return showToast('Ralat: ' + saveError.message, 'error');
 }
 if(savedProd) {
 const idx = masterProducts.findIndex(p => p.sku === sku);
 if(idx >= 0) masterProducts[idx] = savedProd; else masterProducts.push(savedProd);
 }
 }

 // p1_720 — Variant table → cipta/kemaskini satu products_master row per variant.
 // SKU asas (atas) = parent grouping; tiap baris jadual = child row (parent_sku = SKU asas).
 try {
 const vrows = __vrows.filter(r => r.sku && r.sku !== parentKey); // perlu SKU sendiri, jangan langgar parent
 if(hasVariants && vrows.length) {
 const colorRe = /warna|colou?r/i, sizeRe = /saiz|size/i;
 const childRows = vrows.map(r => {
 let vColor = null, vSize = null;
 Object.entries(r.options || {}).forEach(([k, v]) => {
 if(colorRe.test(k)) vColor = v; else if(sizeRe.test(k)) vSize = v;
 });
 const child = {
 sku: r.sku,
 name: name + ' - ' + r.label,
 unit: cleaned.unit || 'pcs',
 price: (r.price != null && !isNaN(r.price)) ? r.price : price,
 parent_sku: parentKey,
 is_published: cleaned.is_published === true,
 category: cleaned.category || null,
 brand: cleaned.brand || null,
 variant_color: vColor,
 variant_size: vSize,
 erp_barcode: r.barcode,
 images: (r.img ? r.img.split(',').map(s => s.trim()).filter(Boolean) : null),
 metadata: { ...metadata, variant_options: r.options, is_variant_child: true, default_variant_sku: null }
 };
 if(r.compare != null && !isNaN(r.compare)) child.compare_at_price = r.compare;
 if(r.cost != null && !isNaN(r.cost)) child.cost_price = r.cost;
 if(r.shopee != null && !isNaN(r.shopee)) child.shopee_price = r.shopee;
 if(r.tiktok != null && !isNaN(r.tiktok)) child.tiktok_price = r.tiktok;
 if(r.weight != null && !isNaN(r.weight)) child.weight_kg = r.weight;
 if(r.length != null && !isNaN(r.length)) child.length_cm = r.length;
 if(r.width != null && !isNaN(r.width)) child.width_cm = r.width;
 if(r.height != null && !isNaN(r.height)) child.height_cm = r.height;
 // buang null supaya default PG bersih
 Object.keys(child).forEach(k => { if(k !== 'metadata' && (child[k] === null || child[k] === '')) delete child[k]; });
 return child;
 });
 const { data: vdata, error: verr } = await db.from('products_master').upsert(childRows, { onConflict: 'sku' }).select();
 if(verr) { console.error('Variant rows save error:', verr); showToast('Variant gagal: ' + verr.message, 'warn'); }
 else {
 (vdata || []).forEach(vp => {
 const i = masterProducts.findIndex(p => p.sku === vp.sku);
 if(i >= 0) masterProducts[i] = vp; else masterProducts.push(vp);
 });
 // initial qty per variant baru (qty>0 & SKU belum wujud sebelum ni)
 for(const r of vrows) {
 if(r.qty != null && r.qty > 0) {
 try {
 await db.from('inventory_batches').insert([{
 sku: r.sku, qty_received: r.qty, qty_remaining: r.qty,
 cost_price: (r.cost != null && !isNaN(r.cost)) ? r.cost : (cleaned.cost_price || 0),
 inbound_date: new Date().toISOString(),
 notes: 'Initial stock (variant) dari Master Product · ' + ((currentUser && currentUser.name) || 'System')
 }]);
 } catch(e) { console.warn('Variant batch insert failed:', e); }
 }
 }
 showToast(childRows.length + ' variant disimpan (parent ' + parentKey + ').', 'success');
 }
 }
 } catch(e) { console.warn('Variant processing skipped:', e); }

 // p1_297 — push this product's price to Shopee + TikTok (custom price or markup
 // fallback). Single SKU = fast, fire-and-forget, never blocks the save.
 const __pushSkus = hasVariants ? __vrows.map(r => r.sku).filter(Boolean).join(',') : sku;
 if(__pushSkus) { try { fetch('/api/marketplace-price-push?mode=push&skus=' + encodeURIComponent(__pushSkus), { headers: window.__authHeaderSync() }).catch(()=>{}); } catch(e){} }
 if(typeof window.__shopeePriceReminder === 'function') window.__shopeePriceReminder();

 // p1_226 — Initial Quantity → inventory_batches insert (single item baru sahaja; variant ada batch sendiri)
 const initQty = getNum('mpInitQty');
 if(!isEdit && !hasVariants && initQty != null && initQty > 0) {
 try {
 await db.from('inventory_batches').insert([{
 sku, qty_received: initQty, qty_remaining: initQty,
 cost_price: cleaned.cost_price || 0,
 inbound_date: new Date().toISOString(),
 notes: 'Initial stock dari Master Product registration · ' + ((currentUser && currentUser.name) || 'System')
 }]);
 } catch(e) { console.warn('Initial batch insert failed:', e); }
 }

 try {
 await db.from('audit_logs').insert([{
 action_type: isEdit ? 'master_product_update' : 'master_product_create',
 actor_name: currentUser ? currentUser.name : 'System',
 details: JSON.stringify({ sku: parentKey, name, brand: cleaned.brand, price, published: cleaned.is_published, variants: hasVariants ? __vrows.length : 0 }),
 created_at: new Date().toISOString()
 }]);
 } catch(_){}

 showToast(`${isEdit ? 'Update' : 'Daftar'} "${name}" (${parentKey})${hasVariants ? ' · ' + __vrows.length + ' variant' : ''} berjaya!`, 'success');

 // Cara B — auto-hantar SEMUA produk BARU ke TikTok (draf), termasuk produk draf POS
 // (Zaid: "auto untuk semua produk baru termasuk draf"). Hanya produk baru + setting ON.
 // Fire-and-forget: tak block simpan; toast sendiri bila siap/gagal. Produk di TikTok
 // tetap masuk sebagai DRAF (save_mode AS_DRAFT), tak terus live.
 try {
  const autoOn = (typeof window.__getSetting === 'function') ? window.__getSetting('integrations.tiktok_auto_create', true) : true;
  if(!isEdit && autoOn){
   showToast('Menghantar "'+name+'" ke TikTok…', 'info');
   window.__tiktokPushProduct(parentKey, { toast:true });
  }
 } catch(e){ console.warn('TikTok auto-create skip:', e); }

 window.clearMpForm();
 if(typeof window.refreshMpDatalists === 'function') window.refreshMpDatalists();
 // p1_409 — if opened from Products "+ Baru" modal, close it & refresh the product grid
 // (masterProducts array already updated in-memory above, so just re-render)
 const mpModal = document.getElementById('masterProductModal');
 if(mpModal && mpModal.style.display !== 'none'){
 window.closeMasterProductModal && window.closeMasterProductModal();
 try { if(typeof window.renderProductDatabase === 'function') window.renderProductDatabase(); }
 catch(e){ console.warn('grid refresh after master save:', e); }
 }
};

// p1_409 — open the full Master Product registration form as a modal from Products "+ Baru".
// The form card lives inside warehouseConfigSection; we relocate it into the modal body on first open.
window.openMasterProductModal = function(){
 const card = document.getElementById('masterProductFormCard');
 const body = document.getElementById('masterProductModalBody');
 if(card && body && card.parentElement !== body){
 body.innerHTML = '';
 body.appendChild(card);
 card.style.marginTop = '0';
 card.style.marginBottom = '0';
 card.style.borderTop = 'none';
 }
 try { window.clearMpForm && window.clearMpForm(); } catch(e){}
 try { window.refreshMpDatalists && window.refreshMpDatalists(); } catch(e){}
 const m = document.getElementById('masterProductModal');
 if(m) m.style.display = 'flex';
 try { window.lucide && lucide.createIcons && lucide.createIcons(); } catch(e){}
 setTimeout(()=>{ const n = document.getElementById('mpName'); if(n) n.focus(); }, 80);
};
window.closeMasterProductModal = function(){
 const m = document.getElementById('masterProductModal');
 if(m) m.style.display = 'none';
};
// p1_409 — relocate the master form card into the modal at boot so the Warehouse Hub
// no longer shows it (truly "moved", not duplicated). Backdrop click closes the modal.
(function mpRelocateInit(){
 function relocate(){
 try {
 const card = document.getElementById('masterProductFormCard');
 const body = document.getElementById('masterProductModalBody');
 if(card && body && card.parentElement !== body){
 body.innerHTML = '';
 body.appendChild(card);
 card.style.marginTop = '0';
 card.style.marginBottom = '0';
 card.style.borderTop = 'none';
 }
 const m = document.getElementById('masterProductModal');
 if(m && !m.__mpBackdrop){
 m.__mpBackdrop = true;
 m.addEventListener('click', function(e){ if(e.target === m) window.closeMasterProductModal(); });
 }
 } catch(e){}
 }
 if(document.readyState === 'loading') document.addEventListener('DOMContentLoaded', relocate);
 else relocate();
})();

// p1_226 — Load existing product into form for edit
window.loadMasterProductForEdit = async function() {
 const sku = (document.getElementById('mpSearchSku')?.value || '').trim().toUpperCase();
 if(!sku) return showToast('Taip SKU dulu untuk Load.', 'warn');
 const p = masterProducts.find(x => x.sku === sku);
 if(!p) return showToast(`SKU "${sku}" tak jumpa dalam Master.`, 'warn');
 const set = (id, v) => { const el = document.getElementById(id); if(el) el.value = (v == null ? '' : String(v)); };
 set('mpName', p.name); set('mpSku', p.sku);
 set('mpBrand', p.brand); set('mpCategory', p.category);
 set('mpModelNo', p.model_no); set('mpParentSku', p.parent_sku);
 set('mpUnit', p.unit || 'pcs');
 set('mpPrice', p.price); set('mpCompareAt', p.compare_at_price); set('mpCostPrice', p.cost_price);
 set('mpShopeePrice', p.shopee_price); set('mpTiktokPrice', p.tiktok_price);
 set('mpInitQty', ''); // edit mode tak override stock
 set('mpVariantColor', p.variant_color); set('mpVariantSize', p.variant_size);
 set('mpErpBarcode', p.erp_barcode);
 set('mpWeightKg', p.weight_kg); set('mpLengthCm', p.length_cm);
 set('mpWidthCm', p.width_cm); set('mpHeightCm', p.height_cm);
 set('mpLocationBin', p.location_bin);
 set('mpDescription', p.description);
 set('mpImageUrl', (p.images && p.images[0]) ? p.images[0] : '');
 // p1_718 — isi galeri gambar (semua) + render thumbnail
 { const __urls = (Array.isArray(p.images) ? p.images.filter(Boolean) : []); const __el = document.getElementById('mpImageUrls'); if(__el) __el.value = __urls.join(','); if(window.mpRenderGallery) window.mpRenderGallery(); }
 set('mpCommissionRate', p.commission_rate);
 set('mpIsPublished', p.is_published ? 'true' : 'false');
 set('mpReorderPoint', p.reorder_point); set('mpReorderQty', p.reorder_qty);
 set('mpLeadTimeDays', p.lead_time_days);
 // Metadata-backed fields
 const m = (p.metadata && typeof p.metadata === 'object') ? p.metadata : {};
 set('mpVendor', m.vendor);
 set('mpCollection', m.collection);
 set('mpTags', Array.isArray(m.tags) ? m.tags.join(', ') : '');
 set('mpNotes', m.notes);
 set('mpSeoTitle', m.seo?.title);
 set('mpSeoDescription', m.seo?.description);
 set('mpSeoSlug', m.seo?.slug);
 set('mpVariantOptions', window.__mpStringifyVariantOptions(m.variants));
 set('mpHasVariants', m.has_variants ? 'true' : 'false');
 set('mpDefaultVariantSku', m.default_variant_sku);
 if(window.mpVariantRenderFromData) window.mpVariantRenderFromData(); // p1_719 — bina rows dari data
 // Show edit badge
 const badge = document.getElementById('mpEditModeBadge');
 if(badge) badge.style.display = 'inline-block';
 // Lock SKU field (cannot rename via this flow)
 const skuField = document.getElementById('mpSku');
 if(skuField) { skuField.readOnly = true; skuField.style.background = '#F3F4F6'; }
 // p1_724 #6 — tajuk jadi mode edit + #2 papar margin + sembunyi amaran dup
 const ttl = document.getElementById('mpFormTitle'); if(ttl) { ttl.removeAttribute('data-i18n'); ttl.textContent = 'Edit Produk: ' + sku; }
 const lbl = document.getElementById('mpSaveBtnLabel'); if(lbl) lbl.textContent = 'Simpan Perubahan';
 if(window.mpUpdateMargin) window.mpUpdateMargin();
 if(window.mpCheckSkuDup) window.mpCheckSkuDup();
 showToast(`Loaded ${sku} — edit semua field, klik Daftar untuk simpan.`, 'success');
 // Scroll to form
 document.getElementById('mpName')?.scrollIntoView({ behavior: 'smooth', block: 'center' });
};

// p1_226 — Reset form (untuk balik ke mode baru)
window.clearMpForm = function() {
 (window.__mpAllFieldIds || []).forEach(id => {
 const el = document.getElementById(id); if(!el) return;
 if(el.tagName === 'SELECT') el.value = el.querySelector('option[selected]')?.value || el.options[0]?.value || '';
 else el.value = '';
 });
 const search = document.getElementById('mpSearchSku'); if(search) search.value = '';
 const badge = document.getElementById('mpEditModeBadge'); if(badge) badge.style.display = 'none';
 const skuField = document.getElementById('mpSku');
 if(skuField) { skuField.readOnly = false; skuField.style.background = ''; }
 if(window.mpRenderGallery) window.mpRenderGallery(); // p1_718 — kosongkan thumbnail galeri
 if(window.mpVariantsReset) window.mpVariantsReset(); // p1_719 — reset variant builder
 // p1_724 — reset tajuk + sembunyi margin/amaran + buang highlight wajib
 const ttl = document.getElementById('mpFormTitle'); if(ttl) { ttl.setAttribute('data-i18n', 'wh_register_title'); ttl.textContent = 'Daftar Produk Baru'; }
 const lbl = document.getElementById('mpSaveBtnLabel'); if(lbl) lbl.textContent = 'Save Produk';
 ['mpMarginLive','mpSkuDupWarn'].forEach(id => { const el = document.getElementById(id); if(el) el.style.display = 'none'; });
 document.querySelectorAll('#masterProductFormCard .mp-invalid').forEach(el => el.classList.remove('mp-invalid'));
};

// p1_226 — Delete master product (with safety checks)
window.deleteMasterProduct = async function() {
 const sku = (document.getElementById('mpSearchSku')?.value || document.getElementById('mpSku')?.value || '').trim().toUpperCase();
 if(!sku) return showToast('Taip SKU dulu (atas atau dalam form) untuk Delete.', 'warn');
 const p = masterProducts.find(x => x.sku === sku);
 if(!p) return showToast(`SKU "${sku}" tak jumpa.`, 'warn');
 if(!confirm(`AMARAN: Padam SKU "${sku}" (${p.name}) dari Master?\n\nIni tak boleh undo. Kalau ada inventory batch / sales history / session items reference SKU ni, Supabase akan tolak DELETE (FK constraint).\n\nTeruskan?`)) return;
 try {
 const { error } = await db.from('products_master').delete().eq('sku', sku);
 if(error) {
 if(error.code === '23503' || /foreign key/i.test(error.message)) {
 return showToast(`Tak boleh delete — masih ada reference (inventory/sales/session). Soft-delete: tukar Status ke Draft je.`, 'error');
 }
 throw error;
 }
 // Remove from in-memory cache
 const idx = masterProducts.findIndex(x => x.sku === sku);
 if(idx >= 0) masterProducts.splice(idx, 1);
 try {
 await db.from('audit_logs').insert([{
 action_type: 'master_product_delete',
 actor_name: currentUser ? currentUser.name : 'System',
 details: JSON.stringify({ sku, name: p.name }),
 created_at: new Date().toISOString()
 }]);
 } catch(_){}
 showToast(`SKU "${sku}" dah padam dari Master.`, 'success');
 window.clearMpForm();
 if(typeof window.refreshMpDatalists === 'function') window.refreshMpDatalists();
 } catch(e) {
 console.error('Delete master product error:', e);
 showToast('Delete gagal: ' + e.message, 'error');
 }
};

// p1_227 — Clean HTML soup (EasyStore export soup → readable plain text)
window.mpCleanDescriptionHtml = function() {
 const ta = document.getElementById('mpDescription');
 if(!ta) return;
 const raw = ta.value || '';
 if(!raw.trim()) { if(typeof showToast === 'function') showToast('Description kosong.', 'warn'); return; }
 if(!confirm('Strip semua HTML tags + EasyStore sheets data dari description?\n\nTeks plain je akan tinggal. Boleh undo dengan klik Reset + Load semula.')) return;
 try {
 // 1) Strip EasyStore prefix marker like [EASYSTORE-ID:xxx-Vxxx]
 let s = raw.replace(/\[EASYSTORE-ID:[^\]]*\]\s*/g, '');
 // 2) Parse via DOMParser, extract textContent (browser handles entities + nested tags safely)
 const doc = new DOMParser().parseFromString(s, 'text/html');
 // Convert <li>, </p>, <br> to line breaks BEFORE extracting text — preserve structure
 doc.querySelectorAll('li').forEach(li => li.insertAdjacentText('beforebegin', '\n• '));
 doc.querySelectorAll('p, h1, h2, h3, h4, h5, h6, div').forEach(p => p.insertAdjacentText('afterend', '\n'));
 doc.querySelectorAll('br').forEach(br => br.replaceWith('\n'));
 // Remove <span> with data-sheets-* attributes entirely (Google Sheets paste artifacts) — but keep their text
 // (textContent already includes their text, so we don't need to explicitly drop them)
 let text = doc.body.textContent || '';
 // 3) Collapse 3+ blank lines to 2, trim trailing spaces, collapse 2+ spaces to 1
 text = text
 .replace(/ /g, ' ') // nbsp -> space
 .replace(/[ \t]+/g, ' ') // collapse spaces
 .replace(/\n[ \t]+/g, '\n') // strip leading spaces per line
 .replace(/\n{3,}/g, '\n\n') // collapse blank lines
 .trim();
 if(!text) { if(typeof showToast === 'function') showToast('Lepas clean, kosong. Original kekal.', 'warn'); return; }
 ta.value = text;
 if(typeof showToast === 'function') showToast(`Clean HTML — ${raw.length} → ${text.length} char.`, 'success');
 } catch(e) {
 console.error('Clean HTML error:', e);
 if(typeof showToast === 'function') showToast('Clean gagal: ' + e.message, 'error');
 }
};

// p1_720 — Variants builder ala Shopify: Option type / Option value (chips) →
// jadual variant auto-jana (cartesian product) dgn SKU/Price/Compare/Cost/Barcode/Qty.
// Hidden #mpVariantOptions ("Nama: v1, v2") + #mpHasVariants kekal utk metadata (back-compat);
// jadual dibaca masa save → cipta satu products_master row per variant (parent_sku = SKU asas).
const __MP_ESC = (s) => String(s == null ? '' : s).replace(/"/g, '&quot;').replace(/</g, '&lt;');

// Tambah satu blok Option type (name + chip box)
window.mpAddOptionType = function(name, values) {
 const wrap = document.getElementById('mpOptionTypes');
 if(!wrap) return;
 const block = document.createElement('div');
 block.className = 'mp-opttype';
 block.innerHTML =
 '<div class="mp-ot-grid">' +
 '<div><label class="small-lbl">Option type</label><input type="text" class="login-input mp-ot-name" placeholder="cth Size" value="' + __MP_ESC(name) + '" oninput="window.mpRebuildVariantTable()"></div>' +
 '<div><label class="small-lbl">Option value</label>' +
 '<div class="mp-chipbox" onclick="this.querySelector(\'.mp-chip-input\').focus()"><span class="mp-chips"></span>' +
 '<input type="text" class="mp-chip-input" placeholder="taip nilai, tekan Enter" onkeydown="window.mpChipKey(event,this)" onblur="window.mpChipCommit(this)"></div></div>' +
 '<button type="button" class="mp-ot-del" title="Buang option type" onclick="window.mpRemoveOptionType(this)"><i data-lucide="x" style="width:15px;height:15px;"></i></button>' +
 '</div>';
 wrap.appendChild(block);
 if(Array.isArray(values) && values.length) {
 const chipsEl = block.querySelector('.mp-chips');
 values.forEach(v => window.__mpAddChip(chipsEl, v));
 }
 if(window.lucide && window.lucide.createIcons) window.lucide.createIcons();
 window.mpRebuildVariantTable();
};
window.mpRemoveOptionType = function(btn) {
 const block = btn && btn.closest('.mp-opttype');
 if(block) block.remove();
 window.mpRebuildVariantTable();
};
// --- Chip helpers ---
window.__mpAddChip = function(chipsEl, val) {
 val = String(val || '').trim();
 if(!val || !chipsEl) return;
 // elak duplikat dlm option type yg sama
 const exists = [...chipsEl.querySelectorAll('.mp-chip')].some(c => (c.dataset.v || '') === val);
 if(exists) return;
 const chip = document.createElement('span');
 chip.className = 'mp-chip';
 chip.dataset.v = val;
 chip.innerHTML = __MP_ESC(val) + ' <i data-lucide="x" onclick="window.mpChipRemove(this)"></i>';
 chipsEl.appendChild(chip);
};
window.mpChipKey = function(e, input) {
 if(e.key === 'Enter' || e.key === ',') {
 e.preventDefault();
 window.mpChipCommit(input);
 } else if(e.key === 'Backspace' && input.value === '') {
 const chips = input.parentElement.querySelector('.mp-chips');
 const last = chips && chips.lastElementChild;
 if(last) { last.remove(); window.mpRebuildVariantTable(); }
 }
};
window.mpChipCommit = function(input) {
 const chips = input.parentElement.querySelector('.mp-chips');
 const parts = (input.value || '').split(',').map(s => s.trim()).filter(Boolean);
 parts.forEach(p => window.__mpAddChip(chips, p));
 input.value = '';
 if(window.lucide && window.lucide.createIcons) window.lucide.createIcons();
 if(parts.length) window.mpRebuildVariantTable();
};
window.mpChipRemove = function(i) {
 const chip = i && i.closest('.mp-chip');
 if(chip) chip.remove();
 window.mpRebuildVariantTable();
};
// Baca option types dari DOM → [{name, values[]}]
window.__mpGetOptionTypes = function() {
 const out = [];
 document.querySelectorAll('#mpOptionTypes .mp-opttype').forEach(b => {
 const name = (b.querySelector('.mp-ot-name')?.value || '').trim();
 const values = [...b.querySelectorAll('.mp-chips .mp-chip')].map(c => c.dataset.v).filter(Boolean);
 out.push({ name, values });
 });
 return out;
};
// Cartesian product
function __mpCartesian(arrays) {
 return arrays.reduce((acc, arr) => acc.flatMap(a => arr.map(v => [...a, v])), [[]]);
}
// Jana semula jadual variant dari option types
window.mpRebuildVariantTable = function() {
 const wrap = document.getElementById('mpVariantTableWrap');
 const ta = document.getElementById('mpVariantOptions');
 const hv = document.getElementById('mpHasVariants');
 if(!wrap) return;
 const types = window.__mpGetOptionTypes().filter(t => t.name && t.values.length);
 // sync hidden sinks (metadata.variants + has_variants)
 if(ta) ta.value = types.map(t => t.name + ': ' + t.values.join(', ')).join('\n');
 if(hv) hv.value = types.length ? 'true' : 'false';
 if(!types.length) { wrap.innerHTML = ''; return; }

 // snapshot nilai sedia ada (kekalkan bila rebuild)
 const prev = {};
 wrap.querySelectorAll('tbody tr').forEach(tr => {
 const key = tr.dataset.combo;
 if(key) prev[key] = {
 img: tr.querySelector('.mpv-img')?.value || '',
 sku: tr.querySelector('.mpv-sku')?.value || '',
 price: tr.querySelector('.mpv-price')?.value || '',
 compare: tr.querySelector('.mpv-compare')?.value || '',
 cost: tr.querySelector('.mpv-cost')?.value || '',
 shopee: tr.querySelector('.mpv-shopee')?.value || '',
 tiktok: tr.querySelector('.mpv-tiktok')?.value || '',
 barcode: tr.querySelector('.mpv-barcode')?.value || '',
 qty: tr.querySelector('.mpv-qty')?.value || '',
 weight: tr.querySelector('.mpv-weight')?.value || '',
 length: tr.querySelector('.mpv-length')?.value || '',
 width: tr.querySelector('.mpv-width')?.value || '',
 height: tr.querySelector('.mpv-height')?.value || ''
 };
 });

 const combos = __mpCartesian(types.map(t => t.values)); // array of value-arrays
 const head = '<thead><tr>' +
 '<th>Gambar (URL)</th><th>Variants</th><th>SKU</th><th>Price (MYR)</th><th>Compare at (MYR)</th><th>Cost (MYR)</th><th>Shopee (MYR)</th><th>TikTok (MYR)</th><th>Barcode</th><th>Qty</th><th>Berat (kg)</th><th>P (cm)</th><th>L (cm)</th><th>T (cm)</th>' +
 '</tr></thead>';
 const rows = combos.map(combo => {
 const label = combo.join(' / ');
 const p = prev[label] || {};
 return '<tr data-combo="' + __MP_ESC(label) + '">' +
 '<td><input class="mpv-img" type="text" placeholder="URL gambar" value="' + __MP_ESC(p.img) + '" style="min-width:140px;"></td>' +
 '<td class="mpv-label"><span class="mp-vlabel">' + __MP_ESC(label) + '</span></td>' +
 '<td><input class="mpv-sku" type="text" placeholder="SKU" value="' + __MP_ESC(p.sku) + '" oninput="window.mpVariantSkuStatus && window.mpVariantSkuStatus()"></td>' +
 '<td><input class="mpv-price" type="number" step="0.01" placeholder="0.00" value="' + __MP_ESC(p.price) + '"></td>' +
 '<td><input class="mpv-compare" type="number" step="0.01" placeholder="0.00" value="' + __MP_ESC(p.compare) + '"></td>' +
 '<td><input class="mpv-cost" type="number" step="0.01" placeholder="0.00" value="' + __MP_ESC(p.cost) + '"></td>' +
 '<td><input class="mpv-shopee" type="number" step="0.01" placeholder="auto" value="' + __MP_ESC(p.shopee) + '"></td>' +
 '<td><input class="mpv-tiktok" type="number" step="0.01" placeholder="auto" value="' + __MP_ESC(p.tiktok) + '"></td>' +
 '<td><input class="mpv-barcode" type="text" placeholder="EAN/UPC" value="' + __MP_ESC(p.barcode) + '"></td>' +
 '<td><input class="mpv-qty" type="number" min="0" placeholder="0" value="' + __MP_ESC(p.qty) + '"></td>' +
 '<td><input class="mpv-weight" type="number" step="0.001" placeholder="0" value="' + __MP_ESC(p.weight) + '"></td>' +
 '<td><input class="mpv-length" type="number" step="0.1" placeholder="0" value="' + __MP_ESC(p.length) + '"></td>' +
 '<td><input class="mpv-width" type="number" step="0.1" placeholder="0" value="' + __MP_ESC(p.width) + '"></td>' +
 '<td><input class="mpv-height" type="number" step="0.1" placeholder="0" value="' + __MP_ESC(p.height) + '"></td>' +
 '</tr>';
 }).join('');
 wrap.innerHTML = '<p id="mpVariantCount" style="font-size:11.5px; font-weight:600; margin:0 0 8px;"></p>' +
 '<table class="mp-vtable">' + head + '<tbody>' + rows + '</tbody></table>';
 if(window.mpVariantSkuStatus) window.mpVariantSkuStatus();
};
// Kumpul baris variant utk save → [{label, options{}, sku, price, compare, cost, barcode, qty}]
window.__mpCollectVariantRows = function() {
 const wrap = document.getElementById('mpVariantTableWrap');
 const types = window.__mpGetOptionTypes().filter(t => t.name && t.values.length);
 if(!wrap || !types.length) return [];
 const num = (v) => { v = (v || '').trim(); return v === '' ? null : parseFloat(v); };
 return [...wrap.querySelectorAll('tbody tr')].map(tr => {
 const label = tr.dataset.combo || '';
 const parts = label.split(' / ');
 const options = {};
 types.forEach((t, i) => { options[t.name] = parts[i]; });
 return {
 label, options,
 img: (tr.querySelector('.mpv-img')?.value || '').trim() || null,
 sku: (tr.querySelector('.mpv-sku')?.value || '').trim().toUpperCase(),
 price: num(tr.querySelector('.mpv-price')?.value),
 compare: num(tr.querySelector('.mpv-compare')?.value),
 cost: num(tr.querySelector('.mpv-cost')?.value),
 shopee: num(tr.querySelector('.mpv-shopee')?.value),
 tiktok: num(tr.querySelector('.mpv-tiktok')?.value),
 barcode: (tr.querySelector('.mpv-barcode')?.value || '').trim() || null,
 qty: num(tr.querySelector('.mpv-qty')?.value),
 weight: num(tr.querySelector('.mpv-weight')?.value),
 length: num(tr.querySelector('.mpv-length')?.value),
 width: num(tr.querySelector('.mpv-width')?.value),
 height: num(tr.querySelector('.mpv-height')?.value)
 };
 });
};
// Buka builder (link Add variants)
window.mpVariantsOpen = function() {
 const builder = document.getElementById('mpVariantBuilder');
 const types = document.getElementById('mpOptionTypes');
 document.getElementById('mpVariantAddLink')?.style.setProperty('display', 'none');
 document.getElementById('mpVariantDelLink')?.style.setProperty('display', 'block');
 if(builder) builder.style.display = 'block';
 if(types && !types.querySelector('.mp-opttype')) window.mpAddOptionType(); // mula 1 blok kosong
 window.mpRebuildVariantTable();
};
// Tutup + buang semua variant
window.mpVariantsClose = function() {
 const builder = document.getElementById('mpVariantBuilder');
 const types = document.getElementById('mpOptionTypes');
 const tbl = document.getElementById('mpVariantTableWrap');
 if(types) types.innerHTML = '';
 if(tbl) tbl.innerHTML = '';
 if(builder) builder.style.display = 'none';
 document.getElementById('mpVariantAddLink')?.style.setProperty('display', 'block');
 document.getElementById('mpVariantDelLink')?.style.setProperty('display', 'none');
 const ta = document.getElementById('mpVariantOptions'); if(ta) ta.value = '';
 const hv = document.getElementById('mpHasVariants'); if(hv) hv.value = 'false';
 const dsku = document.getElementById('mpDefaultVariantSku'); if(dsku) dsku.value = '';
};
// Reset (dipanggil clearMpForm)
window.mpVariantsReset = function() { window.mpVariantsClose(); };
// Render dari data (selepas load) — bina option types dari metadata.variants
window.mpVariantRenderFromData = function() {
 const ta = document.getElementById('mpVariantOptions');
 const types = document.getElementById('mpOptionTypes');
 if(!ta || !types) return;
 types.innerHTML = '';
 const opts = (window.__mpParseVariantOptions || (() => []))(ta.value);
 const hasVar = (document.getElementById('mpHasVariants')?.value === 'true') || opts.length > 0;
 if(hasVar && opts.length) {
 document.getElementById('mpVariantAddLink')?.style.setProperty('display', 'none');
 document.getElementById('mpVariantDelLink')?.style.setProperty('display', 'block');
 document.getElementById('mpVariantBuilder').style.display = 'block';
 opts.forEach(o => window.mpAddOptionType(o.name, o.values || []));
 } else {
 window.mpVariantsClose();
 }
};
// Backward-compat
window.mpAddVariantOption = function() { window.mpVariantsOpen(); };

// p1_724 #1 — amaran live bila SKU yang ditaip dah wujud (mode Baru sahaja)
window.mpCheckSkuDup = function() {
 const el = document.getElementById('mpSkuDupWarn');
 const skuEl = document.getElementById('mpSku');
 if(!el || !skuEl) return;
 if(skuEl.readOnly) { el.style.display = 'none'; return; } // mode edit — memang sengaja
 const sku = (skuEl.value || '').trim().toUpperCase();
 const hit = sku && (typeof masterProducts !== 'undefined') && masterProducts.find(p => p.sku === sku);
 if(hit) {
 el.innerHTML = '<i data-lucide="alert-triangle" style="width:12px;height:12px;vertical-align:-2px;"></i> SKU ini DAH WUJUD' + (hit.name ? ' (' + String(hit.name).slice(0,40) + ')' : '') + ' — Save akan UPDATE produk sedia ada, bukan cipta baru.';
 el.style.display = 'block';
 if(window.lucide && window.lucide.createIcons) window.lucide.createIcons();
 } else { el.style.display = 'none'; }
};

// p1_724 #2 — papar margin live bawah Harga & Stok + amaran bawah 35%
window.mpUpdateMargin = function() {
 const el = document.getElementById('mpMarginLive');
 if(!el) return;
 const price = parseFloat(document.getElementById('mpPrice')?.value);
 const cost = parseFloat(document.getElementById('mpCostPrice')?.value);
 if(isNaN(price) || price <= 0 || isNaN(cost)) { el.style.display = 'none'; return; }
 const margin = (price - cost) / price * 100;
 const low = margin < 35;
 const profit = price - cost;
 el.style.display = 'block';
 el.style.color = low ? '#B23A2E' : '#15803D';
 el.innerHTML = '<strong>Margin: ' + margin.toFixed(1) + '%</strong> (untung RM' + profit.toFixed(2) + ' seunit)' +
 (low ? ' <span style="font-weight:700;">— BAWAH minimum 35%</span>' : '');
};

// p1_724 #5 — kira variant yg ada SKU + highlight baris tertinggal SKU
window.mpVariantSkuStatus = function() {
 const wrap = document.getElementById('mpVariantTableWrap');
 const sum = document.getElementById('mpVariantCount');
 if(!wrap || !sum) return;
 const rows = [...wrap.querySelectorAll('tbody tr')];
 if(!rows.length) { sum.style.display = 'none'; return; }
 let withSku = 0;
 rows.forEach(tr => {
 const inp = tr.querySelector('.mpv-sku');
 const has = inp && inp.value.trim();
 if(has) withSku++;
 if(inp) inp.style.borderColor = has ? '' : '#E11D48';
 });
 const missing = rows.length - withSku;
 sum.style.display = 'block';
 sum.style.color = missing ? '#B23A2E' : '#6B7280';
 sum.innerHTML = withSku + ' / ' + rows.length + ' variant ada SKU (akan disimpan)' +
 (missing ? ' — ' + missing + ' baris tiada SKU akan DILANGKAU' : '');
};

// Auto-populate brand & category & vendor & collection & SKU datalists from existing products
window.refreshMpDatalists = function() {
 if(typeof masterProducts === 'undefined') return;
 const fill = (id, vals) => { const el = document.getElementById(id); if(el) el.innerHTML = vals.map(v => `<option value="${String(v).replace(/"/g, '&quot;')}">`).join(''); };
 fill('mpBrandList', [...new Set(masterProducts.map(p => p.brand).filter(Boolean))].sort());
 fill('mpCategoryList', [...new Set(masterProducts.map(p => p.category).filter(Boolean))].sort());
 // p1_226 — datalists for new metadata-backed fields
 const metas = masterProducts.map(p => (p.metadata && typeof p.metadata === 'object') ? p.metadata : {});
 fill('mpVendorList', [...new Set(metas.map(m => m.vendor).filter(Boolean))].sort());
 fill('mpCollectionList', [...new Set([...(window.__CAMP_COLLECTIONS||[]), ...metas.map(m => m.collection).filter(Boolean)])]); // p1_1000 — 8 koleksi canonical dulu
 fill('mpAllSkusList', masterProducts.map(p => p.sku).filter(Boolean).sort());
};
window.saveProductRegistration = async function() {
 let shipmentNo = document.getElementById("prShipmentNo").value.trim();
 let shipmentDate = document.getElementById("prShipmentDate").value;
 let sku = document.getElementById("prSku").value.trim().toUpperCase();
 let priceRmb = document.getElementById("prPriceRmb").value;
 let units = document.getElementById("prUnitPurchased").value;
 let shippingCost = document.getElementById("prShippingCost").value;
 
 if(!shipmentNo || !shipmentDate || !sku || !priceRmb || !units || !shippingCost) {
 alert("Sila lengkapkan semua maklumat pendaftaran produk.");
 return;
 }
 
 // Parse values
 let qtyReceived = parseInt(units);
 
 // Only send columns that are proven to exist in inventory_batches
 const batchPayload = {
 sku: sku,
 batch_year: new Date(shipmentDate).getFullYear() || new Date().getFullYear(),
 inbound_date: shipmentDate,
 qty_received: qtyReceived,
 qty_remaining: qtyReceived
 };
 
 // Insert to Supabase (inventory_batches)
 let { data: newBatch, error: batchErr } = await db.from('inventory_batches').insert([batchPayload]).select();
 
 if(batchErr) {
 console.error("Batch Insert Error:", batchErr);
 alert("Ralat menyimpan Batch. Pastikan SKU wujud di Master Product.");
 return;
 }

 // Combine extra data into the reason text for tracking
 let trackingInfo = `PO: ${shipmentNo} | RMB: ${priceRmb} | Ship: RM${shippingCost}`;

 // Insert Transaction Audit Trail
 const txnPayload = {
 sku: sku,
 transaction_type: 'PO_IN',
 qty: qtyReceived,
 reason: trackingInfo,
 staff_name: currentUser ? currentUser.name : 'System',
 created_at: new Date().toISOString()
 };
 
 let { data: newTxn, error: txnErr } = await db.from('inventory_transactions').insert([txnPayload]).select();
 
 if(txnErr) {
 console.error("Transaction Insert Error:", txnErr);
 }
 
 // Update Local State
 if(newBatch && newBatch.length> 0) inventoryBatches.push(newBatch[0]);
 if(newTxn && newTxn.length> 0) inventoryTransactions.unshift(newTxn[0]);
 
 alert(`Batch PO (${shipmentNo}) Berjaya Didaftarkan untuk SKU: ${sku}!`);
 
 // Clear fields
 document.getElementById("prShipmentNo").value = "";
 document.getElementById("prShipmentDate").value = "";
 document.getElementById("prSku").value = "";
 document.getElementById("prPriceRmb").value = "";
 document.getElementById("prUnitPurchased").value = "";
 document.getElementById("prShippingCost").value = "";
 
 // Refresh relevant UI if they are open
 if(typeof renderLowStockAlert === "function") renderLowStockAlert();
};

