 // p1_263 — Marketplace integration IDs
 set('pdpShopeeItemId', m.shopee_item_id);
 set('pdpTiktokProductId', m.tiktok_product_id);
 // p1_417 — direct buy links (editable). Auto-fill Shopee from item_id kalau belum diisi.
