window.savePdpData = async function() {
 const sku = document.getElementById('pdpOriginalSku').value;
 const get = (id) => (document.getElementById(id)?.value || '').trim();
 // p1_228 — merge metadata (preserve any existing keys like easystore_*)
 const prevProd = masterProducts.find(p => p.sku === sku) || {};
 const prevMeta = (prevProd.metadata && typeof prevProd.metadata === 'object') ? prevProd.metadata : {};
 const tagsArr = get('pdpTags').split(',').map(t => t.trim()).filter(Boolean);
 const parseVariants = window.__mpParseVariantOptions || (raw => []);
 const metadata = {
 ...prevMeta,
 vendor: get('pdpVendor') || null,
 collection: get('pdpCollection') || null,
 tags: tagsArr.length ? tagsArr : null,
 notes: get('pdpNotes') || null,
 video: get('pdpVideoUrl') || null,  // p1_958 — video per-variant (tunjuk di Cashier)
 seo: {
 title: get('pdpSeoTitle') || null,
 description: get('pdpSeoDescription') || null,
 slug: get('pdpSeoSlug') || null
 },
 variants: parseVariants(get('pdpVariantOptions')),
 has_variants: get('pdpHasVariants') === 'true',
 default_variant_sku: get('pdpDefaultVariantSku').toUpperCase() || null,
 metafields: currentPdpMetafields || {},
 // p1_263 — Marketplace integration IDs (manual entry from PDP modal)
 shopee_item_id: get('pdpShopeeItemId') || null,
 tiktok_product_id: get('pdpTiktokProductId') || null,
 // p1_417 — direct buy links (editable; used by customer landing buy buttons)
 shopee_url: get('pdpShopeeUrl') || null,
 tiktok_url: get('pdpTiktokUrl') || null,
 // p1_746 — Product Name peringkat-produk (dikongsi semua variant, padan istilah Shopee/TikTok)
 product_name: get('pdpProductName') || null,
 // p1_764 — COVER peringkat-produk: gambar muka depan website/Product Master (dikongsi semua variant)
 cover_image: (function(){ const c = window.__pdpCoverUrl || ''; const el = document.getElementById('pdpMediaUrls'); const pool = (el && el.value) ? el.value.split(',').map(s=>s.trim()).filter(Boolean) : []; return (c && pool.indexOf(c) !== -1) ? c : (pool[0] || null); })()
 };
 // p1_533 — disconnect BERSIH: bila staff padam Item/Product ID, buang sekali leftover
 // sync (model_id/sku_id/synced_at) supaya betul-betul terputus + tag grid jadi grey.
 if(!metadata.shopee_item_id) { metadata.shopee_model_id = null; metadata.shopee_synced_at = null; }
 if(!metadata.tiktok_product_id) { metadata.tiktok_sku_id = null; metadata.tiktok_synced_at = null; }

 const updatePayload = {
 name: get('pdpName'),
 category: get('pdpCategory') || null,
 brand: get('pdpBrand') || null,
 price: parseFloat(get('pdpPrice')) || 0,
 compare_at_price: get('pdpCompareAt') ? (parseFloat(get('pdpCompareAt')) || null) : null,
 cost_price: parseFloat(get('pdpCost')) || 0,
 shopee_price: (function(){ const v=get('pdpShopeePrice'); return (v===''||v==null)?null:(parseFloat(v)||null); })(),
 tiktok_price: (function(){ const v=get('pdpTiktokPrice'); return (v===''||v==null)?null:(parseFloat(v)||null); })(),
 shopee_price_mode: get('pdpShopeeMode') || 'rm',
 tiktok_price_mode: get('pdpTiktokMode') || 'rm',
 is_published: get('pdpStatus') === 'true',
 description: get('pdpDescription') || null,
 variant_color: get('pdpVariantColor') || null,
 variant_size: get('pdpVariantSize') || null,
 erp_barcode: get('pdpErpBarcode') || null,
 last_modified_by: (window.currentUser||{}).name || 'System',
 updated_at: new Date().toISOString(),
 metadata
 };

 let imgStr = document.getElementById('pdpMediaUrls').value;
 // p1_749/p1_753/p1_890 — pool media dikongsi. Variant SEMASA pun KEKALKAN cover sendiri
 // (images[0]) via __mergeCoverPool — sama macam sibling. Dulu guna __pool terus → variant
 // semasa ambil pool[0] (cover produk) bila Save → gambar variant berubah ikut cover (bug Zack).
 // Cover produk muka-depan = metadata.cover_image (berasingan, disimpan di bawah).
 const __pool = imgStr ? imgStr.split(',').map(s=>s.trim()).filter(Boolean) : [];
 updatePayload.images = __pool.length ? window.__mergeCoverPool(prevProd.images, __pool) : [];

 try {
 let { error } = await db.from('products_master').update(updatePayload).eq('sku', sku);
 if(error) throw error;
 // p1_428 — Product ID / Item ID / direct links adalah PERINGKAT PRODUK (satu, dikongsi
 // semua variant — Zack). tiktok_sku_id / shopee_model_id peringkat variant kekal (dari sync).
 // Jadi isi sekali → propagate ke semua sibling variant dlm group yg sama.
 try {
 const parent = prevProd.parent_sku;
 if(parent) {
 const siblings = (masterProducts || []).filter(p => p.parent_sku === parent && p.sku !== sku);
 const shared = {
 shopee_item_id: metadata.shopee_item_id,
 tiktok_product_id: metadata.tiktok_product_id,
 shopee_url: metadata.shopee_url,
 tiktok_url: metadata.tiktok_url,
 product_name: metadata.product_name, // p1_746 — Product Name dikongsi semua variant
 cover_image: metadata.cover_image // p1_764 — Cover (muka depan) dikongsi semua variant
 };
 // p1_745/p1_749/p1_752 — 3 INDUK peringkat-produk dikongsi semua variant (Zack):
 //   (1) MEDIA pool (kekalkan cover tiap sibling), (2) Product Name (metadata.product_name
 //   dlm objek 'shared'), (3) Description (lajur description). Sebar ke semua sibling.
 const sharedPool = __pool;
 for(const sib of siblings) {
 const sm = (sib.metadata && typeof sib.metadata === 'object') ? sib.metadata : {};
 const newMeta = { ...sm, ...shared };
 const sibPayload = { metadata: newMeta };
 const sibImgs = sharedPool.length ? window.__mergeCoverPool(sib.images, sharedPool) : null;
 if(sibImgs) sibPayload.images = sibImgs;
 sibPayload.description = updatePayload.description; // p1_752 — Description induk dikongsi
 const { error: se } = await db.from('products_master').update(sibPayload).eq('sku', sib.sku);
 if(!se) { sib.metadata = newMeta; if(sibImgs) sib.images = sibImgs; sib.description = updatePayload.description; } // keep in-memory consistent
 }
 }
 } catch(e){ console.warn('propagate marketplace ids ke sibling:', e); }
 // p1_297b — push this product's price to Shopee + TikTok (fire-and-forget)
 try { fetch('/api/marketplace-price-push?mode=push&skus=' + encodeURIComponent(sku), { headers: window.__authHeaderSync() }).catch(()=>{}); } catch(e){}
 if(typeof showToast === 'function') showToast(`${sku} saved. Harga dipush ke marketplace.`, 'success');
 if(typeof window.__shopeePriceReminder === 'function') window.__shopeePriceReminder();
 else alert("Product saved successfully.");
 document.getElementById('pdpModal').style.display = 'none';
 await window.initApp(); // reload everything
 } catch(e) {
 if(typeof showToast === 'function') showToast('Save gagal: ' + e.message, 'error');
 else alert("Error saving product: " + e.message);
 }
};

