 '40x25': { w:40, h:25, pad:1.2, bcH:28, bcW:1.0, bcFont:10, fHead:0,  fName:0,  fSku:10, fPrice:11, fSeq:0,  showHeader:0, showName:0, showPrice:1, showSeq:0 },
