window.__invSetRkFilter = function(f, el){
  window.__invRkFilter = f;
  document.querySelectorAll('#invRkPills .inv-pill').forEach(x => x.classList.remove('active'));
  if(el) el.classList.add('active');
  window.__invFilterRows();
};
window.__invFilterRows = function(){
  const inp = document.getElementById('invRkSearch');
  const ql = ((inp && inp.value) || '').trim().toLowerCase();
  window.__invSearch = ql;
  const f = window.__invRkFilter || 'all';
  let shown = 0;
  document.querySelectorAll('#invRkBody tr.inv-rk-row').forEach(tr => {
    const cat = tr.getAttribute('data-cat'), hay = tr.getAttribute('data-search') || '', skuid = tr.getAttribute('data-skuid');
    const show = (f === 'all' || f === cat) && (!ql || hay.indexOf(ql) >= 0);
    tr.style.display = show ? '' : 'none';
    if(show) shown++;
    const dtl = document.getElementById('invDtl_'+skuid); if(dtl && !show) dtl.style.display = 'none';
  });
  const empty = document.getElementById('invRkEmpty'); if(empty) empty.style.display = shown ? 'none' : '';
};
// p1_623 — Log Pergerakan Stok per SKU: IN (delivery_orders) + OUT (sales), baki berjalan diankor ke stok semasa
window.__invStockCard = function(sku) {
  sku = (sku || '').trim();
  const out = document.getElementById('invStockCardBody'); if(!out) return;
  const esc = (v) => String(v == null ? '' : v).replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;');
  if(!sku) { out.innerHTML = '<div style="padding:24px; text-align:center; color:#9CA3AF; font-size:12px;">Taip SKU untuk lihat log pergerakan stok.</div>'; return; }
  const prod = (Array.isArray(masterProducts) ? masterProducts : []).find(p => p.sku === sku);
  const batches = Array.isArray(inventoryBatches) ? inventoryBatches : [];
  const curStock = batches.filter(b => b.sku === sku).reduce((s,b) => s + (Number(b.qty_remaining)||0), 0);
  const fmtD = (s) => { if(!s) return '—'; const d=new Date(s); return isNaN(d)?String(s):d.toLocaleDateString('en-MY',{day:'2-digit',month:'short',year:'2-digit'}); };
  // IN — delivery orders
  const dd = window.__doData || { dos:[], items:[] };
  const doDate = {}; (dd.dos||[]).forEach(d => doDate[d.do_ref] = d.delivery_date || null);
  const moves = [];
  (dd.items||[]).forEach(it => { if((it.sku||'').trim() !== sku) return; const q = Number(it.qty)||0; if(!q) return; moves.push({ date: doDate[it.do_ref] || null, type:'IN', qty:q, ref: it.do_ref || 'DO', note:'Restock' }); });
  // OUT — sales (refund = stok balik = IN)
  (Array.isArray(salesHistory) ? salesHistory : []).forEach(s => {
    if(s.is_test) return;
    let items = s.items; if(typeof items === 'string'){ try { items = JSON.parse(items); } catch(e){ items = []; } } if(!Array.isArray(items)) return;
    const recv = parseFloat(s.total_amount || s.total || 0) || 0; const isRefund = recv < 0;
    items.forEach(line => { if((line.sku||'').trim() !== sku) return; const q = Number(line.qty != null ? line.qty : line.quantity)||0; if(!q) return;
      moves.push({ date: s.created_at ? String(s.created_at).slice(0,10) : null, type: isRefund?'IN':'OUT', qty:q, ref: (s.order_no||s.order_number||s.id||'')+'', note: isRefund?'Refund (stok balik)':'Jualan' });
    });
  });
  if(!moves.length) { out.innerHTML = `<div style="padding:24px; text-align:center; color:#9CA3AF; font-size:12px;">Tiada rekod pergerakan untuk <b>${esc(sku)}</b>. Stok semasa: ${curStock}.</div>`; return; }
  moves.sort((a,b) => (a.date||'') < (b.date||'') ? -1 : ((a.date||'') > (b.date||'') ? 1 : 0));
  // baki berjalan: baki SELEPAS gerakan terakhir = stok semasa; kira mundur
  const balAfter = new Array(moves.length); let bal = curStock;
  for(let i = moves.length-1; i >= 0; i--) { balAfter[i] = bal; bal -= (moves[i].type==='IN' ? moves[i].qty : -moves[i].qty); }
  const balBefore = bal; // baki sebelum rekod pertama (stok lama tak berlog)
  const totalIn = moves.filter(m=>m.type==='IN').reduce((s,m)=>s+m.qty,0);
  const totalOut = moves.filter(m=>m.type==='OUT').reduce((s,m)=>s+m.qty,0);
  let html = `<div style="padding:12px 14px; display:flex; gap:18px; flex-wrap:wrap; border-bottom:1px solid var(--border-color); font-size:12px;">
    <span><b>${esc(prod?prod.name:sku)}</b> <span style="color:#9CA3AF; font-family:monospace;">${esc(sku)}</span></span>
    <span style="margin-left:auto; color:#4E7C4A;">Masuk: <b>+${totalIn}</b></span>
    <span style="color:#B23A2E;">Keluar: <b>−${totalOut}</b></span>
    <span>Stok kini: <b>${curStock}</b></span>
  </div>`;
  html += '<div style="overflow-x:auto;"><table style="width:100%; border-collapse:collapse; font-size:12px;"><thead><tr style="color:var(--text-muted); text-align:left;"><th style="padding:7px 12px;">Tarikh</th><th style="padding:7px 12px;">Jenis</th><th style="padding:7px 12px; text-align:right;">Qty</th><th style="padding:7px 12px;">Rujukan</th><th style="padding:7px 12px;">Nota</th><th style="padding:7px 12px; text-align:right;">Baki</th></tr></thead><tbody>';
  for(let i = moves.length-1; i >= 0; i--) { const m = moves[i]; const isIn = m.type==='IN';
    html += `<tr style="border-top:1px solid var(--border-color);">
      <td style="padding:7px 12px; white-space:nowrap;">${fmtD(m.date)}</td>
      <td style="padding:7px 12px;"><span style="background:${isIn?'#E6F0E4':'#F4E4DF'}; color:${isIn?'#4E7C4A':'#B23A2E'}; font-weight:700; font-size:10px; padding:2px 8px; border-radius:10px;">${isIn?'MASUK':'KELUAR'}</span></td>
      <td style="padding:7px 12px; text-align:right; font-weight:700; color:${isIn?'#4E7C4A':'#B23A2E'};">${isIn?'+':'−'}${m.qty}</td>
      <td style="padding:7px 12px; font-family:'SF Mono',Menlo,monospace; font-size:11px;">${esc(m.ref)}</td>
      <td style="padding:7px 12px; color:#6B7280;">${esc(m.note)}</td>
      <td style="padding:7px 12px; text-align:right; font-weight:600;">${balAfter[i]}</td>
    </tr>`;
  }
  html += `<tr style="border-top:1px solid var(--border-color); background:#FAFAFA;"><td colspan="5" style="padding:7px 12px; color:#9CA3AF; font-size:11px;">Baki awal (sebelum rekod berlog)</td><td style="padding:7px 12px; text-align:right; color:#9CA3AF;">${balBefore}</td></tr>`;
  html += '</tbody></table></div>';
  html += '<div style="padding:8px 14px; font-size:11px; color:var(--text-muted); line-height:1.5;">MASUK = restock (delivery order). KELUAR = jualan (test order dikecualikan). Refund = stok balik (masuk). Baki diankor ke stok sebenar sekarang; "Baki awal" ≠ 0 maksudnya ada stok lama sebelum rekod DO bermula.</div>';
  out.innerHTML = html;
};
// p1_807 — lukis graf trend nilai stok dari inventory_snapshots (direkod harian oleh cron).
window.__invDrawTrend = async function() {
 const cv = document.getElementById('invTrendChart');
 if(!cv || typeof db === 'undefined' || !db || typeof Chart === 'undefined') return;
 const empty = document.getElementById('invTrendEmpty');
 let rows = [];
 try { const { data } = await db.from('inventory_snapshots').select('snapshot_date,total_cost,total_units').order('snapshot_date', { ascending: true }).limit(120); rows = data || []; } catch(e){}
 if(rows.length < 2) { if(empty) empty.style.display = 'block'; cv.style.display = 'none'; return; }
 if(empty) empty.style.display = 'none'; cv.style.display = '';
 if(window.__invTrendInst) { try { window.__invTrendInst.destroy(); } catch(e){} }
 const labels = rows.map(r => { const d = new Date(r.snapshot_date + 'T00:00'); return isNaN(d) ? String(r.snapshot_date) : d.toLocaleDateString('en-MY', { day: 'numeric', month: 'short' }); });
 window.__invTrendInst = new Chart(cv.getContext('2d'), {
  type: 'line',
  data: { labels, datasets: [{ label: 'Nilai Stok (Kos RM)', data: rows.map(r => Number(r.total_cost) || 0), borderColor: '#CD7C32', backgroundColor: 'rgba(205,124,50,0.12)', fill: true, tension: 0.25, pointRadius: 2, borderWidth: 2 }] },
  options: { responsive: true, maintainAspectRatio: false, plugins: { legend: { display: false } }, scales: { y: { ticks: { callback: (v) => 'RM' + Number(v).toLocaleString('en-MY') } } } }
 });
};
window.renderInventoryAnalytics = async function() {
 const body = document.getElementById('anInvBody'); if(!body) return;
 if(!window.__doData && typeof window.__doLoad === 'function') {
   body.innerHTML = '<div style="text-align:center; color:var(--text-muted); padding:40px; font-size:13px;">Memuatkan sejarah restock…</div>';
   try { await window.__doLoad(); } catch(e){}
 }
 const esc = (v) => String(v == null ? '' : v).replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;');
 const fmtRM0 = (n) => 'RM ' + Number(n||0).toLocaleString('en-MY',{maximumFractionDigits:0});
 const fmtRM2 = (n) => 'RM ' + Number(n||0).toLocaleString('en-MY',{minimumFractionDigits:2, maximumFractionDigits:2});
 const products = Array.isArray(masterProducts) ? masterProducts : [];
 const batches = Array.isArray(inventoryBatches) ? inventoryBatches : [];
 const isDisc = (p) => !!(p.metadata && p.metadata.discontinued === true);

 // Stok + nilai kos (dari batch landed cost) + batch tertua per SKU
 const stockMap = new Map(), costValMap = new Map(), oldestBatch = new Map();
 batches.forEach(b => {
   const q = Number(b.qty_remaining) || 0;
   stockMap.set(b.sku, (stockMap.get(b.sku) || 0) + q);
   if(q > 0) {
     const c = Number(b.cost_price || b.landed_cost) || 0;
     costValMap.set(b.sku, (costValMap.get(b.sku) || 0) + q * c);
     const d = b.inbound_date || '';
     if(d && (!oldestBatch.has(b.sku) || d < oldestBatch.get(b.sku))) oldestBatch.set(b.sku, d);
   }
 });

 // Velocity: unit terjual per SKU dlm 30 & 90 hari lepas (jualan sebenar sahaja)
 const now = Date.now(), d30 = now - 30*864e5, d90 = now - 90*864e5;
 const u30 = {}, u90 = {};
 (Array.isArray(salesHistory) ? salesHistory : []).forEach(s => {
   if(!(typeof window.__isRealSale === 'function' ? window.__isRealSale(s) : true) || !s.created_at) return;
   const t = new Date(s.created_at).getTime();
   if(t < d90) return;
   let it = s.items; if(typeof it === 'string'){ try { it = JSON.parse(it); } catch(e){ it = []; } }
   if(!Array.isArray(it)) return;
   it.forEach(line => {
     const sku = line.sku; if(!sku) return;
     const q = Number(line.qty != null ? line.qty : line.quantity) || 0;
     u90[sku] = (u90[sku] || 0) + q;
     if(t >= d30) u30[sku] = (u30[sku] || 0) + q;
   });
 });

 // ---- Sejarah restock per SKU (SEMUA tarikh DO, bukan terakhir sahaja) ----
 const doData = window.__doData || { dos:[], items:[] };
 const doDate = {}; (doData.dos||[]).forEach(d => { doDate[d.do_ref] = d.delivery_date || null; });
 const evByS = {}; // sku -> [{date, qty}]
 (doData.items||[]).forEach(it => {
   const sku = (it.sku||'').trim(); if(!sku) return;
   (evByS[sku] || (evByS[sku] = [])).push({ date: doDate[it.do_ref] || null, qty: Number(it.qty) || 0 });
 });
 const lastByS = {}; // sku -> {date, qty, count, events:[{date,qty}] sorted asc}
 Object.keys(evByS).forEach(sku => {
   const all = evByS[sku];
   const evs = all.filter(e => e.date).sort((a,b) => a.date < b.date ? -1 : (a.date > b.date ? 1 : 0));
   const last = evs.length ? evs[evs.length-1] : null;
   lastByS[sku] = { date: last ? last.date : null, qty: last ? last.qty : 0, count: all.length, events: evs };
 });

 // ---- Stock value totals + status breakdown ----
 let totalCost = 0, totalRetail = 0, totalUnits = 0, skuWithStock = 0;
 let cHealthy = 0, cLow = 0, cOut = 0, cDisc = 0;
 const catVal = {}; // {cat: {cost, retail}}
 products.forEach(p => {
   const stock = stockMap.get(p.sku) || 0;
   const ro = parseInt(p.reorder_point) || 5;
   const costV = costValMap.get(p.sku) || 0;
   const retailV = stock * (Number(p.price) || 0);
   totalCost += costV; totalRetail += retailV;
   if(stock > 0) { totalUnits += stock; skuWithStock++; }
   if(isDisc(p)) cDisc++;
   else if(stock === 0) cOut++;
   else if(stock <= ro) cLow++;
   else cHealthy++;
   const cat = p.category || 'Tiada Kategori';
   if(!catVal[cat]) catVal[cat] = { cost:0, retail:0 };
   catVal[cat].cost += costV; catVal[cat].retail += retailV;
 });
 const potensiUntung = totalRetail - totalCost;

 // ---- Restock Tracker categorization (cat: reorder/perhati/sihat/dead) ----
 const THR = window.__invRestockThreshold || 20, LEAD = window.__invLeadDays || 35;
 const tracker = [];
 products.forEach(p => {
   if(isDisc(p)) return;
   const rec = lastByS[p.sku];
   const stock = stockMap.get(p.sku) || 0;
   const lastQty = rec ? rec.qty : 0;
   const pct = lastQty > 0 ? (stock / lastQty * 100) : null;
   const dailyVel = (u30[p.sku] || 0) / 30;
   const sold90 = u90[p.sku] || 0;
   const daysCover = dailyVel > 0 ? stock / dailyVel : (stock > 0 ? Infinity : null);
   let cat;
   if(stock === 0 && sold90 === 0) cat = 'dead';                                  // habis + tak laku 90h = stok mati
   else if(stock === 0) cat = 'reorder';                                          // habis tapi laku = urgent
   else if((pct != null && pct <= THR) || (daysCover != null && daysCover !== Infinity && daysCover <= LEAD)) cat = 'reorder';
   else if((pct != null && pct <= 50) || (daysCover != null && daysCover !== Infinity && daysCover <= LEAD * 1.5)) cat = 'perhati';
   else cat = 'sihat';
   tracker.push({ sku:p.sku, name:p.name || '', lastDate:rec?rec.date:null, lastQty, events:rec?rec.events:[], stock, pct, sold30:(u30[p.sku]||0), sold90, daysCover, vel:dailyVel, ro:(parseInt(p.reorder_point)||5), cat });
 });
 const rankOf = { reorder:0, perhati:1 };
 const action = tracker.filter(t => t.cat === 'reorder' || t.cat === 'perhati')
   .sort((a, b) => (rankOf[a.cat]-rankOf[b.cat]) || ((a.pct==null?1e5:a.pct)-(b.pct==null?1e5:b.pct)) || ((a.daysCover==null?1e9:a.daysCover)-(b.daysCover==null?1e9:b.daysCover)));
 const dead = tracker.filter(t => t.cat === 'dead').sort((a, b) => (a.name||'').localeCompare(b.name||''));
 const nReorder = tracker.filter(t => t.cat === 'reorder').length;
 const nPerhati = tracker.filter(t => t.cat === 'perhati').length;
 const nSihat = tracker.filter(t => t.cat === 'sihat').length;
 const nDead = dead.length;

 // ---- Slow movers (ada stok, 0 jualan 90 hari) ----
 const slow = [];
 products.forEach(p => {
   const stock = stockMap.get(p.sku) || 0;
   if(stock <= 0) return;
   if((u90[p.sku] || 0) > 0) return;
   const tied = costValMap.get(p.sku) || 0;
   const ob = oldestBatch.get(p.sku);
   const ageDays = ob ? Math.floor((now - new Date(ob).getTime()) / 864e5) : null;
   slow.push({ sku:p.sku, name:p.name || '', stock, tied, ageDays, disc:isDisc(p) });
 });
 slow.sort((a, b) => b.tied - a.tied);
 const slowTied = slow.reduce((s, x) => s + x.tied, 0);

 // 2026-06-25 — Dead Stock (visual): slow movers (ada stok, 0 jualan 90h) + gambar produk
 const prodImgMap = new Map(products.map(p => [p.sku, (p.images && p.images[0]) ? p.images[0] : null]));
 window.__invDeadList = slow.map(x => ({ sku:x.sku, name:x.name, stock:x.stock, tied:x.tied, ageDays:x.ageDays, disc:x.disc, img: prodImgMap.get(x.sku) || window.__invDeadPh }));

 const topCats = Object.keys(catVal).map(c => ({ cat:c, ...catVal[c] })).sort((a,b)=>b.cost-a.cost).slice(0, 8);

 // ---- Stock Availability keseluruhan (p1_801): 100% = semua SKU pada/atas tahap restock penuh terakhir.
 // numerator di-cap pada lastQty per-SKU supaya puncak (stok paling banyak) = 100%, tak lebih.
 let availNum = 0, availDen = 0, availSkus = 0;
 tracker.forEach(t => { if(t.lastQty > 0){ availDen += t.lastQty; availNum += Math.min(t.stock, t.lastQty); availSkus++; } });
 const availPct = availDen > 0 ? Math.round(availNum / availDen * 100) : null;
 const availColor = availPct == null ? '#9CA3AF' : (availPct >= 70 ? '#4E7C4A' : (availPct >= 40 ? '#9E7016' : '#B23A2E'));
 // ---- Dead Stock % (p1_802): nilai stok terikat dlm barang TAK BERGERAK (ada stok, 0 jualan 90h) ÷ jumlah nilai stok kos.
 // Tinggi = teruk (modal tersangkut). slowTied + slow dah dikira atas.
 const deadPct = totalCost > 0 ? Math.round(slowTied / totalCost * 100) : null;
 const deadColor = deadPct == null ? '#9CA3AF' : (deadPct >= 30 ? '#B23A2E' : (deadPct >= 15 ? '#9E7016' : '#4E7C4A'));
 // ---- #2 Hari Stok + Inventory Turnover (p1_803): guna unit terjual 90 hari ----
 const soldUnits90 = Object.values(u90).reduce((s, x) => s + (Number(x) || 0), 0);
 const dailySold = soldUnits90 / 90;
 const daysOfStock = dailySold > 0 ? Math.round(totalUnits / dailySold) : null; // null = tiada jualan 90h (∞)
 const turnoverYr = (dailySold > 0 && totalUnits > 0) ? +((soldUnits90 * (365 / 90)) / totalUnits).toFixed(1) : 0;
 const dosColor = daysOfStock == null ? '#9CA3AF' : (daysOfStock > 180 ? '#B23A2E' : (daysOfStock > 90 ? '#9E7016' : '#4E7C4A'));
 // ---- #1 Umur Stok (Stock Aging) by nilai kos, per-batch (FIFO-aware) ----
 const ageBuckets = [
   { lbl: '0–30h', max: 30, cost: 0, col: '#4E7C4A' },
   { lbl: '31–90h', max: 90, cost: 0, col: '#8AA06A' },
   { lbl: '91–180h', max: 180, cost: 0, col: '#CE9420' },
   { lbl: '180h+', max: Infinity, cost: 0, col: '#B23A2E' }
 ];
 batches.forEach(b => {
   const q = Number(b.qty_remaining) || 0; if(q <= 0) return;
   const c = Number(b.cost_price || b.landed_cost) || 0;
   const d = b.inbound_date ? Math.floor((now - new Date(b.inbound_date).getTime()) / 864e5) : 99999;
   const bk = ageBuckets.find(x => d <= x.max) || ageBuckets[3];
   bk.cost += q * c;
 });
 const agingTot = ageBuckets.reduce((s, b) => s + b.cost, 0) || 1;
 // ---- #4 Anggaran Nilai PO Restock + #6 Stockout/jualan terlepas (p1_804) ----
 const unitCost = {}, unitPrice = {};
 products.forEach(p => { unitCost[p.sku] = Number(p.cost_price) || 0; unitPrice[p.sku] = Number(p.price) || 0; });
 let poUnits = 0, poCost = 0, poSkus = 0, stockoutSkus = 0, lostRevDay = 0;
 tracker.forEach(t => {
   if(t.cat === 'reorder') {
     const target = Math.max(Math.ceil((t.vel || 0) * (LEAD + 30)), t.lastQty || 0, t.ro || 0);
     const sugg = Math.max(target - t.stock, 0) || (t.ro || 1);
     poSkus++; poUnits += sugg; poCost += sugg * (unitCost[t.sku] || 0);
   }
   if(t.stock === 0 && (t.sold90 || 0) > 0) { stockoutSkus++; lostRevDay += (t.vel || 0) * (unitPrice[t.sku] || 0); }
 });
 // ---- #3 Sell-Through Rate 90h (p1_805): unit terjual ÷ (terjual + baki). Tinggi = laku bergerak. ----
 const sellThru = (soldUnits90 + totalUnits) > 0 ? Math.round(soldUnits90 / (soldUnits90 + totalUnits) * 100) : null;
 const stColor = sellThru == null ? '#9CA3AF' : (sellThru >= 40 ? '#4E7C4A' : (sellThru >= 20 ? '#9E7016' : '#B23A2E'));
 // ---- #5 Kesihatan Stok ikut Brand (p1_806): nilai + availability + dead stock per jenama ----
 const lastQtyMap = {}; tracker.forEach(t => { lastQtyMap[t.sku] = t.lastQty; });
 const slowCostMap = {}; slow.forEach(s => { slowCostMap[s.sku] = s.tied; });
 const brandAgg = {};
 products.forEach(p => {
   if(isDisc(p)) return;
   const brand = (p.brand || '').trim() || 'Lain-lain';
   const stock = stockMap.get(p.sku) || 0;
   const g = brandAgg[brand] || (brandAgg[brand] = { brand, cost: 0, units: 0, skus: 0, aNum: 0, aDen: 0, dead: 0 });
   g.cost += costValMap.get(p.sku) || 0; g.units += stock; g.skus++;
   const lq = lastQtyMap[p.sku] || 0; if(lq > 0){ g.aDen += lq; g.aNum += Math.min(stock, lq); }
   g.dead += slowCostMap[p.sku] || 0;
 });
 const brandRows = Object.values(brandAgg).map(g => ({ brand: g.brand, cost: g.cost, skus: g.skus, avail: g.aDen > 0 ? Math.round(g.aNum / g.aDen * 100) : null, deadPct: g.cost > 0 ? Math.round(g.dead / g.cost * 100) : 0 })).sort((a, b) => b.cost - a.cost);

 // ---- Render helpers ----
 const card = (inner, pad) => `<div style="background:var(--card-bg); border:1px solid var(--border-color); border-radius:12px; padding:${pad||'0'}; overflow:hidden; margin-bottom:16px;">${inner}</div>`;
 const cardHead = (t) => `<div style="font-weight:700; font-size:13px; padding:12px 14px; border-bottom:1px solid var(--border-color); background:#FAFAFA;">${t}</div>`;
 const dcCell = (r) => { if(r.daysCover === null) return '<span style="color:#9CA3AF;">—</span>'; if(r.daysCover === Infinity) return '<span style="color:#9CA3AF;">∞</span>'; const d = Math.round(r.daysCover); const col = d <= 7 ? '#B23A2E' : (d <= 14 ? '#9E7016' : '#6B7280'); return `<span style="color:${col}; font-weight:700;">${d}h</span>`; };
 const fmtD = (s) => { const d=new Date(s); return isNaN(d)?String(s):d.toLocaleDateString('en-MY',{day:'numeric',month:'short',year:'2-digit'}); };
 const sid = (s) => String(s).replace(/[^A-Za-z0-9]/g,'_');
 const pctCell = (t) => { if(t.pct==null) return '<span style="color:#9CA3AF;">—</span>'; const v=Math.round(t.pct); const col=v<=THR?'#B23A2E':(v<=50?'#9E7016':'#4E7C4A'); return `<span style="color:${col}; font-weight:700;">${v}%</span>`; };
 const badge2 = (cat) => { const m={reorder:['#B23A2E','#F4E4DF','REORDER'], perhati:['#9E7016','#F8EFD7','PERHATI'], sihat:['#4E7C4A','#E6F0E4','SIHAT'], dead:['#6B7280','#F3F4F6','STOK MATI']}; const x=m[cat]||m.sihat; return `<span style="background:${x[1]}; color:${x[0]}; font-weight:700; font-size:10px; padding:2px 8px; border-radius:10px; white-space:nowrap;">${x[2]}</span>`; };
 const SUP = { ST:'Shine Trip', MH:'Mountainhiker', CD:'Chanodug', VD:'Vidalido', NH:'Naturehike', BD:'Blackdog', MG:'Mobigarden', LF:'LFO', MX:'Mix Brand' };
 const supOf = (sku) => { const m = String(sku||'').match(/^[A-Za-z]+/); const pre = m ? m[0].toUpperCase() : ''; return SUP[pre] || (pre || 'Lain'); };
 const suggestOf = (t) => { const target = Math.max(Math.ceil((t.vel||0)*(LEAD+30)), t.lastQty||0, t.ro||0); return Math.max(target - t.stock, 0) || (t.ro||1); };
 const timeline = (t) => { const evs=t.events||[]; if(!evs.length) return '<span style="color:#9CA3AF; font-size:11.5px;">Belum ada rekod DO untuk SKU ni.</span>'; return '<div style="display:flex; flex-wrap:wrap; gap:5px; align-items:center;">'+evs.map((e,i)=>{ const lbl=i===0?'1st':('R'+i); const last=i===evs.length-1; return `<span style="font-size:11px; padding:3px 8px; border-radius:6px; background:${last?'#FAF6EF':'#F3F4F6'}; ${last?'font-weight:700; color:var(--primary);':'color:#6B7280;'}"><span style="color:#9CA3AF; font-size:9.5px;">${lbl}</span> ${fmtD(e.date)}${e.qty?` · ${e.qty}u`:''}</span>`+(last?'':'<span style="color:#D1D5DB;">→</span>'); }).join('')+'</div>'; };
 const Z = window.__invZone || 'tindakan';
 const F = window.__invRkFilter || 'all';

 // ============ ZONE: RINGKASAN ============
 let zRing = '<div style="display:grid; grid-template-columns:repeat(auto-fit, minmax(160px,1fr)); gap:10px; margin-bottom:8px;">'
   + `<div class="sa-kpi"><div class="sa-kpi__lbl">Nilai Stok (Kos)</div><div class="sa-kpi__val">${fmtRM0(totalCost)}</div></div>`
   + `<div class="sa-kpi"><div class="sa-kpi__lbl">Nilai Stok (Retail)</div><div class="sa-kpi__val">${fmtRM0(totalRetail)}</div></div>`
   + `<div class="sa-kpi"><div class="sa-kpi__lbl">Potensi Untung</div><div class="sa-kpi__val" style="color:#4E7C4A;">${fmtRM0(potensiUntung)}</div></div>`
   + `<div class="sa-kpi"><div class="sa-kpi__lbl">Jumlah Unit Stok</div><div class="sa-kpi__val">${totalUnits.toLocaleString()}</div><div style="font-size:11px; color:var(--text-muted); margin-top:2px;">${skuWithStock.toLocaleString()} SKU ada stok</div></div>`
   + `<div class="sa-kpi"><div class="sa-kpi__lbl">Stock Availability</div><div class="sa-kpi__val" style="color:${availColor};">${availPct == null ? '—' : availPct + '%'}</div>`
     + (availPct != null ? `<div style="height:6px; background:#EFEAE3; border-radius:4px; margin-top:6px; overflow:hidden;"><div style="height:100%; width:${availPct}%; background:${availColor};"></div></div>` : '')
     + `<div style="font-size:11px; color:var(--text-muted); margin-top:4px;">100% = ${availSkus.toLocaleString()} SKU pada tahap restock penuh</div></div>`
   + `<div class="sa-kpi"><div class="sa-kpi__lbl">Dead Stock %</div><div class="sa-kpi__val" style="color:${deadColor};">${deadPct == null ? '—' : deadPct + '%'}</div>`
     + (deadPct != null ? `<div style="height:6px; background:#EFEAE3; border-radius:4px; margin-top:6px; overflow:hidden;"><div style="height:100%; width:${Math.min(deadPct,100)}%; background:${deadColor};"></div></div>` : '')
     + `<div style="font-size:11px; color:var(--text-muted); margin-top:4px;">${fmtRM0(slowTied)} terikat · ${slow.length.toLocaleString()} SKU tak bergerak 90h</div></div>`
   + `<div class="sa-kpi"><div class="sa-kpi__lbl">Hari Stok</div><div class="sa-kpi__val" style="color:${dosColor};">${daysOfStock == null ? '∞' : daysOfStock + 'h'}</div><div style="font-size:11px; color:var(--text-muted); margin-top:4px;">${daysOfStock == null ? 'tiada jualan 90h' : 'tahan ~' + daysOfStock + ' hari ikut kadar jualan'}</div></div>`
   + `<div class="sa-kpi"><div class="sa-kpi__lbl">Inventory Turnover</div><div class="sa-kpi__val">${turnoverYr ? turnoverYr + '×' : '—'}</div><div style="font-size:11px; color:var(--text-muted); margin-top:4px;">pusingan stok setahun (anggaran)</div></div>`
   + `<div class="sa-kpi"><div class="sa-kpi__lbl">Sell-Through (90h)</div><div class="sa-kpi__val" style="color:${stColor};">${sellThru == null ? '—' : sellThru + '%'}</div><div style="font-size:11px; color:var(--text-muted); margin-top:4px;">${soldUnits90.toLocaleString()} terjual vs ${totalUnits.toLocaleString()} baki</div></div>`
   + '</div>'
   + '<p class="soft-note" style="margin:0 0 16px;">Nilai Kos = baki stok × landed cost. Nilai Retail = baki stok × harga jual. Potensi Untung anggaran kasar sebelum kos jualan. Stock Availability = berbanding tahap restock penuh terakhir (100% = baru penuh; turun bila terjual).</p>'
   + card(cardHead('Umur Stok (ikut nilai kos)')
     + '<div style="padding:14px;">'
     + '<div style="display:flex; height:22px; border-radius:6px; overflow:hidden; margin-bottom:10px; background:#EFEAE3;">'
     + ageBuckets.map(b => { const pct = b.cost / agingTot * 100; return pct > 0 ? `<div title="${b.lbl}: ${fmtRM0(b.cost)}" style="width:${pct}%; background:${b.col};"></div>` : ''; }).join('')
     + '</div>'
     + '<div style="display:flex; flex-wrap:wrap; gap:14px;">'
     + ageBuckets.map(b => { const pct = Math.round(b.cost / agingTot * 100); return `<div style="font-size:12px;"><span style="display:inline-block; width:10px; height:10px; border-radius:2px; background:${b.col}; margin-right:5px; vertical-align:-1px;"></span>${b.lbl}: <b>${pct}%</b> <span style="color:var(--text-muted);">${fmtRM0(b.cost)}</span></div>`; }).join('')
     + '</div>'
     + '<p class="soft-note" style="margin:10px 0 0;">Stok lama (180h+) berisiko jadi dead stock — pertimbang promosi / clearance.</p>'
     + '</div>')
   + '<div style="display:grid; grid-template-columns:repeat(auto-fit, minmax(120px,1fr)); gap:10px;">'
   + `<div class="sa-kpi" style="border-left:3px solid #B23A2E;"><div class="sa-kpi__lbl">Reorder Segera</div><div class="sa-kpi__val">${nReorder.toLocaleString()}</div></div>`
   + `<div class="sa-kpi" style="border-left:3px solid #B23A2E;"><div class="sa-kpi__lbl">Nilai PO Restock</div><div class="sa-kpi__val">${fmtRM0(poCost)}</div><div style="font-size:11px; color:var(--text-muted); margin-top:2px;">${poUnits.toLocaleString()} unit · ${poSkus.toLocaleString()} SKU</div></div>`
   + `<div class="sa-kpi" style="border-left:3px solid ${stockoutSkus ? '#B23A2E' : '#4E7C4A'};"><div class="sa-kpi__lbl">Habis Stok (laku)</div><div class="sa-kpi__val" style="color:${stockoutSkus ? '#B23A2E' : '#4E7C4A'};">${stockoutSkus.toLocaleString()}</div><div style="font-size:11px; color:var(--text-muted); margin-top:2px;">${stockoutSkus ? '~' + fmtRM0(lostRevDay) + '/hari terlepas' : 'tiada'}</div></div>`
   + `<div class="sa-kpi" style="border-left:3px solid #CE9420;"><div class="sa-kpi__lbl">Perhati</div><div class="sa-kpi__val">${nPerhati.toLocaleString()}</div></div>`
   + `<div class="sa-kpi" style="border-left:3px solid #4E7C4A;"><div class="sa-kpi__lbl">Sihat</div><div class="sa-kpi__val">${nSihat.toLocaleString()}</div></div>`
   + `<div class="sa-kpi" style="border-left:3px solid #9CA3AF;"><div class="sa-kpi__lbl">Stok Mati</div><div class="sa-kpi__val">${nDead.toLocaleString()}</div></div>`
   + `<div class="sa-kpi" style="border-left:3px solid #D1D5DB;"><div class="sa-kpi__lbl">Discontinued</div><div class="sa-kpi__val">${cDisc.toLocaleString()}</div></div>`
   + '</div>'
   + '<div style="margin-top:16px;">' + card(cardHead('Kesihatan Stok ikut Brand')
     + '<div style="overflow-x:auto;"><table style="width:100%; border-collapse:collapse; font-size:12.5px;"><thead><tr style="background:#FAFAFA; text-align:left; color:var(--text-muted);">'
     + '<th style="padding:8px 12px;">Brand</th><th style="padding:8px 12px; text-align:right;">Nilai Stok</th><th style="padding:8px 12px; text-align:right;">SKU</th><th style="padding:8px 12px; text-align:right;">Availability</th><th style="padding:8px 12px; text-align:right;">Dead Stock</th></tr></thead><tbody>'
     + brandRows.map(g => { const ac = g.avail == null ? '#9CA3AF' : (g.avail >= 70 ? '#4E7C4A' : (g.avail >= 40 ? '#9E7016' : '#B23A2E')); const dc = g.deadPct >= 30 ? '#B23A2E' : (g.deadPct >= 15 ? '#9E7016' : '#4E7C4A'); return `<tr><td style="padding:8px 12px; font-weight:600;">${esc(g.brand)}</td><td style="padding:8px 12px; text-align:right;">${fmtRM0(g.cost)}</td><td style="padding:8px 12px; text-align:right; color:var(--text-muted);">${g.skus.toLocaleString()}</td><td style="padding:8px 12px; text-align:right; color:${ac}; font-weight:700;">${g.avail == null ? '—' : g.avail + '%'}</td><td style="padding:8px 12px; text-align:right; color:${dc}; font-weight:700;">${g.deadPct}%</td></tr>`; }).join('')
     + '</tbody></table></div>'
     + '<p class="soft-note" style="margin:8px 14px 12px;">Availability rendah / Dead Stock tinggi pada satu brand = modal tersangkut di situ — guna untuk clearance atau negotiate supplier.</p>') + '</div>'
   + '<div style="margin-top:16px;">' + card(cardHead('Trend Nilai Stok')
     + '<div style="padding:14px; position:relative; height:230px;"><canvas id="invTrendChart"></canvas>'
     + '<div id="invTrendEmpty" style="display:none; text-align:center; color:var(--text-muted); padding:40px 10px; font-size:12.5px;">Trend direkod harian mulai hari ni — datang balik esok-lusa untuk lihat garis trend.</div></div>') + '</div>';

 // ============ ZONE: TINDAKAN ============
 const ctrl = `<div style="display:flex; gap:18px; align-items:center; flex-wrap:wrap; padding:10px 14px; border-bottom:1px solid var(--border-color); font-size:12px; background:#FCFCFD;">
   <span>Alert bila baki ≤ <select onchange="window.__invSetThreshold(this.value)" style="font-size:12px; padding:3px 6px; border:1px solid var(--border-color); border-radius:6px;">${[10,15,20,25,30,40].map(v=>`<option value="${v}" ${v===THR?'selected':''}>${v}%</option>`).join('')}</select></span>
   <span>Lead time China <select onchange="window.__invSetLead(this.value)" style="font-size:12px; padding:3px 6px; border:1px solid var(--border-color); border-radius:6px;">${[21,28,35,42,49].map(v=>`<option value="${v}" ${v===LEAD?'selected':''}>${v} hari (~${Math.round(v/7)} mgg)</option>`).join('')}</select></span>
 </div>`;
 const pills = `<div style="display:flex; gap:10px; align-items:center; flex-wrap:wrap; padding:10px 14px; border-bottom:1px solid var(--border-color);">
   <div id="invRkPills" style="display:flex; gap:6px; flex-wrap:wrap;">
     <span class="inv-pill ${F==='all'?'active':''}" onclick="window.__invSetRkFilter('all',this)">Semua (${action.length})</span>
     <span class="inv-pill ${F==='reorder'?'active':''}" onclick="window.__invSetRkFilter('reorder',this)">Reorder Segera (${nReorder})</span>
     <span class="inv-pill ${F==='perhati'?'active':''}" onclick="window.__invSetRkFilter('perhati',this)">Perhati (${nPerhati})</span>
   </div>
   <input id="invRkSearch" oninput="window.__invFilterRows()" value="${esc(window.__invSearch||'')}" placeholder="Cari SKU / nama…" style="margin-left:auto; font-size:12px; padding:5px 10px; border:1px solid var(--border-color); border-radius:8px; min-width:160px;">
 </div>`;
 const rkRows = action.map(t => `<tr class="inv-rk-row" data-cat="${t.cat}" data-skuid="${sid(t.sku)}" data-search="${esc((t.sku+' '+t.name).toLowerCase())}" onclick="window.__invToggleRow('${sid(t.sku)}')" style="cursor:pointer; border-top:1px solid var(--border-color);">
   <td style="padding:8px 6px 8px 12px; width:16px; color:#9CA3AF;"><i id="invArr_${sid(t.sku)}" data-lucide="chevron-right" style="width:13px;height:13px; transition:transform .15s;"></i></td>
   <td style="padding:8px 6px;"><div style="font-weight:600;">${esc(t.name.slice(0,48))}</div><div style="font-size:10px; color:#9CA3AF; font-family:'SF Mono',Menlo,monospace;">${esc(t.sku)}</div></td>
   <td style="padding:8px 12px; text-align:right; font-weight:700; color:${t.stock===0?'#B23A2E':'inherit'};">${t.stock}</td>
   <td style="padding:8px 12px; text-align:right;">${pctCell(t)}</td>
   <td style="padding:8px 12px; text-align:right;">${dcCell(t)}</td>
   <td style="padding:8px 12px; text-align:right; font-weight:700; color:var(--primary);">+${suggestOf(t)}</td>
   <td style="padding:8px 12px;">${badge2(t.cat)}</td>
 </tr>
 <tr id="invDtl_${sid(t.sku)}" style="display:none; background:#FCFCFD;"><td colspan="7" style="padding:4px 16px 14px 38px;">
   <div style="font-size:11px; color:var(--text-muted); margin:4px 0;">Sejarah Restock · supplier ${esc(supOf(t.sku))}</div>
   ${timeline(t)}
   <div style="font-size:11px; color:var(--text-muted); margin-top:8px;">Jual 30 hari: <b>${t.sold30}</b> · Qty restock akhir: <b>${t.lastQty||'—'}</b> · Cadang order: <b style="color:var(--primary);">+${suggestOf(t)}</b></div>
 </td></tr>`).join('');
 const deadRows = dead.slice(0,200).map(t => `<tr style="border-top:1px solid var(--border-color);">
   <td style="padding:7px 12px; font-family:'SF Mono',Menlo,monospace; font-size:11px;">${esc(t.sku)}</td>
   <td style="padding:7px 12px;">${esc(t.name.slice(0,48))}</td>
   <td style="padding:7px 12px; color:#9CA3AF;">${t.lastDate?fmtD(t.lastDate):'tiada rekod'}</td>
 </tr>`).join('');
 let zTind = card(
   cardHead(`<i data-lucide="clipboard-check" style="width:14px;height:14px;vertical-align:-2px; color:var(--primary);"></i> Perlu Restock <span style="font-weight:500; color:var(--text-muted); font-size:11.5px;">— ${action.length} barang (${nReorder} segera · ${nPerhati} perhati) · ${nSihat} sihat`+(nDead?` · ${nDead} stok mati`:'')+`</span>`)
   + ctrl + pills
   + '<div style="overflow-x:auto;"><table style="width:100%; border-collapse:collapse; font-size:12px;"><thead><tr style="color:var(--text-muted); text-align:left;"><th style="padding:8px 6px 8px 12px;" colspan="2">Produk</th><th style="padding:8px 12px; text-align:right;">Stok</th><th style="padding:8px 12px; text-align:right;" title="Stok ÷ qty restock terakhir">% Baki</th><th style="padding:8px 12px; text-align:right;" title="Hari lagi sebelum habis">Hari Lagi</th><th style="padding:8px 12px; text-align:right;" title="Cadangan kuantiti order">Cadang</th><th style="padding:8px 12px;">Status</th></tr></thead><tbody id="invRkBody">'
   + rkRows + '</tbody></table>'
   + `<div id="invRkEmpty" style="display:${action.length?'none':''}; text-align:center; color:#4E7C4A; padding:24px;">Tiada barang perlu restock — semua sihat.</div></div>`
   + (nDead ? `<div style="border-top:1px solid var(--border-color);"><div onclick="window.__invToggleDead()" style="cursor:pointer; padding:10px 14px; font-size:12px; color:var(--text-muted); display:flex; align-items:center; gap:6px;"><i id="invDeadArr" data-lucide="chevron-right" style="width:13px;height:13px; transition:transform .15s;"></i> Stok Mati — habis + 0 jualan 90 hari: <b style="margin:0 2px;">${nDead}</b> item (calon discontinue)</div><div id="invDeadWrap" style="display:none; overflow-x:auto;"><table style="width:100%; border-collapse:collapse; font-size:11.5px;"><thead><tr style="color:var(--text-muted); text-align:left;"><th style="padding:6px 12px;">SKU</th><th style="padding:6px 12px;">Produk</th><th style="padding:6px 12px;">Restock Akhir</th></tr></thead><tbody>${deadRows}</tbody></table>${dead.length>200?`<div style="padding:8px 14px; font-size:11px; color:var(--text-muted);">200 daripada ${dead.length}.</div>`:''}</div></div>` : '')
   + '<div style="padding:8px 14px; font-size:11px; color:var(--text-muted); line-height:1.5;">Klik baris untuk lihat sejarah restock penuh. % Baki = stok ÷ qty restock terakhir. REORDER = habis-tapi-laku / baki ≤ threshold / hari-lagi ≤ lead time.</div>'
 );
 // Supplier shopping list (reorder sahaja)
 const need = action.filter(t => t.cat === 'reorder');
 const bySup = {};
 need.forEach(t => { const s = supOf(t.sku); (bySup[s] || (bySup[s] = [])).push(t); });
 const supNames = Object.keys(bySup).sort((a,b) => bySup[b].length - bySup[a].length);
 let shopHtml = '';
 supNames.forEach(s => {
   const items = bySup[s];
   const totalQty = items.reduce((x,i) => x + suggestOf(i), 0);
   shopHtml += `<div style="padding:10px 14px; border-bottom:1px solid var(--border-color);">
     <div style="font-weight:700; font-size:12.5px; display:flex; justify-content:space-between; gap:8px;"><span><i data-lucide="package" style="width:13px;height:13px;vertical-align:-2px;"></i> ${esc(s)}</span><span style="color:var(--text-muted); font-weight:500;">${items.length} item · cadang ${totalQty} unit</span></div>
     <table style="width:100%; border-collapse:collapse; font-size:11.5px; margin-top:6px;"><tbody>${items.map(i => `<tr><td style="padding:3px 0; font-family:'SF Mono',Menlo,monospace; width:70px;">${esc(i.sku)}</td><td style="padding:3px 8px;">${esc(i.name.slice(0,38))}</td><td style="padding:3px 8px; text-align:right; color:#6B7280; white-space:nowrap;">stok ${i.stock}</td><td style="padding:3px 0; text-align:right; font-weight:700; color:var(--primary); white-space:nowrap; width:80px;">order ${suggestOf(i)}</td></tr>`).join('')}</tbody></table>
   </div>`;
 });
 if(!shopHtml) shopHtml = '<div style="padding:24px; text-align:center; color:#4E7C4A;">Tiada barang perlu diorder sekarang.</div>';
 zTind += card(
   cardHead(`<i data-lucide="shopping-cart" style="width:14px;height:14px;vertical-align:-2px; color:var(--primary);"></i> Senarai Order Ikut Supplier <span style="font-weight:500; color:var(--text-muted); font-size:11.5px;">— ${need.length} barang · ${supNames.length} supplier</span>`)
   + shopHtml
   + '<div style="padding:8px 14px; font-size:11px; color:var(--text-muted); line-height:1.5;">Cadang order = cukup (lead time + 30 hari) jualan / qty restock lalu / reorder point. Kumpul ikut prefix SKU. Hanya barang REORDER.</div>'
 );
 // ============ ZONE: ANALISA ============
 let slowRows = slow.slice(0, 50).map(x => `<tr>
   <td style="padding:8px 12px; font-family:'SF Mono',Menlo,monospace; font-size:11.5px;">${esc(x.sku)}</td>
   <td style="padding:8px 12px;">${esc(x.name.slice(0,42))}${x.disc?' <span style="font-size:10px; color:#9CA3AF;">(disc)</span>':''}</td>
   <td style="padding:8px 12px; text-align:right; font-weight:700;">${x.stock}</td>
   <td style="padding:8px 12px; text-align:right;">${fmtRM2(x.tied)}</td>
   <td style="padding:8px 12px; text-align:right; color:${x.ageDays!=null && x.ageDays>=180?'#B23A2E':'#6B7280'};">${x.ageDays != null ? x.ageDays+'h' : '—'}</td>
 </tr>`).join('');
 if(!slowRows) slowRows = '<tr><td colspan="5" style="text-align:center; color:#4E7C4A; padding:24px;">Tiada slow mover. Semua stok bergerak.</td></tr>';
 let zAnal = card(
   cardHead(`<i data-lucide="snail" style="width:14px;height:14px;vertical-align:-2px; color:#6B7280;"></i> Slow Mover <span style="font-weight:500; color:var(--text-muted); font-size:11.5px;">— ${slow.length} produk · 0 jualan 90 hari · modal tersangkut ${fmtRM0(slowTied)}</span>`)
   + '<div style="overflow-x:auto;"><table style="width:100%; border-collapse:collapse; font-size:12px;"><thead><tr style="color:var(--text-muted); text-align:left;"><th style="padding:8px 12px;">SKU</th><th style="padding:8px 12px;">Produk</th><th style="padding:8px 12px; text-align:right;">Stok</th><th style="padding:8px 12px; text-align:right;">Modal Tersangkut</th><th style="padding:8px 12px; text-align:right;" title="Umur batch tertua">Umur Stok</th></tr></thead><tbody>'
   + slowRows + '</tbody></table></div>'
   + (slow.length > 50 ? '<div style="padding:8px 14px; font-size:11px; color:var(--text-muted);">Menunjukkan 50 teratas daripada '+slow.length+'.</div>' : '')
 );

 let catRows = topCats.map(c => `<tr>
   <td style="padding:8px 12px;">${esc(c.cat)}</td>
   <td style="padding:8px 12px; text-align:right;">${fmtRM0(c.cost)}</td>
   <td style="padding:8px 12px; text-align:right; color:#6B7280;">${fmtRM0(c.retail)}</td>
 </tr>`).join('');
 if(catRows) zAnal += card(
   cardHead('<i data-lucide="layers" style="width:14px;height:14px;vertical-align:-2px;"></i> Nilai Stok Ikut Kategori <span style="font-weight:500; color:var(--text-muted); font-size:11.5px;">— di mana modal tersangkut</span>')
   + '<div style="overflow-x:auto;"><table style="width:100%; border-collapse:collapse; font-size:12px;"><thead><tr style="color:var(--text-muted); text-align:left;"><th style="padding:8px 12px;">Kategori</th><th style="padding:8px 12px; text-align:right;">Nilai Kos</th><th style="padding:8px 12px; text-align:right;">Nilai Retail</th></tr></thead><tbody>'
   + catRows + '</tbody></table></div>'
 );

 const ageB = [
   { lbl:'0–90 hari', min:0, max:90, col:'#4E7C4A', n:0, units:0, val:0 },
   { lbl:'90–180 hari', min:90, max:180, col:'#65A30D', n:0, units:0, val:0 },
   { lbl:'180–365 hari', min:180, max:365, col:'#9E7016', n:0, units:0, val:0 },
   { lbl:'365+ hari', min:365, max:Infinity, col:'#B23A2E', n:0, units:0, val:0 }
 ];
 const noRec = { n:0, units:0, val:0 };
 products.forEach(p => {
   const stock = stockMap.get(p.sku) || 0; if(stock <= 0) return;
   const val = costValMap.get(p.sku) || 0;
   const rec = lastByS[p.sku];
   if(!rec || !rec.date) { noRec.n++; noRec.units += stock; noRec.val += val; return; }
   const age = Math.floor((now - new Date(rec.date).getTime()) / 864e5);
   const b = ageB.find(x => age >= x.min && age < x.max) || ageB[ageB.length-1];
   b.n++; b.units += stock; b.val += val;
 });
 const ageRows = ageB.map(b => `<tr>
   <td style="padding:8px 12px;"><span style="display:inline-block; width:9px; height:9px; border-radius:2px; background:${b.col}; margin-right:7px;"></span>${b.lbl}</td>
   <td style="padding:8px 12px; text-align:right;">${b.n.toLocaleString()}</td>
   <td style="padding:8px 12px; text-align:right; color:#6B7280;">${b.units.toLocaleString()}</td>
   <td style="padding:8px 12px; text-align:right; font-weight:700; color:${b.col};">${fmtRM0(b.val)}</td>
 </tr>`).join('') + (noRec.n ? `<tr><td style="padding:8px 12px; color:#9CA3AF;"><span style="display:inline-block; width:9px; height:9px; border-radius:2px; background:#D1D5DB; margin-right:7px;"></span>Tiada rekod restock</td><td style="padding:8px 12px; text-align:right; color:#9CA3AF;">${noRec.n.toLocaleString()}</td><td style="padding:8px 12px; text-align:right; color:#9CA3AF;">${noRec.units.toLocaleString()}</td><td style="padding:8px 12px; text-align:right; color:#9CA3AF;">${fmtRM0(noRec.val)}</td></tr>` : '');
 const staleVal = ageB[2].val + ageB[3].val;
 zAnal += card(
   cardHead(`<i data-lucide="clock" style="width:14px;height:14px;vertical-align:-2px; color:#9E7016;"></i> Umur Stok <span style="font-weight:500; color:var(--text-muted); font-size:11.5px;">— sejak restock terakhir · modal lama (180h+) ${fmtRM0(staleVal)}</span>`)
   + '<div style="overflow-x:auto;"><table style="width:100%; border-collapse:collapse; font-size:12px;"><thead><tr style="color:var(--text-muted); text-align:left;"><th style="padding:8px 12px;">Umur</th><th style="padding:8px 12px; text-align:right;">SKU</th><th style="padding:8px 12px; text-align:right;">Unit</th><th style="padding:8px 12px; text-align:right;">Nilai Kos</th></tr></thead><tbody>'
   + ageRows + '</tbody></table></div>'
   + '<div style="padding:8px 14px; font-size:11px; color:var(--text-muted); line-height:1.5;">Umur = hari sejak SKU ni terakhir restock (DO). Modal lama (180h+) merah = duit tertimbun dalam stok yang dah lama tak ditambah — calon clearance kalau jualan perlahan.</div>'
 );

 // Log Pergerakan Stok (stock card per SKU) — diletak PALING ATAS zon Analisa
 const skuOpts = products.slice().sort((a,b)=>(a.sku||'').localeCompare(b.sku||'')).map(p => `<option value="${esc(p.sku)}">${esc((p.name||'').slice(0,42))}</option>`).join('');
 const stockCard = card(
   cardHead('<i data-lucide="arrow-left-right" style="width:14px;height:14px;vertical-align:-2px; color:var(--primary);"></i> Log Pergerakan Stok <span style="font-weight:500; color:var(--text-muted); font-size:11.5px;">— pilih SKU: masuk (restock) & keluar (jualan), baki berjalan</span>')
   + '<div style="padding:12px 14px; border-bottom:1px solid var(--border-color);"><input id="invStockCardSku" list="invStockCardSkus" placeholder="Taip / pilih SKU…" onchange="window.__invStockCard(this.value)" onkeydown="if(event.key===\'Enter\'){event.preventDefault();window.__invStockCard(this.value);}" style="font-size:13px; padding:7px 11px; border:1px solid var(--border-color); border-radius:8px; min-width:240px;"><datalist id="invStockCardSkus">' + skuOpts + '</datalist></div>'
   + '<div id="invStockCardBody"><div style="padding:24px; text-align:center; color:#9CA3AF; font-size:12px;">Taip SKU di atas untuk lihat log pergerakan stok (masuk & keluar) + baki berjalan.</div></div>'
 );
 zAnal = stockCard + zAnal;

 // ============ ZONE: DEAD STOCK (visual, bergambar) ============
 const deadCount = (window.__invDeadList||[]).length;
 const deadUnits = (window.__invDeadList||[]).reduce((s,x)=>s+(x.stock||0),0);
 const deadTied = (window.__invDeadList||[]).reduce((s,x)=>s+(x.tied||0),0);
 const dsSort = window.__invDeadSort || 'units';
 const zDead = card(
   cardHead(`<i data-lucide="package-x" style="width:14px;height:14px;vertical-align:-2px; color:#B23A2E;"></i> Dead Stock <span style="font-weight:500; color:var(--text-muted); font-size:11.5px;">— ada stok tapi 0 jualan 90 hari · ${deadCount} SKU · ${deadUnits.toLocaleString()} unit · modal tersangkut ${fmtRM0(deadTied)}</span>`)
   + `<div style="display:flex; gap:10px; align-items:center; flex-wrap:wrap; padding:10px 14px; border-bottom:1px solid var(--border-color);">
       <div style="display:flex; gap:6px; align-items:center; font-size:12px;">Susun: <select onchange="window.__invSetDeadSort(this.value)" style="font-size:12px; padding:4px 8px; border:1px solid var(--border-color); border-radius:6px;">
         <option value="units" ${dsSort==='units'?'selected':''}>Unit terbanyak</option>
         <option value="modal" ${dsSort==='modal'?'selected':''}>Modal tersangkut</option>
         <option value="umur" ${dsSort==='umur'?'selected':''}>Paling lama</option>
       </select></div>
       <input id="invDeadSearch" oninput="window.__invDeadFilter()" value="${esc(window.__invDeadSearch||'')}" placeholder="Cari SKU / nama…" style="margin-left:auto; font-size:12px; padding:6px 10px; border:1px solid var(--border-color); border-radius:8px; min-width:180px;">
     </div>`
   + `<div id="invDeadGrid" style="display:grid; grid-template-columns:repeat(auto-fill, minmax(150px, 1fr)); gap:12px; padding:14px;"></div>`
   + '<div style="padding:8px 14px; font-size:11px; color:var(--text-muted); line-height:1.5;">Dead Stock = barang ADA stok tapi TIADA jualan langsung dalam 90 hari. Unit = baki stok semasa. Modal tersangkut = baki × landed cost. Calon clearance / bundle / promosi.</div>'
 );

 // ============ ASSEMBLE 3 SUB-TAB ============
 const styleB = '<style>'
   + '#anInvBody .inv-subtab{font-size:12.5px;font-weight:700;padding:9px 16px;border:none;border-bottom:2.5px solid transparent;background:none;color:var(--text-muted);cursor:pointer;display:inline-flex;align-items:center;gap:6px;}'
   + '#anInvBody .inv-subtab.active{color:var(--primary);border-bottom-color:var(--primary);}'
   + '#anInvBody .inv-pill{font-size:11.5px;padding:5px 12px;border:1px solid var(--border-color);border-radius:16px;background:#F9FAFB;color:#374151;cursor:pointer;user-select:none;}'
   + '#anInvBody .inv-pill.active{background:var(--primary);color:#fff;border-color:var(--primary);font-weight:700;}'
   + '</style>';
 const subtab = (k, icon, label) => `<span class="inv-subtab ${Z===k?'active':''}" onclick="window.__invSubTab('${k}', this)"><i data-lucide="${icon}" style="width:14px;height:14px;"></i> ${label}</span>`;
 body.innerHTML = styleB
   + `<div id="invSubTabs" style="display:flex; gap:2px; border-bottom:1px solid var(--border-color); margin-bottom:16px; flex-wrap:wrap;">${subtab('ringkasan','layout-dashboard','Ringkasan')}${subtab('tindakan','clipboard-check','Tindakan')}${subtab('analisa','bar-chart-3','Analisa')}${subtab('deadstock','package-x','Dead Stock')}</div>`
   + `<div id="invZone_ringkasan" style="display:${Z==='ringkasan'?'':'none'}">${zRing}</div>`
   + `<div id="invZone_tindakan" style="display:${Z==='tindakan'?'':'none'}">${zTind}</div>`
   + `<div id="invZone_analisa" style="display:${Z==='analisa'?'':'none'}">${zAnal}</div>`
   + `<div id="invZone_deadstock" style="display:${Z==='deadstock'?'':'none'}">${zDead}</div>`;
 if(window.lucide && lucide.createIcons) try { lucide.createIcons(); } catch(e){}
 window.__invFilterRows();
 if(Z === 'ringkasan') setTimeout(() => { try { window.__invDrawTrend(); } catch(e){} }, 60); // p1_807 — lukis graf trend
 window.__invRenderDeadGrid();
};

// p1_500 — Export Analytics: pilih bahagian → satu CSV berbilang seksyen
window.__anExportOpen = function() {
 if(!window.__anData && typeof renderAnalytics === 'function') renderAnalytics();
 const p = document.getElementById('anExpPeriod');
 if(p) p.textContent = (window.__anData && window.__anData.periodLabel) || '';
 const m = document.getElementById('anExportModal');
 if(m) m.style.display = 'flex';
 if(window.lucide && lucide.createIcons) try { lucide.createIcons(); } catch(e){}
};
window.__anExportToggleAll = function(on) {
 ['anExpKpi','anExpTrend','anExpProd','anExpBrand','anExpCat','anExpChannel','anExpPayment','anExpStaff','anExpCust','anExpHour','anExpDow'].forEach(id => { const e=document.getElementById(id); if(e) e.checked = !!on; });
};
window.__anExportRun = function() {
 const d = window.__anData;
 if(!d) { if(typeof showToast === 'function') showToast('Buka Analytics dulu.', 'warn'); return; }
 const chk = (id) => { const e = document.getElementById(id); return e ? e.checked : false; };
 const q = (v) => '"' + String(v == null ? '' : v).replace(/"/g, '""') + '"';
 const pct = (rev) => d.kpis.rev ? Math.round(rev / d.kpis.rev * 100) : 0;
 const out = [];
 out.push('Laporan Analytics 10 CAMP');
 out.push('Tempoh,' + q(d.periodLabel));
 out.push('Dijana,' + q(new Date().toLocaleString('en-MY')));
 out.push('');
 const sec = (title, header, rows) => { out.push('=== ' + title + ' ==='); out.push(header.join(',')); (rows || []).forEach(r => out.push(r.map(q).join(','))); out.push(''); };
 let any = false;
 if(chk('anExpKpi')) { any = true; sec('KPI RINGKASAN', ['Metrik','Nilai'], [['Jualan (RM)', d.kpis.rev.toFixed(2)],['Order', d.kpis.orders],['Purata/Order (RM)', d.kpis.aov.toFixed(2)],['Unit Terjual', d.kpis.units],['Customer Baru', d.kpis.newC],['Kadar Ulang (%)', d.kpis.repeatRate]]); }
 if(chk('anExpTrend')) { any = true; sec('TREND JUALAN (semasa vs sebelum)', ['Tarikh','Semasa (RM)','Tempoh Sebelum (RM)'], d.trend.labels.map((l,i)=>[l, (d.trend.cur[i]||0).toFixed(2), (d.trend.prev[i]||0).toFixed(2)])); }
 if(chk('anExpProd')) { any = true; sec('TOP PRODUK', ['#','Produk','Unit','Hasil (RM)'], d.topProd.map((x,i)=>[i+1, x.name, x.units, x.rev.toFixed(2)])); }
 if(chk('anExpBrand')) { any = true; sec('TOP BRAND', ['#','Brand','Unit','Hasil (RM)'], d.topBrand.map((x,i)=>[i+1, x.k, x.units, x.rev.toFixed(2)])); }
 if(chk('anExpCat')) { any = true; sec('TOP KATEGORI', ['#','Kategori','Unit','Hasil (RM)'], d.topCat.map((x,i)=>[i+1, x.k, x.units, x.rev.toFixed(2)])); }
 if(chk('anExpChannel')) { any = true; sec('PRESTASI CHANNEL', ['Channel','Order','Hasil (RM)','%'], d.channels.map(x=>[x.k, x.orders, x.rev.toFixed(2), pct(x.rev)])); }
 if(chk('anExpPayment')) { any = true; sec('SALES BY PAYMENT METHOD', ['Kaedah','Order','Hasil (RM)','%'], d.payments.map(x=>[x.k, x.orders, x.rev.toFixed(2), pct(x.rev)])); }
 if(chk('anExpStaff')) { any = true; sec('SALES BY STAFF', ['Staff','Order','Unit','Hasil (RM)','%'], d.staff.map(x=>[x.k, x.orders, x.units, x.rev.toFixed(2), pct(x.rev)])); }
 if(chk('anExpCust')) { any = true; sec('TOP CUSTOMER', ['#','Customer','Order','Hasil (RM)'], d.topCust.map((x,i)=>[i+1, x.name, x.orders, x.rev.toFixed(2)])); }
 if(chk('anExpHour')) { any = true; sec('JAM PALING SIBUK', ['Jam','Hasil (RM)'], d.hours.map((v,i)=>[i+':00', (v||0).toFixed(2)])); }
 if(chk('anExpDow')) { any = true; sec('HARI PALING SIBUK', ['Hari','Hasil (RM)'], d.dows.map(x=>[x.day, (x.rev||0).toFixed(2)])); }
 if(!any) { if(typeof showToast === 'function') showToast('Pilih sekurang-kurangnya satu bahagian.', 'warn'); return; }
 const blob = new Blob(['﻿' + out.join('\n')], { type: 'text/csv;charset=utf-8;' });
 const url = URL.createObjectURL(blob);
 const a = document.createElement('a');
 a.href = url; a.download = 'analytics-10camp-' + new Date().toISOString().slice(0,10) + '.csv';
 document.body.appendChild(a); a.click(); document.body.removeChild(a);
 setTimeout(() => URL.revokeObjectURL(url), 1000);
 const m = document.getElementById('anExportModal'); if(m) m.style.display = 'none';
 if(typeof showToast === 'function') showToast('Analytics di-export ke CSV.', 'success');
};

window.renderProductSales = function() {
 const tbody = document.getElementById('prodSalesTbody');
 if(!tbody) return;

 const stats = __computeProductSales();
 const all = [...stats.values()];

 // Populate brand filter
 const brandSel = document.getElementById('prodSalesBrand');
 if(brandSel && brandSel.options.length <= 1) {
 const brands = [...new Set(all.map(s => s.brand).filter(Boolean))].sort();
 brandSel.innerHTML = '<option value="">Semua</option>' + brands.map(b => `<option value="${b}">${b}</option>`).join('');
 }

 const q = (document.getElementById('prodSalesSearch').value || '').trim().toLowerCase();
 const filterBrand = document.getElementById('prodSalesBrand').value;
 const filterMode = document.getElementById('prodSalesFilter').value;
 const sortMode = document.getElementById('prodSalesSort').value;
 const pageSize = parseInt(document.getElementById('prodSalesPageSize').value) || 100;

 // Compute balance
 all.forEach(r => {
 r.balance = r.stock - r.totalSold;
 });

 let filtered = all.filter(r => {
 if(filterBrand && r.brand !== filterBrand) return false;
 if(filterMode === 'negative' && r.balance>= 0) return false;
 if(filterMode === 'zero_stock' && r.stock !== 0) return false;
 if(filterMode === 'movers' && r.totalSold === 0) return false;
 if(filterMode === 'dead' && r.totalSold> 0) return false;
 if(q) {
 const hay = `${r.sku} ${r.name||''} ${r.brand||''}`.toLowerCase();
 if(!hay.includes(q)) return false;
 }
 return true;
 });

 // Sort
 filtered.sort((a, b) => {
 switch(sortMode) {
 case 'balance_asc': return a.balance - b.balance;
 case 'sold_desc': return b.totalSold - a.totalSold;
 case 'recent_desc': return b.recentSold - a.recentSold;
 case 'stock_asc': return a.stock - b.stock;
 case 'sku': return a.sku.localeCompare(b.sku);
 default: return a.balance - b.balance;
 }
 });

 const total = filtered.length;
 const slice = filtered.slice(0, pageSize);

 // Stats cards
 const totalSold = all.reduce((s, r) => s + r.totalSold, 0);
 const totalRevenue = all.reduce((s, r) => s + r.revenue, 0);
 const negativeBalance = all.filter(r => r.balance < 0).length;
 const zeroStock = all.filter(r => r.stock === 0).length;
 document.getElementById('prodSalesSummaryStats').innerHTML = `
 <div style="background:var(--primary-50,#FFF8F0); padding:10px; border-radius:6px;"><div style="font-size:10px; color:var(--primary-800,#7C4A1A);">Total Unit Sold</div><div style="font-size:18px; font-weight:bold;">${totalSold.toLocaleString()}</div></div>
 <div style="background:#EEF3EC; padding:10px; border-radius:6px;"><div style="font-size:10px; color:#34522F;">Total Revenue</div><div style="font-size:18px; font-weight:bold;">RM ${totalRevenue.toLocaleString(undefined,{minimumFractionDigits:2,maximumFractionDigits:2})}</div></div>
 <div style="background:#FAF0EE; padding:10px; border-radius:6px;"><div style="font-size:10px; color:#7C2A20;">Negative Balance</div><div style="font-size:18px; font-weight:bold;">${negativeBalance} SKU</div></div>
 <div style="background:#F8EFD7; padding:10px; border-radius:6px;"><div style="font-size:10px; color:#7A5410;">Zero Stock</div><div style="font-size:18px; font-weight:bold;">${zeroStock} SKU</div></div>
 `;

 document.getElementById('prodSalesSummaryLine').innerHTML =
 `Match: <strong>${total}</strong> · Show: <strong>${slice.length}</strong>${total> slice.length ? ` <span style="color:#B23A2E;">(turunkan saiz halaman / tightenkan filter untuk lihat semua)</span>` : ''}`;

 if(slice.length === 0) {
 tbody.innerHTML = '<tr><td colspan="9" style="text-align:center; padding:30px; color:#999;">Tiada produk match filter.</td></tr>';
 return;
 }

 tbody.innerHTML = slice.map(r => {
 const balanceColor = r.balance < 0 ? '#B23A2E' : (r.balance < 5 ? '#C68A1A' : '#101010');
 const balanceText = r.balance < 0 ? `−${Math.abs(r.balance).toFixed(0)}` : r.balance.toFixed(0);
 const lastSaleStr = r.lastSale ? new Date(r.lastSale).toISOString().slice(0,10) : '-';
 const lastSaleColor = r.lastSale && (Date.now() - new Date(r.lastSale).getTime()) < 90*86400000 ? '#101010' : '#9CA3AF';
 const stockColor = r.stock === 0 ? '#B23A2E' : (r.stock < (r.reorder_point || 5) ? '#C68A1A' : '#111');
 const recentBadge = r.recentSold> 0 ? `<span style="background:#E4EFE2; color:#345E43; padding:1px 5px; border-radius:3px; font-size:10px; margin-left:4px;"></span>` : '';
 return `
 <tr>
 <td style="font-family:monospace; font-size:11px;"><strong>${r.sku}</strong></td>
 <td style="max-width:280px;"><div>${(r.name || '').slice(0, 70)}</div><span style="color:#888; font-size:10px;">${r.brand || '-'} · ${r.category || '-'}</span></td>
 <td style="text-align:right; font-weight:bold;">${r.totalSold.toFixed(0)}</td>
 <td style="text-align:right;">${r.recentSold.toFixed(0)}${recentBadge}</td>
 <td style="text-align:right; color:${stockColor}; font-weight:bold;">${r.stock}</td>
 <td style="text-align:right; color:${balanceColor}; font-weight:bold; font-size:14px;">${balanceText}</td>
 <td style="text-align:right; color:#666;">${r.reorder_point ?? '-'}</td>
 <td style="text-align:right; color:#666;">${r.revenue.toFixed(2)}</td>
 <td style="text-align:center; color:${lastSaleColor}; font-size:11px;">${lastSaleStr}</td>
 </tr>
 `;
 }).join('');
};

window.exportProductSalesCsv = function() {
 const stats = __computeProductSales();
 const all = [...stats.values()];
 all.forEach(r => r.balance = r.stock - r.totalSold);
 all.sort((a, b) => a.balance - b.balance);

 const header = ['SKU','Name','Brand','Category','Total_Sold_Lifetime','Last_6mo_Sold','Stock_Now','Balance','Reorder_Point','Revenue_RM','Last_Sale_Date'];
 const csv = [header.join(',')].concat(all.map(r => [
 r.sku,
 `"${(r.name || '').replace(/"/g, '""')}"`,
 `"${r.brand || ''}"`,
 `"${r.category || ''}"`,
 r.totalSold.toFixed(0),
 r.recentSold.toFixed(0),
 r.stock,
 r.balance.toFixed(0),
 r.reorder_point ?? '',
 r.revenue.toFixed(2),
 r.lastSale ? new Date(r.lastSale).toISOString().slice(0,10) : ''
].join(','))).join('\n');

 const blob = new Blob([csv], { type: 'text/csv;charset=utf-8;' });
 const url = URL.createObjectURL(blob);
 const link = document.createElement('a');
 link.href = url;
 link.download = `product_sales_summary_${new Date().toISOString().slice(0,10)}.csv`;
 link.click();
 showToast(`Exported ${all.length} rows`, 'success');
};

