// CRM V2 — enriched customers + segments
// ===================================
// p1_80 fix #1: Recompute segment dropdown counts from full customersData
// so the hardcoded "(430)" no longer goes stale. Runs on every render.
window.__updateCrmSegmentCounts = function() {
 const sel = document.getElementById('crmSegment');
 if(!sel || typeof customersData === 'undefined' || !Array.isArray(customersData)) return;
 const all = customersData;
 const counts = {
 vip: all.filter(c => c.is_member).length,
 email_consent: all.filter(c => c.accepts_email_marketing).length,
 sms_consent: all.filter(c => c.accepts_sms_marketing).length,
 tiktok: all.filter(c => (c.tags||'').toLowerCase().includes('tiktok')).length,
 shopee: all.filter(c => (c.tags||'').toLowerCase().includes('shopee')).length,
 never_bought: all.filter(c => (c.total_orders||0) === 0).length,
 big_spender: all.filter(c => (c.total_spent||0) >= 1000).length,
 };
 const labels = {
 vip: 'VIP (3+ orders)',
 email_consent: 'Email consent',
 sms_consent: 'SMS consent',
 tiktok: 'TikTok customers',
 shopee: 'Shopee customers',
 never_bought: 'Newsletter / never bought',
 big_spender: 'Big spender (RM1K+)'
 };
 Array.from(sel.options).forEach(opt => {
 if(opt.value && counts[opt.value] !== undefined) {
 opt.textContent = labels[opt.value] + ' (' + counts[opt.value] + ')';
 }
 });
};

// p1_336 — Segarkan Total: kira semula total_spent/total_orders pelanggan dari sales_history sebenar.
// Padan ikut nombor telefon (utama), fallback nama (sama logik openCustomerDetail). Kecuali test + batal/refund.
window.__crmRefreshTotals = async function(){
 if(typeof db === 'undefined' || !db) { if(typeof showToast==='function') showToast('DB tak available', 'error'); return; }
 if(typeof customersData === 'undefined' || !Array.isArray(customersData)) return;
 const sales = (typeof salesHistory !== 'undefined' && Array.isArray(salesHistory)) ? salesHistory : [];
 if(!sales.length) { if(typeof showToast==='function') showToast('Data jualan belum dimuat — cuba lagi sekejap.', 'warn'); return; }
 if(!confirm('Kira semula total belanja, bilangan order + MATA (1 point = RM1) SEMUA pelanggan dari rekod jualan sebenar?\n\nPadan ikut telefon → email → nama. Kecuali order test + batal/refund. Selamat — boleh ulang bila-bila.')) return;
 const dead = (st) => { const c = window.__aoStatusMeta(st).canon; return c === 'Cancelled' || c === 'Refunded'; };
 const skipName = (nm) => { const n = (nm||'').trim().toLowerCase(); return !n || n === 'walk-in' || n === 'walk in' || n === 'online customer' || n === 'shopee buyer' || n === 'tiktok buyer'; };
 const digits = (p) => String(p||'').replace(/\D/g,'');
 // 1) index jualan ikut phone(normalize) + email + nama
 const byPhone = {}, byName = {}, byEmail = {};
 for(const s of sales){
 if(s.is_test) continue;
 if(dead(s.status)) continue;
 const amt = parseFloat(s.total_amount || s.total || 0) || 0;
 const pd = digits(s.customer_phone);
 if(pd){ (byPhone[pd] = byPhone[pd] || {spent:0, orders:0}); byPhone[pd].spent += amt; byPhone[pd].orders += 1; }
 const em = ((s.customer_email || (s.metadata && s.metadata.buyer_email) || '')).trim().toLowerCase();
 if(em){ (byEmail[em] = byEmail[em] || {spent:0, orders:0}); byEmail[em].spent += amt; byEmail[em].orders += 1; }
 const nm = (s.customer_name||'').trim().toLowerCase();
 if(!skipName(nm)){ (byName[nm] = byName[nm] || {spent:0, orders:0}); byName[nm].spent += amt; byName[nm].orders += 1; }
 }
 // 2) kira per pelanggan (phone → email → nama), kumpul yang berubah; points = floor(spent)
 const updates = [];
 for(const c of customersData){
 let agg = {spent:0, orders:0};
 const pd = digits(c.phone);
 const em = (c.email||'').trim().toLowerCase();
 // p1_486 — keutamaan phone → NAMA → email (walk-in selalu bertanda nama; email sparse + sebahagian order takde email)
 if(pd && byPhone[pd]) agg = byPhone[pd];
 else if(c.name && !skipName(c.name) && byName[c.name.trim().toLowerCase()]) agg = byName[c.name.trim().toLowerCase()];
 else if(em && byEmail[em]) agg = byEmail[em];
 const newSpent = Math.round(agg.spent * 100) / 100;
 const newOrders = agg.orders;
 const newPoints = window.__pointsForSpend(newSpent); // RM10 = 1 mata
 if(newSpent !== (Math.round((c.total_spent||0)*100)/100) || newOrders !== (c.total_orders||0) || newPoints !== (parseInt(c.points)||0)){
 updates.push({ id: c.id, total_spent: newSpent, total_orders: newOrders, points: newPoints, c });
 }
 }
 const btn = document.getElementById('crmRefreshBtn');
 if(!updates.length){ if(typeof showToast==='function') showToast('Semua total dah tepat — tiada perubahan.', 'info'); return; }
 if(btn){ btn.disabled = true; btn.style.opacity = '0.6'; }
 // 3) tulis batch (10 serentak)
 let done = 0, failed = 0;
 const CONC = 10;
 for(let i = 0; i < updates.length; i += CONC){
 const chunk = updates.slice(i, i + CONC);
 const res = await Promise.all(chunk.map(u =>
 db.from('customers').update({ total_spent: u.total_spent, total_orders: u.total_orders, points: u.points }).eq('id', u.id)
 .then(r => { if(r.error) return false; u.c.total_spent = u.total_spent; u.c.total_orders = u.total_orders; u.c.points = u.points; return true; })
 .catch(() => false)
 ));
 res.forEach(ok => { if(ok) done++; else failed++; });
 if(btn) btn.innerHTML = `<i data-lucide="loader" style="width:14px;height:14px;"></i> ${done}/${updates.length}`;
 }
 if(btn){ btn.disabled = false; btn.style.opacity = ''; btn.innerHTML = '<i data-lucide="refresh-cw" style="width:14px;height:14px;"></i> Segarkan Total'; }
 if(typeof showToast === 'function') showToast(`Segar siap — ${done} pelanggan dikemaskini${failed ? ', ' + failed + ' gagal' : ''}.`, failed ? 'warn' : 'success');
 if(typeof renderCustomersV2 === 'function') renderCustomersV2();
 if(window.lucide && lucide.createIcons) try { lucide.createIcons(); } catch(e){}
};

// p1_249 — All Orders section (walk-in + online entry + list)
// p1_319 — Status kanonik merentas channel. Marketplace sync simpan pelbagai status
// (Pending/To Fulfil/Processing/Voided/Completed) — selaraskan ke 6 bucket + warna konsisten.
window.__aoStatusMeta = function(stRaw){
 const s = String(stRaw == null ? '' : stRaw).toLowerCase();
 if(s.includes('refund')) return { canon:'Refunded', label:'Refunded', bg:'var(--primary-50,#FFF8F0)', fg:'var(--primary-800,#7C4A1A)' };
 if(s.includes('cancel') || s.includes('void')) return { canon:'Cancelled', label:'Cancelled', bg:'#F4E4DF', fg:'#7C2A20' };
 if(s.includes('complete') || s.includes('deliver')) return { canon:'Completed', label:'Completed', bg:'#E4EFE2', fg:'#345E43' };
 if(s.includes('process') || s.includes('ship') || s.includes('transit') || s.includes('confirm')) return { canon:'Processing', label:((window.t&&window.t('ao_badge_shipped'))||'Dah Hantar'), bg:'var(--primary-100,#FFEDD5)', fg:'var(--primary-800,#7C4A1A)' };
 if(s.includes('fulfil') || s.includes('ready') || s.includes('await')) return { canon:'To Fulfil', label:((window.t&&window.t('ao_badge_tofulfil'))||'Perlu Pack'), bg:'#F8EFD7', fg:'#7A5410' };
 if(s.includes('pending') || s.includes('unpaid') || s.includes('hold')) return { canon:'Pending', label:((window.t&&window.t('ao_badge_pending'))||'Belum Bayar'), bg:'#F7F0D8', fg:'#854D0E' };
 return { canon:'', label: stRaw || '-', bg:'#F3F4F6', fg:'#6B7280' };
};
// p1_319 — kira qty merentas channel (POS Cashier guna `quantity`, Shopee/TikTok guna `qty`)
window.__aoItemQty = function(it){ return parseInt(it && (it.qty != null ? it.qty : it.quantity)) || 0; };

// p1_332/p1_333 — link ke order di seller centre platform (untuk print Airway Bill di sana).
// TikTok: link TERUS ke order (ada tiktok_order_id). Shopee: takde ID dalaman dalam data
// (semua order Shopee = migrasi EasyStore), jadi link ke SENARAI order — staff cari + print AWB.
window.__aoSellerCentreUrl = function(s){
 const md = (s && s.metadata) || {};
 const ch = (s && s.channel || '').toLowerCase();
 if(md.tiktok_order_id){
 return { url: `https://seller-my.tiktok.com/order/detail?order_no=${encodeURIComponent(md.tiktok_order_id)}`, label: 'TikTok Seller Centre', short: 'TikTok', color: '#111111', direct: true };
 }
 if(ch.includes('shopee')){
 return { url: 'https://seller.shopee.com.my/portal/sale/order', label: 'Shopee Seller Centre', short: 'Shopee', color: '#EE4D2D', direct: false };
 }
 if(ch.includes('tiktok')){
 return { url: 'https://seller-my.tiktok.com/order', label: 'TikTok Seller Centre', short: 'TikTok', color: '#111111', direct: false };
 }
 return null;
};

// p1_325 — julat tarikh dari dropdown aoPeriod (today/yesterday/N hari/custom/all)
window.__aoDateRange = function(){
 const period = document.getElementById('aoPeriod')?.value || 'all';
 const now = Date.now();
 const sod = new Date(); sod.setHours(0,0,0,0); const startToday = sod.getTime();
 if(period === 'all') return { from:0, to:Infinity };
 if(period === 'today') return { from:startToday, to:Infinity };
 if(period === 'yesterday') return { from:startToday - 86400000, to:startToday };
 if(period === 'custom'){
 const fv = document.getElementById('aoDateFrom')?.value;
 const tv = document.getElementById('aoDateTo')?.value;
 let from = fv ? new Date(fv + 'T00:00:00').getTime() : 0;
 let to = tv ? new Date(tv + 'T23:59:59.999').getTime() : Infinity;
 if(from > to) { const tmp = from; from = to; to = tmp; } // kalau Zaid masuk tarikh terbalik, tukar
 return { from, to };
 }
 const days = parseInt(period, 10);
 if(days) return { from: now - days*86400000, to:Infinity };
 return { from:0, to:Infinity };
};
