// p1_1174 — bina HTML baris preview barang (header + tiap barang jajar lajur: Qty bawah ITEMS, Jumlah bawah RM)
window.__aoBuildItemRows = function(s){
 const esc = (x)=>String(x==null?'':x).replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/"/g,'&quot;').replace(/'/g,'&#39;');
 const oid = s.id;
 const arr = Array.isArray(s.items) ? s.items : [];
 const mono = "font-family:'SF Mono',Menlo,monospace;";
 const bg = 'background:#FBFAF7;';
 const count = arr.reduce((n,it)=>n+(window.__aoItemQty?window.__aoItemQty(it):0),0);
 let html = `<tr class="aoItemRow" data-aoitems="${oid}" style="${bg}"><td style="border:none;"></td><td colspan="10" style="padding:7px 12px 3px; font-size:10px; color:#9CA3AF; font-weight:700; text-transform:uppercase; letter-spacing:.5px; border:none;">${arr.length} jenis &middot; ${count} unit — tekan no. order (oren) untuk detail penuh</td></tr>`;
 if(!arr.length){ return html + `<tr class="aoItemRow" data-aoitems="${oid}" style="${bg}"><td style="border:none;"></td><td colspan="10" style="padding:8px 10px; color:#9CA3AF; font-size:11.5px; border:none;">Tiada barang direkod.</td></tr>`; }
 html += arr.map((it,ii)=>{
  const iq = window.__aoItemQty ? window.__aoItemQty(it) : 0;
  const iimg = (typeof window.__aoImgFor==='function') ? window.__aoImgFor(it.sku) : '';
  const inm = String(it.name || it.sku || '-');
  const up = parseFloat(it.price!=null?it.price:(it.unit_price!=null?it.unit_price:0))||0;
  const lt = up*iq;
  const last = (ii===arr.length-1);
  const thumb = iimg
   ? `<img src="${esc(iimg)}" loading="lazy" onerror="this.style.display='none'; this.nextElementSibling.style.display='flex';" style="width:50px;height:50px;object-fit:cover;border-radius:8px;border:1px solid #E5E7EB;flex:0 0 auto;display:block;"><span style="display:none;width:50px;height:50px;border:1px dashed #D1D5DB;border-radius:8px;align-items:center;justify-content:center;font-size:8px;color:#9CA3AF;flex:0 0 auto;">No Img</span>`
   : `<span style="display:flex;width:50px;height:50px;border:1px dashed #D1D5DB;border-radius:8px;align-items:center;justify-content:center;font-size:8px;color:#9CA3AF;flex:0 0 auto;">No Img</span>`;
  return `<tr class="aoItemRow" data-aoitems="${oid}" style="${bg} ${last?'box-shadow:inset 0 -2px 0 #EDE6DA;':''}">`
   + `<td style="border:none;"></td>`
   + `<td colspan="5" style="padding:7px 10px; border:none;"><div style="display:flex; align-items:center; gap:12px;">${thumb}<span style="font-size:12px; color:#374151; line-height:1.35;">${esc(inm.slice(0,110))}${it.sku?` <span style="color:#9CA3AF; font-size:10px; ${mono}">${esc(it.sku)}</span>`:''} <span style="color:#B0A597; font-size:11px; ${mono}">@ RM ${up.toFixed(2)}</span></span></div></td>`
   + `<td style="padding:7px 10px; text-align:center; font-weight:800; color:var(--primary-600,#B86A26); font-size:13px; border:none;">&times;${iq}</td>`
   + `<td style="padding:7px 10px; text-align:right; font-weight:800; color:#101010; font-size:12.5px; ${mono} border:none;">RM ${lt.toFixed(2)}</td>`
   + `<td style="border:none;"></td><td style="border:none;"></td><td style="border:none;"></td>`
   + `</tr>`;
 }).join('');
 return html;
};
