// p1_331 — filter + sort order ikut input toolbar (guna-semula: render + export CSV)
window.__aoGetFiltered = function(){
 if(typeof salesHistory === 'undefined' || !Array.isArray(salesHistory)) return [];
 const q = (document.getElementById('aoSearch')?.value || '').trim().toLowerCase();
 const channel = document.getElementById('aoChannel')?.value || '';
 const status = document.getElementById('aoStatus')?.value || '';
 const dr = window.__aoDateRange();
 const hideTest = !!document.getElementById('aoHideTest')?.checked;
 const ONLINE_CHANNELS = ['shopee', 'tiktok', 'whatsapp', 'easystore'];
 const filtered = salesHistory.filter(s => {
 if(hideTest && s.is_test) return false;
 if(s.created_at) { const t = new Date(s.created_at).getTime(); if(t < dr.from || t > dr.to) return false; }
 const chLower = (s.channel || '').toLowerCase();
 if(channel === 'walkin') { if(!(chLower.includes('walk') || chLower.includes('cashier'))) return false; }
 else if(channel === 'online') { if(!ONLINE_CHANNELS.some(c => chLower.includes(c))) return false; }
 else if(channel && s.channel !== channel) return false;
 if(status && window.__aoStatusMeta(s.status).canon !== status) return false;
 if(window.__aoNoReceipt){ const _pf = window.__ppGetProofs ? window.__ppGetProofs(s) : (s.payment_proof_url ? [s.payment_proof_url] : []); if(_pf.length) return false; } // p1_1173 — chip Tiada Resit
 if(q) {
 const itemsTxt = Array.isArray(s.items) ? s.items.map(i => (i.sku || '') + ' ' + (i.name || '')).join(' ') : '';
 const md = s.metadata || {};
 const refTxt = `${md.shopee_order_sn||''} ${md.tiktok_order_id||''} ${md.online_order_ref||''}`;
 const hay = `${s.customer_name||''} ${s.customer_phone||''} ${s.customer_email||''} ${itemsTxt} ${refTxt} #${s.id}`.toLowerCase();
 if(!hay.includes(q)) return false;
 }
 return true;
 });
 // p1_437 — sort ikut pilihan dropdown SUSUN
 const sortBy = (document.getElementById('aoSort') || {}).value || 'id_desc';
 const idNum = (s) => { const n = parseInt(s.id, 10); return isNaN(n) ? 0 : n; };
 if(sortBy === 'date_asc') filtered.sort((a, b) => (a.created_at || '').localeCompare(b.created_at || ''));
 else if(sortBy === 'id_asc') filtered.sort((a, b) => idNum(a) - idNum(b));
 else if(sortBy === 'id_desc') filtered.sort((a, b) => idNum(b) - idNum(a));
 else filtered.sort((a, b) => (b.created_at || '').localeCompare(a.created_at || '')); // date_desc (default)
 return filtered;
};

