// p1_436 — navigate to prev/next order within the filtered list WITHOUT closing the modal
window.__aoNavOrder = function(currentId, dir) {
 const list = window.__aoNavIds || [];
 const idx = list.indexOf(currentId);
 if(idx < 0) return;
 const next = idx + dir;
 if(next < 0 || next >= list.length) return;
 const overlay = document.getElementById('aoViewOverlay');
 if(overlay) overlay.remove();
 window.__aoViewOrder(list[next]);
};

window.__aoViewOrder = function(saleId) {
 if(typeof salesHistory === 'undefined' || !Array.isArray(salesHistory)) return;
 const s = salesHistory.find(x => x.id === saleId);
 if(!s) { if(typeof showToast === 'function') showToast('Order tak jumpa dalam ingatan — cuba Refresh.', 'warn'); return; }
 const esc = (v) => String(v == null ? '' : v).replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;').replace(/"/g,'&quot;').replace(/'/g,'&#39;');
 const md = s.metadata || {};
 const m = window.__aoStatusMeta(s.status);
 const dt = s.created_at ? new Date(s.created_at).toLocaleString('en-MY', {day:'2-digit', month:'short', year:'numeric', hour:'2-digit', minute:'2-digit'}) : '-';
 const orderRef = md.shopee_order_sn || md.tiktok_order_id || md.online_order_ref || null;
 const carrier = md.shipping_carrier || md.shipping_provider || null;
 const items = Array.isArray(s.items) ? s.items : [];
 let itemsSub = 0;
 const itemRows = items.length ? items.map(it => {
 const qty = window.__aoItemQty(it);
 const price = parseFloat(it.price || 0) || 0;
 const line = qty * price;
 itemsSub += line;
 // p1_476 — gambar produk untuk rujukan staff (pack/semak). Fallback kotak "No Img".
 const img = (typeof window.__aoImgFor === 'function') ? window.__aoImgFor(it.sku) : '';
 const imgCell = img
   ? `<img src="${esc(img)}" loading="lazy" onerror="this.style.display='none'; this.nextElementSibling.style.display='flex';" style="width:42px; height:42px; object-fit:cover; border-radius:7px; border:1px solid #E5E7EB; display:block;"><span style="display:none; width:42px; height:42px; border:1px dashed #D1D5DB; border-radius:7px; align-items:center; justify-content:center; font-size:8px; color:#9CA3AF; text-align:center;">No Img</span>`
   : `<span style="display:flex; width:42px; height:42px; border:1px dashed #D1D5DB; border-radius:7px; align-items:center; justify-content:center; font-size:8px; color:#9CA3AF; text-align:center;">No Img</span>`;
 // p1_756 — diskaun per-item (Aliff: tunjuk detail diskaun tiap barang jika diberi).
 // discount_amount = diskaun SEUNIT; total diskaun baris = discount_amount × qty.
 const discUnit = parseFloat(it.discount_amount || 0) || 0;
 const origPrice = parseFloat(it.original_price || 0) || 0;
 const lineDisc = discUnit * qty;
 const hargaCell = (discUnit > 0 && origPrice > 0)
   ? `<s style="color:#9CA3AF;">RM ${origPrice.toFixed(2)}</s><br>RM ${price.toFixed(2)}`
   : `RM ${price.toFixed(2)}`;
 const diskaunCell = (discUnit > 0)
   ? `<span style="display:inline-block; padding:1px 7px; background:#F8EFD7; color:#7A5410; border-radius:50px; font-size:10.5px; font-weight:700; white-space:nowrap;" title="${esc(it.discount_reason || 'Diskaun manual')}">−RM ${lineDisc.toFixed(2)}</span>${it.discount_reason ? `<br><span style="font-size:9.5px; color:#9CA3AF;">${esc(it.discount_reason)}</span>` : ''}`
   : '<span style="color:#D1D5DB;">—</span>';
 return `<tr style="border-bottom:1px solid #F3F4F6;">
 <td style="padding:7px 6px;">${imgCell}</td>
 <td style="padding:7px 6px; font-family:'SF Mono',Menlo,monospace; font-size:11px; color:#374151; white-space:nowrap;">${esc(it.sku || '-')}</td>
 <td style="padding:7px 6px; font-size:11.5px; color:#1f2937;">${esc(it.name || '-')}</td>
 <td style="padding:7px 5px; text-align:center; font-weight:800; font-size:12.5px; color:var(--primary);">${qty}</td>
 <td style="padding:7px 6px; text-align:right; font-size:11px; color:#6B7280; white-space:nowrap;">${hargaCell}</td>
 <td style="padding:7px 6px; text-align:right; font-size:11px;">${diskaunCell}</td>
 <td style="padding:7px 6px; text-align:right; font-size:11.5px; font-weight:700; white-space:nowrap;">RM ${line.toFixed(2)}</td>
 </tr>`;
 }).join('') : '<tr><td colspan="7" style="text-align:center; color:#9CA3AF; padding:18px; font-size:12px;">Tiada senarai barang direkod untuk order ni.</td></tr>';
 const totalItems = items.reduce((n, it) => n + window.__aoItemQty(it), 0);
 const grandTotal = parseFloat(s.total_amount || s.total || 0) || 0;
 const proof = s.payment_proof_url || '';
 const isMarketplace = /shopee|tiktok/i.test(s.channel || '');
 const infoRow = (label, val) => val ? `<div style="display:flex; gap:8px; font-size:12.5px; padding:3px 0; min-width:0;"><span style="color:#6B7280; min-width:64px; flex-shrink:0;">${label}</span><span style="font-weight:600; color:#111827; min-width:0; word-break:break-word; overflow-wrap:anywhere;">${esc(val)}</span></div>` : '';
 // p1_476 — status resit email (sebab Payment Proofs dah digabung ke All Orders)
 const emailSent = s.email_status === 'sent' && !!s.email_sent_at;
 const emailFailed = s.email_status && /^(failed|error)/i.test(s.email_status);
 const emailSentWhen = emailSent ? new Date(s.email_sent_at).toLocaleString('en-MY',{day:'2-digit',month:'short',year:'numeric',hour:'2-digit',minute:'2-digit'}) : '';
 const emailBadge = emailSent
   ? `<div style="display:inline-flex; align-items:center; gap:5px; margin-top:5px; background:#E4EFE2; color:#345E43; padding:3px 10px; border-radius:20px; font-size:11px; font-weight:700;"><i data-lucide="mail-check" style="width:12px;height:12px;"></i> Resit emel dihantar · ${esc(emailSentWhen)}</div>`
   : (emailFailed ? `<div style="display:inline-flex; align-items:center; gap:5px; margin-top:5px; background:#F4E4DF; color:#7C2A20; padding:3px 10px; border-radius:20px; font-size:11px; font-weight:700;"><i data-lucide="mail-x" style="width:12px;height:12px;"></i> Email gagal — cuba hantar semula</div>` : '');
 // p1_320 — fulfilment state + controls
 const f = md.fulfilment || {};
 const canFulfil = !['Completed','Cancelled','Refunded'].includes(m.canon);
 const fmtWhen = (iso) => iso ? new Date(iso).toLocaleString('en-MY',{day:'2-digit',month:'short',hour:'2-digit',minute:'2-digit'}) : '';
 const couriers = ['J&T Express','Pos Laju','Ninja Van','Flash Express','City-Link Express','DHL','GDex','Shopee Xpress','TikTok arranged','Self-deliver / COD','Lain-lain'];
 const chips = [];
 if(f.packed_at) chips.push(`<span style="display:inline-flex; align-items:center; gap:4px; background:#E4EFE2; color:#345E43; padding:3px 9px; border-radius:20px; font-size:11px; font-weight:700;"><i data-lucide="check" style="width:11px;height:11px;"></i> Packed · ${esc(fmtWhen(f.packed_at))}${f.packed_by ? ' · ' + esc(f.packed_by) : ''}</span>`);
 if(f.shipped_at) chips.push(`<span style="display:inline-flex; align-items:center; gap:4px; background:var(--primary-100,#FFEDD5); color:var(--primary-800,#7C4A1A); padding:3px 9px; border-radius:20px; font-size:11px; font-weight:700;"><i data-lucide="truck" style="width:11px;height:11px;"></i> Dah Hantar${f.courier ? ' · ' + esc(f.courier) : ''}${f.tracking_no ? ' · ' + esc(f.tracking_no) : ''}</span>`);
 const chipsHtml = chips.length ? `<div style="display:flex; flex-wrap:wrap; gap:6px; margin-bottom:10px;">${chips.join('')}</div>` : '';
 const courierSel = `<select id="aoFulCourier" style="flex:1; min-width:120px; padding:8px; border:1px solid #E5E7EB; border-radius:7px; font-size:12px;">${couriers.map(c=>`<option value="${esc(c)}" ${f.courier===c?'selected':''}>${esc(c)}</option>`).join('')}</select>`;
 const controls = canFulfil ? `
 <div style="display:flex; gap:6px; flex-wrap:wrap; margin-bottom:8px;">
 ${courierSel}
 <input id="aoFulTracking" type="text" placeholder="No. tracking / AWB" value="${esc(f.tracking_no||'')}" style="flex:2; min-width:140px; padding:8px; border:1px solid #E5E7EB; border-radius:7px; font-size:12px;">
 </div>
 <div style="display:flex; gap:6px; flex-wrap:wrap;">
 ${!f.packed_at ? `<button onclick="window.__aoSetFulfil(${s.id},'packed')" style="flex:1; min-width:110px; background:#fff; border:1px solid #ABC6A0; color:#345E43; padding:9px; border-radius:8px; cursor:pointer; font-size:12.5px; font-weight:700;"><i data-lucide="package-check" style="width:13px;height:13px;vertical-align:-2px;"></i> Tanda Packed</button>` : ''}
 <button onclick="window.__aoSetFulfil(${s.id},'shipped',{courier:(document.getElementById('aoFulCourier')||{}).value, tracking:((document.getElementById('aoFulTracking')||{}).value||'')})" style="flex:2; min-width:130px; background:var(--primary-600,#B86A26); border:none; color:#fff; padding:9px; border-radius:8px; cursor:pointer; font-size:12.5px; font-weight:700;"><i data-lucide="truck" style="width:13px;height:13px;vertical-align:-2px;"></i> ${f.shipped_at ? 'Kemaskini Hantar' : 'Tanda Dah Hantar'}</button>
 <button onclick="window.__aoSetFulfil(${s.id},'completed')" style="flex:1; min-width:100px; background:#fff; border:1px solid #6EE7B7; color:#345E43; padding:9px; border-radius:8px; cursor:pointer; font-size:12.5px; font-weight:700;"><i data-lucide="check-circle" style="width:13px;height:13px;vertical-align:-2px;"></i> Selesai</button>
 </div>` : `<div style="font-size:12px; color:#6B7280;">Order ni dah <strong>${esc(m.label)}</strong>.</div>`;
 const sc = window.__aoSellerCentreUrl(s);
 const mpNote = isMarketplace ? `${sc ? `<a href="${esc(sc.url)}" target="_blank" rel="noopener" style="display:inline-flex; align-items:center; gap:7px; background:${sc.color}; color:#fff; padding:10px 14px; border-radius:8px; font-size:12.5px; font-weight:700; text-decoration:none; margin-bottom:8px;"><i data-lucide="external-link" style="width:14px;height:14px;"></i> Buka ${esc(sc.label)}${sc.direct ? ' — print Airway Bill' : ' — cari order & print AWB'}</a>` : ''}<div class="soft-note soft-note--inline" style="margin-bottom:8px;"><i data-lucide="info"></i> ${sc && !sc.direct ? 'Order Shopee = migrasi EasyStore, takde ID Shopee dalam data — buka senarai To-Ship, cari order ni, print AWB. ' : ''}AWB / label penghantaran dijana di seller centre platform.</div>` : '';
 // p1_754 — "Urus Pack/Delivery" dalam seksyen Fulfilment (Zack: akses mudah utk staff, sama macam Urus Resit)
 window.__aoManageProofSaleId = s.id; // supaya refresh selepas urus buka balik order ni
 const dproofs = window.__dpGetProofs ? window.__dpGetProofs(s) : [];
 const dtiles = dproofs.map(u => {
  const low = String(u).toLowerCase();
  const isImg = !low.endsWith('.pdf') && !low.endsWith('.heic') && !low.endsWith('.heif');
  return isImg
   ? `<img src="${esc(u)}" loading="lazy" onclick="window.__ppOpenImg && window.__ppOpenImg('${esc(u).replace(/'/g, "\\'")}')" onerror="this.style.opacity='0.3'" style="width:72px; height:72px; object-fit:cover; border-radius:8px; border:1px solid #E5E7EB; cursor:zoom-in;">`
   : `<a href="${esc(u)}" target="_blank" rel="noopener" style="display:inline-flex; flex-direction:column; align-items:center; gap:3px; width:72px; height:72px; justify-content:center; border:1px solid #E5E7EB; border-radius:8px; color:var(--primary); font-weight:700; font-size:10px; text-decoration:none;"><i data-lucide="file-text" style="width:16px;height:16px;"></i> Buka</a>`;
 }).join('');
 const deliveryBlock = `<div style="margin-top:12px; padding-top:11px; border-top:1px dashed #E7D9B0;">
 <div style="display:flex; justify-content:space-between; align-items:center; margin-bottom:7px; gap:8px; flex-wrap:wrap;">
 <span style="font-size:12px; color:#7A5410; font-weight:600;">Gambar Pack/Delivery <span style="color:#9CA3AF; font-weight:400;">(${dproofs.length}/${window.__DP_MAX || 4})</span></span>
 <button onclick="window.__dpManageProofs(${s.id})" style="background:#fff; border:1px solid #E0B3A9; color:var(--primary-800,#7C4A1A); padding:6px 12px; border-radius:7px; cursor:pointer; font-size:11.5px; font-weight:700;"><i data-lucide="images" style="width:12px;height:12px;vertical-align:-2px;"></i> Urus Pack/Delivery</button>
 </div>
 ${dproofs.length ? `<div style="display:flex; gap:8px; flex-wrap:wrap;">${dtiles}</div>` : '<p style="font-size:11px; color:#9CA3AF; margin:0;">Gambar parcel sebelum/selepas hantar — tekan "Urus Pack/Delivery" untuk tambah.</p>'}
 </div>`;
 const fulfilHtml = `<div style="border:1px solid #ECD9A4; background:#FBF7EC; border-radius:10px; padding:14px; margin-bottom:14px;">
 <div style="font-size:10.5px; font-weight:800; letter-spacing:0.5px; color:#7A5410; text-transform:uppercase; margin-bottom:8px;"><i data-lucide="truck" style="width:12px;height:12px;vertical-align:-2px;"></i> Fulfilment / Penghantaran</div>
 ${chipsHtml}${mpNote}${controls}${deliveryBlock}
 </div>`;
 // p1_436 — Back/Next nav across the filtered order list
 const __navList = window.__aoNavIds || [];
 const __navIdx = __navList.indexOf(s.id);
 const __hasPrev = __navIdx > 0;
 const __hasNext = __navIdx >= 0 && __navIdx < __navList.length - 1;
 const __navOn = 'background:#F3F4F6; border:1px solid #E5E7EB; color:#374151; min-width:34px; height:34px; padding:0 10px; border-radius:8px; cursor:pointer; font-size:13px; font-weight:700; display:inline-flex; align-items:center; gap:4px; justify-content:center;';
 const __navOff = 'background:#F9FAFB; border:1px solid #F0F0F0; color:#D1D5DB; min-width:34px; height:34px; padding:0 10px; border-radius:8px; cursor:not-allowed; font-size:13px; font-weight:700; display:inline-flex; align-items:center; gap:4px; justify-content:center;';
 const html = `<div id="aoViewOverlay" style="position:fixed; inset:0; background:rgba(0,0,0,0.55); z-index:3800; display:flex; align-items:flex-start; justify-content:center; padding:20px; padding-top:calc(20px + env(safe-area-inset-top)); overflow-y:auto;" onclick="if(event.target===this) this.remove();">
 <div style="background:#fff; max-width:680px; width:100%; border-radius:14px; padding:0; margin:auto; overflow:hidden; box-shadow:0 20px 60px rgba(0,0,0,0.3);">
 <div style="display:flex; justify-content:space-between; align-items:center; padding:18px 22px; border-bottom:1px solid #F0F0F0; background:linear-gradient(135deg,#FAF6EF,#fff);">
 <div>
 <div style="font-size:18px; font-weight:800; color:#101010;">Order #${s.id} <span style="background:${m.bg}; color:${m.fg}; padding:2px 9px; border-radius:5px; font-size:11px; font-weight:700; margin-left:6px; vertical-align:2px;">${esc(m.label)}</span></div>
 <div style="font-size:12px; color:#6B7280; margin-top:3px;"><i data-lucide="calendar" style="width:11px;height:11px;vertical-align:-1px;"></i> ${dt} &nbsp;·&nbsp; <i data-lucide="store" style="width:11px;height:11px;vertical-align:-1px;"></i> ${esc(s.channel || '-')}</div>
 </div>
 <div style="display:flex; gap:7px; align-items:center;">
 <button ${__hasPrev ? `onclick="window.__aoNavOrder(${s.id}, -1)"` : 'disabled'} title="Order sebelum" style="${__hasPrev ? __navOn : __navOff}"><i data-lucide="chevron-left" style="width:15px;height:15px;"></i> Back</button>
 <button ${__hasNext ? `onclick="window.__aoNavOrder(${s.id}, 1)"` : 'disabled'} title="Order seterusnya" style="${__hasNext ? __navOn : __navOff}">Next <i data-lucide="chevron-right" style="width:15px;height:15px;"></i></button>
 <button onclick="document.getElementById('aoViewOverlay').remove()" title="Tutup" style="background:none; border:none; font-size:26px; cursor:pointer; color:#999; line-height:1; margin-left:4px;">×</button>
 </div>
 </div>
 <div style="padding:18px 22px;">
 <div style="display:grid; grid-template-columns:minmax(0,1fr) minmax(0,1fr); gap:16px; margin-bottom:16px;">
 <div style="min-width:0;">
 <div style="font-size:10.5px; font-weight:800; letter-spacing:0.5px; color:#9CA3AF; text-transform:uppercase; margin-bottom:6px;">Pelanggan</div>
 ${infoRow('Nama', s.customer_name || 'Walk-In')}
 ${infoRow('Phone', s.customer_phone)}
 ${infoRow('Email', s.customer_email || md.buyer_email)}
 ${emailBadge}
 ${isMarketplace && !s.customer_phone ? '<div style="font-size:11px; color:#9CA3AF; padding-top:4px;">Alamat penuh ada di seller centre ' + esc(s.channel) + '.</div>' : ''}
 </div>
 <div style="min-width:0;">
 <div style="font-size:10.5px; font-weight:800; letter-spacing:0.5px; color:#9CA3AF; text-transform:uppercase; margin-bottom:6px;">Order</div>
 ${infoRow('No. Ref', orderRef)}
 ${infoRow('Bayar', s.payment_method)}
 ${infoRow('Kurier', carrier)}
 ${infoRow('Staff', s.staff_name)}
 </div>
 </div>
 <div style="font-size:10.5px; font-weight:800; letter-spacing:0.5px; color:#9CA3AF; text-transform:uppercase; margin-bottom:6px;"><i data-lucide="package" style="width:12px;height:12px;vertical-align:-2px;"></i> Barang untuk Pack (${totalItems})</div>
 <div style="border:1px solid #F0F0F0; border-radius:10px; overflow-x:auto; margin-bottom:14px;">
 <table style="width:100%; border-collapse:collapse;">
 <thead><tr style="background:#FAFAFA; font-size:10px; color:#6B7280; text-transform:uppercase; letter-spacing:0.4px;">
 <th style="text-align:left; padding:6px 6px;">Gambar</th><th style="text-align:left; padding:6px 6px;">SKU</th><th style="text-align:left; padding:6px 6px;">Nama</th><th style="text-align:center; padding:6px 5px; white-space:nowrap;">Qty</th><th style="text-align:right; padding:6px 6px; white-space:nowrap;">Harga</th><th style="text-align:right; padding:6px 6px; white-space:nowrap;">Diskaun</th><th style="text-align:right; padding:6px 6px; white-space:nowrap;">Jumlah</th>
 </tr></thead>
 <tbody>${itemRows}</tbody>
 </table>
 </div>
 ${(() => {
 // p1_758 — ringkasan total + baris DISKAUN peringkat-order (Aliff: amaun diskaun tak muncul).
 // Diskaun order = custom + VIP dari metadata (per-item discount dah tunjuk di lajur Diskaun).
 const custDisc = parseFloat(md.custom_discount_amount || 0) || 0;
 const vipDisc = parseFloat(md.vip_discount_amount || 0) || 0;
 const orderDisc = custDisc + vipDisc;
 const discLabel = (custDisc && vipDisc) ? 'Diskaun (custom + VIP)' : (vipDisc ? 'Diskaun VIP' : 'Diskaun');
 const row = (l, v, c) => `<div style="display:flex; justify-content:space-between; font-size:12px; color:${c||'#6B7280'}; padding:2px 0;"><span>${l}</span><span>${v}</span></div>`;
 return `<div style="padding:11px 14px; background:#FAF6EF; border-radius:10px; margin-bottom:14px;">
 ${row(items.length + ' jenis · ' + totalItems + ' unit', 'Subtotal RM ' + itemsSub.toFixed(2))}
 ${orderDisc > 0.001 ? row(discLabel, '− RM ' + orderDisc.toFixed(2), '#059669') : ''}
 <div style="display:flex; justify-content:space-between; align-items:center; border-top:1px dashed #E0CDA8; padding-top:8px; margin-top:6px;">
 <span style="font-size:12px; font-weight:700; color:#6B7280;">TOTAL</span>
 <span style="font-size:18px; font-weight:800; color:#101010;">RM ${grandTotal.toFixed(2)}</span>
 </div>
 </div>`;
 })()}
 ${fulfilHtml}
 ${((() => {
 // p1_525 — Bukti bayar / Resit SEHINGGA 3 gambar (staff boleh tambah/buang via Urus Resit)
 const proofs = window.__ppGetProofs ? window.__ppGetProofs(s) : (proof ? [proof] : []);
 window.__aoManageProofSaleId = s.id; // supaya refresh selepas urus buka balik order ni
 const tiles = proofs.map(u => {
  const low = String(u).toLowerCase();
  const isImg = !low.endsWith('.pdf') && !low.endsWith('.heic') && !low.endsWith('.heif');
  return isImg
   ? `<img src="${esc(u)}" loading="lazy" onclick="window.__ppOpenImg && window.__ppOpenImg('${esc(u).replace(/'/g, "\\'")}')" onerror="this.style.opacity='0.3'" style="width:90px; height:90px; object-fit:cover; border-radius:8px; border:1px solid #E5E7EB; cursor:zoom-in;">`
   : `<a href="${esc(u)}" target="_blank" rel="noopener" style="display:inline-flex; flex-direction:column; align-items:center; gap:3px; width:90px; height:90px; justify-content:center; border:1px solid #E5E7EB; border-radius:8px; color:var(--primary); font-weight:700; font-size:11px; text-decoration:none;"><i data-lucide="file-text" style="width:18px;height:18px;"></i> Buka</a>`;
 }).join('');
 return `<div style="margin-bottom:14px;">
  <div style="display:flex; justify-content:space-between; align-items:center; margin-bottom:6px; gap:8px; flex-wrap:wrap;">
   <span style="font-size:12px; color:#6B7280;">Bukti bayar / Resit <span style="color:#9CA3AF;">(${proofs.length}/${window.__PP_MAX || 3})</span></span>
   <button onclick="window.__ppManageProofs(${s.id})" style="background:var(--primary-50,#FFF8F0); border:1px solid var(--primary-200,#FED7AA); color:var(--primary-800,#7C4A1A); padding:5px 11px; border-radius:7px; cursor:pointer; font-size:11.5px; font-weight:700;"><i data-lucide="images" style="width:12px;height:12px;vertical-align:-2px;"></i> Urus Resit (max 3)</button>
  </div>
  ${proofs.length ? `<div style="display:flex; gap:8px; flex-wrap:wrap;">${tiles}</div>` : '<p style="font-size:11.5px; color:#9CA3AF; margin:0;">Belum ada resit — tekan "Urus Resit" untuk tambah (sehingga 3).</p>'}
 </div>`;
 })())}
 <div style="display:flex; gap:8px; flex-wrap:wrap;">
 <button onclick="window.__aoPrintPackingSlip && window.__aoPrintPackingSlip(${s.id})" style="flex:1.4; min-width:150px; background:var(--primary-500,#CD7C32); border:none; color:#fff; padding:10px; border-radius:8px; cursor:pointer; font-size:13px; font-weight:700;"><i data-lucide="printer" style="width:13px;height:13px;vertical-align:-2px;"></i> Cetak Packing Slip</button>
 <button id="aoEmailReceiptBtn" onclick="window.__aoSendReceiptEmail(${s.id})" style="flex:1.2; min-width:150px; background:${emailSent ? '#ECF3EA' : 'var(--primary-50,#FFF8F0)'}; border:1px solid ${emailSent ? '#ABC6A0' : '#A5B4FC'}; color:${emailSent ? '#345E43' : 'var(--primary-800,#7C4A1A)'}; padding:10px; border-radius:8px; cursor:pointer; font-size:13px; font-weight:700;"><i data-lucide="${emailSent ? 'mail-check' : 'mail'}" style="width:13px;height:13px;vertical-align:-2px;"></i> ${emailSent ? 'Hantar Semula Resit' : 'Hantar Resit Email'}</button>
 <button onclick="document.getElementById('aoViewOverlay').remove(); window.__ppEditSale && window.__ppEditSale(${s.id});" style="flex:1; min-width:90px; background:var(--primary-50,#FFF8F0); border:1px solid var(--primary-300,#FDBA74); color:var(--primary-800,#7C4A1A); padding:10px; border-radius:8px; cursor:pointer; font-size:13px; font-weight:700;"><i data-lucide="edit-3" style="width:13px;height:13px;vertical-align:-2px;"></i> Edit</button>
 <button onclick="document.getElementById('aoViewOverlay').remove()" style="flex:1; min-width:80px; background:#101010; border:none; color:#fff; padding:10px; border-radius:8px; cursor:pointer; font-size:13px; font-weight:700;">Tutup</button>
 </div>
 </div>
 </div>
 </div>`;
 const tmp = document.createElement('div');
 tmp.innerHTML = html;
 document.body.appendChild(tmp.firstChild);
 if(window.lucide && lucide.createIcons) try { lucide.createIcons(); } catch(e){}
};

// p1_475/p1_477 — Hantar resit email ke pelanggan dari panel order detail All Orders.
// Guna /api/send-receipt-email (Resend, dari admin@10camp.com). Flow: resolve email →
// PREVIEW (server pulang HTML, tak hantar) → staff semak → tekan Hantar Sekarang.
window.__aoEmailPreviewCtx = window.__aoEmailPreviewCtx || null;

window.__aoSendReceiptEmail = async function(saleId) {
 if(typeof salesHistory === 'undefined' || !Array.isArray(salesHistory)) return;
 const s = salesHistory.find(x => x.id === saleId);
 if(!s) { if(typeof showToast === 'function') showToast('Order tak jumpa dalam ingatan — cuba Refresh.', 'warn'); return; }
 const md = s.metadata || {};
 let email = (s.customer_email || md.buyer_email || '').trim();
 if(!email) {
  email = (prompt('Order #' + saleId + ' takde email pelanggan.\nMasukkan email untuk hantar resit:', '') || '').trim();
  if(!email) return;
 }
 if(!/^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(email)) { if(typeof showToast === 'function') showToast('Email tak sah: ' + email, 'warn'); return; }
 const btn = document.getElementById('aoEmailReceiptBtn');
 const orig = btn ? btn.innerHTML : '';
 if(btn) { btn.disabled = true; btn.innerHTML = '<i data-lucide="loader" style="width:13px;height:13px;vertical-align:-2px;"></i> Menyediakan preview…'; if(window.lucide && lucide.createIcons) try { lucide.createIcons(); } catch(e){} }
 try {
  // Simpan email kalau beza (server baca dari DB utk preview + hantar)
  if((s.customer_email || '').trim().toLowerCase() !== email.toLowerCase() && typeof db !== 'undefined' && db) {
   try { await db.from('sales_history').update({ customer_email: email }).eq('id', saleId); s.customer_email = email; } catch(e) { console.warn('simpan email gagal:', e.message); }
  }
  const res = await fetch('/api/send-receipt-email', {
   method: 'POST', headers: await window.__authHeaders({ 'Content-Type': 'application/json' }),
   body: JSON.stringify({ sale_id: saleId, preview: true })
  });
  const data = await res.json().catch(() => ({}));
  if(data.preview && data.html) { window.__aoShowEmailPreview(saleId, email, data.html); }
  else if(data.skipped) { if(typeof showToast === 'function') showToast('Tak boleh preview: ' + (data.reason || 'skipped'), 'warn'); }
  else { if(typeof showToast === 'function') showToast('Gagal sediakan preview: ' + (data.error || data.reason || res.status), 'error'); }
 } catch(e) { if(typeof showToast === 'function') showToast('Network error: ' + e.message, 'error'); }
 if(btn) { btn.disabled = false; btn.innerHTML = orig; if(window.lucide && lucide.createIcons) try { lucide.createIcons(); } catch(e){} }
};

// p1_477 — modal preview email sebelum hantar betul
window.__aoShowEmailPreview = function(saleId, email, html) {
 window.__aoEmailPreviewCtx = { saleId, email };
 const esc = (v) => String(v == null ? '' : v).replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;').replace(/"/g,'&quot;');
 const existing = document.getElementById('aoEmailPreviewOverlay'); if(existing) existing.remove();
 const overlay = document.createElement('div');
 overlay.id = 'aoEmailPreviewOverlay';
 overlay.style.cssText = 'position:fixed; inset:0; background:rgba(0,0,0,0.6); z-index:4200; display:flex; align-items:center; justify-content:center; padding:20px;';
 overlay.onclick = (e) => { if(e.target === overlay) overlay.remove(); };
 overlay.innerHTML = `
  <div style="background:#fff; max-width:640px; width:100%; max-height:92vh; border-radius:14px; overflow:hidden; display:flex; flex-direction:column; box-shadow:0 20px 60px rgba(0,0,0,0.35);">
   <div style="padding:16px 20px; border-bottom:1px solid #F0F0F0; display:flex; justify-content:space-between; align-items:flex-start; gap:10px;">
    <div>
     <div style="font-size:16px; font-weight:800; color:#101010;"><i data-lucide="eye" style="width:16px;height:16px;vertical-align:-3px;"></i> Preview Resit Email</div>
     <div style="font-size:12px; color:#6B7280; margin-top:3px;">Akan dihantar ke <strong>${esc(email)}</strong> &middot; dari admin@10camp.com</div>
    </div>
    <button onclick="document.getElementById('aoEmailPreviewOverlay').remove()" style="background:none; border:none; font-size:24px; cursor:pointer; color:#999; line-height:1;">×</button>
   </div>
   <div style="flex:1; overflow:auto; background:#F3F4F6;">
    <iframe id="aoEmailPreviewFrame" title="Preview resit" style="width:100%; height:60vh; border:none; background:#F9FAFB; display:block;"></iframe>
   </div>
   <div style="padding:14px 20px; border-top:1px solid #F0F0F0; display:flex; gap:10px;">
    <button onclick="document.getElementById('aoEmailPreviewOverlay').remove()" style="flex:1; background:#fff; border:1px solid #E5E7EB; color:#374151; padding:11px; border-radius:9px; cursor:pointer; font-size:13px; font-weight:700;">Batal</button>
    <button id="aoEmailPreviewSendBtn" onclick="window.__aoEmailSendNow()" style="flex:2; background:var(--primary-500,#CD7C32); border:none; color:#fff; padding:11px; border-radius:9px; cursor:pointer; font-size:13px; font-weight:800;"><i data-lucide="send" style="width:14px;height:14px;vertical-align:-2px;"></i> Hantar Sekarang</button>
   </div>
  </div>`;
 document.body.appendChild(overlay);
 const frame = document.getElementById('aoEmailPreviewFrame');
 if(frame) { try { frame.srcdoc = html; } catch(e) { try { const d = frame.contentWindow.document; d.open(); d.write(html); d.close(); } catch(_){} } }
 if(window.lucide && lucide.createIcons) try { lucide.createIcons(); } catch(e){}
};

// p1_477 — hantar betul selepas preview disahkan
window.__aoEmailSendNow = async function() {
 const ctx = window.__aoEmailPreviewCtx || {};
 const saleId = ctx.saleId, email = ctx.email;
 if(!saleId) return;
 const sendBtn = document.getElementById('aoEmailPreviewSendBtn');
 const orig = sendBtn ? sendBtn.innerHTML : '';
 if(sendBtn) { sendBtn.disabled = true; sendBtn.innerHTML = '<i data-lucide="loader" style="width:14px;height:14px;vertical-align:-2px;"></i> Menghantar…'; if(window.lucide && lucide.createIcons) try { lucide.createIcons(); } catch(e){} }
 try {
  const res = await fetch('/api/send-receipt-email', {
   method: 'POST', headers: await window.__authHeaders({ 'Content-Type': 'application/json' }),
   body: JSON.stringify({ sale_id: saleId, force: true })
  });
  const data = await res.json().catch(() => ({}));
  if(data.success) {
   if(typeof showToast === 'function') showToast('Resit dihantar ke ' + (data.to || email) + '.', 'success');
   const s = (typeof salesHistory !== 'undefined' && Array.isArray(salesHistory)) ? salesHistory.find(x => x.id === saleId) : null;
   if(s) { s.email_status = 'sent'; s.email_sent_at = new Date().toISOString(); }
   const pv = document.getElementById('aoEmailPreviewOverlay'); if(pv) pv.remove();
   const ov = document.getElementById('aoViewOverlay');
   if(ov) { ov.remove(); if(typeof window.__aoViewOrder === 'function') window.__aoViewOrder(saleId); }
   return;
  }
  else if(data.skipped) { if(typeof showToast === 'function') showToast('Tak jadi hantar: ' + (data.reason || 'skipped') + (/RESEND_API_KEY/.test(data.reason||'') ? ' — env Resend belum set di Netlify.' : ''), 'warn'); }
  else { if(typeof showToast === 'function') showToast('Gagal hantar: ' + (data.error || data.reason || res.status), 'error'); }
 } catch(e) { if(typeof showToast === 'function') showToast('Network error: ' + e.message, 'error'); }
 if(sendBtn) { sendBtn.disabled = false; sendBtn.innerHTML = orig; if(window.lucide && lucide.createIcons) try { lucide.createIcons(); } catch(e){} }
};

// p1_320 — set fulfilment state (packed / shipped+tracking / completed). Simpan ke metadata.fulfilment + update status.
window.__aoSetFulfil = async function(saleId, action, opts) {
 opts = opts || {};
 if(typeof db === 'undefined' || !db) { if(typeof showToast==='function') showToast('DB tak available', 'error'); return; }
 if(typeof salesHistory === 'undefined' || !Array.isArray(salesHistory)) return;
 const s = salesHistory.find(x => x.id === saleId);
 if(!s) return;
 const u = window.currentUser || {};
 const who = (u.name || 'Unknown') + ' (' + (u.staff_id || '?') + ')';
 const now = new Date().toISOString();
 const md = Object.assign({}, s.metadata || {});
 const f = Object.assign({}, md.fulfilment || {});
 let newStatus = s.status;
 let msg = '';
 if(action === 'packed') {
 f.packed_at = now; f.packed_by = who; msg = 'ditanda PACKED';
 } else if(action === 'shipped') {
 const tracking = String(opts.tracking || '').trim();
 const courier = opts.courier || '';
 if(!tracking && !confirm('Tiada no. tracking dimasukkan. Tetap tanda Dah Hantar?')) return;
 f.shipped_at = now; f.shipped_by = who;
 if(courier) f.courier = courier;
 if(tracking) f.tracking_no = tracking;
 if(!f.packed_at) { f.packed_at = now; f.packed_by = who; }
 newStatus = 'Processing';
 msg = 'ditanda DAH HANTAR';
 } else if(action === 'completed') {
 f.delivered_at = now; f.delivered_by = who; newStatus = 'Completed'; msg = 'ditanda SELESAI';
 } else { return; }
 md.fulfilment = f;
 try {
 const { error } = await db.from('sales_history').update({ status: newStatus, metadata: md }).eq('id', saleId);
 if(error) throw error;
 s.status = newStatus; s.metadata = md;
 if(typeof showToast === 'function') showToast(`Order #${saleId} ${msg}.`, 'success');
 window.renderAllOrders && window.renderAllOrders();
 window.__aoUpdateOrderBadge && window.__aoUpdateOrderBadge();
 const ov = document.getElementById('aoViewOverlay');
 if(ov) { ov.remove(); window.__aoViewOrder(saleId); }
 } catch(e) {
 if(typeof showToast === 'function') showToast('Update gagal: ' + (e.message || e), 'error');
 }
};

// p1_323 — helper: cari lokasi bin untuk SKU
window.__aoBinFor = function(sku) {
 if(typeof masterProducts === 'undefined') return '';
 const p = masterProducts.find(x => x.sku === sku);
 return (p && p.location_bin) ? String(p.location_bin) : '';
};

// p1_466 — gambar rujukan untuk Senarai Pick (cari dari masterProducts ikut SKU)
window.__aoImgFor = function(sku) {
 if(typeof masterProducts === 'undefined') return '';
 const p = masterProducts.find(x => x.sku === sku);
 return (p && Array.isArray(p.images) && p.images[0]) ? String(p.images[0]) : '';
};
// p1_323 — helper: ambil setting kedai untuk header cetak
window.__aoShopHeader = function() {
 let shop = {};
 try { shop = (JSON.parse(localStorage.getItem('complianceSettings_v1') || '{}').shop) || {}; } catch(e){}
 return { name: shop.name || '10 CAMP', addr: shop.address || '', ssm: shop.ssm || '' };
};

