// p1_323 — Cetak Senarai Pick (gabung semua order "Perlu Pack" ikut filter semasa, disusun ikut lokasi rak)
window.__aoPrintPickingList = function() {
 if(typeof salesHistory === 'undefined' || !Array.isArray(salesHistory)) return;
 const q = (document.getElementById('aoSearch')?.value || '').trim().toLowerCase();
 const channel = document.getElementById('aoChannel')?.value || '';
 const dr = window.__aoDateRange();
 const hideTest = !!document.getElementById('aoHideTest')?.checked;
 const ONLINE_CHANNELS = ['shopee', 'tiktok', 'whatsapp', 'easystore'];
 const orders = salesHistory.filter(s => {
 if(window.__aoStatusMeta(s.status).canon !== 'To Fulfil') return false;
 if(hideTest && s.is_test) return false;
 if(s.created_at) { const t = new Date(s.created_at).getTime(); if(t < dr.from || t > dr.to) return false; }
 const chLower = (s.channel || '').toLowerCase();
 if(channel === 'walkin') { if(!(chLower.includes('walk') || chLower.includes('cashier'))) return false; }
 else if(channel === 'online') { if(!ONLINE_CHANNELS.some(c => chLower.includes(c))) return false; }
 else if(channel && s.channel !== channel) return false;
 if(q) {
 const itemsTxt = Array.isArray(s.items) ? s.items.map(i => (i.sku || '') + ' ' + (i.name || '')).join(' ') : '';
 if(!`${s.customer_name||''} ${s.customer_phone||''} ${itemsTxt}`.toLowerCase().includes(q)) return false;
 }
 return true;
 });
 if(!orders.length) { if(typeof showToast === 'function') showToast('Tiada order "Perlu Pack" untuk dicetak.', 'info'); return; }
 const esc = (v) => String(v == null ? '' : v).replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;');
 const bySku = {};
 let totalUnits = 0;
 orders.forEach(s => {
 (Array.isArray(s.items) ? s.items : []).forEach(it => {
 const sku = it.sku || '?';
 if(!bySku[sku]) bySku[sku] = { sku, name: it.name || sku, bin: window.__aoBinFor(sku), img: window.__aoImgFor(sku), qty: 0, ordCount: 0 };
 const qn = window.__aoItemQty(it);
 bySku[sku].qty += qn; bySku[sku].ordCount += 1; totalUnits += qn;
 });
 });
 const rows = Object.values(bySku).sort((a, b) => (a.bin || 'zzzz').localeCompare(b.bin || 'zzzz') || a.sku.localeCompare(b.sku));
 const shop = window.__aoShopHeader();
 const today = new Date().toLocaleString('en-MY', {day:'2-digit',month:'short',year:'numeric',hour:'2-digit',minute:'2-digit'});
 const win = window.open('', '_blank', 'width=820,height=900');
 if(!win) { if(typeof showToast === 'function') showToast('Popup disekat browser — benarkan popup untuk cetak.', 'warn'); return; }
 win.document.write(`<!DOCTYPE html><html><head><title>Senarai Pick</title>
 <style>
 body { font-family:'Helvetica Neue',Arial,sans-serif; max-width:800px; margin:auto; padding:28px; color:#111; }
 .header { border-bottom:3px solid #111; padding-bottom:10px; margin-bottom:16px; }
 .header h1 { font-size:20px; margin:0; }
 .header h2 { font-size:17px; margin:8px 0 0; color:var(--primary-500,#CD7C32); }
 .sub { font-size:12px; color:#555; margin-top:4px; }
 table { width:100%; border-collapse:collapse; font-size:13px; }
 th,td { border:1px solid #999; padding:7px 8px; text-align:left; }
 th { background:#f3f4f6; }
 .center { text-align:center; }
 .bin { font-family:'SF Mono',Menlo,monospace; background:#F8EFD7; font-weight:bold; }
 .qty { font-size:16px; font-weight:bold; text-align:center; }
 .pic { width:60px; height:60px; object-fit:cover; border:1px solid #ccc; border-radius:5px; display:block; margin:auto; }
 .pic-none { width:60px; height:60px; border:1px dashed #ccc; border-radius:5px; display:flex; align-items:center; justify-content:center; color:#bbb; font-size:9px; margin:auto; }
 @media print { @page { margin:1.2cm; } button { display:none; } body { -webkit-print-color-adjust:exact; print-color-adjust:exact; } }
 </style></head><body>
 <div class="header">
 <h1>${esc(shop.name)}</h1>
 <h2>SENARAI PICK — Perlu Pack</h2>
 <div class="sub">${esc(today)} · ${orders.length} order · ${rows.length} SKU · ${totalUnits} unit · disusun ikut lokasi rak</div>
 </div>
 <table>
 <thead><tr><th class="center">Lokasi Rak</th><th>SKU</th><th class="center">Gambar</th><th>Nama Produk</th><th class="center">Qty</th><th class="center">Order</th><th class="center">Tick</th></tr></thead>
 <tbody>
 ${rows.map(r => `<tr>
 <td class="center bin">${esc(r.bin || '—')}</td>
 <td><strong>${esc(r.sku)}</strong></td>
 <td class="center">${r.img ? `<img class="pic" src="${esc(r.img)}" alt="${esc(r.sku)}" onerror="this.outerHTML='<div class=\\'pic-none\\'>No Img</div>'">` : `<div class="pic-none">No Img</div>`}</td>
 <td>${esc((r.name || '').slice(0, 70))}</td>
 <td class="qty">${r.qty}</td>
 <td class="center">${r.ordCount}</td>
 <td class="center">&#9744;</td>
 </tr>`).join('')}
 </tbody>
 </table>
 <p style="margin-top:24px; font-size:10px; color:#999; text-align:center;">Auto-generated by POS10C · Senarai Pick · ${esc(today)}</p>
 <button onclick="window.print()" style="position:fixed; top:20px; right:20px; padding:10px 20px; background:var(--primary-500,#CD7C32); color:white; border:none; border-radius:6px; font-weight:bold; cursor:pointer;">Print</button>
 </body></html>`);
 win.document.close();
};

// p1_329/p1_330 — muat SEMUA baris berperingkat 1000-1000 (PostgREST max-rows ~1000 walau limit besar)
// p1_1092 — opts pilihan: { select:'kolum,kolum', filter:fn(q)=>q } utk query berkolum/bertapis.
window.__fetchAllRows = async function(table, orderCol, ascending, opts) {
 const all = [];
 const PAGE = 1000;
 // p1_480 — WAJIB ada ORDER BY stabil masa paginate .range(); tanpa order, Postgres
 // boleh pulang baris dalam susunan berbeza antara page → baris ter-SKIP/duplicate
 // (punca "customer hilang dari senarai cashier"). Default ke PK 'id' kalau caller tak bagi.
 const oc = orderCol || 'id';
 const asc = orderCol ? !!ascending : true;
 for(let start = 0; start < 1000000; start += PAGE) {
 let q = db.from(table).select((opts && opts.select) || '*').order(oc, { ascending: asc });
 if(opts && typeof opts.filter === 'function') q = opts.filter(q);
 const { data, error } = await q.range(start, start + PAGE - 1);
 if(error) throw error;
 if(!data || !data.length) break;
 all.push(...data);
 if(data.length < PAGE) break;
 }
 return all;
};
// p1_1092 — inventory_batches melepasi 1,000 baris (13 Jul 2026): PostgREST potong pada
// max-rows 1000 WALAUPUN .limit(100000), jadi batch terbaru tergugur (susunan inbound_date
// ASC buang hujung) → produk baru Zack kekal "STOK HABIS" walau stok dah didaftar.
// Muat berperingkat ikut id (unik — tiada skip/dup antara page), lepas tu susun FIFO
// inbound_date ASC (sort JS stabil: seri kekal ikut id) sebab deduct FIFO harap susunan ni.
window.__loadAllBatches = async function() {
 const rows = await window.__fetchAllRows('inventory_batches', 'id', true);
 rows.sort((a, b) => new Date(a.inbound_date || 0) - new Date(b.inbound_date || 0));
 return rows;
};
window.__aoFetchAllSales = function() { return window.__fetchAllRows('sales_history', 'created_at', false); };

// p1_324 — badge "order baru / perlu pack" di sidebar (Orders parent + All Orders sub-item)
window.__aoUpdateOrderBadge = function() {
 if(typeof salesHistory === 'undefined' || !Array.isArray(salesHistory)) return;
 let n = 0;
 for(const s of salesHistory) { if(!s.is_test && window.__aoStatusMeta(s.status).canon === 'To Fulfil') n++; }
 ['ordersNavBadge','aoNavBadge'].forEach(id => {
 const el = document.getElementById(id);
 if(!el) return;
 if(n > 0) { el.textContent = n > 99 ? '99+' : String(n); el.style.display = ''; }
 else el.style.display = 'none';
 });
};

// p1_324 — Refresh sebenar: re-query sales_history dari DB (bukan render in-memory je)
window.__aoRefresh = async function(silent) {
 if(typeof db === 'undefined' || !db) { window.renderAllOrders && window.renderAllOrders(); return; }
 if(typeof salesHistory === 'undefined' || !Array.isArray(salesHistory)) return;
 const btn = document.getElementById('aoRefreshBtn');
 if(btn) { btn.disabled = true; btn.style.opacity = '0.6'; }
 try {
 const prevIds = new Set(salesHistory.map(s => s.id));
 const data = await window.__aoFetchAllSales();
 if(Array.isArray(data)) {
 salesHistory.length = 0;
 for(const d of data) salesHistory.push(d);
 }
 const newCount = (data || []).filter(s => !prevIds.has(s.id)).length;
 window.renderAllOrders && window.renderAllOrders();
 window.__aoUpdateOrderBadge && window.__aoUpdateOrderBadge();
 if(!silent && typeof showToast === 'function') showToast(newCount > 0 ? `${newCount} order baru ditarik. Jumlah ${salesHistory.length} order.` : `Dikemaskini — ${salesHistory.length} order, tiada yang baru.`, 'success');
 } catch(e) {
 if(typeof showToast === 'function') showToast('Refresh gagal: ' + (e.message || e), 'error');
 } finally {
 if(btn) { btn.disabled = false; btn.style.opacity = ''; }
 }
};

