 // Consent display
 + '<div style="display:flex; gap:14px; margin-bottom:14px; font-size:11.5px; color:#6B7280;">'
 + (c.accepts_email_marketing ? '<span style="display:inline-flex; align-items:center; gap:4px; color:#3F7350;"><i data-lucide="mail-check" style="width:13px;height:13px;"></i> Email consent</span>' : '<span style="display:inline-flex; align-items:center; gap:4px;"><i data-lucide="mail-x" style="width:13px;height:13px;color:#D1D5DB;"></i> No email consent</span>')
 + (c.accepts_sms_marketing ? '<span style="display:inline-flex; align-items:center; gap:4px; color:#3F7350;"><i data-lucide="message-square" style="width:13px;height:13px;"></i> SMS consent</span>' : '<span style="display:inline-flex; align-items:center; gap:4px;"><i data-lucide="message-square-off" style="width:13px;height:13px;color:#D1D5DB;"></i> No SMS consent</span>')
 + '</div>'
 // p1_564 — sejarah ganjaran ditebus (dari metadata.loyalty_redeem jualan customer ni)
 + (() => {
 const reds = (sales || []).map(s => { let m = s.metadata; if(typeof m === 'string'){ try { m = JSON.parse(m); } catch(e){ m = null; } } return (m && m.loyalty_redeem) ? { date: s.created_at, r: m.loyalty_redeem } : null; }).filter(Boolean);
 if(!reds.length) return '';
 const rows = reds.map(x => '<div style="display:flex; justify-content:space-between; padding:5px 0; border-bottom:1px solid #F3F4F6; font-size:11.5px;"><span>' + escHtml(x.r.label || x.r.type || 'redeem') + '</span><span style="color:#6B7280;">' + (x.date ? new Date(x.date).toLocaleDateString('en-MY',{day:'2-digit',month:'short',year:'2-digit'}) : '') + (x.r.points_cost ? ' &middot; &minus;' + x.r.points_cost + ' mata' : '') + '</span></div>').join('');
 return '<h3 style="font-size:13px; margin:6px 0 8px; color:#111;">Ganjaran ditebus (' + reds.length + ')</h3><div style="border:1px solid #E5E7EB; border-radius:8px; padding:6px 12px; margin-bottom:14px;">' + rows + '</div>';
 })()
 // Sales history — full, no cap. Scrollable container.
 + '<h3 style="font-size:13px; margin:6px 0 8px; color:#111; display:flex; justify-content:space-between; align-items:center;"><span>Pembelian / Purchases (<span style="color:var(--primary);">' + sales.length + '</span>)</span></h3>'
 + '<div style="border:1px solid #E5E7EB; border-radius:8px; max-height:280px; overflow-y:auto;">'
 + '<table style="width:100%; font-size:12px; border-collapse:collapse;"><thead style="position:sticky; top:0; background:#FAFAFA; z-index:1;"><tr><th style="text-align:left; padding:6px 8px; font-size:10px; color:#6B7280; text-transform:uppercase;">Tarikh</th><th style="text-align:left; padding:6px 8px; font-size:10px; color:#6B7280; text-transform:uppercase;">Channel</th><th style="text-align:center; padding:6px 8px; font-size:10px; color:#6B7280; text-transform:uppercase;">Items</th><th style="text-align:left; padding:6px 8px; font-size:10px; color:#6B7280; text-transform:uppercase;">Bayar</th><th style="text-align:right; padding:6px 8px; font-size:10px; color:#6B7280; text-transform:uppercase;">Jumlah</th></tr></thead><tbody>'
 + salesRows
 + '</tbody></table>'
 + '</div>'
 + '</div>'
