window.cpPopulateEwallets = function() {
 const sel = document.getElementById('cpEwalletProvider');
 const empty = document.getElementById('cpEwalletEmptyMsg');
 if(!sel) return;
 let s = {};
 try { s = JSON.parse(localStorage.getItem('complianceSettings_v1') || '{}'); } catch(e){}
 const wallets = s.ewallets || {};
 const enabled = Object.entries(wallets).filter(([_, v]) => v && v.enabled);
 sel.innerHTML = '<option value="">— Pilih e-wallet —</option>' +
 enabled.map(([k, _]) => `<option value="${k}">${k}</option>`).join('');
 if(empty) empty.classList.toggle('is-hidden', enabled.length> 0);
 // p1_554 (#12) — isi __ewalletPatterns supaya validasi format Ref aktif dalam panel checkout (dulu kosong → skip).
 const __EW_PAT = [
 { re:/touch|tng|t.?n.?g/i, pattern:/^\d{16,20}$/, hint:'16-20 digit' },
 { re:/boost/i, pattern:/^[A-Za-z0-9]{8,}$/, hint:'min 8 aksara' },
 { re:/grab/i, pattern:/^[A-Z0-9]{10,}$/i, hint:'min 10 aksara' },
 { re:/shopee/i, pattern:/^[A-Z0-9-]{10,}$/i, hint:'min 10 aksara' },
 { re:/mae|maybank/i, pattern:/^\d{6,}$/, hint:'min 6 digit' }
 ];
 window.__ewalletPatterns = {};
 enabled.forEach(([k]) => { const m = __EW_PAT.find(p => p.re.test(k)); if(m) window.__ewalletPatterns[k] = { pattern: m.pattern, hint: m.hint }; });
};

window.cpRecomputeTotal = function() {
 let raw = 0;
 (typeof cart !== 'undefined' ? cart : []).forEach(it => {
 raw += (it.quantity || it.qty || 1) * (parseFloat(it.price) || 0);
 });
 raw = round2(raw);
 let final = raw;
 // p1_204 — Custom manual discount FIRST (cp* inputs in active checkout panel)
 const cdType = (document.getElementById('cpDiscType') || {}).value || 'rm';
 const cdAmtIn = parseFloat((document.getElementById('cpDiscAmt') || {}).value) || 0;
 let customDiscount = 0;
 if(cdAmtIn > 0) customDiscount = cdType === 'pct' ? round2(raw * cdAmtIn / 100) : round2(cdAmtIn);
 if(customDiscount > raw) customDiscount = raw;
 const afterCustom = round2(raw - customDiscount);
 // VIP discount applied on top of custom-discounted amount
 // p1_369 — auto-discount gated OFF (Zaid). VIP dikenali tapi harga tak tolak sendiri.
 let vipDiscount = 0;
 if(window.VIP_AUTO_DISCOUNT && window.__currentCheckoutVip && window.__currentCheckoutVip.discount_pct) {
 vipDiscount = round2(afterCustom * window.__currentCheckoutVip.discount_pct / 100);
 }
 final = round2(afterCustom - vipDiscount);
 const totalDiscount = customDiscount + vipDiscount;
 // p1_249 — defensive null checks (Zaid screenshot: "null is not an object cpConfirmAmount")
 const tdEl = document.getElementById('cpTotalDisplay'); if(tdEl) tdEl.textContent = final.toFixed(2);
 const caEl = document.getElementById('cpConfirmAmount'); if(caEl) caEl.textContent = final.toFixed(2);
 const discLine = document.getElementById('cpDiscountLine');
 if(discLine) {
 if(totalDiscount > 0) {
 discLine.style.display = 'block';
 const parts = [];
 if(customDiscount > 0) parts.push('Diskaun custom −RM ' + customDiscount.toFixed(2));
 if(vipDiscount > 0) parts.push((window.__currentCheckoutVip?.tier || 'VIP') + ' −RM ' + vipDiscount.toFixed(2));
 discLine.innerHTML = parts.join(' · ') + ' (subtotal RM ' + raw.toFixed(2) + ')';
 } else {
 discLine.style.display = 'none';
 }
 }
 const legacy = document.getElementById('paymentTotalDisplay');
 if(legacy) legacy.textContent = final.toFixed(2);
 // p1_853 — refresh baki bila total berubah (cth: diskaun ditambah)
 if(typeof window.cpCashRender === 'function') window.cpCashRender();
};

// p1_853 — Tunai Diterima + Baki (kira duit pulang). Keypad besar untuk laju di phone.
window.__cpCashRaw = ''; // string mentah yang ditaip (cth "150" atau "27.50")
window.cpCashKey = function(k){
 let s = window.__cpCashRaw || '';
 if(k === 'clear'){ s = ''; }
 else if(k === 'back'){ s = s.slice(0, -1); }
 else if(k === '.'){ if(!s.includes('.')) s = (s === '' ? '0' : s) + '.'; }
 else { // digit 0-9
 if(s.includes('.') && s.split('.')[1].length >= 2) return; // max 2 titik perpuluhan
 if(s.replace('.', '').length >= 7) return; // had waras (<= RM 99999.99)
 s = (s === '0') ? k : s + k;
 }
 window.__cpCashRaw = s;
 window.cpCashRender();
};
window.cpCashQuick = function(amt){
 if(amt === 'exact'){
 const t = parseFloat((document.getElementById('cpTotalDisplay') || {}).textContent) || 0;
 window.__cpCashRaw = t.toFixed(2);
 } else {
 window.__cpCashRaw = String(amt);
 }
 window.cpCashRender();
};
window.cpCashRender = function(){
 const raw = window.__cpCashRaw || '';
 const recv = parseFloat(raw) || 0;
 const total = parseFloat((document.getElementById('cpTotalDisplay') || {}).textContent) || 0;
 const rEl = document.getElementById('cpCashReceived');
 if(rEl) rEl.textContent = (raw === '' ? '0.00' : window.__money(recv));
 const cEl = document.getElementById('cpCashChange');
 const wrap = document.getElementById('cpCashChangeWrap');
 if(cEl && wrap){
 const change = round2(recv - total);
 if(raw === '' || recv === 0){
 cEl.textContent = 'RM 0.00'; wrap.className = 'cp-cash__change';
 } else if(change >= 0){
 cEl.textContent = 'RM ' + window.__money(change); wrap.className = 'cp-cash__change is-ok';
 } else {
 cEl.textContent = 'Kurang RM ' + window.__money(Math.abs(change)); wrap.className = 'cp-cash__change is-short';
 }
 }
};
window.cpCashReset = function(){ window.__cpCashRaw = ''; window.__cpCashPayment = null; if(typeof window.cpCashRender === 'function') window.cpCashRender(); };

