window.__posBrowseType = 'collection';
window.__posBrowseClose = function(){ const o = document.getElementById('posBrowseOverlay'); if(o) o.remove(); };
window.__posBrowseOpen = function(type){
 window.__posBrowseType = type || window.__posBrowseType || 'collection';
 const old = document.getElementById('posBrowseOverlay'); if(old) old.remove();
 const ov = document.createElement('div'); ov.id = 'posBrowseOverlay';
 ov.style.cssText = 'position:fixed; inset:0; background:rgba(16,16,16,.55); z-index:9800; display:flex; align-items:flex-start; justify-content:center; padding:24px 14px; overflow:auto;';
 ov.addEventListener('click', e => { if(e.target === ov) window.__posBrowseClose(); });
 ov.innerHTML = '<div style="background:#fff; width:100%; max-width:780px; border-radius:16px; overflow:hidden; box-shadow:0 20px 60px rgba(0,0,0,.3); margin:auto;">'
  + '<div style="display:flex; align-items:center; justify-content:space-between; padding:16px 18px; border-bottom:1px solid #EEE;">'
   + '<div style="font-weight:800; font-size:16px;"><i data-lucide="layout-grid" style="width:18px;height:18px;vertical-align:-3px;margin-right:6px;"></i>Katalog Produk</div>'
   + '<button onclick="window.__posBrowseClose()" title="Tutup" style="border:none;background:#F3F4F6;width:32px;height:32px;border-radius:50%;cursor:pointer;"><i data-lucide="x" style="width:16px;height:16px;"></i></button>'
  + '</div>'
  + '<div id="posBrowseTabs" style="display:flex; gap:8px; padding:14px 18px 0;"></div>'
  // p1_1075 — search dalam Katalog (Ariff): taip "flysheet" → semua kumpulan flysheet (semua bentuk:
  // hexagon, rectangle, twin peak, octagon…) terus keluar, tak perlu tahu nama kategori penuh.
  // Carian merentas SEMUA jenis kumpulan (Koleksi + Brand + Kategori) sekali gus, hasil ada badge jenis.
  + '<div style="position:relative; padding:12px 18px 0;">'
   + '<i data-lucide="search" style="position:absolute; left:31px; top:24px; width:14px; height:14px; color:#9CA3AF; pointer-events:none;"></i>'
   + '<input type="text" id="posBrowseSearch" oninput="window.__posBrowseRender()" placeholder="Cari kumpulan… cth: flysheet, dome, chair" autocomplete="off" style="width:100%; margin:0; padding:10px 14px 10px 38px; border:1.5px solid #E5E7EB; border-radius:10px; font-size:13px; font-weight:500; font-family:var(--font-main,Poppins); box-sizing:border-box;">'
  + '</div>'
  + '<div id="posBrowseBody" style="padding:16px 18px 22px; max-height:70vh; overflow:auto;"></div>'
  + '</div>';
 document.body.appendChild(ov);
 window.__posBrowseRender();
 if(window.lucide && lucide.createIcons) try { lucide.createIcons(); } catch(e){}
};
window.__posBrowseSetTab = function(type){ window.__posBrowseType = type; const s = document.getElementById('posBrowseSearch'); if(s) s.value = ''; /* p1_1075 — tukar tab = keluar mod carian */ window.__posBrowseRender(); if(window.lucide && lucide.createIcons) try { lucide.createIcons(); } catch(e){} };
window.__posBrowseRender = function(){
 const tabsEl = document.getElementById('posBrowseTabs'); const bodyEl = document.getElementById('posBrowseBody');
 if(!tabsEl || !bodyEl) return;
 const type = window.__posBrowseType;
 const tabs = [['collection','Koleksi','folder-tree'],['brand','Brand','award'],['category','Kategori','layers']];
 tabsEl.innerHTML = tabs.map(function(t){ const on = t[0] === type;
  return '<button onclick="window.__posBrowseSetTab(\'' + t[0] + '\')" style="flex:1; padding:9px 10px; border-radius:10px; border:1.5px solid ' + (on?'var(--primary)':'#E5E7EB') + '; background:' + (on?'var(--primary)':'#fff') + '; color:' + (on?'#fff':'#374151') + '; font-weight:700; font-size:13px; cursor:pointer; display:inline-flex; align-items:center; justify-content:center; gap:6px;"><i data-lucide="' + t[2] + '" style="width:14px;height:14px;"></i>' + t[1] + '</button>';
 }).join('');
 const prods = (typeof masterProducts !== 'undefined' && Array.isArray(masterProducts)) ? masterProducts : [];
 // p1_1075 — bila ada carian: cari nama kumpulan merentas SEMUA jenis (Koleksi + Brand + Kategori),
 // bukan tab semasa sahaja — staff tak perlu tahu "flysheet" tu kategori ke koleksi ke brand.
 const q = ((document.getElementById('posBrowseSearch') || {}).value || '').trim().toLowerCase();
 const tally = new Map(); // key "type::name" bila carian; nama biasa bila tab
 const bump = (t, g) => {
  if(!g) return;
  if(q && g.toLowerCase().indexOf(q) === -1) return;
  const k = q ? (t + '::' + g) : g;
  tally.set(k, (tally.get(k) || 0) + 1);
 };
 for(const p of prods){
  if(!isPublished(p)) continue; if(window.__isDiscontinued && window.__isDiscontinued(p)) continue;
  if(q){
   bump('collection', (window.__collectionOf ? window.__collectionOf(p) : ''));
   bump('brand', (p.brand || '').trim());
   bump('category', (p.category || '').trim());
  } else {
   let g = '';
   if(type === 'brand') g = (p.brand || '').trim();
   else if(type === 'category') g = (p.category || '').trim();
   else g = (window.__collectionOf ? window.__collectionOf(p) : '');
   bump(type, g);
  }
 }
 const groups = Array.from(tally.entries()).sort((a,b) => b[1] - a[1]);
 const esc = (typeof hesc === 'function') ? hesc : (x)=>String(x==null?'':x);
 if(!groups.length){ bodyEl.innerHTML = '<div style="padding:34px; text-align:center; color:#9CA3AF;">' + (q ? 'Tiada kumpulan padan dengan "' + esc(q) + '".' : 'Tiada kumpulan untuk tab ini.') + '</div>'; return; }
 const typeLabel = { collection:'Koleksi', brand:'Brand', category:'Kategori' };
 bodyEl.innerHTML = '<div style="display:grid; grid-template-columns:repeat(auto-fill,minmax(148px,1fr)); gap:12px;">'
  + groups.map(function(gc){ const count = gc[1];
    const gType = q ? gc[0].split('::')[0] : type;
    const name = q ? gc[0].slice(gc[0].indexOf('::') + 2) : gc[0];
    // p1_1015 — tab Brand: utamakan LOGO brand; kalau tiada logo (brand tak dikenali) → fallback gambar produk.
    const brandLogo = (gType === 'brand') ? window.__brandLogoUrl(name) : '';
    const img = brandLogo || window.__groupThumb(gType, name);
    const badge = q ? '<span style="position:absolute; top:7px; left:7px; background:rgba(16,16,16,.72); color:#FAF6EF; font-size:9.5px; font-weight:700; padding:2px 7px; border-radius:999px; letter-spacing:.02em;">' + typeLabel[gType] + '</span>' : '';
    const media = img
     ? '<div style="position:relative; aspect-ratio:1/1; background:' + (brandLogo ? '#fff' : '#FBF7F0') + '; border-radius:11px 11px 0 0; overflow:hidden; display:flex; align-items:center; justify-content:center;' + (brandLogo ? ' padding:16px;' : '') + '"><img src="' + esc(img) + '" style="max-width:100%; max-height:100%; width:' + (brandLogo ? 'auto' : '100%') + '; height:' + (brandLogo ? 'auto' : '100%') + '; object-fit:contain;" loading="lazy">' + badge + '</div>'
     : '<div style="position:relative; aspect-ratio:1/1; background:#F4E8D8; border-radius:11px 11px 0 0; display:flex; align-items:center; justify-content:center; color:#A5611F; font-weight:800; font-size:22px; letter-spacing:.02em;">' + esc(String(name).slice(0,2).toUpperCase()) + badge + '</div>';
    return '<button onclick="window.__posPickGroup(\'' + gType + '\',' + JSON.stringify(String(name)).replace(/"/g,'&quot;') + ')" style="text-align:left; padding:0; border:1px solid #EAE0D2; border-radius:12px; background:#fff; cursor:pointer; overflow:hidden;">'
     + media
     + '<div style="padding:8px 10px 10px;"><div style="font-size:12.5px; font-weight:700; color:#101010; line-height:1.25;">' + esc(name) + '</div><div style="font-size:11px; color:#8C7C6A; margin-top:2px;">' + count + ' produk</div></div>'
     + '</button>';
  }).join('') + '</div>';
};
window.__posPickGroup = function(type, name){
 window.__posBrandFilter = (type === 'brand') ? name : '';
 window.__posCollectionFilter = (type === 'collection') ? name : '';
 window.__posCategoryFilter = (type === 'category') ? name : '';
 const inp = document.getElementById('searchInput'); if(inp) inp.value = '';
 window.__posBrowseClose();
 window.__bpRendered = false; if(window.__bpRenderBrandPills) window.__bpRenderBrandPills(); window.__bpRendered = true;
 if(typeof renderPOS === 'function') renderPOS('');
 if(window.showToast) showToast('Tunjuk: ' + name + ' (' + (type==='collection'?'Koleksi':type==='brand'?'Brand':'Kategori') + ')', 'info');
};

// p1_310 — Collections list (EasyStore-style): products grouped into Brands +
// Categories with counts. Click a row → open Products grid filtered to it.
window.renderCollections = function() {
 const body = document.getElementById('collectionsBody');
 if(!body) return;
 const prods = (typeof masterProducts !== 'undefined' && Array.isArray(masterProducts)) ? masterProducts : [];
 // p1_1003 — kalau katalog belum siap load (race: buka/refresh Collections masa boot, sebelum initApp
 // muat masterProducts) → jangan render 0/kosong. Tunjuk "Memuatkan…" + auto-retry sampai katalog sampai.
 if(prods.length === 0 && window.currentUser){
  window.__collLoadRetry = (window.__collLoadRetry || 0);
  if(window.__collLoadRetry < 50){
   window.__collLoadRetry++;
   body.innerHTML = '<div style="padding:44px; text-align:center; color:#9CA3AF;"><i data-lucide="loader" style="width:26px;height:26px;"></i><br><span style="font-size:13px;">Memuatkan katalog…</span></div>';
   if(window.lucide && lucide.createIcons) try { lucide.createIcons(); } catch(e){}
   setTimeout(() => { try { window.renderCollections(); } catch(e){} }, 400);
  } else {
   // p1_1005 — retry habis (~20s) dan katalog masih kosong → jangan spinner selamanya; tunjuk empty + cuba lagi
   body.innerHTML = '<div style="padding:40px; text-align:center; color:#9CA3AF;"><i data-lucide="package-x" style="width:30px;height:30px;opacity:.5;"></i><br><span style="font-size:13px;">Katalog kosong atau gagal dimuat.</span><br><button onclick="window.__collLoadRetry=0; window.renderCollections();" class="btn-brand-outline" style="margin-top:12px; font-size:12px; padding:7px 16px;">Cuba lagi</button></div>';
   if(window.lucide && lucide.createIcons) try { lucide.createIcons(); } catch(e){}
  }
  return;
 }
 window.__collLoadRetry = 0;
 const pub = (typeof isPublished === 'function') ? isPublished : (() => true);
 // group helper → [{name, total(unit), listings, live, liveListings}]
 // p1_965 — kira LISTING (varian dicantum ikut parent_sku, sama macam grid Produk) +
 //   unit/SKU mentah. Dulu cuma tunjuk unit (104) tapi grid tunjuk listing (66) → tak padan,
 //   nampak macam produk hilang. Key listing mirror grid renderProductDatabase.
 const listingKey = (p) => (p.parent_sku && String(p.parent_sku).trim()) ? ('p:' + p.parent_sku) : ('s:' + p.sku);
 const groupBy = (field) => {
 const m = new Map();
 for(const p of prods) {
 const v = (p[field] || '').trim();
 if(!v) continue;
 if(!m.has(v)) m.set(v, { name: v, total: 0, live: 0, _L: new Set(), _LL: new Set() });
 const g = m.get(v); g.total++;
 const lk = listingKey(p); g._L.add(lk);
 if(pub(p)) { g.live++; g._LL.add(lk); }
 }
 return Array.from(m.values())
 .map(g => ({ name: g.name, total: g.total, live: g.live, listings: g._L.size, liveListings: g._LL.size }))
 .sort((a,b) => b.listings - a.listings);
 };
 const brands = groupBy('brand');
 const cats = groupBy('category');
 const noBrand = prods.filter(p => !(p.brand || '').trim()).length;
 const noCat = prods.filter(p => !(p.category || '').trim()).length;
 // p1_1000 — "Collections" segment: 8 koleksi tetap (auto ikut kategori + override per-SKU).
 const collMap = new Map();
 (window.__CAMP_COLLECTIONS || []).forEach(c => collMap.set(c, { name: c, total: 0, live: 0, _L: new Set(), _LL: new Set() }));
 for(const p of prods) {
  const c = window.__collectionOf ? window.__collectionOf(p) : '';
  if(!c) continue;
  if(!collMap.has(c)) collMap.set(c, { name: c, total: 0, live: 0, _L: new Set(), _LL: new Set() });
  const g = collMap.get(c); g.total++;
  const lk = listingKey(p); g._L.add(lk);
  if(pub(p)) { g.live++; g._LL.add(lk); }
 }
 const colls = Array.from(collMap.values()).map(g => ({ name: g.name, total: g.total, live: g.live, listings: g._L.size, liveListings: g._LL.size }));
 const noColl = prods.filter(p => !(window.__collectionOf ? window.__collectionOf(p) : '')).length;

 // p1_1002 — thumbnail wakil (gambar produk pertama dlm kumpulan yg ada gambar) di setiap baris
 const thumbEl = (type, name) => {
  const img = window.__groupThumb ? window.__groupThumb(type, name) : '';
  return img
   ? `<span style="width:32px;height:32px;border-radius:7px;overflow:hidden;flex-shrink:0;background:#FBF7F0;display:inline-flex;border:1px solid #EEE4D6;"><img src="${hesc(img)}" style="width:100%;height:100%;object-fit:contain;" loading="lazy"></span>`
   : `<span style="width:32px;height:32px;border-radius:7px;flex-shrink:0;background:#F4E8D8;color:#A5611F;font-weight:800;font-size:11px;display:inline-flex;align-items:center;justify-content:center;">${hesc(String(name).slice(0,2).toUpperCase())}</span>`;
 };
 const row = (type, g) =>
 `<div onclick="window.__collectionOpen('${type}','${hesc(g.name).replace(/'/g, "\\'")}')" style="display:flex; align-items:center; justify-content:space-between; padding:9px 14px 9px 24px; border-bottom:1px solid #F3F4F6; cursor:pointer;" onmouseover="this.style.background='#F9FAFB'" onmouseout="this.style.background='#fff'">
 <span style="display:inline-flex; align-items:center; gap:11px; font-size:13.5px; color:var(--primary-800,#7C4A1A); font-weight:600;">${thumbEl(type, g.name)}${hesc(g.name)}</span>
 <span style="display:inline-flex; align-items:center; gap:16px;"><span style="font-size:10.5px; font-weight:700; color:#4E7C4A; background:#E4EFE2; padding:2px 8px; border-radius:999px;">${g.liveListings} live</span><span style="font-size:13px; color:#6B7280; min-width:64px; text-align:right;" title="${g.listings} listing (varian dicantum) · ${g.total} unit/SKU">${g.listings} <span style="color:#9CA3AF; font-size:11px;">/ ${g.total}</span></span></span>
 </div>`;
 const groupHeader = (icon, title, sub) =>
 `<div style="display:flex; align-items:center; gap:9px; padding:12px 14px; background:#F9FAFB; border-bottom:1px solid #E5E7EB; font-weight:700; font-size:13px; color:#101010;"><i data-lucide="${icon}" style="width:16px;height:16px;color:var(--primary-500,#CD7C32);"></i>${title} <span style="font-weight:500; color:#9CA3AF; font-size:11.5px;">${sub}</span></div>`;

 let html = '';
 html += '<div style="display:flex; align-items:center; justify-content:space-between; margin:18px 0 14px;"><h2 class="section-title" data-skip-title-sync style="margin:0;"><i data-lucide="folder-tree" style="width:22px;height:22px;vertical-align:middle;margin-right:6px;"></i>Collections</h2><span style="font-size:12px; color:#6B7280;">' + prods.length + ' produk · ' + (window.__CAMP_COLLECTIONS||[]).length + ' koleksi · ' + brands.length + ' brand · ' + cats.length + ' kategori</span></div>';
 html += '<div style="border:1px solid #E5E7EB; border-radius:12px; overflow:hidden; background:#fff;">';
 // Collections group (p1_1000) — koleksi overall untuk POS app, auto ikut kategori + override per-SKU
 html += groupHeader('folder-tree', 'Collections', (window.__CAMP_COLLECTIONS||[]).length + ' koleksi · auto ikut kategori');
 html += colls.map(g => row('collection', g)).join('');
 if(noColl) html += `<div style="padding:9px 14px 9px 34px; border-bottom:1px solid #F3F4F6; font-size:12px; color:#9CA3AF;">${noColl} produk belum ada koleksi (set di editor produk → medan Collection)</div>`;
 // Brands group
 html += groupHeader('award', 'Brands', brands.length + ' brand');
 html += brands.map(g => row('brand', g)).join('');
 if(noBrand) html += `<div style="padding:9px 14px 9px 34px; border-bottom:1px solid #F3F4F6; font-size:12px; color:#9CA3AF;">${noBrand} produk tiada brand</div>`;
 // Categories group
 html += groupHeader('layers', 'Categories', cats.length + ' kategori');
 html += cats.map(g => row('category', g)).join('');
 if(noCat) html += `<div style="padding:9px 14px 9px 34px; font-size:12px; color:#9CA3AF;">${noCat} produk tiada kategori</div>`;
 html += '</div>';
 html += '<div style="margin-top:14px; font-size:12px; color:#9CA3AF;">Tekan mana-mana koleksi untuk lihat produk di dalamnya. Nombor = <b>listing</b> (varian dah dicantum, sama macam grid Produk) <b>/</b> jumlah unit-SKU.</div>';
 // p1_1001 — Urus Koleksi (mgmt sahaja): tambah/buang koleksi custom. Keahlian produk: auto ikut
 // kategori ATAU set terus di editor produk (medan Collection, by SKU).
 const __cu = window.currentUser;
 const canManage = __cu && (__cu.role === 'mgmt' || (window.isBoss && window.isBoss(__cu)));
 if(canManage){
  const clist = window.__getCollections();
  html += '<div class="admin-card" style="padding:16px; margin-top:16px;">';
  html += '<div style="font-weight:800; font-size:13.5px; margin-bottom:10px;"><i data-lucide="folder-plus" style="width:15px;height:15px;vertical-align:-2px;"></i> Urus Koleksi</div>';
  html += '<p style="font-size:11.5px; color:#9CA3AF; margin:0 0 12px;">Tambah koleksi ikut keperluan. Produk masuk koleksi secara auto ikut kategori, atau set terus di editor produk (medan Collection — by SKU).</p>';
  html += '<div style="display:flex; flex-wrap:wrap; gap:7px; margin-bottom:12px;">' + clist.map(c => `<span style="display:inline-flex; align-items:center; gap:6px; background:#F3EEE7; color:#7A4A1E; border:1px solid #E8D9C7; padding:4px 10px; border-radius:999px; font-size:12px; font-weight:600;">${hesc(c)}<button onclick="window.__collRemove('${hesc(c).replace(/'/g, "\\'")}')" title="Buang" style="border:none; background:none; color:#B23A2E; cursor:pointer; font-size:15px; line-height:1; padding:0;">&times;</button></span>`).join('') + '</div>';
  html += '<div style="display:flex; gap:8px;"><input id="collNewName" type="text" placeholder="Nama koleksi baru…" onkeydown="if(event.key===\'Enter\'){event.preventDefault(); window.__collAdd();}" style="flex:1; padding:8px 11px; border:1px solid #E5E7EB; border-radius:8px; font-size:13px; font-family:var(--font-main,Poppins),sans-serif;"><button onclick="window.__collAdd()" class="btn-brand-primary" style="font-size:13px; padding:8px 16px; white-space:nowrap;">Tambah</button></div>';
  html += '</div>';
 }
 body.innerHTML = html;
 if(window.lucide && lucide.createIcons) try { lucide.createIcons(); } catch(e){}
};

// p1_310 — open the Products grid filtered to a collection (brand/category)
// p1_965 — RESET semua filter lain dulu (search/category/STATUS + status pills + page).
//   Dulu: status filter lama (cth "Low"/"Draft"/"Live") kekal aktif bila buka koleksi →
//   produk yang tak match status tersembunyi → nampak macam "tak semua produk ada di collection".
window.__collectionOpen = function(type, value) {
 if(typeof switchHub === 'function') switchHub(['databaseSection'], 'Products', null);
 if(typeof window.renderProductDatabase === 'function') window.renderProductDatabase(); // ensure filter selects populated
 const sEl = document.getElementById('pdSearch'); if(sEl) sEl.value = '';
 const bEl = document.getElementById('pdBrand'); if(bEl) bEl.value = (type === 'brand') ? value : '';
 const cEl = document.getElementById('pdCategory'); if(cEl) cEl.value = (type === 'category') ? value : '';
 window.__pdbCollectionFilter = (type === 'collection') ? value : ''; // p1_1000 — filter grid ikut koleksi
 // reset status filter ke "Semua" supaya koleksi tunjuk SEMUA produk di dalamnya
 const stEl = document.getElementById('pdStatus'); if(stEl) stEl.value = '';
 const allPill = document.querySelector('#pdbStatusPills .pdb-pill[data-status=""]');
 if(allPill) document.querySelectorAll('#pdbStatusPills .pdb-pill').forEach(b => b.classList.toggle('pdb-pill--active', b === allPill));
 window.__pdbPage = 1; // mula dari muka surat pertama
 if(typeof window.renderProductDatabase === 'function') window.renderProductDatabase();
};

// p1_345 — tukar halaman produk + scroll ke atas
window.__pdbGoPage = function(target){
 window.__pdbPage = target;
 window.renderProductDatabase && window.renderProductDatabase();
 const top = document.getElementById('pdStats') || document.getElementById('databaseSection');
 if(top && top.scrollIntoView) try { top.scrollIntoView({ behavior:'smooth', block:'start' }); } catch(e){}
};
window.renderProductDatabase = function() {
 const gridEl = document.getElementById('pdGridView');
 const tableBody = document.getElementById('pdTableBody');
 if(!gridEl || typeof masterProducts === 'undefined') return;

 // Populate filter dropdowns lazily
 const brandSel = document.getElementById('pdBrand');
 const catSel = document.getElementById('pdCategory');
 if(brandSel && brandSel.options.length <= 1) {
 const brands = [...new Set(masterProducts.map(p => p.brand).filter(Boolean))].sort();
 brandSel.innerHTML = '<option value="">All brands</option>' + brands.map(b => `<option value="${b}">${b}</option>`).join('');
 }
 if(catSel && catSel.options.length <= 1) {
 const cats = [...new Set(masterProducts.map(p => p.category).filter(Boolean))].sort();
 catSel.innerHTML = '<option value="">All categories</option>' + cats.map(c => `<option value="${c}">${c}</option>`).join('');
 }

 // Read filters
 const q = (document.getElementById('pdSearch')?.value || '').trim().toLowerCase();
 const fBrand = document.getElementById('pdBrand')?.value || '';
 const fCat = document.getElementById('pdCategory')?.value || '';
 const fStatus = document.getElementById('pdStatus')?.value || '';
 const sort = document.getElementById('pdSort')?.value || 'name';
 const perPage = parseInt(document.getElementById('pdPerPage')?.value) || 48;

 // Stock map
 const stockMap = new Map();
 (typeof inventoryBatches !== 'undefined' ? inventoryBatches : []).forEach(b => {
 stockMap.set(b.sku, (stockMap.get(b.sku) || 0) + (b.qty_remaining || 0));
 });

 // p1_1123 — Dead Stock: set SKU yang ADA jualan dlm 90 hari (jualan sebenar shj), dikira sekali
 // & cache 5 minit (salesHistory besar; render dipanggil tiap taip carian). Definisi sama
 // Analytics > Inventory: ada stok tapi SKU tiada dlm set ini = dead.
 const soldSet = (fStatus === 'dead') ? (function(){
   const nowT = Date.now();
   const sh = (typeof salesHistory !== 'undefined' && Array.isArray(salesHistory)) ? salesHistory : [];
   const c = window.__pdbDeadCache;
   if(c && (nowT - c.at) < 300e3 && c.n === sh.length) return c.set;
   const d90 = nowT - 90*864e5;
   const set = new Set();
   sh.forEach(s => {
     if(!(typeof window.__isRealSale === 'function' ? window.__isRealSale(s) : true) || !s.created_at) return;
     if(new Date(s.created_at).getTime() < d90) return;
     let it = s.items; if(typeof it === 'string'){ try { it = JSON.parse(it); } catch(e){ it = []; } }
     if(Array.isArray(it)) it.forEach(l => { if(l && l.sku && (Number(l.qty != null ? l.qty : l.quantity) || 0) > 0) set.add(l.sku); });
   });
   window.__pdbDeadCache = { at: nowT, n: sh.length, set };
   return set;
 })() : null;

 // p1_1123 — Tier harga A/B/C: tercile automatik atas produk Live berharga (price > 0; 0 = harga
 // belum diisi, terkecuali dari semua tier). A = 1/3 termahal, B = tengah, C = 1/3 termurah.
 let tierCut = null;
 if(fStatus === 'tier_a' || fStatus === 'tier_b' || fStatus === 'tier_c'){
   const prices = masterProducts
     .filter(p => isPublished(p) && !(p.metadata && p.metadata.discontinued === true) && Number(p.price) > 0)
     .map(p => Number(p.price)).sort((a, b) => a - b);
   if(prices.length) tierCut = { lo: prices[Math.floor(prices.length/3)], hi: prices[Math.floor(prices.length*2/3)] };
 }

 // Filter
 let list = masterProducts.filter(p => {
 if(fBrand && p.brand !== fBrand) return false;
 if(fCat && p.category !== fCat) return false;
 if(window.__pdbCollectionFilter && (window.__collectionOf ? window.__collectionOf(p) : '') !== window.__pdbCollectionFilter) return false; // p1_1000

 const stock = stockMap.get(p.sku) || 0;
 const reorder = parseInt(p.reorder_point) || 5;
 const disc = !!(p.metadata && p.metadata.discontinued === true);
 if(fStatus === 'published' && !isPublished(p)) return false;
 if(fStatus === 'draft' && (isPublished(p) || disc)) return false;
 if(fStatus === 'oos' && (stock > 0 || disc)) return false;
 if(fStatus === 'low' && (stock === 0 || stock > reorder || disc)) return false;
 // Zack — stok di bawah 10 unit (had tetap 10, tak ikut reorder_point per-produk)
 if(fStatus === 'under10' && (stock === 0 || stock >= 10 || disc)) return false;
 // p1_1123 — dead stock: ada stok, bukan discontinued, 0 jualan sebenar 90 hari
 if(fStatus === 'dead' && (stock <= 0 || disc || (soldSet && soldSet.has(p.sku)))) return false;
 // p1_1123 — tier harga (produk tanpa harga / draf / discontinued terkecuali dari semua tier)
 if(fStatus === 'tier_a' || fStatus === 'tier_b' || fStatus === 'tier_c'){
   const v = Number(p.price) || 0;
   if(!tierCut || v <= 0 || disc || !isPublished(p)) return false;
   if(fStatus === 'tier_a' && v < tierCut.hi) return false;
   if(fStatus === 'tier_b' && (v < tierCut.lo || v >= tierCut.hi)) return false;
   if(fStatus === 'tier_c' && v >= tierCut.lo) return false;
 }
 if(fStatus === 'noimage') {
   const hasImg = (Array.isArray(p.images) && p.images[0]) || (typeof p.images === 'string' && p.images);
   if(hasImg) return false;
 }
 // p1_490 — filter Discontinued (stok habis, tak renew). Tag dlm metadata.discontinued.
 if(fStatus === 'discontinued' && !(p.metadata && p.metadata.discontinued === true)) return false;
 // p1_968 — produk belum dihantar ke TikTok (Cara B): tiada metadata.tiktok_product_id + bukan discontinued
 if(fStatus === 'not_tiktok' && ((p.metadata && p.metadata.tiktok_product_id) || (p.metadata && p.metadata.discontinued === true))) return false;
 if(q) {
 const hay = `${p.sku||''} ${p.name||''} ${p.brand||''} ${p.category||''} ${p.erp_barcode||''}`.toLowerCase();
 if(!hay.includes(q)) return false;
 }
 return true;
 });

 // Sort
 const sortFns = {
 'name': (a, b) => (a.name||'').localeCompare(b.name||''),
 'price-desc': (a, b) => (b.price||0) - (a.price||0),
 'price-asc': (a, b) => (a.price||0) - (b.price||0),
 'stock-desc': (a, b) => (stockMap.get(b.sku)||0) - (stockMap.get(a.sku)||0),
 'brand': (a, b) => (a.brand||'').localeCompare(b.brand||'') || (a.name||'').localeCompare(b.name||'')
 };
 list.sort(sortFns[sort] || sortFns.name);

 // Stats cards (whole catalog, not just filtered)
 // p1_612 — produk Discontinued (sengaja berhenti jual) TAK dikira dalam Draft/Low/OOS supaya angka tepat
 const isDisc = (p) => !!(p.metadata && p.metadata.discontinued === true);
 const hasImage = (p) => (Array.isArray(p.images) && !!p.images[0]) || (typeof p.images === 'string' && !!p.images);
 const totalProducts = masterProducts.length;
 const publishedCount = masterProducts.filter(p => isPublished(p)).length;
 const draftCount = masterProducts.filter(p => !isPublished(p) && !isDisc(p)).length;
 const lowStockCount = masterProducts.filter(p => {
   if(isDisc(p)) return false;
   const stk = stockMap.get(p.sku) || 0;
   const ro = parseInt(p.reorder_point) || 5;
   return stk > 0 && stk <= ro;
 }).length;
 const oosCount = masterProducts.filter(p => !isDisc(p) && (stockMap.get(p.sku) || 0) === 0).length;
 const noImageCount = masterProducts.filter(p => !hasImage(p)).length;

 // Update header sub counts
 const grandEl = document.getElementById('pdGrandCount'); if(grandEl) grandEl.textContent = totalProducts.toLocaleString();
 const liveEl = document.getElementById('pdbLiveCount'); if(liveEl) liveEl.textContent = publishedCount.toLocaleString();
 const draftEl = document.getElementById('pdbDraftCount'); if(draftEl) draftEl.textContent = draftCount.toLocaleString();

 // New stat cards (pdb-stat class)
 const statsEl = document.getElementById('pdStats');
 if(statsEl) {
 statsEl.innerHTML = `
 <div class="pdb-stat"><div class="pdb-stat__label">Total catalog</div><div class="pdb-stat__value">${totalProducts.toLocaleString()}</div><div class="pdb-stat__hint">${list.length.toLocaleString()} match filter</div></div>
 <div class="pdb-stat pdb-stat--success"><div class="pdb-stat__label">Live</div><div class="pdb-stat__value">${publishedCount.toLocaleString()}</div><div class="pdb-stat__hint">Visible in Cashier</div></div>
 <div class="pdb-stat pdb-stat--warning"><div class="pdb-stat__label">Draft</div><div class="pdb-stat__value">${draftCount.toLocaleString()}</div><div class="pdb-stat__hint">Awaiting review</div></div>
 <div class="pdb-stat pdb-stat--danger"><div class="pdb-stat__label">Low / OOS</div><div class="pdb-stat__value">${(lowStockCount + oosCount).toLocaleString()}</div><div class="pdb-stat__hint">${lowStockCount} low · ${oosCount} out</div></div>
 <div class="pdb-stat pdb-stat--info"><div class="pdb-stat__label">No Image</div><div class="pdb-stat__value">${noImageCount.toLocaleString()}</div><div class="pdb-stat__hint">Missing photo</div></div>
 `;
 }

 // Active filter chips
 const chipsEl = document.getElementById('pdbActiveChips');
 if(chipsEl) {
 const chips = [];
 if(q) chips.push({label: 'Search: "' + q + '"', clear: "document.getElementById('pdSearch').value=''; window.renderProductDatabase();"});
 if(fBrand) chips.push({label: 'Brand: ' + fBrand, clear: "document.getElementById('pdBrand').value=''; window.renderProductDatabase();"});
 if(fCat) chips.push({label: 'Category: ' + fCat, clear: "document.getElementById('pdCategory').value=''; window.renderProductDatabase();"});
 if(window.__pdbCollectionFilter) chips.push({label: 'Collection: ' + window.__pdbCollectionFilter, clear: "window.__pdbCollectionFilter=''; window.renderProductDatabase();"});
 if(fStatus) {
   // p1_1123 — label tier tunjuk julat RM sebenar (tercile dikira atas)
   const fmtT = (n) => 'RM ' + Number(n||0).toLocaleString('en-MY', {maximumFractionDigits:0});
   const map = { published:'Live', draft:'Draft', oos:'Out of Stock', low:'Low Stock', noimage:'No Image', discontinued:'Discontinued', not_tiktok:'Belum di TikTok', under10:'Stok < 10',
     dead:'Dead Stock (0 jualan 90 hari)',
     tier_a:'Tier A · Mahal' + (tierCut ? ` (≥ ${fmtT(tierCut.hi)})` : ''),
     tier_b:'Tier B · Sederhana' + (tierCut ? ` (${fmtT(tierCut.lo)} – ${fmtT(tierCut.hi)})` : ''),
     tier_c:'Tier C · Murah' + (tierCut ? ` (< ${fmtT(tierCut.lo)})` : '') };
   const allPill = "document.querySelectorAll('#pdbStatusPills .pdb-pill').forEach(b=>b.classList.remove('pdb-pill--active'));document.querySelector('#pdbStatusPills .pdb-pill[data-status=\\\"\\\"]').classList.add('pdb-pill--active');document.getElementById('pdStatus').value='';window.renderProductDatabase();";
   chips.push({label: 'Status: ' + (map[fStatus] || fStatus), clear: allPill});
 }
 if(chips.length > 0) {
   chipsEl.innerHTML =
     '<span class="pdb-active-chips__label">Filtering by:</span>' +
     chips.map(c => `<span class="pdb-active-chip">${c.label}<button onclick="${c.clear.replace(/"/g, '&quot;')}" aria-label="Remove">×</button></span>`).join('') +
     '<button class="pdb-active-clear" onclick="window.pdbClearFilters()">Clear all</button>';
   chipsEl.style.display = 'flex';
 } else {
   chipsEl.style.display = 'none';
 }
 }

 // Summary line
 // p1_301 — collapse variants: 1 card per parent_sku (lead product + group stock)
 const __pdbGroups = new Map();
 for(const gp of list) {
 const key = (gp.parent_sku && String(gp.parent_sku).trim()) ? ('p:' + gp.parent_sku) : ('s:' + gp.sku);
 if(!__pdbGroups.has(key)) __pdbGroups.set(key, []);
 __pdbGroups.get(key).push(gp);
 }
 const grouped = Array.from(__pdbGroups.values()).map(g => {
 const lead = g.find(x => x.sku === x.parent_sku) || g[0];
 const gstock = g.reduce((s, v) => s + (stockMap.get(v.sku) || 0), 0);
 return Object.assign({}, lead, {
 __vcount: g.length,
 __gstock: gstock,
 // p1_686 — senarai harga setiap variant (susun menaik) utk papar dalam kad
 __variants: g.map(v => ({ label: v.variant_color || v.variant_size || v.sku || '—', price: Number(v.price || 0) })).sort((a, b) => a.price - b.price),
 __cleanName: g.length > 1 ? (String(lead.name || '').split('—')[0].trim() || lead.name) : (lead.name || '')
 });
 });

 // p1_345 — pagination produk (Prev/Next) — sebelum ni slice(0,perPage) tunjuk page pertama je
 const __pdbSig = [q, fBrand, fCat, document.getElementById('pdStatus')?.value || '', perPage].join('|');
 if(window.__pdbLastSig !== __pdbSig) { window.__pdbPage = 1; window.__pdbLastSig = __pdbSig; }
 const __pdbTotalPages = Math.max(1, Math.ceil(grouped.length / perPage));
 if(!window.__pdbPage || window.__pdbPage < 1) window.__pdbPage = 1;
 if(window.__pdbPage > __pdbTotalPages) window.__pdbPage = __pdbTotalPages;
 const __pdbPage = window.__pdbPage;
 const __pdbStart = (__pdbPage - 1) * perPage;
 const slice = grouped.slice(__pdbStart, __pdbStart + perPage);

 const summaryEl = document.getElementById('pdSummary');
 if(summaryEl) {
 const fromN = grouped.length ? __pdbStart + 1 : 0;
 const toN = __pdbStart + slice.length;
 const bs = "padding:4px 10px; border:1px solid #E5E7EB; background:#fff; border-radius:6px; cursor:pointer; font-size:12px; font-weight:700; color:#374151;";
 const bd = "padding:4px 10px; border:1px solid #F3F4F6; background:#F9FAFB; border-radius:6px; font-size:12px; font-weight:700; color:#D1D5DB; cursor:not-allowed;";
 const pager = __pdbTotalPages > 1 ? `<span style="display:inline-flex; align-items:center; gap:6px; margin-left:10px;"><button ${__pdbPage <= 1 ? 'disabled style="'+bd+'"' : 'onclick="window.__pdbGoPage('+(__pdbPage-1)+')" style="'+bs+'"'}>‹ Prev</button><span style="font-weight:700;">Halaman ${__pdbPage} / ${__pdbTotalPages}</span><button ${__pdbPage >= __pdbTotalPages ? 'disabled style="'+bd+'"' : 'onclick="window.__pdbGoPage('+(__pdbPage+1)+')" style="'+bs+'"'}>Next ›</button></span>` : '';
 summaryEl.innerHTML = `Memaparkan <strong>${fromN}-${toN}</strong> dari <strong>${grouped.length.toLocaleString()}</strong> produk${pager}`;
 }

 if(slice.length === 0) {
 const empty = `<div class="empty-state" style="grid-column:1/-1;">
 <div class="empty-state__icon"></div>
 <div class="empty-state__title">Tiada produk match filter</div>
 <div class="empty-state__desc">Cuba clear filter atau tukar status ke "Semua".</div>
 <button class="btn btn--secondary" onclick="document.getElementById('pdSearch').value='';document.getElementById('pdBrand').value='';document.getElementById('pdCategory').value='';document.getElementById('pdStatus').value='';renderProductDatabase()">Reset Filter</button>
 </div>`;
 gridEl.innerHTML = empty;
 if(tableBody) tableBody.innerHTML = `<tr><td colspan="8">${empty}</td></tr>`;
 return;
 }

 // Render Grid
 if(__pdView === 'grid') {
 gridEl.innerHTML = slice.map(p => {
 const isGrp = p.__vcount > 1;
 const stock = isGrp ? p.__gstock : (stockMap.get(p.sku) || 0);
 const reorder = p.reorder_point || 5;
 const stockClass = stock === 0 ? 'out' : (stock < reorder ? 'low' : '');
 const stockLabel = stock === 0 ? 'OOS' : `${stock} ${p.unit || 'pcs'}`;
 const img = (window.__coverOf && window.__coverOf(p)) || (p.images && p.images[0]) || ''; // p1_765 — guna cover produk
 const pub = isPublished(p);
 const statusBadge = pub
 ? '<span class="badge badge--success pd-card__status-badge">Live</span>'
 : '<span class="badge badge--warning pd-card__status-badge">Draft</span>';
 const cost = p.cost_price ? Number(p.cost_price).toFixed(2) : null;
 // p1_263 — Marketplace integration indicators (Shopee / TikTok). Read dari metadata JSONB.
 const meta = (p.metadata && typeof p.metadata === 'object') ? p.metadata : {};
 // p1_533 — integrated = ada ID mapping SAHAJA (bukan timestamp sync lama). Bila staff
 // padam Product ID/Item ID (disconnect), tag jadi grey betul (dulu synced_at lama buat ia kekal hidup).
 const shopeeIntegrated = !!meta.shopee_item_id;
 const tiktokIntegrated = !!meta.tiktok_product_id;
 const integrationBadges = `
 <div class="pd-card__integrations" style="position:absolute; top:6px; left:6px; display:flex; gap:3px; z-index:2;">
 <span title="${shopeeIntegrated ? ('Tersambung Shopee · Item ' + (meta.shopee_item_id || '?') + (p.shopee_price != null ? ' · RM ' + Number(p.shopee_price).toFixed(2) : '') + ' · klik untuk detail') : 'BELUM di Shopee — harga/stok tak sync'}" style="background:${shopeeIntegrated ? '#EE4D2D' : '#E5E7EB'}; color:${shopeeIntegrated ? '#fff' : '#9CA3AF'}; padding:2px 5px; border-radius:3px; font-size:9px; font-weight:800; letter-spacing:0.3px; line-height:1; display:inline-flex; align-items:center; gap:2px;"><i data-lucide="${shopeeIntegrated ? 'check' : 'x'}" style="width:8px;height:8px;"></i> SP</span>
 <span title="${tiktokIntegrated ? 'Synced dengan TikTok Shop · click product untuk lihat detail' : 'BELUM disync dengan TikTok Shop'}" style="background:${tiktokIntegrated ? '#000' : '#E5E7EB'}; color:${tiktokIntegrated ? '#fff' : '#9CA3AF'}; padding:2px 5px; border-radius:3px; font-size:9px; font-weight:800; letter-spacing:0.3px; line-height:1; display:inline-flex; align-items:center; gap:2px;"><i data-lucide="${tiktokIntegrated ? 'check' : 'x'}" style="width:8px;height:8px;"></i> TT</span>
 </div>`;
 return `
 <div class="pd-card" onclick="window.openPdpModal('${p.sku.replace(/'/g, "\\'")}')" tabindex="0" role="button" aria-label="Edit ${p.sku}">
 ${statusBadge}
 ${integrationBadges}
 <span class="pd-card__stock-pill ${stockClass}">${stockLabel}</span>
 <div class="pd-card__image-wrap">
 ${img
 ? `<img class="pd-card__image" src="${window.__thumbUrl(img, 320)}" data-full="${String(img).replace(/"/g,'&quot;')}" alt="${(p.name||'').replace(/"/g,'&quot;')}" loading="lazy" onerror="window.__imgThumbErr(this, '${String(img).replace(/'/g, "\\'")}')"><button type="button" class="zoom-hotspot" aria-label="Zoom image" title="Zoom image" onclick="event.stopPropagation(); window.__imgZoom(this.previousElementSibling.getAttribute('data-full')||this.previousElementSibling.src, this.previousElementSibling.alt);"><svg xmlns="http://www.w3.org/2000/svg" width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round"><circle cx="11" cy="11" r="8"/><line x1="21" x2="16.65" y1="21" y2="16.65"/><line x1="11" x2="11" y1="8" y2="14"/><line x1="8" x2="14" y1="11" y2="11"/></svg></button>`
 : `<span class="pd-card__image-placeholder"></span>`}
 </div>
 <div class="pd-card__body">
 <span class="pd-card__brand">${hesc(p.brand || p.category || '·')}</span>
 <span class="pd-card__title">${hesc((window.__productNameOf(p) || '').slice(0, 90))}${isGrp ? ` <span style="background:#101010; color:#fff; padding:1px 6px; border-radius:4px; font-size:9px; font-weight:800; white-space:nowrap;">${p.__vcount} variants</span>` : ''}</span>
 <span class="pd-card__sku">${hesc(isGrp ? (p.parent_sku || p.sku) : p.sku)}${(!isGrp && p.location_bin) ? ` · <span style="background:#F8EFD7; color:#7A5410; padding:1px 6px; border-radius:3px; font-size:9.5px; font-weight:700; font-family:'SF Mono',Menlo,monospace; letter-spacing:0.3px;">${hesc(p.location_bin)}</span>` : ''}</span>
 ${isGrp
 ? `<div class="pd-card__varprices" style="width:100%; font-size:${p.__vcount >= 12 ? 8 : (p.__vcount >= 8 ? 9 : (p.__vcount >= 5 ? 10.5 : 12))}px; max-height:150px; overflow-y:auto; margin-top:3px;">${p.__variants.map(v => `<div style="display:flex; justify-content:space-between; gap:8px; line-height:1.5;"><span style="color:#6B7280; overflow:hidden; text-overflow:ellipsis; white-space:nowrap;">${hesc(v.label)}</span><span style="font-weight:800; color:#101010; flex-shrink:0;">RM ${v.price.toFixed(2)}</span></div>`).join('')}</div>`
 : `<span class="pd-card__price">RM ${(p.price || 0).toFixed(2)}${window.__marginTagHtml ? window.__marginTagHtml(p.price, p.cost_price) : ''}</span>`}
 </div>
 <div class="pd-card__footer">
 <span>${hesc(p.category || '—')}</span>
 <span style="display:inline-flex; gap:6px; align-items:center;">
 <button onclick="event.stopPropagation(); window.shareProductWA('${p.sku.replace(/'/g, "\\'")}')" aria-label="Share to WhatsApp" title="Share ke WhatsApp" style="background:none; border:none; cursor:pointer; padding:2px 4px; color:#25D366;"><i data-lucide="message-circle" style="width:14px; height:14px;"></i></button>
 <button onclick="event.stopPropagation(); window.shareProduct('${p.sku.replace(/'/g, "\\'")}')" aria-label="Share public-safe description" title="Share (copy / native)" style="background:none; border:none; cursor:pointer; padding:2px 4px; color:var(--neutral-700);"><i data-lucide="share-2" style="width:13px; height:13px;"></i></button>
 <button onclick="event.stopPropagation(); window.openPdpModal('${p.sku.replace(/'/g, "\\'")}')" aria-label="Edit details">Edit ›</button>
 </span>
 </div>
 </div>
 `;
 }).join('');
 } else if(tableBody) {
 // Render Table
 tableBody.innerHTML = slice.map(p => {
 const isGrp = p.__vcount > 1;
 const stock = isGrp ? p.__gstock : (stockMap.get(p.sku) || 0);
 const reorder = p.reorder_point || 5;
 const stockColor = stock === 0 ? 'var(--danger-600)' : (stock < reorder ? 'var(--warning-600)' : 'var(--neutral-700)');
 const img = (window.__coverOf && window.__coverOf(p)) || (p.images && p.images[0]) || ''; // p1_765 — guna cover produk
 const pub = isPublished(p);
 return `
 <tr onclick="window.openPdpModal('${p.sku.replace(/'/g, "\\'")}')" tabindex="0" role="button">
 <td>${img ? `<img src="${window.__thumbUrl ? window.__thumbUrl(img, 100) : img}" class="pd-row-img" loading="lazy" decoding="async" alt="">` : '<div class="pd-row-img" style="display:flex;align-items:center;justify-content:center;color:var(--neutral-400);"></div>'}</td>
 <td><span class="pd-row-name">${hesc((window.__productNameOf(p)||'').slice(0, 70))}${isGrp ? ` <span style="background:#101010; color:#fff; padding:1px 5px; border-radius:3px; font-size:9px; font-weight:800;">${p.__vcount} variants</span>` : ''}</span><span class="pd-row-meta">${hesc(isGrp ? (p.parent_sku||p.sku) : p.sku)}${(!isGrp && p.erp_barcode) ? ' · '+hesc(p.erp_barcode) : ''}</span></td>
 <td>${p.brand || '—'}</td>
 <td>${p.category || '—'}</td>
 <td>${p.location_bin ? `<span style="background:#F8EFD7; color:#7A5410; padding:2px 7px; border-radius:4px; font-size:10.5px; font-weight:700; font-family:'SF Mono',Menlo,monospace; letter-spacing:0.3px;">${p.location_bin}</span>` : '<span style="color:#D1D5DB; font-size:11px;">—</span>'}</td>
 <td style="text-align:right;" class="pd-row-price">RM ${(p.price||0).toFixed(2)}</td>
 <td style="text-align:right; color:${stockColor}; font-weight:var(--weight-bold);">${stock}</td>
 <td style="text-align:center;">${pub ? '<span class="badge badge--success">Live</span>' : '<span class="badge badge--warning">Draft</span>'}</td>
 <td>
 <button class="btn btn--ghost btn--sm" onclick="event.stopPropagation(); window.openPdpModal('${p.sku.replace(/'/g, "\\'")}')">Edit</button>
 <button class="btn btn--ghost btn--sm" style="padding:4px 8px; margin-left:4px; color:#25D366;" onclick="event.stopPropagation(); window.shareProductWA('${p.sku.replace(/'/g, "\\'")}')" title="Share ke WhatsApp"><i data-lucide="message-circle" style="width:13px; height:13px;"></i></button>
 <button class="btn btn--ghost btn--sm" style="padding:4px 8px; margin-left:4px;" onclick="event.stopPropagation(); window.shareProduct('${p.sku.replace(/'/g, "\\'")}')" title="Share (copy / native)"><i data-lucide="share-2" style="width:13px; height:13px;"></i></button>
 ${(p.metadata && p.metadata.tiktok_product_id)
   ? `<a class="btn btn--ghost btn--sm" style="padding:4px 8px; margin-left:4px; color:#101010;" href="https://seller-my.tiktok.com/product/edit/${p.metadata.tiktok_product_id}?shop_region=MY" target="_blank" rel="noopener" onclick="event.stopPropagation();" title="Buka di TikTok Seller Centre"><i data-lucide="external-link" style="width:13px; height:13px;"></i></a>`
   : `<button class="btn btn--ghost btn--sm" style="padding:4px 8px; margin-left:4px; color:#101010;" onclick="event.stopPropagation(); window.__tiktokPushFromList('${(p.parent_sku||p.sku).replace(/'/g, "\\'")}')" title="Hantar ke TikTok (draf)"><i data-lucide="send" style="width:13px; height:13px;"></i></button>`}
 </td>
 </tr>
 `;
 }).join('');
 }

 if(typeof lucide !== 'undefined' && lucide.createIcons) lucide.createIcons();
};

// Initial render when section opens — wire to nav click
document.addEventListener('DOMContentLoaded', () => {
 const dbBtn = document.querySelector('[data-tab="inv_database"]');
 if(dbBtn) dbBtn.addEventListener('click', () => setTimeout(renderProductDatabase, 100));
});

// =============================================================
// Compliance section — open with category filter (3 sidebar entries)
// =============================================================
window.openComplianceFiltered = function(category, defaultTab, title) {
 // Show the section
 if(typeof switchHub === 'function') switchHub(['complianceSection'], title || 'Compliance', null);
 if(typeof renderCompliancePanel === 'function') renderCompliancePanel();

 // Filter visible tabs to the category
 document.querySelectorAll('#complTabBar.compl-tab').forEach(t => {
 const cat = t.getAttribute('data-category');
 const matches = !category || cat === category;
 t.style.display = matches ? '' : 'none';
 });

 // Switch to default tab (must be in visible category)
 if(defaultTab && typeof window.__switchComplTab === 'function') {
 setTimeout(() => window.__switchComplTab(defaultTab), 50);
 }

 // Update breadcrumb if the function exists
 if(typeof updateBreadcrumb === 'function') updateBreadcrumb(title);
};

// Reset filter (show all tabs)
window.openComplianceAll = function() {
 document.querySelectorAll('#complTabBar.compl-tab').forEach(t => { t.style.display = ''; });
 if(typeof switchHub === 'function') switchHub(['complianceSection'], 'Compliance & Settings', null);
 if(typeof renderCompliancePanel === 'function') renderCompliancePanel();
};

// =============================================================
// B2B / Wholesale Customers (p1_17)
// =============================================================
window.renderB2BCustomers = function() {
 const tbody = document.getElementById('b2bTbody');
 const statsEl = document.getElementById('b2bStats');
 if(!tbody) return;
 if(typeof customersData === 'undefined' || !Array.isArray(customersData)) {
 tbody.innerHTML = '<tr><td colspan="8" style="text-align:center; color:#999;">Loading...</td></tr>';
 return;
 }

 const all = customersData.filter(c => c.is_b2b === true);
 const q = (document.getElementById('b2bSearch')?.value || '').trim().toLowerCase();
 const status = document.getElementById('b2bStatus')?.value || 'all';
 const sortMode = document.getElementById('b2bSort')?.value || 'spent_desc';

 // p1_139 — build actual orders count from salesHistory as fallback when denormalized counter unreliable
 const b2bOrderCounts = {};
 if(typeof salesHistory !== 'undefined' && Array.isArray(salesHistory)) {
 salesHistory.forEach(s => {
 const phone = (s.customer_phone || '').trim();
 const name = (s.customer_name || '').trim();
 if(phone) b2bOrderCounts[phone] = (b2bOrderCounts[phone] || 0) + 1;
 if(name) b2bOrderCounts[name.toLowerCase()] = (b2bOrderCounts[name.toLowerCase()] || 0) + 1;
 });
 }
 const realOrders = (c) => {
 const denorm = Number(c.total_orders || 0);
 if(denorm > 0) return denorm;
 const phoneMatch = (c.pic_phone || c.phone || '').trim();
 const nameMatch = (c.company_name || c.name || '').trim().toLowerCase();
 return (b2bOrderCounts[phoneMatch] || 0) + (b2bOrderCounts[nameMatch] || 0);
 };

 let filtered = all.filter(c => {
 if(q) {
 const hay = `${c.company_name||''} ${c.name||''} ${c.phone||''} ${c.pic_phone||''} ${c.buyer_tin||''}`.toLowerCase();
 if(!hay.includes(q)) return false;
 }
 // p1_139 — use realOrders() to handle denormalized total_orders drift
 if(status === 'active' && realOrders(c) === 0) return false;
 if(status === 'inactive' && realOrders(c) > 0) return false;
 return true;
 });

 filtered.sort((a, b) => {
 switch(sortMode) {
 case 'spent_desc': return (b.total_spent||0) - (a.total_spent||0);
 case 'orders_desc': return (b.total_orders||0) - (a.total_orders||0);
 case 'recent': return (b.created_at||'').localeCompare(a.created_at||'');
 case 'name': return (a.company_name||a.name||'').localeCompare(b.company_name||b.name||'');
 }
 return 0;
 });

 if(statsEl) {
 const totalSpent = filtered.reduce((s, c) => s + (c.total_spent||0), 0);
 // p1_139 — was misleadingly labelled "Credit Exposure" but only sums credit LIMITS, not outstanding balance.
 // Relabel to accurate name. Real exposure tracking pending invoice/AR table integration.
 const totalCreditLimit = filtered.reduce((s, c) => s + (parseFloat(c.credit_limit)||0), 0);
 const activeCount = filtered.filter(c => realOrders(c) > 0).length;
 statsEl.innerHTML = `
 <div style="background:var(--primary-50,#FFF8F0); padding:10px; border-radius:6px;"><div style="font-size:10px; color:var(--primary-800,#7C4A1A);">B2B Total</div><div style="font-size:18px; font-weight:bold;">${filtered.length}</div></div>
 <div style="background:#EEF3EC; padding:10px; border-radius:6px;"><div style="font-size:10px; color:#34522F;">Active (≥1 order)</div><div style="font-size:18px; font-weight:bold;">${activeCount}</div></div>
 <div style="background:#F8EFD7; padding:10px; border-radius:6px;"><div style="font-size:10px; color:#7A5410;">Total Spent</div><div style="font-size:18px; font-weight:bold;">RM ${totalSpent.toLocaleString(undefined,{minimumFractionDigits:2,maximumFractionDigits:2})}</div></div>
 <div style="background:var(--primary-50,#FFF8F0); padding:10px; border-radius:6px;"><div style="font-size:10px; color:var(--primary-800,#7C4A1A);">Total Credit Limits</div><div style="font-size:18px; font-weight:bold;">RM ${totalCreditLimit.toLocaleString(undefined,{minimumFractionDigits:2,maximumFractionDigits:2})}</div></div>
 `;
 }

 if(filtered.length === 0) {
 // p1_141 — better empty state with Lucide icon + bigger padding
 tbody.innerHTML = '<tr><td colspan="8" style="text-align:center; color:#9CA3AF; padding:36px 20px;"><div style="margin-bottom:8px;"><i data-lucide="briefcase" style="width:32px; height:32px; color:#D1D5DB;"></i></div><div style="font-size:13px; color:#6B7280;">Tiada B2B customer padan filter.</div><div style="font-size:11px; color:#9CA3AF; margin-top:4px;">Cuba clear filter atau klik <strong>+ Tambah B2B</strong> untuk register wholesale account baharu.</div></td></tr>';
 if(window.lucide && lucide.createIcons) lucide.createIcons();
 return;
 }

 tbody.innerHTML = filtered.map(c => {
 const company = (c.company_name || c.name || '(no name)').slice(0, 50);
 const pic = c.name && c.company_name ? c.name : '-';
 const tin = c.buyer_tin || '-';
 const terms = c.payment_terms || '-';
 const cl = c.credit_limit ? `RM ${parseFloat(c.credit_limit).toFixed(2)}` : '-';
 // p1_139 — display Total Spent: use realOrders to show actual count, threshold uses CSS var
 const spentNum = Number(c.total_spent || 0);
 const orders = realOrders(c);
 const escAttr = (s) => String(s == null ? '' : s).replace(/"/g,'&quot;').replace(/'/g, '&#39;');
 // p1_140 — clicking company/PIC opens detail modal (last orders + returns)
 return `
 <tr style="cursor:pointer;">
 <td onclick="window.openB2BDetail('${escAttr(c.id)}')"><strong>${company}</strong>${c.pic_phone?`<br><span style="color:#999;font-size:10px;">${c.pic_phone}</span>`:''}</td>
 <td onclick="window.openB2BDetail('${escAttr(c.id)}')">${pic}</td>
 <td onclick="window.openB2BDetail('${escAttr(c.id)}')" style="font-family:monospace; font-size:11px;">${tin}</td>
 <td onclick="window.openB2BDetail('${escAttr(c.id)}')">${terms}</td>
 <td onclick="window.openB2BDetail('${escAttr(c.id)}')" style="text-align:right;">${cl}</td>
 <td onclick="window.openB2BDetail('${escAttr(c.id)}')" style="text-align:right; font-weight:bold; color:${spentNum > 1000 ? 'var(--success)' : 'var(--text-main)'};">RM ${spentNum.toFixed(2)}</td>
 <td onclick="window.openB2BDetail('${escAttr(c.id)}')" style="text-align:right;">${orders}</td>
 <td>
 <button class="btn btn--secondary btn--sm" onclick="event.stopPropagation(); window.openB2BPriceList('${escAttr(c.id)}')" title="Set harga rundingan per produk">Harga</button>
        <button class="btn btn--secondary btn--sm" onclick="event.stopPropagation(); window.openB2BEditModal('${escAttr(c.id)}')">Edit</button>
 <!-- p1_139 — Delete action added (was missing; staff had to use Supabase directly) -->
 <button class="btn btn--secondary btn--sm" style="color:#7C2A20;" onclick="event.stopPropagation(); window.deleteB2BCustomer('${escAttr(c.id)}', '${escAttr(company)}')" title="Padam B2B"><i data-lucide="trash-2" style="width:11px; height:11px;"></i></button>
 </td>
 </tr>
 `;
 }).join('');
 if(window.lucide && lucide.createIcons) lucide.createIcons();
};

// p1_140 — B2B detail modal: KPI + last orders + returns log (was missing — no drill-down before)
window.openB2BDetail = async function(id) {
 if(typeof customersData === 'undefined' || !Array.isArray(customersData)) return;
 const c = customersData.find(x => String(x.id) === String(id));
 if(!c) { if(typeof showToast === 'function') showToast('B2B tak dijumpai', 'warn'); return; }
 const company = c.company_name || c.name || '(no name)';
 const pic = c.name && c.company_name ? c.name : '';
 const phone = c.pic_phone || c.phone || '';
 const email = c.pic_email || c.email || '';
 const escHtml = (s) => String(s == null ? '' : s).replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;');

 // Sales matching by phone OR name (limit 10)
 const sales = (typeof salesHistory !== 'undefined' && Array.isArray(salesHistory))
 ? salesHistory.filter(s => (phone && s.customer_phone === phone) || (s.customer_name && s.customer_name.toLowerCase() === (c.company_name||c.name||'').toLowerCase())).slice(0, 10)
 : [];
 const realOrderCount = sales.length;
 const realSpent = sales.reduce((s, o) => s + Number(o.total || o.amount || 0), 0);

 // Channel mix
 const channelMix = {};
 sales.forEach(s => { const ch = s.channel || 'POS Cashier'; channelMix[ch] = (channelMix[ch] || 0) + 1; });
 const topChannel = Object.entries(channelMix).sort((a,b) => b[1]-a[1])[0];

 const salesRows = sales.length
 ? sales.map(s => `<tr><td>${s.created_at ? new Date(s.created_at).toLocaleDateString('en-MY') : (s.timestamp ? new Date(s.timestamp).toLocaleDateString('en-MY') : '-')}</td><td>${escHtml(s.channel || '-')}</td><td style="text-align:right;">RM ${Number(s.total || s.amount || 0).toFixed(2)}</td></tr>`).join('')
 : '<tr><td colspan="3" style="text-align:center; color:#999; padding:8px;">Tiada pembelian / No purchases yet</td></tr>';

 // Modal skeleton first (returns fetched async)
 const html = `
 <div id="b2bDetailModal" style="position:fixed; inset:0; background:rgba(0,0,0,0.55); z-index:3700; display:flex; align-items:center; justify-content:center; padding:20px;" onclick="if(event.target===this) this.remove();">
 <div style="background:#fff; max-width:640px; width:100%; border-radius:12px; padding:24px; max-height:90vh; overflow-y:auto;">
 <div style="display:flex; justify-content:space-between; align-items:start; margin-bottom:12px;">
 <div>
 <h2 style="margin:0; font-size:20px;">${escHtml(company)}</h2>
 <div style="font-size:12px; color:#666; margin-top:2px;">${escHtml(pic || '(no PIC)')} · ${escHtml(phone || '-')}${email ? ' · ' + escHtml(email) : ''}</div>
 ${c.buyer_tin ? `<div style="font-size:11px; color:#666; margin-top:4px; font-family:monospace;">TIN: ${escHtml(c.buyer_tin)}</div>` : ''}
 </div>
 <button onclick="document.getElementById('b2bDetailModal').remove()" style="background:none; border:none; font-size:22px; cursor:pointer; color:#999;">×</button>
 </div>
 <!-- KPI 4-grid: Spent / Orders / Credit Limit / Top Channel -->
 <div style="display:grid; grid-template-columns:repeat(4, 1fr); gap:8px; margin-bottom:14px;">
 <div style="background:#EEF3EC; padding:10px; border-radius:6px;"><div style="font-size:10px; color:#34522F;">Belanja (real)</div><div style="font-size:16px; font-weight:bold;">RM ${realSpent.toFixed(2)}</div></div>
 <div style="background:#F8EFD7; padding:10px; border-radius:6px;"><div style="font-size:10px; color:#7A5410;">Pesanan (real)</div><div style="font-size:16px; font-weight:bold;">${realOrderCount}</div></div>
 <div style="background:var(--primary-50,#FFF8F0); padding:10px; border-radius:6px;"><div style="font-size:10px; color:var(--primary-800,#7C4A1A);">Credit Limit</div><div style="font-size:14px; font-weight:bold;">${c.credit_limit ? 'RM ' + parseFloat(c.credit_limit).toFixed(2) : '-'}</div></div>
 <div style="background:var(--primary-50,#FFF8F0); padding:10px; border-radius:6px;"><div style="font-size:10px; color:var(--primary-800,#7C4A1A);">Top Channel</div><div style="font-size:13px; font-weight:bold;">${topChannel ? escHtml(topChannel[0]) + ' (' + topChannel[1] + ')' : '-'}</div></div>
 </div>
 <h3 style="font-size:13px; margin:6px 0; color:#111;">10 Pembelian Terakhir</h3>
 <table style="width:100%; font-size:12px; border-collapse:collapse;"><thead><tr style="background:var(--card-bg);"><th style="text-align:left; padding:6px;">Tarikh</th><th style="text-align:left; padding:6px;">Channel</th><th style="text-align:right; padding:6px;">Jumlah</th></tr></thead><tbody>${salesRows}</tbody></table>
 <h3 style="font-size:13px; margin:14px 0 6px; color:#111;">Returns / Damage Log</h3>
 <div id="b2bDetailReturns" style="font-size:12px;">
 <p style="color:#9CA3AF; padding:8px;">Memuatkan returns…</p>
 </div>
 </div>
 </div>`;
 const tmp = document.createElement('div');
 tmp.innerHTML = html;
 document.body.appendChild(tmp.firstChild);

 // Async fetch returns_log for this customer (match by company name in notes/order_ref)
 try {
 if(typeof db !== 'undefined' && db) {
 const { data } = await db.from('returns_log').select('reported_at,sku,qty,type,reason,cost_impact').or(`notes.ilike.%${(company||'').replace(/[,()'"\\]/g,' ')}%,order_ref.ilike.%${(company||'').replace(/[,()'"\\]/g,' ')}%`).order('reported_at', { ascending: false }).limit(5);
 const wrap = document.getElementById('b2bDetailReturns');
 if(!wrap) return;
 const rows = data || [];
 if(rows.length === 0) {
 wrap.innerHTML = '<p style="color:#101010; padding:8px; font-size:11px;">Tiada returns / damage berkaitan B2B ni.</p>';
 } else {
 wrap.innerHTML = `<table style="width:100%; font-size:11px; border-collapse:collapse;"><thead><tr style="background:var(--card-bg);"><th style="text-align:left; padding:5px;">Tarikh</th><th style="text-align:left; padding:5px;">SKU</th><th style="text-align:left; padding:5px;">Type</th><th style="text-align:right; padding:5px;">Qty</th><th style="text-align:right; padding:5px;">Loss RM</th></tr></thead><tbody>` +
 rows.map(r => `<tr><td style="padding:4px;">${r.reported_at ? new Date(r.reported_at).toLocaleDateString('en-MY') : '-'}</td><td style="padding:4px; font-family:monospace;">${escHtml(r.sku||'-')}</td><td style="padding:4px;">${escHtml(r.type||'-')}</td><td style="padding:4px; text-align:right;">${r.qty||0}</td><td style="padding:4px; text-align:right; color:#7C2A20;">RM ${Number(r.cost_impact||0).toFixed(2)}</td></tr>`).join('') +
 `</tbody></table>`;
 }
 }
 } catch(e) {
 const wrap = document.getElementById('b2bDetailReturns');
 if(wrap) wrap.innerHTML = '<p style="color:#9CA3AF; padding:8px; font-size:11px;">Returns log tak available.</p>';
 }
};

// p1_141 — CSV export untuk B2B list (UTF-8 BOM untuk Excel kenal Malay text)
window.exportB2BCSV = function() {
 if(typeof customersData === 'undefined' || !Array.isArray(customersData)) return;
 const b2b = customersData.filter(c => c.is_b2b === true);
 // Apply current filters
 const q = (document.getElementById('b2bSearch')?.value || '').trim().toLowerCase();
 const status = document.getElementById('b2bStatus')?.value || 'all';
 const list = b2b.filter(c => {
 if(q) {
 const hay = `${c.company_name||''} ${c.name||''} ${c.phone||''} ${c.pic_phone||''} ${c.buyer_tin||''}`.toLowerCase();
 if(!hay.includes(q)) return false;
 }
 const orders = Number(c.total_orders || 0);
 if(status === 'active' && orders === 0) return false;
 if(status === 'inactive' && orders > 0) return false;
 return true;
 });
 const headers = ['Company','PIC Name','PIC Phone','PIC Email','Buyer TIN','Payment Terms','Credit Limit','Total Spent','Total Orders','Address','Notes'];
 const csvEscape = v => { const s = String(v == null ? '' : v); return /[",\n\r]/.test(s) ? '"'+s.replace(/"/g,'""')+'"' : s; };
 const rows = [headers].concat(list.map(c => [
 c.company_name || c.name || '',
 c.company_name && c.name ? c.name : '',
 c.pic_phone || c.phone || '',
 c.pic_email || c.email || '',
 c.buyer_tin || '',
 c.payment_terms || '',
 c.credit_limit || '',
 (c.total_spent || 0).toFixed(2),
 c.total_orders || 0,
 c.address || '',
 c.b2b_notes || ''
 ]));
 const csv = '﻿' + rows.map(r => r.map(csvEscape).join(',')).join('\r\n');
 const blob = new Blob([csv], {type:'text/csv;charset=utf-8'});
 const url = URL.createObjectURL(blob);
 const a = document.createElement('a');
 a.href = url;
 a.download = 'b2b-customers-' + new Date().toISOString().slice(0,10) + '.csv';
 a.click();
 URL.revokeObjectURL(url);
 if(typeof showToast === 'function') showToast(`Exported ${list.length} B2B rows.`, 'success');
};

// p1_139 — Delete B2B handler (was missing entirely)
window.deleteB2BCustomer = async function(id, name) {
 if(!confirm(`Padam B2B customer "${name}"? Tindakan ini tak boleh undo.`)) return;
 try {
 if(typeof db === 'undefined' || !db) throw new Error('DB tak available');
 const { error } = await db.from('customers').delete().eq('id', id);
 if(error) throw error;
 // Remove from in-memory array
 if(Array.isArray(window.customersData)) {
 window.customersData = window.customersData.filter(c => String(c.id) !== String(id));
 }
 if(typeof showToast === 'function') showToast(`B2B "${name}" padam.`, 'success');
 window.renderB2BCustomers();
 } catch(e) {
 console.error(e);
 if(typeof showToast === 'function') showToast('Padam gagal: ' + e.message, 'error');
 }
};

window.openB2BAddModal = function() {
 document.getElementById('b2bModalTitle').textContent = 'B2B Customer Baru';
 document.getElementById('b2bEditId').value = '';
 ['b2bCompany','b2bPicName','b2bPicPhone','b2bPicEmail','b2bTin','b2bCreditLimit','b2bAddress','b2bNotes'].forEach(id => {
 const el = document.getElementById(id); if(el) el.value = '';
 });
 document.getElementById('b2bPaymentTerms').value = '';
 document.getElementById('b2bModal').style.display = 'flex';
};

window.openB2BEditModal = function(id) {
 const c = (customersData || []).find(x => String(x.id) === String(id));
 if(!c) { if(typeof showToast==='function') showToast('Customer tak jumpa', 'error'); return; }
 document.getElementById('b2bModalTitle').textContent = 'Edit B2B Customer';
 document.getElementById('b2bEditId').value = c.id;
 document.getElementById('b2bCompany').value = c.company_name || c.name || '';
 document.getElementById('b2bPicName').value = c.company_name ? (c.name || '') : '';
 document.getElementById('b2bPicPhone').value = c.pic_phone || c.phone || '';
 document.getElementById('b2bPicEmail').value = c.pic_email || c.email || '';
 document.getElementById('b2bTin').value = c.buyer_tin || '';
 document.getElementById('b2bPaymentTerms').value= c.payment_terms || '';
 document.getElementById('b2bCreditLimit').value = c.credit_limit || '';
 document.getElementById('b2bAddress').value = c.address || '';
 document.getElementById('b2bNotes').value = c.b2b_notes || '';
 document.getElementById('b2bModal').style.display = 'flex';
};

window.saveB2BCustomer = async function() {
 const company = (document.getElementById('b2bCompany').value || '').trim();
 if(!company) { if(typeof showToast==='function') showToast('Company name wajib diisi', 'error'); return; }

 const pic = (document.getElementById('b2bPicName').value || '').trim();
 const phone = (document.getElementById('b2bPicPhone').value || '').trim();
 const email = (document.getElementById('b2bPicEmail').value || '').trim();
 const tin = (document.getElementById('b2bTin').value || '').trim();
 const terms = document.getElementById('b2bPaymentTerms').value || null;
 const cl = parseFloat(document.getElementById('b2bCreditLimit').value) || null;
 const addr = (document.getElementById('b2bAddress').value || '').trim();
 const notes = (document.getElementById('b2bNotes').value || '').trim();
 const editId = document.getElementById('b2bEditId').value;

 const payload = {
 is_b2b: true,
 company_name: company,
 name: pic || company,
 phone: phone || null,
 email: email || null,
 pic_phone: phone || null,
 pic_email: email || null,
 buyer_tin: tin || null,
 payment_terms: terms,
 credit_limit: cl,
 address: addr || null,
 b2b_notes: notes || null
 };

 try {
 if(editId) {
 const { error } = await db.from('customers').update(payload).eq('id', editId);
 if(error) throw error;
 if(typeof showToast==='function') showToast('B2B customer updated ', 'success');
 } else {
 const { data, error } = await db.from('customers').insert([payload]).select();
 if(error) throw error;
 if(data && data[0] && Array.isArray(customersData)) customersData.push(data[0]);
 if(typeof showToast==='function') showToast('B2B customer saved ', 'success');
 }
 // Reload list (p1_330 — muat semua, elak had 1000)
 let fresh = [];
 try { fresh = await window.__fetchAllRows('customers'); }
 catch(e) { try { const r = await db.from('customers').select('*'); fresh = r.data || []; } catch(_){} }
 if(fresh && fresh.length) window.customersData = fresh;
 document.getElementById('b2bModal').style.display = 'none';
 window.renderB2BCustomers();
 } catch(e) {
 console.error(e);
 if(typeof showToast==='function') showToast('Save failed: ' + (e.message||'').slice(0,80), 'error');
 }
};

// =============================================================
// 2026-06-25 — B2B per-company price list management (JS-injected modal, no index.html edit)
// =============================================================
// 2026-06-25 — papar ringkasan B2B dalam checkout panel (TIN prefill + terma + jimat)
window.__cpApplyB2B = function(pc) {
 const isB2B = !!(pc && pc.is_b2b);
 if(isB2B && pc.buyer_tin) { const t = document.getElementById('cpBuyerTin'); if(t && !t.value) t.value = pc.buyer_tin; }
 const vipBanner = document.getElementById('cpVipBanner');
 let b = document.getElementById('cpB2BBanner');
 if(!isB2B) { if(b) { b.style.display = 'none'; b.innerHTML = ''; } return; }
 if(!b) {
  b = document.createElement('div');
  b.id = 'cpB2BBanner';
  b.style.cssText = 'margin:8px 0; padding:10px 12px; border-radius:8px; background:#EEF3EC; border:1px solid #CFE0CC; font-size:12px; color:#2F4A2B; line-height:1.5;';
  if(vipBanner && vipBanner.parentElement) vipBanner.parentElement.insertBefore(b, vipBanner);
  else { const host = document.getElementById('checkoutPanel'); if(host) host.insertBefore(b, host.firstChild); }
 }
 b.style.display = 'block';
 let saved = 0, b2bItems = 0;
 if(typeof cart !== 'undefined' && Array.isArray(cart)) {
  cart.forEach(it => { if(it && it.b2b_priced && it.retail_price != null) { saved += (Number(it.retail_price) - Number(it.price)) * (Number(it.quantity) || 0); b2bItems++; } });
 }
 const esc = s => String(s == null ? '' : s).replace(/&/g, '&amp;').replace(/</g, '&lt;');
 const terms = pc.payment_terms ? esc(pc.payment_terms) : 'Tunai / segera';
 const cl = pc.credit_limit ? ('RM ' + Number(pc.credit_limit).toLocaleString('en-MY', { minimumFractionDigits: 2, maximumFractionDigits: 2 })) : '-';
 b.innerHTML = `<div style="font-weight:700; margin-bottom:2px;">Akaun B2B — ${esc(pc.company_name || pc.name || '')}</div>`
  + `<div>Terma bayaran: <strong>${terms}</strong> &middot; Had kredit: <strong>${cl}</strong></div>`
  + (b2bItems > 0
    ? `<div>${b2bItems} item harga rundingan &middot; jimat <strong>RM ${saved.toFixed(2)}</strong> vs retail</div>`
    : `<div style="color:#7A5410;">Tiada harga khas utk item dlm cart — guna retail. Set di B2B &gt; Harga.</div>`);
};
window.__ensureB2BPriceModal = function() {
 let m = document.getElementById('b2bPriceModal');
 if(m) return m;
 m = document.createElement('div');
 m.id = 'b2bPriceModal';
 m.style.cssText = 'display:none; position:fixed; inset:0; background:rgba(0,0,0,.5); z-index:10000; align-items:center; justify-content:center; padding:16px;';
 m.innerHTML = `<div style="background:#fff; border-radius:12px; max-width:580px; width:100%; max-height:90vh; overflow:auto; padding:20px; box-shadow:0 20px 50px rgba(0,0,0,.3);">
   <div style="display:flex; justify-content:space-between; align-items:center; margin-bottom:4px;">
     <h3 style="margin:0; font-size:16px; color:#111;">Harga Khas B2B</h3>
     <button onclick="document.getElementById('b2bPriceModal').style.display='none'" style="background:none; border:none; font-size:24px; cursor:pointer; color:#888; line-height:1;">&times;</button>
   </div>
   <div id="b2bPriceCompany" style="font-size:12px; color:#666; margin-bottom:12px;"></div>
   <div style="background:#F9FAFB; border:1px solid #E5E7EB; border-radius:8px; padding:12px; margin-bottom:14px;">
     <div style="font-size:11px; font-weight:700; color:#374151; margin-bottom:8px; letter-spacing:.3px;">+ TAMBAH / KEMASKINI HARGA</div>
     <input id="b2bPriceSkuInput" list="b2bPriceSkuList" placeholder="Cari SKU atau nama produk" style="width:100%; box-sizing:border-box; padding:8px; border:1px solid #D1D5DB; border-radius:6px; margin-bottom:8px; font-size:13px;">
     <datalist id="b2bPriceSkuList"></datalist>
     <div style="display:flex; gap:8px; align-items:center;">
       <input id="b2bPriceUnit" type="number" step="0.01" min="0" placeholder="Harga seunit (RM)" style="flex:1; box-sizing:border-box; padding:8px; border:1px solid #D1D5DB; border-radius:6px; font-size:13px;">
       <input id="b2bPriceMinQty" type="number" step="1" min="1" value="1" title="Kuantiti minimum sebelum harga ni apply" style="width:84px; box-sizing:border-box; padding:8px; border:1px solid #D1D5DB; border-radius:6px; font-size:13px;">
       <button onclick="window.saveB2BPriceRow()" class="btn btn--primary btn--sm" style="white-space:nowrap;">Simpan</button>
     </div>
     <div id="b2bPriceHint" style="font-size:11px; color:#9CA3AF; margin-top:6px;">Min qty = harga khas hanya apply bila beli &ge; jumlah ni. Letak 1 untuk sentiasa.</div>
   </div>
   <table class="data-table" style="width:100%; font-size:12px;">
     <thead><tr><th>SKU</th><th>Produk</th><th style="text-align:right;">Retail</th><th style="text-align:right;">Harga B2B</th><th style="text-align:right;">Min</th><th></th></tr></thead>
     <tbody id="b2bPriceTbody"></tbody>
   </table>
 </div>`;
 document.body.appendChild(m);
 return m;
};
window.openB2BPriceList = function(customerId) {
 const c = (customersData || []).find(x => String(x.id) === String(customerId));
 if(!c) { if(typeof showToast === 'function') showToast('Customer tak jumpa', 'error'); return; }
 window.__b2bPriceCustId = customerId;
 const m = window.__ensureB2BPriceModal();
 document.getElementById('b2bPriceCompany').textContent = (c.company_name || c.name || '') + ' — harga rundingan per produk';
 const dl = document.getElementById('b2bPriceSkuList');
 if(dl && typeof masterProducts !== 'undefined' && Array.isArray(masterProducts)) {
  const esc = s => String(s == null ? '' : s).replace(/"/g, '&quot;');
  // setiap variant = SKU sendiri; tunjuk label variant (L Khaki / XL Black) supaya senang beza
  dl.innerHTML = masterProducts.slice(0, 5000).map(p => {
   const vlabel = p.variant_size || p.variant_color || '';
   const txt = (p.name || '') + (vlabel ? (' [' + vlabel + ']') : '');
   return `<option value="${esc(p.sku)}">${esc(txt)}</option>`;
  }).join('');
 }
 document.getElementById('b2bPriceSkuInput').value = '';
 document.getElementById('b2bPriceUnit').value = '';
 document.getElementById('b2bPriceMinQty').value = '1';
 window.__renderB2BPriceRows();
 m.style.display = 'flex';
};
window.__renderB2BPriceRows = function() {
 const tb = document.getElementById('b2bPriceTbody');
 if(!tb) return;
 const cid = window.__b2bPriceCustId;
 const rows = (window.__b2bPriceList || []).filter(r => String(r.customer_id) === String(cid));
 if(!rows.length) { tb.innerHTML = '<tr><td colspan="6" style="text-align:center; color:#9CA3AF; padding:18px;">Belum ada harga khas. Tambah di atas.</td></tr>'; return; }
 const esc = s => String(s == null ? '' : s).replace(/&/g, '&amp;').replace(/</g, '&lt;').replace(/"/g, '&quot;').replace(/'/g, '&#39;');
 tb.innerHTML = rows.map(r => {
  const p = (typeof masterProducts !== 'undefined' && Array.isArray(masterProducts)) ? masterProducts.find(x => (x.sku || '').toUpperCase() === (r.sku || '').toUpperCase()) : null;
  const retail = p ? (parseFloat(p.price) || 0) : null;
  const vlabel = p ? (p.variant_size || p.variant_color || '') : '';
  const name = p ? ((p.name || '') + (vlabel ? (' [' + vlabel + ']') : '')) : '—';
  return `<tr>
    <td style="font-family:monospace;">${esc(r.sku)}</td>
    <td>${esc(name)}</td>
    <td style="text-align:right; color:#9CA3AF;">${retail != null ? ('RM ' + retail.toFixed(2)) : '-'}</td>
    <td style="text-align:right; font-weight:700; color:#34522F;">RM ${Number(r.unit_price).toFixed(2)}</td>
    <td style="text-align:right;">${Number(r.min_qty) || 1}</td>
    <td style="text-align:right; white-space:nowrap;"><button onclick="window.editB2BPriceRow('${esc(r.sku)}')" class="btn btn--secondary btn--sm">Edit</button> <button onclick="window.deleteB2BPriceRow('${esc(r.sku)}')" class="btn btn--secondary btn--sm" style="color:#7C2A20;">Padam</button></td>
  </tr>`;
 }).join('');
};
window.editB2BPriceRow = function(sku) {
 const cid = window.__b2bPriceCustId;
 const r = (window.__b2bPriceList || []).find(x => String(x.customer_id) === String(cid) && (x.sku || '').toUpperCase() === (sku || '').toUpperCase());
 if(!r) return;
 document.getElementById('b2bPriceSkuInput').value = r.sku;
 document.getElementById('b2bPriceUnit').value = r.unit_price;
 document.getElementById('b2bPriceMinQty').value = r.min_qty || 1;
 document.getElementById('b2bPriceHint').textContent = 'Edit harga sedia ada untuk ' + r.sku;
 try { document.getElementById('b2bPriceUnit').focus(); } catch(e){}
};
window.saveB2BPriceRow = async function() {
 const cid = window.__b2bPriceCustId;
 if(!cid) return;
 const skuRaw = (document.getElementById('b2bPriceSkuInput').value || '').trim();
 const unit = parseFloat(document.getElementById('b2bPriceUnit').value);
 const minQty = parseInt(document.getElementById('b2bPriceMinQty').value) || 1;
 if(!skuRaw) { if(typeof showToast === 'function') showToast('Pilih SKU dulu', 'error'); return; }
 if(!(unit >= 0)) { if(typeof showToast === 'function') showToast('Harga tak sah', 'error'); return; }
 // input boleh jadi SKU atau nama produk — selaraskan ke SKU kanonik
 let sku = skuRaw;
 const mp = (typeof masterProducts !== 'undefined' && Array.isArray(masterProducts)) ? masterProducts : [];
 const bySku = mp.find(x => (x.sku || '').toUpperCase() === skuRaw.toUpperCase());
 const byName = bySku ? null : mp.find(x => (x.name || '').toLowerCase() === skuRaw.toLowerCase());
 if(bySku) sku = bySku.sku; else if(byName) sku = byName.sku;
 const payload = { customer_id: cid, sku, unit_price: Math.round(unit * 100) / 100, min_qty: minQty, set_by: (typeof currentUser !== 'undefined' && currentUser && currentUser.name) ? currentUser.name : null, updated_at: new Date().toISOString() };
 try {
  const { data, error } = await db.from('b2b_price_list').upsert([payload], { onConflict: 'customer_id,sku' }).select();
  if(error) throw error;
  if(!Array.isArray(window.__b2bPriceList)) window.__b2bPriceList = [];
  const saved = (data && data[0]) ? data[0] : payload;
  const idx = window.__b2bPriceList.findIndex(r => String(r.customer_id) === String(cid) && (r.sku || '').toUpperCase() === sku.toUpperCase());
  if(idx >= 0) window.__b2bPriceList[idx] = saved; else window.__b2bPriceList.push(saved);
  if(typeof showToast === 'function') showToast('Harga B2B disimpan untuk ' + sku, 'success');
  document.getElementById('b2bPriceSkuInput').value = '';
  document.getElementById('b2bPriceUnit').value = '';
  document.getElementById('b2bPriceMinQty').value = '1';
  window.__renderB2BPriceRows();
  // kalau customer ni tengah attached di cashier → reprice cart serta-merta
  if(window.posCustomer && String(window.posCustomer.id) === String(cid) && typeof window.__repriceCartForCustomer === 'function') {
   window.__repriceCartForCustomer();
   if(typeof renderCart === 'function') renderCart();
  }
 } catch(e) { console.error(e); if(typeof showToast === 'function') showToast('Simpan gagal: ' + (e.message || '').slice(0, 80), 'error'); }
};
window.deleteB2BPriceRow = async function(sku) {
 const cid = window.__b2bPriceCustId;
 if(!cid) return;
 if(!confirm('Padam harga khas untuk ' + sku + '?')) return;
 try {
  const { error } = await db.from('b2b_price_list').delete().eq('customer_id', cid).eq('sku', sku);
  if(error) throw error;
  window.__b2bPriceList = (window.__b2bPriceList || []).filter(r => !(String(r.customer_id) === String(cid) && (r.sku || '').toUpperCase() === (sku || '').toUpperCase()));
  if(typeof showToast === 'function') showToast('Harga khas dipadam', 'success');
  window.__renderB2BPriceRows();
  if(window.posCustomer && String(window.posCustomer.id) === String(cid) && typeof window.__repriceCartForCustomer === 'function') {
   window.__repriceCartForCustomer();
   if(typeof renderCart === 'function') renderCart();
  }
 } catch(e) { console.error(e); if(typeof showToast === 'function') showToast('Padam gagal: ' + (e.message || '').slice(0, 80), 'error'); }
};

