window.__applySidebarI18N = function(){
 try {
  const M = window.__SIDEBAR_I18N; if(!M) return;
  const lang = (window.I18N && window.I18N.lang) || 'bm';
  const pick = (m)=> m ? (m[lang]||m.en||m.bm) : null;
  document.querySelectorAll('.menu-list .menu-item[data-tab]').forEach(el=>{
   const v = pick(M.items[el.getAttribute('data-tab')]);
   if(v!=null){ const sp = el.querySelector('span'); if(sp) sp.textContent = v; }
  });
  document.querySelectorAll('.menu-list .menu-item.nav-parent[data-nav-parent]').forEach(el=>{
   const v = pick(M.parents[el.getAttribute('data-nav-parent')]);
   if(v!=null){ const sp = el.querySelector('span'); if(sp) sp.textContent = v; }
  });
  document.querySelectorAll('.menu-list .nav-section-label').forEach((el,i)=>{
   const v = pick(M.sections[i]); if(v!=null) el.textContent = v;
  });
 } catch(e){}
};
window.applyI18N = function() {
 document.querySelectorAll('[data-i18n]').forEach(el => {
 const key = el.getAttribute('data-i18n');
 const val = window.t(key);
 if(val) el.textContent = val;
 });
 // p1_50: placeholders (search inputs, etc.)
 document.querySelectorAll('[data-i18n-placeholder]').forEach(el => {
 const key = el.getAttribute('data-i18n-placeholder');
 const val = window.t(key);
 if(val) el.setAttribute('placeholder', val);
 });
 // p1_50: aria-labels for icon buttons
 document.querySelectorAll('[data-i18n-aria]').forEach(el => {
 const key = el.getAttribute('data-i18n-aria');
 const val = window.t(key);
 if(val) el.setAttribute('aria-label', val);
 });
 // p1_95: title tooltips
 document.querySelectorAll('[data-i18n-title]').forEach(el => {
 const key = el.getAttribute('data-i18n-title');
 const val = window.t(key);
 if(val) el.setAttribute('title', val);
 });
 // Update lang button label
 document.querySelectorAll('#langLabel, .lp-lang-btn__label').forEach(lbl => {
 lbl.textContent = window.I18N.lang.toUpperCase();
 });
 document.documentElement.setAttribute('lang', window.I18N.lang === 'bm' ? 'ms' : 'en');
 // p1_819 — terjemah label sidebar aktif (peta data-tab/nav-parent/section)
 if(typeof window.__applySidebarI18N === 'function') window.__applySidebarI18N();
};

// p1_821 — AUTO-TRANSLATE seluruh UI back office ke English bila mode EN (app dibina BM-dahulu;
// majoriti kandungan hardcoded BM). Guna /api/translate (gpt-4o-mini) + cache kekal (localStorage).
// NON-DESTRUKTIF: simpan teks BM asal per text-node → toggle balik BM pulih serta-merta. Re-apply
// pada re-render via MutationObserver. Skop: #posAppLayout sahaja (landing dah i18n betul). Skip
// SKU/nombor/harga/jenama + widget AI + elemen data-i18n (dah dihandle applyI18N).
window.__UITX = (function(){
 const CACHE_KEY = 'uiTxCache_en_v2';   // p1_823 — bump: buang cache lama (terjemahan salah cth "meals") → terjemah semula dgn prompt domain
 let cache = {};
 try { cache = JSON.parse(localStorage.getItem(CACHE_KEY) || '{}'); } catch(e){}
 let saveT; const saveCache = () => { clearTimeout(saveT); saveT = setTimeout(() => { try { localStorage.setItem(CACHE_KEY, JSON.stringify(cache)); } catch(e){} }, 1000); };
 const origMap = new WeakMap();   // textNode -> original BM string
 const changed = new Set();       // text nodes we translated (skip re-collect + restore on BM)
 const phOrig = new WeakMap();    // input/textarea -> original BM placeholder
 const phChanged = new Set();     // placeholder elements we translated (restore on BM)
 let observer = null, sweepT = null, inflight = false, applying = false, pending = false;
 const SKIP_TAG = { SCRIPT:1, STYLE:1, NOSCRIPT:1, INPUT:1, TEXTAREA:1, CODE:1, PRE:1 };   // p1_825 — SELECT/OPTION dibuang dari skip supaya teks dropdown diterjemah
 const SKIP_ID = { saWidget:1, saPanel:1, caWidget:1, caPanel:1, roadmapSection:1, shopAppLayout:1 };
 function visible(el){ if(!el) return false; if(el.offsetParent !== null) return true; return !!(el.getClientRects && el.getClientRects().length); }
 const lang = () => (window.I18N && window.I18N.lang) || 'bm';
 function skipped(node){
  let el = node.parentElement;
  while(el){
   if(el.tagName && SKIP_TAG[el.tagName]) return true;
   if(el.id && SKIP_ID[el.id]) return true;
   if(el.nodeType===1 && (el.hasAttribute('data-i18n') || el.hasAttribute('data-no-tx') || el.isContentEditable)) return true;
   el = el.parentElement;
  }
  return false;
 }
 function translatable(s){
  const t = (s||'').trim();
  if(t.length < 2) return false;
  if(!/[A-Za-zÀ-ſ]/.test(t)) return false;          // mesti ada huruf
  if(/^[\d\s.,:;%+\-/()RM×x*]+$/i.test(t)) return false;       // nombor/harga/simbol je
  if(/^[A-Z]{1,5}\d{2,}[A-Z]?$/.test(t)) return false;         // SKU cth BD152
  if(/^RM\s?[\d.,]+$/i.test(t)) return false;                  // harga RM
  return true;
 }
 function collect(root){
  const out = [];
  const w = document.createTreeWalker(root, NodeFilter.SHOW_TEXT, { acceptNode(n){
   if(changed.has(n)) return NodeFilter.FILTER_REJECT;
   if(!n.nodeValue || !translatable(n.nodeValue)) return NodeFilter.FILTER_REJECT;
   const pe = n.parentElement;
   const vEl = (pe && pe.tagName === 'OPTION') ? pe.closest('select') : pe;   // option tutup = offsetParent null → semak select
   if(!visible(vEl)) return NodeFilter.FILTER_REJECT;   // hidden section / landing tersembunyi → langkau
   if(skipped(n)) return NodeFilter.FILTER_REJECT;
   return NodeFilter.FILTER_ACCEPT;
  }});
  let n; while((n = w.nextNode())) out.push(n);
  return out;
 }
 function applyCached(nodes){
  applying = true;
  nodes.forEach(n => {
   const raw = n.nodeValue; const key = raw.trim(); const en = cache[key];
   if(en && en !== key){ if(!origMap.has(n)) origMap.set(n, raw); n.nodeValue = raw.replace(key, en); changed.add(n); }
  });
  applying = false;
 }
 // p1_824 — placeholder input/textarea (atribut, bukan text node) — auto-translate juga
 function phSkip(el){
  if(el.hasAttribute('data-i18n-placeholder') || el.hasAttribute('data-no-tx')) return true;
  let p = el.parentElement;
  while(p){ if(p.id && SKIP_ID[p.id]) return true; if(p.nodeType===1 && p.hasAttribute('data-no-tx')) return true; p = p.parentElement; }
  return false;
 }
 function collectPh(root){
  const out = [];
  root.querySelectorAll('input[placeholder], textarea[placeholder]').forEach(el => {
   if(phChanged.has(el)) return;
   const raw = el.getAttribute('placeholder');
   if(!raw || !translatable(raw)) return;
   if(!visible(el) || phSkip(el)) return;
   out.push(el);
  });
  return out;
 }
 function applyPh(els){
  applying = true;
  els.forEach(el => {
   const raw = el.getAttribute('placeholder'); if(!raw) return;
   const key = raw.trim(); const en = cache[key];
   if(en && en !== key){ if(!phOrig.has(el)) phOrig.set(el, raw); el.setAttribute('placeholder', raw.replace(key, en)); phChanged.add(el); }
  });
  applying = false;
 }
 // p1_827 — kamus berkongsi di server (table ui_tx): load segera masa buka (instant, takde tunggu AI)
 // + simpan terjemahan baru balik → auto-membesar, semua staff dapat. BM = asal, EN = kamus baked.
 let __sharedLoaded = false;
 async function loadShared(){
  if(__sharedLoaded) return; __sharedLoaded = true;
  if(!window.db) return;
  try {
   const { data } = await window.db.from('ui_tx').select('src,en').limit(20000);
   const serverKeys = {};
   if(Array.isArray(data)){ data.forEach(r => { if(r && r.src != null && r.en != null){ cache[r.src] = r.en; serverKeys[r.src] = 1; } }); }
   // bootstrap: tolak terjemahan dlm cache tempatan (warm-up sesi lepas) yg belum ada di server
   const seed = [];
   Object.keys(cache).forEach(k => { if(!serverKeys[k] && cache[k] != null) seed.push({ src:k, en:cache[k] }); });
   if(seed.length) pushShared(seed);
   saveCache();
  } catch(e){}
 }
 function pushShared(rows){
  if(!rows || !rows.length || !window.db) return;
  for(let i=0;i<rows.length;i+=400){
   const chunk = rows.slice(i, i+400);
   try { window.db.from('ui_tx').upsert(chunk, { onConflict: 'src' }).then(()=>{}, ()=>{}); } catch(e){}
  }
 }
 async function fetchTx(strings){
  for(let i=0;i<strings.length;i+=55){
   const chunk = strings.slice(i, i+55);
   try {
    const r = await fetch('/api/translate', { method:'POST', headers:{'Content-Type':'application/json'}, body: JSON.stringify({ texts: chunk, target:'en' }) });
    const j = await r.json().catch(()=>({}));
    const out = (j && Array.isArray(j.translations)) ? j.translations : chunk;
    const rows = [];
    chunk.forEach((s,k)=>{ const en = (out[k]!=null) ? out[k] : s; cache[s] = en; rows.push({ src:s, en:en }); });
    pushShared(rows);   // simpan ke kamus berkongsi
   } catch(e){ chunk.forEach(s => { if(cache[s]==null) cache[s] = s; }); }
  }
  saveCache();
 }
 async function sweep(){
  if(lang() !== 'en') return;
  const root = document.body;   // p1_821b — body (sebahagian section bocor luar posAppLayout) + skrin nampak je
  const nodes = collect(root), phels = collectPh(root);
  if(!nodes.length && !phels.length) return;
  applyCached(nodes); applyPh(phels);
  const need = [], seen = {};
  collect(root).forEach(n => { const k = n.nodeValue.trim(); if(cache[k]==null && !seen[k]){ seen[k]=1; need.push(k); } });
  collectPh(root).forEach(el => { const k = (el.getAttribute('placeholder')||'').trim(); if(k && cache[k]==null && !seen[k]){ seen[k]=1; need.push(k); } });
  if(need.length && !inflight){
   inflight = true;
   try { await fetchTx(need); } finally { inflight = false; }
   applyCached(collect(root)); applyPh(collectPh(root));
   if(pending){ pending = false; scheduleSweep(); }   // tangkap kandungan yg render masa fetch (page render berperingkat)
  }
 }
 function scheduleSweep(){ if(inflight){ pending = true; return; } clearTimeout(sweepT); sweepT = setTimeout(()=>{ sweep(); }, 300); }
 function startObserve(){
  if(observer || lang()!=='en') return;
  const root = document.body; if(!root) return;
  observer = new MutationObserver((muts)=>{ if(applying) return; for(const m of muts){ if(m.addedNodes.length || m.type==='characterData'){ scheduleSweep(); break; } } });
  observer.observe(root, { childList:true, subtree:true, characterData:true });
 }
 function stopObserve(){ if(observer){ observer.disconnect(); observer = null; } }
 function restore(){ applying = true; changed.forEach(n => { const o = origMap.get(n); if(o!=null && n.nodeValue!=null) n.nodeValue = o; }); changed.clear(); phChanged.forEach(el => { const o = phOrig.get(el); if(o!=null) el.setAttribute('placeholder', o); }); phChanged.clear(); applying = false; }
 return {
  enable(){ if(lang()!=='en') return; loadShared().then(()=>{ sweep().then(startObserve); }); startObserve(); },
  disable(){ stopObserve(); restore(); },
  refresh(){ if(lang()==='en') scheduleSweep(); }
 };
})();

