 + '<span id="mbCount" style="font-weight:800; color:var(--primary-800,#7C4A1A);"></span>'
 // p1_1158 — pilih/kosong pukal (Zaid: "jenuh nak untick 1 per 1" — 2,450 checkbox)
 + '<span style="display:inline-flex; gap:6px;">'
